INSERT INTO users (id, email, password_hash, full_name, role, target_band, avatar_url, is_active) VALUES ('c9bb450a-4d11-45da-8dd9-4187616c2cc9', 'test@gmail.com', '$2b$12$T/wZY6PvbaTkdseNO6//luV2OiyyQkHhmWrXgxXYN3XeOPPT74SJG', 'string', 'student', NULL, '', 1);
INSERT INTO courses (id, title, description, level, thumbnail_url, price) VALUES ('51ab6c3b-cb47-4729-9d92-8749dac4f244', 'IELTS Foundation (Band 4.0-5.5)', 'Perfect for beginners. Focuses on grammar, essential vocabulary, and basic test formats.', 'beginner', '', 0);
INSERT INTO courses (id, title, description, level, thumbnail_url, price) VALUES ('2c2c44f8-53af-437e-b2c5-f776f69714d5', 'IELTS Academic Intensive (Band 6.5+)', 'Master advanced reading strategies and academic writing tasks with AI feedback.', 'intermediate', '', 49.99);
INSERT INTO courses (id, title, description, level, thumbnail_url, price) VALUES ('4de8d772-8f28-4b2b-8f8b-67dfce9f01a6', 'IELTS Speaking & Writing Expert', 'Deep dive into complex structures and high-level vocabulary for Band 8.0.', 'advanced', '', 89.99);
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('11036a99-bd06-4c8b-b623-2be6aa6f51b2', 'Alleviate', 'To make suffering less severe.', '', 'Health', '7.5');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('520fa669-73b2-42c2-8161-dc434b03ef5d', 'Sustainable', 'Able to be maintained at a certain rate.', '', 'Environment', '6.5');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('5260926c-4959-472b-9409-8dbc9aae31d6', 'Innovation', 'A new method, idea, or product.', '', 'Technology', '5.0');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0c397464-38e0-4a5a-8b32-b15944085110', 'Detrimental', 'Tending to cause harm.', '', 'Health', '7.5');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('19b3c055-d36e-4410-bde6-4d3d6fdb4921', 'Ecosystem', 'A biological community of interacting organisms.', '', 'Environment', '6.5');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3e4f1151-792c-4ab8-82dc-43ebb111f9a1', 'Automation', 'The use of largely automatic equipment.', '', 'Technology', '5.0');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8495d269-1716-44f6-851f-5dd9c700c340', 'a', 'The name of the Latin script letter A/a.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2e4d52ca-ae38-4f37-921a-21fa49efa99c', 'about', 'Moving around; astir.', 'After my bout with Guillan-Barre Syndrome, it took me 6 months to be up and about again.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('51efc7e5-deda-4dba-80fa-784b5e97b5fc', 'above', 'Heaven.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('79e3f16b-2ac1-439b-804c-675c11543a5e', 'across', '(crosswords, often in combination) A word that runs horizontally in the completed puzzle grid or its associated clue.', 'I solved all of the acrosses, but then got stuck on 3 down.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('72fc7209-c426-401c-9e48-6dd0921030c3', 'action', 'Something done so as to accomplish a purpose.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0bf86869-59b8-466a-8df9-084e0612b751', 'activity', 'The state or quality of being active; activeness.', 'Pit row was abuzz with activity.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('69208d1e-59e4-4497-99fb-2ffccbf16d5e', 'actor', 'A person who performs, plays a part in a theatrical play or film.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b6b907c3-8597-47dd-83c0-81d3270950a5', 'actress', 'A female who performs on the stage or in films.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('5f082293-4910-4bd6-81b8-cc310800d7af', 'add', 'An act or instance of adding.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('825da0a4-4ec3-4b81-bf61-20d396379d1e', 'address', 'Direction.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ea651b86-9461-4682-80bc-87dcb11f1265', 'adult', 'A fully grown human or animal.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('5022bdc7-27a6-4fd1-bc59-ee3941604c22', 'advice', 'An opinion offered in an effort to be helpful.', 'She was offered various piece of advice on what to do with her new-found wealth.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('76510447-5585-4046-bce8-168b169614c1', 'afraid', '(usually used predicatively, not attributively, be afraid) Impressed with fear or apprehension; in fear.', 'He is afraid of death.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2f9a5a6b-6097-436b-af97-19fd722ec0e6', 'after', 'Later; second (of two); next, following, subsequent', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('51736623-a10f-4eb9-90bd-52b7aaf8f734', 'afternoon', 'The part of the day from noon or lunchtime until sunset, evening, or suppertime or 6pm.', '', 'Time', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('57177546-bf62-449f-b1c0-46d119398e94', 'again', 'Another time; once more.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1cac39ef-9f9e-4c56-8f07-fb91b103e1e4', 'age', 'The whole duration of a being, whether animal, plant, or other kind, being alive.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('51da8628-d92b-4a22-a5fc-528305e8b7a9', 'ago', 'Gone; gone by; gone away; passed; passed away.', 'in days ago/in days agone', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9ed7f134-544a-4827-8cfe-a50019deb228', 'agree', 'To harmonize in opinion, statement, or action; to be in unison or concord; to be or become united or consistent; to concur.', 'all parties agree in the expediency of the law.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('58291f3b-3223-436c-b200-836d38f28cc1', 'air', 'The substance constituting earth''s atmosphere, particularly:', 'I''m going outside to get some air.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b3923a70-950e-4112-939e-5b8f594665ab', 'airport', 'An airfield (an area designated for the takeoff and landing of aircraft), including one or more runways and (for commercial airports) one or more passenger terminals.', 'Because of this, and contrary to popular belief, British airports primarily act as giant wealth extractors, transporting our richest citizens out of the country as often as possible to take their money overseas. ― The Independent, Heathrow expansion to mainly benefit wealthy frequent fliers, research finds, 23 june 2018.', 'Travel', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('5fa72129-8b14-403b-9a1d-9734a4e93aba', 'all', '(with a possessive pronoun) Everything that one is capable of.', 'She gave her all, and collapsed at the finish line.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('59f98e7e-42e2-40ca-b4b7-29ee7a8d83e5', 'also', '(focus) In addition; besides; as well; further; too.', 'They had porridge for breakfast, and also toast.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('79357359-9a17-4236-91ef-bf5de702095f', 'always', 'At all times; throughout all time; since the beginning.', 'Airplanes did not always exist as a form of transportation.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e8d9e1c7-bc75-4341-9f85-dd5211da44df', 'amazing', 'To fill with wonder and surprise; to astonish, astound, surprise or perplex.', 'He was amazed when he found that the girl was a robot.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6cc9a0d0-7fd9-4247-9f01-46b3d89117fc', 'and', 'In rhythm, the second half of a divided beat.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f66f0278-fcdd-46f7-ae70-9b79a1bdd1e0', 'angry', 'Displaying or feeling anger.', 'An angry mob started looting the warehouse.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c9695838-5d02-455a-99ff-098baa6207d0', 'animal', 'In scientific usage, a multicellular organism that is usually mobile, whose cells are not encased in a rigid cell wall (distinguishing it from plants and fungi) and which derives energy solely from the consumption of other organisms (distinguishing it from plants).', 'A cat is an animal, not a plant. Humans are also animals, under the scientific definition, as we are not plants.', 'Nature', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ee2ac155-6e71-4838-9d30-94f79cf2c3f0', 'another', 'An additional one of the same kind.', 'There is one sterling and here is another', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('62b8b3ef-3659-42bf-8f96-8ffd99bcbf97', 'answer', 'A response or reply; something said or done in reaction to a statement or question.', 'Her answer to his proposal was a slap in the face.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('44b38c39-3dec-48c8-b2f3-cc5757aa8770', 'any', 'To even the slightest extent, at all.', 'I will not remain here any longer.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('132b24fe-2b90-4045-b6db-5cc566901b03', 'anyone', 'Any person; anybody.', 'Almost anyone can change a light bulb.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('245a1b00-3152-40a7-b452-fc71af26c588', 'anything', 'Someone or something of importance.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c70b7151-a0e7-43ab-b15c-fd73f28ff3cf', 'apartment', 'A complete domicile occupying only part of a building, especially one for rent; a flat.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('dd67d6c2-8437-4477-aba1-d7f7e1abadc7', 'apple', 'A common, round fruit produced by the tree Malus domestica, cultivated in temperate climates.', '', 'Food', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1788ffb1-7b70-4bf2-8490-e64c29d32cc4', 'area', 'A measure of the extent of a surface; it is measured in square units.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('bfd316bd-2d5f-40bd-86dc-188cf64e7b42', 'arm', 'The portion of the upper human appendage, from the shoulder to the wrist and sometimes including the hand.', 'She stood with her right arm extended and her palm forward to indicate “Stop!”', 'Body', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8ce131ad-1862-4226-a37d-1b928b1d59b0', 'around', '(with the verb "to be") Present in the vicinity.', 'Is Clare around today?', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8afdba41-2445-43d9-a44f-442ec7895f60', 'arrive', 'To reach; to get to a certain place.', 'He arrived home for two days.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('5c1a917e-25af-49d6-8e0b-87cd76433b1f', 'art', 'The conscious production or arrangement of sounds, colours, forms, movements, or other elements in a manner that affects the senses and emotions, usually specifically the production of the beautiful in a graphic or plastic medium.', 'There is a debate as to whether graffiti is art or vandalism.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9919047e-5454-4d45-a340-7a9ab538f88a', 'article', 'A piece of nonfictional writing such as a story, report, opinion piece, or entry in a newspaper, magazine, journal, dictionary, encyclopedia, etc.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9b7be9b2-4065-429e-ab2b-a1ba25e2a0e9', 'artist', 'A person who creates art.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('86f16ecd-ecc8-4cab-8007-7ded6ff155a0', 'as', 'To such an extent or degree; to the same extent or degree.', 'It''s not as well made, but it''s twice as expensive.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('52b8878f-b271-49e7-845a-1340a4270bc1', 'ask', 'An act or instance of asking.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('604c7430-637b-4e68-9f62-6a407cc76622', 'at', 'To reply to or talk to someone, either online or face-to-face. (from the practice of targeting a message or reply to someone online by writing @name)', 'Cars 2 is the most influential film of all time. Don''t @ me.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a944d8ff-66d4-4f90-b4f1-20f256978a26', 'august', 'Awe-inspiring, majestic, noble, venerable.', 'an august patron of the arts', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('411e1709-9176-4397-87f7-bbc9dae0933f', 'aunt', 'The sister or sister-in-law of one’s parent.', '', 'Family', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d01fee52-3c0a-4c27-8193-e3f9fdec8879', 'autumn', 'Traditionally the third of the four seasons, when deciduous trees lose their leaves; typically regarded as being from September 24 to December 22 in parts of the Northern Hemisphere, and the months of March, April and May in the Southern Hemisphere.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('69638369-65e3-47b4-aade-3a19ab9c4ac9', 'away', 'To depart; to go to another place.', 'At 9 o''clock sharp he awayed to bed.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('17f88488-e6bc-44f3-9aa2-7e5e99f5718c', 'baby', 'A very young human, particularly from birth to a couple of years old or until walking is fully mastered.', '', 'Family', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7dc84dd5-3807-428d-94fc-6729ffe1bcf0', 'back', 'The rear of the body, especially the part between the neck and the end of the spine and opposite the chest and belly.', 'Could you please scratch my back?', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1a7be35f-65fb-44d8-a5c7-7476484267a1', 'bad', 'Error, mistake.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a6bb8c90-6b6d-495f-b2c9-11ddbdac40e2', 'bag', 'A flexible container made of cloth, paper, plastic, etc.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2c07de6c-2b29-4d3e-9c2b-64a39f0bfe51', 'ball', 'A solid or hollow sphere, or roughly spherical mass.', 'a ball of spittle; a fecal ball', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d4759990-1d82-4a33-8eb2-94d49630d784', 'banana', 'An elongated curved tropical fruit that grows in bunches and has a creamy flesh and a smooth skin.', '', 'Food', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1ad05375-935a-42fa-885b-37961a089a17', 'band', 'A strip of material used for strengthening or coupling.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c4f994bf-c767-4cb1-b604-49337e8e11e3', 'bank', 'An institution where one can place and borrow money and take care of financial affairs.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('54252d73-dd68-4fcd-a70a-a063ec8df565', 'bath', 'A tub or pool which is used for bathing: bathtub.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d40b51b8-4a7a-4cbd-aef7-b01ac22c2975', 'bathroom', 'A room containing a shower and/or bathtub, and (typically but not necessarily) a toilet.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('5e523072-bed4-41b5-bbe2-b3a48c41c4c6', 'beach', 'The shore of a body of water, especially when sandy or pebbly.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8f83790a-d7ac-4902-9fce-43703f535755', 'beautiful', 'Someone who is beautiful. Can be used as a term of address.', 'Hey, beautiful!', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('750432a2-df19-48a8-bb19-344276f2d73f', 'because', 'For the reason (that).', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('11c7f23b-0179-4db9-905f-00bb05f1f458', 'become', 'To arrive, come (to a place).', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('5657f2ce-d775-42e2-b620-e5d91fd0e781', 'bed', 'A piece of furniture, usually flat and soft, on which to rest or sleep.', 'My cat often sleeps on my bed.
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('24a78e49-7cbc-4048-a7ac-969d1615b965', 'bedroom', 'A room in a house where a bed is kept for sleeping.', 'Please don''t enter my bedroom without knocking.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1cfcb04a-5093-4347-9388-debcd61b1e8b', 'beer', 'An alcoholic drink fermented from starch material, commonly barley malt, often with hops or some other substance to impart a bitter flavor.', 'Beer is brewed all over the world.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('95694a6b-7736-4fc5-b986-c4cf24443576', 'before', 'At an earlier time.', 'I''ve never done this before.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('619c0e6d-1169-4afd-be19-a497144b6b32', 'begin', 'Beginning; start.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4961d4c1-390f-41c9-90ba-06750377e2bf', 'beginning', 'The act of doing that which begins anything; commencement of an action, state, or space of time; entrance into being or upon a course; the first act, effort, or state of a succession of acts or states.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('44c4dff3-ac6c-48c1-96f2-86154c1f19c4', 'behind', 'The rear, back-end', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('382b9765-4c65-4b58-a36c-858beebcf2d0', 'believe', 'To accept as true, particularly without absolute certainty (i.e., as opposed to knowing)', 'I believe there are faeries.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0893f855-a583-4711-a65c-8311de7dad7e', 'below', 'In a lower place.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('070ade03-0d84-41a2-9dcf-a2d5e9ae76fe', 'best', 'The supreme effort one can make, or has made.', 'I did my best.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e4183a3d-94a8-4d5c-859d-83158931a813', 'better', 'An entity, usually animate, deemed superior to another; one who has a claim to precedence; a superior.', 'He quickly found Ali his better in the ring.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('984b2d75-833f-4e8f-9c9a-ac519954258d', 'between', 'A kind of needle, shorter than a sharp, with a small rounded eye, used for making fine stitches on heavy fabrics.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('490b71fb-46ae-4929-bbc7-e2bae29963c3', 'bicycle', 'A vehicle that has two wheels, one behind the other, a steering handle, and a saddle seat or seats and is usually propelled by the action of a rider’s feet upon pedals.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('58e15745-57fd-4dfa-93b2-c86210ab662d', 'big', 'Someone or something that is large in stature', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1b9cdf25-0bbf-4ee7-ba1a-6eaccddc3c16', 'bike', 'A vehicle that has two wheels, one behind the other, a steering handle, and a saddle seat or seats and is usually propelled by the action of a rider’s feet upon pedals.', '', 'Travel', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('28545342-64f9-463a-86eb-975bbacb5836', 'bill', 'Any of various bladed or pointed hand weapons, originally designating an Anglo-Saxon sword, and later a weapon of infantry, especially in the 14th and 15th centuries, commonly consisting of a broad, heavy, double-edged, hook-shaped blade, with a short pike at the back and another at the top, attached to the end of a long staff.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3021f062-c3c2-469b-afde-91ddd43e7fcb', 'bird', 'A member of the class of animals Aves in the phylum Chordata, characterized by being warm-blooded, having feathers and wings usually capable of flight, and laying eggs.', 'Ducks and sparrows are birds.', 'Nature', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e095b034-4362-4e5a-af7f-8fca55e7c8b2', 'birthday', 'The anniversary of the day on which someone is born.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('49f4c708-7391-4b0c-99aa-919343d69db2', 'black', 'The colour/color perceived in the absence of light, but also when no light is reflected, but rather absorbed.', '', 'Colors', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('869c41f2-dfa5-4e7a-b6af-d721759e2a95', 'blog', 'A website that allows users to reflect, share opinions, and discuss various topics in the form of an online journal, sometimes letting readers comment on their posts. Most blogs are written in a slightly informal tone (personal journals, news, businesses, etc.)', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1eea7133-65b1-43b9-9ac8-c78a6655bedb', 'blonde', 'A pale yellowish (golden brown) color, especially said of hair color.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d74063cc-785f-4350-aae3-0665e7c94743', 'blue', 'The colour of the clear sky or the deep sea, between green and violet in the visible spectrum, and one of the primary additive colours for transmitted light; the colour obtained by subtracting red and green from white light using magenta and cyan filters; or any colour resembling this.', '', 'Colors', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ac29efa2-66b2-498b-b829-a4c464df0031', 'boat', 'A craft used for transportation of goods, fishing, racing, recreational cruising, or military use on or in the water, propelled by oars or outboard motor or inboard motor or by wind.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('85188266-031e-4528-bdf6-36eaa61fb2b5', 'body', 'Physical frame.', '', 'Body', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b88b6455-90c6-4678-b5b6-52face4e2154', 'book', 'A collection of sheets of paper bound together to hinge at one edge, containing printed or written material, pictures, etc.', 'He was frustrated because he couldn''t find anything about dinosaurs in the book.', 'Education', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a1279e74-882a-418d-a88c-411b515aa024', 'boot', 'A heavy shoe that covers part of the leg.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('bc9ca5a1-6463-4856-8deb-9549ec7b3e66', 'bored', 'To inspire boredom in somebody.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a3514d14-2827-432b-8a0c-2d4c254a9c50', 'boring', 'To inspire boredom in somebody.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c48ce5f6-4ebc-41ac-a24c-c096c525782e', 'born', 'To carry or convey, literally or figuratively.', 'Judging from the look on his face, he wasn''t bearing good news.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2852d57d-8922-41f7-a32a-411bbb276b26', 'both', 'Each of the two, or of the two kinds.', '"Did you want this one or that one?" — "Give me both."', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4b54c695-8365-42f3-992f-d5ef3a78fdb3', 'bottle', 'A container, typically made of glass or plastic and having a tapered neck, used primarily for holding liquids.', 'Beer is often sold in bottles.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('754bd263-ca2b-41e4-af68-e68fc2d50768', 'box', 'Senses relating to a three-dimensional object or space.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('955c390e-a201-4e7e-bfac-73f9fb71eed6', 'boy', 'A young male.', 'Kate is dating a boy named Jim.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e3e75f26-c9c2-47f6-878c-79233083e7cd', 'boyfriend', 'A male partner in an unmarried romantic relationship.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('bb15098f-e16d-4cbe-96eb-ad86b8e89d30', 'bread', 'A foodstuff made by baking dough made from cereals.', '', 'Food', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9760ca6e-0f70-47dd-acb7-9d443027de01', 'break', 'An instance of breaking something into two or more pieces.', 'The femur has a clean break and so should heal easily.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('32201aff-9841-4856-9dda-a88003ef11c5', 'breakfast', 'The first meal of the day, usually eaten in the morning.', 'You should put more protein in her breakfast so she will grow.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('67aee899-ffd8-49aa-b38c-72eb5d1b1f0b', 'bring', '(ditransitive) To transport toward somebody/somewhere.', 'Waiter, please bring me a single malt whiskey.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('362684bb-e865-4e2b-b348-e9f5de8efcb1', 'brother', 'Son of the same parents as another person.', '', 'Family', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('61ed15d9-47e0-40e1-918b-250506050d07', 'brown', 'A colour like that of chocolate or coffee.', 'The browns and greens in this painting give it a nice woodsy feel.', 'Colors', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('13b0a454-594a-447a-81ac-818d063252f5', 'build', 'The physique of a human body; constitution or structure of a human body.', 'Rugby players are of sturdy build.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6d7946ca-7123-4310-9e85-f5af89458f7c', 'building', 'The act or process by which something is built; construction.', 'The building of the bridge will be completed in a couple of weeks.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c56b8451-3903-4cd4-a3d9-7b8225b56f7e', 'bus', 'A motor vehicle for transporting large numbers of people along roads.', '', 'Travel', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2e5dd0eb-d485-4a28-b3dc-3bbfc0e406b8', 'business', 'A specific commercial enterprise or establishment.', 'I was left my father''s business.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('aa9d4c2d-091f-457d-8a8f-6f9cde91066a', 'busy', 'A police officer.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e4e68bd0-4b0a-4072-afc6-95e2f46527b3', 'but', 'An instance or example of using the word "but".', 'It has to be done – no ifs or buts.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('866d949b-3f77-471b-b74f-5ea56480007d', 'butter', 'A soft, fatty foodstuff made by churning the cream of milk (generally cow''s milk).', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8e5229bd-84b2-4ede-8f6f-8f6b20b6f648', 'buy', 'Something which is bought; a purchase.', 'At only $30, the second-hand kitchen table was a great buy.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a4775fc2-665d-43d7-99b0-d76dc12cba23', 'by', 'A flying insect, of the clade Anthophila within the hymenopteran superfamily Apoidea, known for its organised societies (though only a minority have them), for collecting pollen and (in some species) producing wax and honey.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8f02d1ca-a727-438b-9cdd-a11c77905835', 'bye', 'The position of a person or team in a tournament or competition who draws no opponent in a particular round so advances to the next round unopposed, or is awarded points for a win in a league table; also the phantom opponent of such a person or team.', 'Craig''s Crew plays the bye next week.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a31ebd94-f8c3-455a-91d7-e9ed74f2435c', 'cafe', 'A convenience store, originally one that sold coffee and similar basic items.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9f779cd8-f43c-4c4b-a307-7bf97d278e1c', 'cake', 'A rich, sweet dessert food, typically made of flour, sugar and eggs and baked in an oven, and often covered in icing.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('de59eb42-ec83-405c-b335-470e99c94f0a', 'call', 'A telephone conversation.', 'I received several calls today.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('041e2a78-e0ac-41f5-817a-50f05db47d1b', 'camera', 'A device for taking still or moving pictures or photographs.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('12bc8db6-be96-42ab-b0fa-d6dbc77b8625', 'can', '(auxiliary verb, defective) To know how to; to be able to.', 'She can speak English, French, and German.   I can play football.   Can you remember your fifth birthday?', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0c3cda82-95ca-42cd-8cbc-7a232040625f', 'cannot', 'Something that cannot be done.', 'the cans and cannots', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3f5a41a0-2e04-431a-8b86-953553794af5', 'capital', 'Already-produced durable goods available for use as a factor of production, such as steam shovels (equipment) and office buildings (structures).', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('06275273-d639-472f-9ea4-0e0e9b399eed', 'car', 'A wheeled vehicle that moves independently, with at least three wheels, powered mechanically, steered by a driver and mostly for personal transportation.', 'She drove her car to the mall.', 'Travel', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ac06c317-4ddf-4232-ae44-7fbb1a285027', 'card', 'A playing card.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4280adee-5937-43ba-a067-f3c7b859013b', 'career', 'One''s calling in life; a person''s occupation; one''s profession.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7f32eee8-aca4-4287-b7e7-4e39488a90c1', 'carrot', 'A vegetable with a nutritious, juicy, sweet root that is often orange in colour, Daucus carota, especially the subspecies sativus in the family Apiaceae.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2fe29bcb-45c0-4c54-9907-dd30ef4d71de', 'carry', 'A manner of transporting or lifting something; the grip or position in which something is carried.', 'Adjust your carry from time to time so that you don''t tire too quickly.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1f3ea198-7dce-4c00-9e75-e34d1d364235', 'cat', 'An animal of the family Felidae:', '', 'Nature', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('aa24c2d0-68be-4371-a484-ee52ceb39627', 'cent', '(money) A subunit of currency equal to one-hundredth of the main unit of currency in many countries. Symbol: ¢.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('36a8dce5-886e-4537-b56f-9b14471b14f3', 'centre', 'The point in the interior of a circle that is equidistant from all points on the circumference.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('15501d1f-3991-4d97-9752-b49a465b1e46', 'century', 'A period of 100 consecutive years; often specifically a numbered period with conventional start and end dates, e.g., the twentieth century, which stretches from (strictly) 1901 through 2000, or (informally) 1900 through 1999. The first century AD was from 1 to 100.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1d097197-6348-4c41-90f1-1e04c2556b98', 'chair', 'An item of furniture used to sit on or in, comprising a seat, legs, back, and sometimes arm rests, for use by one person. Compare stool, couch, sofa, settee, loveseat and bench.', 'All I need to weather a snowstorm is hot coffee, a warm fire, a good book and a comfortable chair.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3eacdd9f-4de0-4b3b-8bac-0534fc89d573', 'change', 'The process of becoming different.', 'The product is undergoing a change in order to improve it.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f2af7c35-2b86-499a-aaca-925756101295', 'chart', 'A map.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('97f49e4c-8b1b-4d22-9551-b1c3ef5ecfe6', 'cheap', 'Trade; traffic; chaffer; chaffering.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2aa6b117-cbeb-450e-af16-3da386f55083', 'check', 'A situation in which the king is directly threatened by an opposing piece.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f6d098c6-bee6-46cd-9e30-716183f9706f', 'cheese', 'A dairy product made from curdled or cultured milk.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0737bae5-0b45-420e-b669-a8f111362044', 'chicken', 'A domestic fowl, Gallus gallus, especially when young.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('bfe92305-9fbd-4902-84f4-924559aa59db', 'child', 'A person who has not yet reached adulthood, whether natural (puberty), cultural (initiation), or legal (majority)', 'Go easy on him: he is but a child.', 'Family', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9c81b947-cdfb-44e3-8692-a23267e24aca', 'chocolate', 'A food made from ground roasted cocoa beans.', 'Chocolate is a very popular treat.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0d6285df-3927-45cc-9761-2326691ee3a6', 'choose', 'To pick; to make the choice of; to select.', 'I chose a nice ripe apple from the fruit bowl.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('36b189b5-29f9-40fd-b10d-c59799e4d4e5', 'cinema', 'A movie theatre, a movie house', 'The cinema is right across the street from the restaurant.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('91bcae1d-6cf9-48e8-bee2-b0bb8ee58a27', 'city', 'A large settlement, bigger than a town; sometimes with a specific legal definition, depending on the place.', 'São Paulo is the largest city in South America.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('da10d33a-cd59-46e3-a1c2-2bb8b42b0e48', 'class', 'A group, collection, category or set sharing characteristics or attributes.', 'Often used to imply membership of a large class.', 'Education', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a1c9a815-61b0-4662-9789-01a526405f46', 'classroom', 'A room, often in a school, where classes take place', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('99e879bb-e6c2-4d28-9c5c-3e4eba7addcd', 'clean', 'Removal of dirt.', 'This place needs a clean.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d048acfa-0f91-4a75-b4b9-d2d2b0f6f2aa', 'climb', 'An act of climbing.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e595856d-3854-40f4-bd5f-0594c93c7353', 'clock', 'An instrument used to measure or keep track of time; a non-portable timepiece.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1887e2e5-1720-4224-844a-327429f56a4a', 'close', 'An end or conclusion.', 'We owe them our thanks for bringing the project to a successful close.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('fa20ac74-e593-440c-ac8c-da8eae82e1a9', 'clothes', 'A woven fabric such as used in dressing, decorating, cleaning or other practical use.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ec27d882-9eb9-4d7d-96fe-31eb1f496b45', 'far', 'Distant; remote in space.', 'He went to a far land.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('30d1b96d-7a87-492f-80d9-93fe6e550ed5', 'club', 'An association of members joining together for some common purpose, especially sports or recreation.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4e29a607-4307-4e26-ad94-bf7d08e31f7d', 'coat', 'An outer garment covering the upper torso and arms.Wp', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c493342f-3be8-41c4-9788-82af10835d90', 'coffee', 'A beverage made by infusing the beans of the coffee plant in hot water.', '', 'Food', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ae78cb7f-0600-4d2f-8db1-bebcd1f8299e', 'cold', '(of a thing) Having a low temperature.', 'A cold wind whistled through the trees.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('fe17e50c-55dc-4dda-a492-e6509fa65160', 'college', 'A corporate group; a group of colleagues.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('67035cf3-f467-4c34-bedf-d8ff69c06e64', 'colour', 'The spectral composition of visible light', 'Humans and birds can perceive color.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('917acc8e-1351-49e8-8ee0-1c48050e6076', 'come', 'Coming, arrival; approach.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2d262ea5-218a-4a49-b2e3-2036d03f895a', 'common', 'Mutual good, shared by more than one.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ab88f96f-1288-4b5e-9617-32aebae07027', 'company', 'A team; a group of people who work together professionally.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7a9852a0-f1e0-40f1-b3b4-8e57b47184b0', 'compare', 'Comparison.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ad8855d0-5bda-4d33-acac-160f1dd6cdc9', 'complete', 'A completed survey.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ee5dba5e-12bc-4de3-a095-f9dace6736f3', 'computer', 'A person employed to perform computations; one who computes.', '', 'Technology', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ade1f6b4-5ebd-47e3-a661-a90cb880ab05', 'concert', 'Agreement in a design or plan; union formed by mutual communication of opinions and views; accordance in a scheme; harmony; simultaneous action.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('dc1450c9-4586-4f57-b14c-1fd22c991825', 'conversation', 'Expression and exchange of individual ideas through talking with other people; also, a set instance or occasion of such talking.', 'I had an interesting conversation with Nicolas yesterday about how much he''s getting paid.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2d6c2540-cd75-4a0e-9d69-3d47061e236a', 'cook', 'A person who prepares food.', 'I''m a terrible cook, so I eat a lot of frozen dinners.', 'Food', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c4a077e4-26b5-459b-8d0a-f506ae649909', 'cooking', 'To prepare (food) for eating by heating it, often by combining it with other ingredients.', 'I''m cooking bangers and mash.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b0ab442d-e803-452d-b579-437dbecd6ca9', 'cool', 'A moderate or refreshing state of cold; moderate temperature of the air between hot and cold; coolness.', 'in the cool of the morning', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0204661d-276c-4b41-a836-b657e20207d3', 'correct', 'Free from error; true; accurate.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('05a06769-5d29-43e1-aeaa-a0440fd92f83', 'cost', 'To incur a charge of; to require payment of a (specified) price.', 'It will cost you a lot of money to take a trip around the world.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('cfbfcee3-1616-4f7b-a4f0-d7a14ffd1a4a', 'could', '(auxiliary verb, defective) To know how to; to be able to.', 'She can speak English, French, and German.   I can play football.   Can you remember your fifth birthday?', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('bc4eacb5-5544-4d47-ae01-ad4947317324', 'country', '(chiefly British) An area of land; a district, region.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3bcf51d7-8ced-497b-a2d7-e58ac1fba9fd', 'course', 'A sequence of events.', 'The normal course of events seems to be just one damned thing after another.', 'Education', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b3077c3a-552c-47f4-8f2c-660d05c9e2a0', 'cousin', 'The child of a person''s uncle or aunt; a first cousin.', 'I think my cousin is a good man.', 'Family', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d182c8c8-1152-4030-9db3-641c90278a38', 'cow', '(properly) An adult female of the species Bos taurus, especially one that has calved.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('671972a2-6e53-4bdf-a6fe-43dd9b0ea3f8', 'cream', 'The butterfat/milkfat part of milk which rises to the top; this part when separated from the remainder.', 'Take 100 ml of cream and 50 grams of sugar…', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b58a6185-d401-47da-abcc-c313ce2b1bb4', 'create', 'To bring into existence; (sometimes in particular:)', 'You can create the color orange by mixing yellow and red.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c61a7ecf-6381-4e84-8af0-544112f16aee', 'culture', 'The arts, customs, lifestyles, background, and habits that characterize a particular society or nation.', '', 'Society', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e12b519f-f5c2-4bd8-9115-07884368c2e2', 'cup', 'A concave vessel for drinking from, usually made of opaque material (as opposed to a glass) and with a handle.', 'Pour the tea into the cup.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('81709a10-4d23-481a-9ea0-2d43e7b7dbdc', 'customer', 'A patron, a client; one who purchases or receives a product or service from a business or merchant, or intends to do so.', 'Every person who passes by is a potential customer.', 'Business', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('37e64663-ee4d-457a-988b-cc8725464206', 'cut', 'The act of cutting.', 'He made a fine cut with his sword.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('79495225-5947-41f8-8bec-dfbcd26fa81c', 'dad', 'A father, a male parent.', 'His dad was always there for him.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('05a0e52e-a350-483c-a677-b037aca6a87f', 'dance', 'A sequence of rhythmic steps or movements usually performed to music, for pleasure or as a form of social interaction.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('498f8bcb-92d1-4024-a995-f90ecdaa9bd2', 'dancer', 'A person who dances, usually as a job or profession.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('aee274ce-37d7-4a07-bb32-08c22128a748', 'dancing', 'To move with rhythmic steps or movements, especially in time to music.', 'I danced with her all night long.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('60c93364-2196-4bad-8ef3-d8b455e1afbd', 'dangerous', 'Full of danger.', 'Railway crossings without gates are highly dangerous.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('bd94615d-6053-42a7-ae67-9244124c47ca', 'dark', 'Having an absolute or (more often) relative lack of light.', 'The room was too dark for reading.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('df74ef17-d35e-4ea7-9cc0-7e4e92dd1912', 'date', 'The fruit of the date palm, Phoenix dactylifera, somewhat in the shape of an olive, containing a soft, sweet pulp and enclosing a hard kernel.', 'We made a nice cake from dates.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('cd097f94-7ac3-4dfd-bce6-47e516822dfd', 'daughter', 'One’s female offspring.', 'I already have a son, so I would like to have a daughter.', 'Family', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e88f7aee-8a69-4907-bd9b-a3b06402a69f', 'day', 'Any period of 24 hours.', 'I''ve been here for two days and a bit.', 'Time', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('696d80fe-7a74-4dd9-83d1-dd7b1b9c6703', 'dear', 'A very kind, loving person.', 'My cousin is such a dear, always drawing me pictures.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d5a092fc-f120-47ee-be02-e397f0f9b647', 'decide', 'To resolve (a contest, problem, dispute, etc.); to choose, determine, or settle', 'Her last-minute goal decided the game.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7560136e-4309-46a3-b1ca-28c4f5b4861e', 'delicious', 'Pleasing to taste; tasty.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1be71e76-e66d-421d-8252-be255815d443', 'describe', 'To represent in words.', 'The feeling is difficult to describe, but not unpleasant.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3fa28c24-de5f-4f8c-91eb-b5a73eb4152d', 'description', 'A sketch or account of anything in words; a portraiture or representation in language; an enumeration of the essential qualities of a thing or species.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9cee6fc0-0763-4a3e-9bdf-77e86d8f3a37', 'design', 'A specification of an object or process, referring to requirements to be satisfied and thus conditions to be met for them to solve a problem.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d641e5b8-5fa7-423a-9cee-f31f217c2a12', 'desk', 'A table, frame, or case, in past centuries usually with a sloping top but now usually with a flat top, for the use of writers and readers. It often has a drawer or repository underneath.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c3f38dc0-5a2e-4423-b8dc-1e5bcb0d9bac', 'detail', 'Something small enough to escape casual notice.', 'Note this fine detail in the lower left corner.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9b2cf590-44b5-4c23-afc2-f65d98b29f22', 'dialogue', 'A conversation or other form of discourse between two or more individuals.', 'Bill and Melinda maintained a dialogue via email over the course of their long-distance relationship.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4ca8faa5-22fa-4e04-a7ce-2f8a1c2c3f17', 'dictionary', 'A reference work with a list of words from one or more languages, normally ordered alphabetically, explaining each word''s meaning, and sometimes containing information on its etymology, pronunciation, usage, translations, and other data.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('87ec7889-5e0a-41f2-a34a-01a85db583c0', 'die', 'To stop living; to become dead; to undergo death.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('297b626b-78d1-4d89-9bcf-e6cd0bf8d068', 'diet', 'The food and beverage a person or animal consumes.', 'The diet of the Giant Panda consists mainly of bamboo.', 'Food', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('271ee462-ace5-4873-bf5a-745800f9f209', 'difference', 'The quality of being different.', 'You need to learn to be more tolerant of difference.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('88bb4668-4400-48a2-b6a9-0f09a1ca5f7f', 'different', 'The different ideal.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('edbe2007-0f49-4074-9773-a9ecdca31e93', 'difficult', 'To make difficult; to impede; to perplex.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ae640a11-d2ba-4acc-bc19-3668137bf0d5', 'dinner', 'A midday meal (in a context in which the evening meal is called supper or tea).', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9c1483b0-6421-4279-9f28-752fab614f77', 'dirty', 'To make (something) dirty.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d4386d12-2c3a-47a9-9d3b-538f24673432', 'discuss', 'To converse or debate concerning a particular topic.', 'I don''t wish to discuss this further. Let''s talk about something else.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('43014aac-6c26-433e-a9f5-37a483987513', 'dish', 'A vessel such as a plate for holding or serving food, often flat with a depressed region in the middle.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f3f4d9c7-0f3a-4fd0-83e6-d67d998fe14f', 'do', 'A party, celebration, social function.', 'We’re having a bit of a do on Saturday to celebrate my birthday.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('119bc6fd-4781-490c-a77a-260490dbc81c', 'doctor', 'A physician; a member of the medical profession; one who is trained and licensed to heal the sick or injured. The final examination and qualification may award a doctor degree in which case the post-nominal letters are D.O., DPM, M.D., DMD, DDS, in the US or MBBS in the UK.', 'If you still feel unwell tomorrow, see your doctor.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('38c1a5b2-57fd-4492-be4d-5ba5a8352f77', 'dog', 'A mammal, Canis familiaris or Canis lupus familiaris, that has been domesticated for thousands of years, of highly variable appearance due to human breeding.', 'The dog barked all night long.', 'Nature', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('13ff494a-4385-4dc6-ab63-1868c6e78343', 'dollar', 'Official designation for currency in some parts of the world, including Canada, the United States, Australia, New Zealand, Hong Kong, and elsewhere. Its symbol is $.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a9d941b1-e8f2-4c95-a39d-9d5509301a87', 'door', 'A portal of entry into a building, room, or vehicle, consisting of a rigid plane movable on a hinge. Doors are frequently made of wood or metal. May have a handle to help open and close, a latch to hold the door closed and a lock that ensures the door cannot be opened without the key.', 'I knocked on the vice president''s door', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('cf2137c3-5410-42ce-aada-d2d516e3e244', 'down', 'A negative aspect; a downer.', 'I love almost everything about my job. The only down is that I can''t take Saturdays off.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('723e1626-b8cf-4feb-b6e2-761b8edcdbab', 'downstairs', 'The lower floor of a house, at ground level.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('13c29e31-5c24-4896-9fa5-ed0d0e405644', 'draw', 'The result of a contest that neither side has won; a tie.', 'The game ended in a draw.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a7a67855-e383-45da-b3ef-777468d04a18', 'dress', 'An item of clothing (usually worn by a woman or young girl) which both covers the upper part of the body and includes skirts below the waist.', 'Amy and Mary looked very pretty in their dresses.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4bc61ae0-98e7-4d36-a10c-d6868b06bf0b', 'drink', 'To consume (a liquid) through the mouth.', 'He drank the water I gave him.', 'Food', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('27f60a4e-2c4b-4e8c-99e4-0cbd5ab0e340', 'drive', 'Motivation to do or achieve something; ability coupled with ambition.', 'Crassus had wealth and wit, but Pompey had drive and Caesar as much again.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d67e44c6-213c-428b-97b0-76e72f1c95b7', 'driver', 'One who drives something, in any sense of the verb to drive.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e67f8277-d61a-4801-a840-6e1558d8d6db', 'during', 'To last, continue, endure.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('89c2c6c4-f82e-491c-984f-b3162e4d208e', 'each', '(operations) An individual item: the least quantitative unit in a grouping.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c5b7bfda-d6cc-47aa-b582-074bd02849fa', 'ear', 'The organ of hearing, consisting of the pinna, auditory canal, eardrum, malleus, incus, stapes and cochlea.', '', 'Body', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('89b36b2f-396c-4266-9dd8-17473b8ef7fd', 'early', 'A shift (scheduled work period) that takes place early in the day.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('db86d0b8-ad89-4a86-a208-09babe153fc8', 'east', 'One of the four principal compass points, specifically 90°, conventionally directed to the right on maps; the direction of the rising sun at an equinox. Abbreviated as E.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('00921fb0-c0f3-42bb-a9ed-be4589cf3015', 'easy', 'Something that is easy', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f120163d-0641-49e3-83ee-345554bdf924', 'eat', 'Something to be eaten; a meal; a food item.', '', 'Food', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3213cabe-b740-4276-9e8e-73d6b54f3ea6', 'egg', 'An approximately spherical or ellipsoidal body produced by birds, reptiles, insects and other animals, housing the embryo during its development.', '', 'Food', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4284faf3-de2f-41e9-b3a6-a472df20241d', 'eight', 'The digit/figure 8.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('517085a7-9472-4835-8f04-05089e653069', 'eighteen', 'The cardinal number occurring after seventeen and before nineteen, represented in Roman numerals as XVIII and in Arabic numerals as 18.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f7931c76-2f1d-4cf2-88ad-d11fb0088130', 'eighty', 'The cardinal number occurring after seventy-nine and before eighty-one, represented in Roman numerals as LXXX and in Arabic numerals as 80.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2e293992-b909-4795-8fc3-4e36af6d57f7', 'elephant', 'A mammal of the order Proboscidea, having a trunk, and two large ivory tusks jutting from the upper jaw.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('fd24340b-459c-435b-8259-5682f1264195', 'eleven', 'A cricket team of eleven players. Hence first eleven - the team of best cricket players (at a school), second eleven - the "B" team, etc.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b0a3a8cc-0421-44e8-8d45-990e733b1514', 'else', '(used only with indefinite or interrogative pronouns) Other; in addition to previously mentioned items.', 'The instructor is busy. Can anyone else help me?', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('83ac257a-d3ce-4505-ba56-13f53d755f77', 'email', 'A system for transferring messages from one computer to another, usually through a network.', 'He sent me his details via email.', 'Technology', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d0202760-af09-4446-8833-65ab4a84416b', 'empty', '(usually plural) A container, especially a bottle, whose contents have been used up, leaving it empty.', 'Put the empties out to be recycled.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('987de3a1-0fd9-4695-a0a0-d62e6dd88a6f', 'end', 'The terminal point of something in space or time.', 'At the end of the road, turn left.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('beccc0d7-be98-4665-b090-152545ef689a', 'english', 'Spinning or rotary motion given to a ball around the vertical axis, as in billiards or bowling.', 'You can''t hit it directly, but maybe if you give it some english.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2c8000f5-1615-4d64-9a45-4c59f381a47c', 'enjoy', 'To receive pleasure or satisfaction from something', 'Enjoy your holidays!   I enjoy dancing.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2839a6c0-cbf8-4bad-9100-d5b095809e99', 'enough', 'Sufficiently.', 'Are you man enough to fight me?', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('463b5e12-2bd0-4d29-941f-549991b62d1d', 'euro', 'Person living or originating from Europe', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e966be37-cfcb-4982-bbb8-f85bc371c4e3', 'even', '(diminutive) An even number.', 'So let''s see. There are two evens here and three odds.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7658d375-b215-40b7-9eba-1b481711b311', 'evening', 'The time of the day between dusk and night, when it gets dark.', '', 'Time', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f080aebf-da93-496c-a70f-fd1ca1c45e4b', 'event', 'An occurrence; something that happens.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('172e1115-c83e-48ab-b87f-2f2e13199c4c', 'ever', 'Occurring at any time, occurring even but once during a timespan.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f40fee98-8463-4c66-b2ed-50f7fb1a0660', 'everybody', 'All people.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6293fe70-b86d-42de-b880-ed7dab26aa81', 'everyone', 'Every person.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4c4ed4f5-4fc0-42d1-846a-abffebfd24bf', 'everything', 'All the things under discussion.', 'I checked the list again and everything is done.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8a393d88-ad43-469e-a465-8d9fddac87ae', 'exam', 'The act of examining.', '', 'Education', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('66a72e74-137b-4a7b-b5b6-c6f58667514f', 'example', 'Something that is representative of all such things in a group.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7380e723-a19a-4a23-be1c-2a32de5b8764', 'excited', 'To stir the emotions of.', 'The fireworks which opened the festivities excited anyone present.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('84ffcdb3-fa72-4c15-b6ee-47d04fe57bd1', 'exciting', 'To stir the emotions of.', 'The fireworks which opened the festivities excited anyone present.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('712892b0-211e-4635-912e-3d1ba88e415e', 'exercise', 'Any activity designed to develop or hone a skill or ability.', 'The teacher told us that the next exercise is to write an essay.', 'Health', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c3fd4fbe-9bec-4027-8074-60d215248374', 'expensive', 'Given to expending a lot of money; profligate, lavish.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a0c9b47a-9e90-4161-819e-596b425c09f0', 'explain', 'To make plain, manifest, or intelligible; to clear of obscurity; to illustrate the meaning of.', 'To explain a chapter of the Bible.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('212eb25a-2b5d-430d-95d9-4d4681c83d0d', 'extra', 'Something additional, such as an item above and beyond the ordinary school curriculum, or added to the usual charge on a bill.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('56bc2833-144f-4ff7-865d-d3b06d2cba6e', 'eye', 'An organ through which animals see (perceive surroundings via light).', 'Bright lights really hurt my eyes.', 'Body', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('08a3fafc-fde6-476f-9920-c1554269d077', 'face', 'The front part of the head of a human or other animal, featuring the eyes, nose and mouth, and the surrounding area.', 'That girl has a pretty face.', 'Body', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('234a8e88-c8be-4bda-862d-a46d775b9420', 'fact', 'Something actual as opposed to invented.', 'In this story, the Gettysburg Address is a fact, but the rest is fiction.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b053da66-c55f-48fb-8d8a-b95ba1176a98', 'fall', 'The act of moving to a lower position under the effect of gravity.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ffc1ed4d-b1cd-4b8a-bd73-91bbebdd0fd7', 'false', 'One of two options on a true-or-false test.', 'The student received a failing grade for circling every true and false on her quiz.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('cd83f500-5a55-486a-a4f6-c6a0a7c50d17', 'family', 'A group of people who are closely related to one another (by blood, marriage or adoption); kin; for example, a set of parents and their children; an immediate family.', 'Our family lives in town.', 'Family', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4e857d00-f3c3-4e98-bc53-f5a37454458c', 'famous', 'To make famous; to bring renown to.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('24692e9c-bc86-4337-ad09-2c6bd2b5c500', 'fantastic', 'A fanciful or whimsical person.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3420bbc6-ebe0-468e-a3b7-17bf981da6cf', 'sometimes', 'Former; sometime.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8fcec47c-c595-42d7-9475-bd84b1686f56', 'farm', 'A place where agricultural and similar activities take place, especially the growing of crops or the raising of livestock.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2c55964e-63fc-4059-b661-0ad9270ccbf8', 'farmer', 'A person who works the land and/or who keeps livestock, especially on a farm.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('45d7a0d6-e257-453c-bf7c-fdaab7db284b', 'fast', 'A train that calls at only some stations it passes between its origin and destination, typically just the principal stations', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('669dfbbb-e587-45dd-856a-2665d8cead8e', 'fat', 'A specialized animal tissue with a high oil content, used for long-term storage of energy.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('95ebf944-74aa-4a7c-b6af-431c9ab424a0', 'father', 'A (generally human) male who begets a child.', 'My father was a strong influence on me.', 'Family', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f3e340d8-87d7-4197-b680-276efddd51a0', 'favourite', 'A person or thing who enjoys special regard or favour.', 'The teacher''s favourite always went first.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6bc619fc-78b5-426f-896c-d4939fcdd05b', 'feel', 'A quality of an object experienced by touch.', 'Bark has a rough feel.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7e1f676b-0943-4bb3-b1c8-8691cfc1a349', 'feeling', '(heading) To use or experience the sense of touch.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('402d93a3-2987-4745-8b04-603eb7d6693c', 'festival', 'An event or community gathering, usually staged by a local community, which centers on some theme, sometimes on some unique aspect of the community.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a2707492-eb58-4340-883f-666f033a8bad', 'few', 'Few people, few things.', 'Many are called, but few are chosen.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('5489ec05-6aac-44c2-a34d-75ea54e6b922', 'fifteen', 'The cardinal number occurring after fourteen (14) and before sixteen (16).', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6f0d2af3-3d7a-471a-8d23-4d9379a53b60', 'fifth', 'The person or thing in the fifth position.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4df4a841-cb7e-4fc5-af0a-42281a59728f', 'fifty', 'A banknote or coin with a denomination of 50.', 'Do you want small bills or are fifties OK?', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e0d2cf53-0533-4b9d-90c1-6804214c9b48', 'fill', 'To occupy fully, to take up all of.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f1e8d137-7ecf-4ddd-92ca-b7bae6b58c2c', 'film', 'A thin layer of some substance; a pellicle; a membranous covering, causing opacity.', 'a clear plastic film for wrapping food', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('70beca1f-1399-47d0-90d9-fd65789a1d57', 'final', 'A final examination; a test or examination given at the end of a term or class; the test that concludes a class.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('218f94b1-7011-491c-bca5-47f4b6b9421a', 'find', 'Anything that is found (usually valuable), as objects on an archeological site or a person with talent.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('87947985-51cb-4faa-ac96-f14ef415a944', 'fine', 'Fine champagne; French brandy.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0563a746-92e0-4e89-b7b0-65c0246aba47', 'finish', 'An end; the end of anything.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3f9879e0-5ac0-464d-8338-3a2b417cc62f', 'fire', 'A (usually self-sustaining) chemical reaction involving the bonding of oxygen with carbon or other fuel, with the production of heat and the presence of flame or smouldering.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('22684332-7b3b-4909-917a-1d7ad5fb957b', 'first', 'The person or thing in the first position.', 'He was the first to complete the course.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7e3502ae-faf0-4d95-8612-45c3a48ab0f8', 'fish', 'A cold-blooded vertebrate animal that lives in water, moving with the help of fins and breathing with gills.', 'Salmon is a fish.', 'Food', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('948ff606-7ebc-4127-9d65-24fb5851fd85', 'five', 'The digit/figure 5.', 'He wrote a five followed by four zeroes.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('42ab3016-5bbc-40bb-88aa-a45da57df9d7', 'flat', 'An area of level ground.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('99903cb3-87b8-4734-8fbb-5d5c96308293', 'flight', 'The act of flying.', 'Most birds are capable of flight.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c44c1f2c-45e4-4a30-80ec-27a16de51dc6', 'floor', 'The interior bottom or surface of a house or building; the supporting surface of a room.', 'The room has a wooden floor.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0610d374-9613-4ca3-8433-fb4c1912197d', 'flower', 'A colorful, conspicuous structure associated with angiosperms, frequently scented and attracting various insects, and which may or may not be used for sexual reproduction.', '', 'Nature', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a63ccb4c-802f-4a75-b731-147b18d9d69b', 'fly', 'Any insect of the order Diptera; characterized by having two wings (except for some wingless species), also called true flies.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0e7acb74-2b9a-496b-942a-e2c8c284da87', 'follow', '(sometimes attributive) In billiards and similar games, a stroke causing a ball to follow another ball after hitting it.', 'a follow shot', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('39d201c9-3efc-4014-b33f-1243b128efe1', 'food', 'Any solid substance that can be consumed by living organisms, especially by eating, in order to sustain life.', 'The innkeeper brought them food and drink.', 'Food', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e71fecc5-c300-467b-8f57-4a4e5cd75caa', 'foot', 'A biological structure found in many animals that is used for locomotion and that is frequently a separate organ at the terminal part of the leg.', 'A spider has eight feet.', 'Body', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6a347594-8358-4647-934e-642bce55a933', 'football', '(general) A sport played on foot in which teams attempt to get a ball into a goal or zone defended by the other team.', 'Roman and medieval football matches were more violent than any modern type of football.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e0b79f01-355f-4d2a-b1cf-8a8e1cf81f20', 'forget', 'To lose remembrance of.', 'I have forgotten most of the things I learned in school.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('774e11fc-8dfe-4cca-9ef6-1b124c7c4d04', 'form', '(heading, physical) To do with shape.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('452c4998-d3d2-42b2-8a8c-57c870290b0c', 'forty', 'A bottle of beer containing forty fluid ounces.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('79748de1-70cf-4009-a378-a1e02d9d0799', 'four', 'The digit or figure 4; an occurrence thereof.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4abaa6a3-0557-471a-98b0-120662bf74cb', 'fourteen', 'The cardinal number occurring after thirteen and before fifteen, represented in Roman numerals as XIV and in Arabic numerals as 14.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d5c6edc5-fe21-4a88-a2a6-bb9d6e808612', 'fourth', '(not used in the plural) The person or thing in the fourth position.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('24f929b6-97d3-4dd7-a111-3bb196a162ff', 'free', 'Free transfer', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('806440f2-ef73-4daf-a538-5478b6e99d50', 'he', 'The game of tag, or it, in which the player attempting to catch the others is called "he".', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f5d0eb6f-2471-43b4-952c-acb202e17798', 'queue', 'An animal''s tail.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8dcde437-c115-4c27-bbc0-3fb02b38d12b', 'friend', 'A person other than a family member, spouse or lover whose company one enjoys and towards whom one feels affection.', 'John and I have been friends ever since we were roommates at college.   Trust is important between friends.   I used to find it hard to make friends when I was shy.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0aa59860-8186-4516-94b0-581f109406b9', 'friendly', 'A game which is of no consequence in terms of ranking, betting etc.', 'This match is merely a friendly, so don''t worry too much about it.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('74474d05-ea6a-422e-a6ee-48e5a86d5ea8', 'from', 'Used to indicate source or provenance.', 'I got a letter from my brother.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e2790d88-e632-4b99-932e-21c5dd4c9b39', 'front', 'The foremost side of something or the end that faces the direction it normally moves.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4250badf-bbc0-43af-9462-4d50794a2735', 'fruit', '(often in the plural) In general, a product of plant growth useful to man or animals.', '', 'Food', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('36cf025d-ebcd-439d-8057-c3cb3657f8f0', 'full', 'Containing the maximum possible amount that can fit in the space available.', 'The jugs were full to the point of overflowing.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('06531a92-6d74-4348-98e9-d00ce708dc07', 'fun', 'Amusement, enjoyment or pleasure', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('79cd133a-9847-427e-9441-d0ecf0b6cdc7', 'funny', 'A joke.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ebc8de75-c20d-484f-9b35-022dbc57130b', 'future', 'The time ahead; those moments yet to be experienced.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('85b62d82-3948-4d1d-a1cc-497b9e379442', 'game', 'A playful or competitive activity.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7c55ca26-852c-4fc2-87df-fcb73e382f50', 'garden', 'An outdoor area containing one or more types of plants, usually plants grown for food or ornamental purposes.', 'a vegetable garden  a flower garden', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('902615e7-d2d1-40f5-a6b2-940f681332e0', 'geography', 'A description of the earth: a treatise or textbook on geography; an atlas or gazetteer.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4e1e2fd4-825e-4e04-8f1e-0d3dbfc08a04', 'get', 'Offspring.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('efe9e6d2-af6d-49e4-bfe2-d65464693820', 'girl', 'A female child, adolescent, or a young woman.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f48e55d3-279f-40fc-be2c-f542ff7b250a', 'girlfriend', 'A female partner in an unmarried romantic relationship.', 'Marc went to the park with his girlfriend and watched the sunset with her.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f325ecf4-7ae3-4b4c-98eb-6945f95b436e', 'give', 'The amount of bending that something undergoes when a force is applied to it; a tendency to yield under pressure; resilence.', 'There is no give in his dogmatic religious beliefs.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d9b587ed-e4a6-4bbd-b7a9-6cf2a586f162', 'glass', 'To apply fibreglass to.', 'to fibreglass the hull of a fishing-boat', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9f73fc5a-70fc-46ca-89ee-708661a91b6f', 'go', 'The act of going.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('16b3a2bf-a48b-41d2-92b2-a0301e4b3359', 'good', '(of people)', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('cce502b4-b7f5-48ee-a968-5e7732736eda', 'goodbye', 'An utterance of goodbye, the wishing of farewell to someone.', 'They made their good-byes.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('860b5d90-da96-4165-950e-e79212c6ae38', 'grandfather', 'A father of someone''s parent.', '', 'Family', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2c01fae7-0633-45a3-b172-f4752858940a', 'grandmother', 'A mother of someone''s parent.', '', 'Family', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0c8a2d74-3bd0-4279-9bb6-3eac78d42c8e', 'grandparent', 'To be, or act as, a grandfather to.', '', 'Family', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('62a1f0a4-cfd1-4632-8c1c-2f876072f9ce', 'great', 'A person of major significance, accomplishment or acclaim.', 'Newton and Einstein are two of the greats of the history of science.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4bc30495-5666-4ee9-9a84-ad0c30b32452', 'green', 'Having green as its color.', 'The former flag of Libya is fully green.', 'Colors', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('923dc085-ac4f-4005-893d-b5a7800bf5a7', 'grey', 'Having a color.', 'Wash colored items separately from whites and darks to prevent the colors from bleeding.', 'Colors', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3cb81c39-5fe0-4c78-b489-163cb439b31a', 'group', 'A number of things or persons being in some relation to one another.', 'A group of people gathered in front of the Parliament to demonstrate against the Prime Minister''s proposals.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('16ffaef1-5cfe-4dab-8b58-c20f31ad4cdb', 'grow', 'To become larger, to increase in magnitude.', 'Children grow quickly.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2aeac46e-d45a-4d9a-ac19-348b6ae822c0', 'guess', 'To reach a partly (or totally) unqualified conclusion.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('83bcb845-b990-483c-8932-870f5958e870', 'guitar', 'A stringed musical instrument, of European origin, usually with a fretted fingerboard and six strings, played with the fingers or a plectrum (guitar pick).', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('efb9df37-f088-46ea-b496-bd7db4fa3532', 'gym', 'A sports facility specialized for lifting weights and exercise.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c8e381f1-7d04-421c-91a0-c5fe5908b25d', 'hair', 'A pigmented filament of keratin which grows from a follicle on the skin of humans and other mammals.', '', 'Body', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('aa69aafb-8c46-4928-94cb-fbc76279e579', 'half', 'One of two usually roughly equal parts into which anything may be divided, or considered as divided.', 'I ate the slightly smaller half of the apple.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d9ba5387-126f-494a-87d9-3a0bb35ad102', 'hand', 'The part of the forelimb below the forearm or wrist in a human, and the corresponding part in many other animals.', 'Her hands are really strong.', 'Body', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a17df694-47ef-423f-b20d-274fa785cf2d', 'happen', 'To occur or take place.', 'Let me tell you how it happened.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e88e474f-d573-484f-8d1f-bba6ba27fba8', 'happy', 'A happy event, thing, person, etc.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('27747a73-8601-48d2-aa07-bdf53573ba9b', 'hard', 'A firm or paved beach or slope convenient for hauling vessels out of the water.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9f0cb352-5197-4e7b-9da7-8fe973ce3896', 'hat', 'A covering for the head, often in the approximate form of a cone or a cylinder closed at its top end, and sometimes having a brim and other decoration.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('155e5763-2660-4623-947a-9d31a20011f2', 'hate', 'An object of hatred.', 'One of my pet hates is traffic wardens.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a0163a7c-a8fa-4af0-849d-7f04fca37ca9', 'have', 'A wealthy or privileged person.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3e1847c8-34c6-4438-a1a2-9492009f83b2', 'head', 'The part of the body of an animal or human which contains the brain, mouth and main sense organs.', 'Be careful when you pet that dog on the head; it may bite.', 'Body', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4f764608-a29e-4277-80a4-670311d65a14', 'health', 'The state of being free from physical or psychological disease, illness, or malfunction; wellness.', 'Her mental health is really affected by stressful environments.', 'Health', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c410cc64-3932-4e03-a96e-d60ca6b0c73d', 'healthy', 'Enjoying health and vigor of body, mind, or spirit: well.', 'He was father to three healthy kids.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2cb911ff-b7e7-414d-a54d-efe4c8674bff', 'hear', '(stative) To perceive sounds through the ear.', 'I was deaf, and now I can hear.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3f85dd99-8282-4160-b5bd-288613d5764e', 'hello', '"Hello!" or an equivalent greeting.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('071c54d9-7c88-4847-a11e-bf7ff9c5216d', 'help', 'Action given to provide assistance; aid.', 'I need some help with my homework.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('5373c2fd-7d4c-4e1a-9202-9a609ec0bed2', 'her', 'A female person or animal.', 'I think this bird is a him, but it may be a her.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('cdd719b0-e30c-4cb7-8927-6f94b6b6db4d', 'here', '(abstract) This place; this location.', 'An Alzheimer patient''s here may in his mind be anywhere he called home in the time he presently re-lives.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('226271df-11b7-4627-a748-e6e6df240dc1', 'hey', 'An exclamation to get attention.', 'Hey! Listen!', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ab4b88b0-a549-4851-9c43-0377f5b8fd48', 'hi', 'The word "hi" used as a greeting.', 'I didn''t even get a hi.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('357aa2d4-48e1-4585-a9ca-376f0a6e4410', 'high', 'A high point or position, literally or figuratively; an elevated place; a superior region; a height; the sky; heaven.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a5525fd2-bfcb-4144-b317-3659f9b5cb1c', 'him', 'Honorific alternative letter-case form of him, sometimes used when referring to God or another important figure who is understood from context.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6794fc84-b49e-47e7-a5ca-79b47ccfbccc', 'his', 'Honorific alternative letter-case form of his, sometimes used when referring to God or another important figure who is understood from context.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('908fb3b9-3d86-40ae-8143-c6b389ddca83', 'history', 'The aggregate of past events.', 'History repeats itself if we don’t learn from its mistakes.', 'Education', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('cb445a21-26c4-4da2-9143-78021aa21d74', 'hobby', 'An activity that one enjoys doing in one''s spare time.', 'I like to collect stamps from different countries as a hobby.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('815e63db-7dd8-459b-8e19-0970c8aa677c', 'holiday', 'A day on which a festival, religious event, or national celebration is traditionally observed.', 'Today is a Wiccan holiday!', 'Travel', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('eccc624d-ee9a-471c-981b-48517c449653', 'home', 'A dwelling.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('37f5cac6-a060-4af1-8fc8-cf648234b5b0', 'homework', 'Work that is done at home, especially school exercises assigned by a teacher.', 'You must do your homework before you can watch television.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3005f2e2-6c1b-4b3b-ad49-f7eefb2afcbf', 'hope', 'To want something to happen, with a sense of expectation that it might.', 'I am still hoping that all will turn out well.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('79724086-ffd5-4d3d-a37a-0c7586e9fd5f', 'horse', 'Any of several animals related to Equus ferus caballus.', '', 'Nature', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('10e03e85-02de-4e97-9f1e-b788f3698ba4', 'hospital', 'A large medical facility, usually in a building with multiple floors, where seriously ill or injured patients are given extensive medical and/or surgical treatment.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('801269a5-2e49-46cb-882d-119ad5d43c85', 'hot', '(with up) To heat; to make or become hot.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0366eeb9-441d-4893-a408-07778f2a483a', 'hotel', 'A large town house or mansion; a grand private residence, especially in France.', '', 'Travel', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('16c6b303-7e1f-4e65-bbb0-fa5cd62b6281', 'hour', 'A time period of sixty minutes; one twenty-fourth of a day.', 'I spent an hour at lunch.', 'Time', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('184c610f-19f9-4b4e-a918-bb2080be9e34', 'house', 'A structure built or serving as an abode of human beings.', 'This is my house and my family''s ancestral home.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e501efa2-2d72-4914-8bc9-9b96915c25cf', 'how', 'The means by which something is accomplished.', 'I am not interested in the why, but in the how.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('158406ba-9e59-43f7-bffd-a0c87549523e', 'however', 'Nevertheless; yet, still; in spite of (that).', 'He told me not to do it. I, however, did it anyway. / I did it anyway, however. / (sometimes proscribed:) However, I did it anyway.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e9016e55-c275-4e6b-bf55-51847aae3a63', 'hundred', 'A hundred-dollar bill, or any other note denominated 100 (e.g. a hundred euros).', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8e8a64f8-9524-4210-9556-6569b6298e2b', 'hungry', 'Affected by hunger; desiring of food; having a physical need for food.', 'My kids go to bed hungry every night because I haven''t got any money.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1e8602ea-925b-438a-b35f-06ecb964e5ee', 'husband', 'The master of a house; the head of a family; a householder.', '', 'Family', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b756ee24-c4eb-4b0d-be54-591453499376', 'i', 'The name of the Latin-script letter I.', 'the position of an i-dot (the dot of an i)', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('240fb322-4f4e-4571-8155-5de5836c60ac', 'ice', 'Water in frozen (solid) form.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8e46f1a5-1aa4-40fb-a7da-e976e11ae17b', 'ice cream', 'A dessert made from frozen sweetened cream or a similar substance, usually flavoured.', 'Strawberries are particularly delicious with ice cream.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0cc10478-9df0-46f6-9d9b-30b5ced98651', 'idea', 'An abstract archetype of a given thing, compared to which real-life examples are seen as imperfect approximations; pure essence, as opposed to actual examples.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('09ed49e9-1731-4a05-94a8-dd8a14050a60', 'if', 'An uncertainty, possibility, condition, doubt etc.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('571119fe-a28d-47a1-84c9-4cf391c03de9', 'imagine', 'A short fanfic or prompt placing a reader insert in a novel scenario with a character or celebrity.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('49a5e422-9be6-41d4-be66-3bbf184af995', 'important', 'Having relevant and crucial value.', 'It is very important to give your daughter independence in her life so she learns from experience.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2d92d7e3-b222-4940-915c-c1e667263905', 'letter', 'A symbol in an alphabet.', 'There are twenty-six letters in the English alphabet.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3a62ac4c-2ac4-4d66-a8c9-0f17f7bdefa0', 'improve', 'To make (something) better; to increase the value or productivity (of something).', 'Buying more servers would improve performance.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2133c314-8c10-4d3c-8cc0-9e771f086325', 'in', 'A position of power or influence, or a way to get it.', 'His parents got him an in with the company.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('104555d0-e74c-48b8-abec-61f4bc417e2a', 'include', 'A piece of source code or other content that is dynamically retrieved for inclusion in another item.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2db10bde-2ad1-4542-b6d3-d86c7302ebfc', 'information', 'That which resolves uncertainty; anything that answers the question of "what a given entity is".', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('406d0ae4-8f6f-409f-835b-f9f268646486', 'interest', 'The price paid for obtaining, or price received for providing, money or goods in a credit transaction, calculated as a fraction of the amount or value of what was borrowed.', 'Our bank offers borrowers an annual interest of 5%.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('fd9c418a-755a-4f12-9f88-2adc59a0ffdb', 'interested', 'To engage the attention of; to awaken interest in; to excite emotion or passion in, in behalf of a person or thing.', 'Action films don''t really interest me.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a6b123f6-1a98-4f73-be04-b67a03020010', 'interesting', 'To engage the attention of; to awaken interest in; to excite emotion or passion in, in behalf of a person or thing.', 'Action films don''t really interest me.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('250d7793-18a3-4cb8-84b4-c94295a17a78', 'internet', 'Any set of computer networks that communicate using the Internet Protocol. (An intranet.)', '', 'Technology', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('224fddaf-c321-4f57-896e-e57d29c89655', 'interview', 'An official face-to-face meeting of monarchs or other important figures.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ccaaad14-e90a-4673-9599-3d331f935a91', 'into', 'To or towards the inside of.', 'Mary danced into the house.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7b76febd-9d3e-40a7-bd53-dd3aaa0d1682', 'introduce', '(of people) To cause (someone) to be acquainted (with someone else).', 'Let me introduce you to my friends.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7e54d57e-be3f-4e05-b5ee-a5f406d472df', 'island', 'A contiguous area of land, smaller than a continent, totally surrounded by water.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('153fdb40-afe7-4a0b-bafc-ace30c100234', 'it', 'One who is neither a he nor a she; a creature; a dehumanized being.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b1547e9d-e168-4a7c-bbcc-c7904697eb1a', 'its', 'One who is neither a he nor a she; a creature; a dehumanized being.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('841ce316-c44e-47ba-8b03-b60780d2f8bd', 'jacket', 'A piece of clothing worn on the upper body outside a shirt or blouse, often waist length to thigh length.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('421f5d5a-8494-4236-9f08-b4875d796c7d', 'jeans', 'Denim.', 'She wore a tattered jean jacket.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('77e62ff6-8565-485a-9f7b-6bdb46ee76a8', 'job', 'A task.', 'A job half done is hardly done at all.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('21cf92da-7ff5-40b2-9706-700256477e21', 'join', 'An intersection of piping or wiring; an interconnect.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8681b455-84dc-46d1-b37c-016adf6c0e9f', 'journey', 'A set amount of travelling, seen as a single unit; a discrete trip, a voyage.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('cbf06ba5-b969-4090-bd65-f9dd5fe3941b', 'juice', 'A liquid from a plant, especially fruit.', 'Squeeze the orange and some juice will come out.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0f4457a4-c8be-440a-b09a-ab46cc0a4645', 'just', 'Factually right, correct; factual.', 'It is a just assessment of the facts.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('46c97eb9-71a8-413e-8c41-f1b3062f549d', 'keep', 'The main tower of a castle or fortress, located within the castle walls.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('aaf5f026-2921-4e62-8e49-44d234af8ea7', 'key', 'An object designed to open and close a lock.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('5e954680-1038-46fa-b729-7e5603a53cc2', 'kilometre', '(official BIPM spelling, Australian, New Zealand, Irish, Indian and South African spelling) An SI unit of length equal to 103 metres. Symbol: km', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a7e0e9f2-213a-496c-872c-1562cf4752c6', 'kind', 'A type, race or category; a group of entities that have common characteristics such that they may be grouped together.', 'This is a strange kind of tobacco.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3b1176f1-87f9-4c36-a95d-f6935f75bd8e', 'kitchen', 'A room or area for preparing food.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a748f147-1589-4714-aa83-b09224e7736b', 'know', 'Knowledge; the state of knowing.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3f72a699-f298-4e24-8c18-3b68b0c0da3d', 'land', 'The part of Earth which is not covered by oceans or other bodies of water.', 'Most insects live on land.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0dff8e45-bfbb-4723-9d42-18329199ef4f', 'language', 'A body of words, and set of methods of combining them (called a grammar), understood by a community and used as a form of communication.', 'Deaf and mute people communicate using languages like ASL.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('fbddb34f-14e1-43bf-b561-f3880a3d0722', 'large', 'An old musical note, equal to two longas, four breves, or eight semibreves.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('24e265e5-99fa-44bf-ae58-5b78c2e78fbb', 'last', 'Final, ultimate, coming after all others of its kind.', '“Eyes Wide Shut” was the last film to be directed by Stanley Kubrick.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('83c607e2-8c37-4750-b986-08865b8e0a7c', 'late', 'A shift (scheduled work period) that takes place late in the day or at night.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1437d6f5-348b-44e7-9b81-ad47f69d4869', 'later', 'Near the end of a period of time.', 'It was late in the evening when we finally arrived.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('06bbfb47-8e4c-47e7-bef5-8dd43f3c616d', 'laugh', 'An expression of mirth particular to the human species; the sound heard in laughing; laughter.', 'His deep laughs boomed through the room.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('895452b8-6894-46a1-a164-6855ee7db168', 'learn', 'The act of learning something', '', 'Education', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('76db4381-6f51-474c-9488-9f4aa2cafec7', 'leave', 'To have a consequence or remnant.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f06aab17-db81-4589-b3ea-2ff36ef27d75', 'left', 'The left side or direction.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2304251c-60b2-4baa-b2e3-7f3cd3fa0674', 'leg', 'A limb or appendage that an animal uses for support or locomotion.', '{{ux|en|Insects have six legs.}', 'Body', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2877b688-aa3b-4b3e-bb3d-e9028d1d6d25', 'lesson', 'A section of learning or teaching into which a wider learning content is divided.', 'In our school a typical working week consists of around twenty lessons and ten hours of related laboratory work.', 'Education', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f0dfac9a-f11d-4c8f-8786-80df4a32092c', 'let', 'The allowing of possession of a property etc. in exchange for rent.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7b4a2937-572a-4f18-90c0-459c038c5a7b', 'library', 'An institution which holds books and/or other forms of media for use by the public or qualified people often lending them out, as well as providing various other services for its users.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('49fea634-746e-4bc1-a0bc-3c34dd04a09d', 'lie', 'The terrain and conditions surrounding the ball before it is struck.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('40bb7e13-16d8-4d4d-a955-4e860afa2894', 'life', 'The state of organisms preceding their death, characterized by biological processes such as metabolism and reproduction and distinguishing them from inanimate objects; the state of being alive and living.', 'Having experienced both, the vampire decided that he preferred (un)death to life.  He gave up on life.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('58b033be-43ac-4771-8300-a8dc96aacd38', 'light', 'Visible electromagnetic radiation. The human eye can typically detect radiation (light) in the wavelength range of about 400 to 750 nanometers. Nearby shorter and longer wavelength ranges, although not visible, are commonly called ultraviolet and infrared light.', 'As you can see, this spacious dining-room gets a lot of light in the mornings.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('5b9820e0-5e87-45e2-85e0-10a78e5de416', 'like', '(usually in the plural) Something that a person likes (prefers).', 'Tell me your likes and dislikes.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('570b0a40-f017-4987-80c0-3636fdebcdef', 'line', 'A path through two or more points (compare ‘segment’); a continuous mark, including as made by a pen; any path, curved or straight.', 'The arrow descended in a curved line.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8b22e3f1-b173-4ed5-9cd8-f81e6d59ac09', 'lion', 'A big cat, Panthera leo, native to Africa, India and formerly much of Europe.', 'Tigers and lions share a common ancestor from a few million years ago.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('37498c60-143a-4dd8-967b-5690abecc20c', 'list', 'A strip of fabric, especially from the edge of a piece of cloth.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9b5e5929-3f74-42e6-a7b9-ae3b712404db', 'listen', 'An instance of listening.', 'Give the motor a listen and tell me if it sounds off.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b4fd5cfe-45ab-4b20-b519-5d498c93bf6d', 'little', 'A small amount.', 'Can I try a little of that sauce?', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('72e2667f-4420-40da-9cc6-97afbcce821b', 'live', 'To be alive; to have life.', 'He''s not expected to live for more than a few months.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d33a0742-5caf-4c43-8083-77c0a77e6862', 'local', 'A person who lives near a given place.', 'It''s easy to tell the locals from the tourists.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0f96c343-85f6-4f79-8f28-cf1d29da2c04', 'long', 'A long vowel.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('11f86c99-d26b-403f-81f8-d8d610b58d98', 'lose', 'To cause (something) to cease to be in one''s possession or capability due to unfortunate or unknown circumstances, events or reasons.', 'He lost his hearing in the explosion.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('27fb2a9b-e785-4e52-a006-84a445baae7a', 'lot', 'A large quantity or number; a great deal.', 'lots of people think so', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4c5dbe24-f6b2-4ac6-a890-0de6fa5ca25c', 'love', 'Strong affection.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('34356c82-6a3d-4491-9e5c-53b4820c9fcb', 'lunch', 'A light meal usually eaten around midday, notably when not as main meal of the day.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('51f5a3fb-7db7-449e-bbba-7b638b4d7c3e', 'machine', 'A device that directs and controls energy, often in the form of movement or electricity, to produce a certain effect.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('eb10466c-c773-467b-8d5a-ebaa7638d5ed', 'magazine', 'A non-academic periodical publication, generally consisting of sheets of paper folded in half and stapled at the fold.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c9068d4c-6c4e-4ca9-8f18-95ac88485212', 'main', 'Short for mainline.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('5c52bed4-945b-4312-a1a7-fdfeb6862d31', 'make', 'Brand or kind; model.', 'What make of car do you drive?', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e2ff3f4f-6177-49bd-b84e-70b13fd195d0', 'man', 'An adult male human.', 'The show is especially popular with middle-aged men.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1a982702-cd5d-45c1-9504-90e9c7181fdf', 'many', 'A multitude; a great aggregate; a mass of people; the generality; the common herd.', 'Democracy must balance the rights of the few against the will of the many.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4dcfc75a-8077-4939-9271-71b7dd875eee', 'map', 'A visual representation of an area, whether real or imaginary.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e6c098c4-6978-47a3-b0eb-1b57949ed0c9', 'march', 'A formal, rhythmic way of walking, used especially by soldiers, bands and in ceremonies.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('601aba8c-3364-41ea-ad5b-d81a9f6a686d', 'market', 'A gathering of people for the purchase and sale of merchandise at a set time, often periodic.', 'The privilege to hold a weekly market was invaluable for any feudal era burgh.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('55513e80-1dab-4860-94dd-1257185b4de5', 'married', 'A married person.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('32fa83c0-f30e-4ec5-afb9-fb790b078e3c', 'match', 'A competitive sporting event such as a boxing meet, a baseball game, or a cricket match.', 'My local team are playing in a match against their arch-rivals today.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c5b47720-713a-4bb0-bb61-9535fe2c8b17', 'may', 'To be strong; to have power (over).', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('eb850565-059b-4d5d-981c-3469bfb04578', 'maybe', 'Something that is possibly true.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('409c6476-afb8-45fd-9b1a-545823cba12d', 'me', 'As the direct object of a verb.', 'Can you hear me?', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('af3a14f5-c807-4611-9384-cd0bd989b9b9', 'meal', 'Food that is prepared and eaten, usually at a specific time, and usually in a comparatively large quantity (as opposed to a snack).', 'Breakfast is the morning meal, lunch is the noon meal, and dinner, or supper, is the evening meal.', 'Food', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('bdc5d8b3-c876-4fc8-81e1-630c6cb86656', 'mean', 'To lament.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('50acd6cb-ac26-4c5b-af77-73d26deac4e8', 'meaning', '(of words or symbols) The entity, perception, feeling or concept thereby represented or evoked.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('cec46472-3c3d-45de-8bd7-4bca7090d8cb', 'meat', 'The flesh (muscle tissue) of an animal used as food.', 'A large portion of domestic meat production comes from animals raised on factory farms.', 'Food', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4a847151-6253-40df-abde-c916bf5aaf6f', 'meet', 'A sports competition, especially for track and field (a track meet) or swimming (a swim meet).', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1375c27b-85ea-41dc-b0fc-ba8e8c8c8a36', 'meeting', '(gerund) The act of persons or things that meet.', 'Meeting him will be exciting. I enjoy meeting new people.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('bfe63cb7-9033-4547-ab41-c67515274552', 'member', 'One who officially belongs to a group.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4ad82b7f-65dc-4ef0-b00f-68db99118a7a', 'menu', 'The details of the food to be served at a banquet; a bill of fare.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('bf2752c9-7ef3-4d41-991a-51ea00826cb3', 'message', 'A communication, or what is communicated; any concept or information conveyed.', 'We''ve just received an urgent message from the President.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7bc59478-34b7-4ca9-8b39-7b94a6400f25', 'metre', 'To measure with a metering device.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9cc56b21-6c46-4bd0-bd94-a1de0cdab501', 'midnight', 'The middle of the night: the sixth temporal hour, equidistant between sunset and sunrise.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('bc80a205-5e91-46cd-83ff-6fdaee9835bf', 'mile', 'The international mile: a unit of length precisely equal to 1.609344 kilometers established by treaty among Anglophone nations in 1959, divided into 5,280 feet or 1,760 yards.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('cbaff2d3-5f88-42d7-a340-bd06aa419d55', 'milk', 'A white liquid produced by the mammary glands of female mammals to nourish their young. From certain animals, especially cows, it is also called dairy milk and is a common food for humans as a beverage or used to produce various dairy products such as butter, cheese, and yogurt.', '', 'Food', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4603f55c-9968-4446-9c1b-7bc09a245b26', 'million', '(long and short scales) The cardinal number 1,000,000: 106; a thousand thousand.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9ce779db-d377-4f3d-bd6e-d172323bc515', 'minute', 'A unit of time equal to sixty seconds (one-sixtieth of an hour).', 'You have twenty minutes to complete the test.', 'Time', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f342d3b4-a59d-4246-9bdb-c8d742054a34', 'miss', 'A failure to hit.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('cb756488-35e0-4f56-8f21-43c71f5a9b10', 'mistake', 'An error; a blunder.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9e8bec2d-f1f4-4373-914c-536e0d4c0692', 'model', 'A person who serves as a subject for artwork or fashion, usually in the medium of photography but also for painting or drawing.', 'The beautiful model had her face on the cover of almost every fashion magazine imaginable.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('147f7b90-ec88-42f5-a24a-75817269c9ea', 'modern', 'Someone who lives in modern times.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a7734fa3-700f-40cd-99c4-fffdb6584a2c', 'moment', 'A brief, unspecified amount of time.', 'Wait a moment, while I lock the front door.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('cf7f1b93-4a29-4919-ae70-69a653596e2a', 'money', 'A legally or socially binding conceptual contract of entitlement to wealth, void of intrinsic value, payable for all debts and taxes, and regulated in supply.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('691afa88-3d71-424b-9e7f-397d59b25483', 'month', 'A period into which a year is divided, historically based on the phases of the moon.', 'July is my favourite month.', 'Time', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e5029805-5494-4d9d-84af-a40060dd27e3', 'moon', 'The Earth''s moon Luna; the sole natural satellite of the Earth, represented in astronomy and astrology by ☾.', '', 'Nature', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('51c4981f-65f0-4839-b531-336e4110f5cd', 'more', 'To a greater degree or extent.', 'I could no more climb that than fly!', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('eeeeef50-dc9f-427b-9927-54fcd5a66fe1', 'morning', 'The part of the day from dawn to noon.', 'I''ll see you tomorrow morning.', 'Time', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8b319245-a3b7-478b-a038-32f924b1aff3', 'most', 'The greatest amount.', 'The most I can offer for the house is $150,000.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('fce0d7a7-9be6-4c03-8c65-3a157ea9088b', 'mother', 'A (human) female who has given birth to a baby', 'He had something of his mother in him.', 'Family', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7f0578a4-3765-4e66-850e-4f867c02cb4a', 'mountain', 'An elevation of land of considerable dimensions rising more or less abruptly, forming a conspicuous figure in the landscape, usually having a small extent of surface at its summit.', 'We spent the weekend hiking in the mountains.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3eaca619-24b5-4ddd-8002-6c836aee8986', 'mouse', 'Any small rodent of the genus Mus.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d55076d6-fc79-447b-ae0a-d9486def5465', 'mouth', 'The opening of a creature through which food is ingested.', '"Open your mouth and say ''aah''," directed the doctor.', 'Body', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('98bd996e-4425-4984-bc8b-84a769c72dd3', 'move', 'The act of moving; a movement.', 'A slight move of the tiller, and the boat will go off course.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('fbf3f09f-72cf-47ca-9dec-d193109e1273', 'movie', 'A recorded sequence of images displayed on a screen at a rate sufficiently fast to create the appearance of motion.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4afdab8c-6ac2-4b3f-a47b-a5bb2ba0df59', 'much', 'Large, great.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('aad8873e-f7df-4f7f-a897-4fb84f8be432', 'mum', 'Mother.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('39ac475e-0004-403c-a124-79b480b0b086', 'museum', 'A building or institution dedicated to the acquisition, conservation, study, exhibition, and educational interpretation of objects having scientific, historical, cultural or artistic value.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('afb6c362-b351-4528-b4b0-dbb2f821af9a', 'music', 'A series of sounds organized in time, employing melody, harmony, tempo etc. usually to convey a mood.', 'I keep listening to this music because it''s a masterpiece.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('bff823a4-a7ac-4e92-b772-970f6d6a02df', 'must', 'Something that is mandatory or required.', 'If you''ll be out all day, a map is a must.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0e033a27-11b7-4a57-aaf2-b9a132e07ceb', 'my', 'Used to express surprise, shock or amazement.', 'My, what big teeth you have!', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('24169731-84ff-43db-8861-313d4105d81c', 'name', 'Any nounal word or phrase which indicates a particular person, place, class, or thing.', 'I''ve never liked the name my parents gave me so I changed it at the age of twenty.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d02230f9-c7a1-441e-946c-d866e6da1308', 'natural', 'A native inhabitant of a place, country etc.', '', 'Environment', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('61973832-6daa-44d0-b57e-77c05d9db39d', 'near', 'The left side of a horse or of a team of horses pulling a carriage etc.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a2baf857-3e27-489e-9646-5217c617f36b', 'neck', 'The part of the body connecting the head and the trunk found in humans and some animals.', 'Giraffes have long necks.', 'Body', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6f43d8ab-caba-41cd-939e-6a0d5f711129', 'need', 'A requirement for something; something needed.', 'I''ve always tried to have few needs beyond food, clothing and shelter.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0fb5b368-22f4-4a3a-8578-c5757c44659f', 'negative', 'Refusal or withholding of assents; prohibition, veto', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('070c2cdc-67dd-4753-a17b-c23e731835ad', 'neighbour', 'A person living on adjacent or nearby land; a person situated adjacently or nearby; anything (of the same type of thing as the subject) in an adjacent or nearby position.', 'My neighbour has two noisy cats.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b99d847b-cf28-4f27-9aeb-5f6ee8ea0660', 'never', 'At no time; on no occasion; in no circumstance.', 'I finally finished, and I never want to do that again.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8bff7a8e-4d94-4ff7-8744-fabc721dbc01', 'new', 'Things that are new.', 'Out with the old, in with the new.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0fd51b82-13bd-43ef-bdce-66ae5e64dd91', 'news', 'New information of interest.', 'Is there any news about the storm?', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ac3c8432-6489-4448-9cb2-641c6e838279', 'newspaper', 'A publication, usually published daily or weekly and usually printed on cheap, low-quality paper, containing news and other articles.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('553051f4-16a3-4b65-a2b7-8c6e0ac88282', 'next', 'The one that follows after this one.', 'Next, please, don''t hold up the queue!', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f61d6ce8-0ef4-42d7-b764-0d91e8af5e53', 'next to', 'Beside, alongside, by, adjacent to, or near.', 'Cleanliness is next to godliness.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1ae9dcb4-d5cf-4bfb-a2ec-03cd721463bd', 'nice', 'Niceness.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('53fe4034-1538-4a53-93fa-be1bf4d8bdfa', 'night', 'The period between sunset and sunrise, when a location faces far away from the sun, thus when the sky is dark.', 'How do you sleep at night when you attack your kids like that!?', 'Time', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('38e6d9dd-5b62-4be5-a853-bde76fc78265', 'nine', 'The digit or figure 9.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d3923e9b-d1ef-4a23-a3a1-ca2e9ea8daea', 'nineteen', 'The cardinal number occurring after eighteen and before twenty, represented in Roman numerals as XIX and in Arabic numerals as 19. It is the last/largest of the "teens".', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d2b324a1-1628-4ee7-b3af-eda35326d60d', 'ninety', 'The cardinal number occurring after eighty-nine and before ninety-one, represented in Roman numerals as XC and in Arabic numerals as 90.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('aa0d0224-0682-4663-a7d1-230eb3ebdd0c', 'no', 'A negating expression; an answer that shows disagreement or disapproval', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('205e0f9b-829a-4d5b-bfb5-1eb9fe6608a2', 'no one', 'Used in contrast to anyone, someone or everyone: not one person; nobody.', 'We went to the store but no one was there.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f98faf66-f182-4b44-a5d0-653a62da19a8', 'nobody', 'Someone who is not important or well-known.', 'Whether you''re a nobody or a player, everyone in Tinseltown wants to be King of Hollywood! - Conquering Hollywood', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('07b40a65-13a6-4f11-ae58-d2113c7ab88f', 'north', 'One of the four major compass points, specifically 0°, directed toward the North Pole, and conventionally upwards on a map, abbreviated as N.', 'Minnesota is in the north of the USA.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('27455679-f1bb-486d-8291-7994f6057f50', 'nose', 'A protuberance on the face housing the nostrils, which are used to breathe or smell.', 'She has a cold in the nose.', 'Body', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('946616ad-dcbf-4672-981b-d91a3380b574', 'not', 'A unary operation on logical values that changes true to false, and false to true.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d21658d5-f36d-46dc-b5da-5acd93bc763d', 'note', '(heading) A symbol or annotation.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ac3cd125-3c13-47c8-830e-b8710a0ac9ca', 'nothing', 'Something trifling, or of no consequence or importance.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('12d6b921-0f47-42c1-b410-3fd98fed4ee9', 'now', 'The present time.', 'Now is the right time.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('fd5e2c6e-f496-44e2-9b64-373f51d6ede0', 'number', 'An abstract entity used to describe quantity.', 'Zero, one, −1, 2.5, and pi are all numbers.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('96f28d39-0412-421e-a291-c0fdd3f22286', 'nurse', 'A wet nurse.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6318adcb-9179-46e0-9b0d-c3bbd1f76ef1', 'o''clock', '(modifying a numeral, one to twelve) In conjunction with a numeral, indicates the time within a twelve-hour period (midnight to noon or noon to midnight), specifically the time when the hour hand of a clock points precisely to the symbol or marking corresponding to the designated numeral.', '(rare, nonstandard) What o''clock is it?', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b73716a4-9589-4530-b5c8-b3ee3aa07787', 'object', 'A thing that has physical existence.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('eec3c116-14c5-403e-91a5-7d60ca657408', 'of', 'Expressing distance or motion.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b8361f07-702f-412e-8deb-135a52378c53', 'off', '(usually in phrases such as ''from the off'', ''at the off'', etc.) Beginning; starting point.', 'He has been very obviously an untrustworthy narrator right from the off.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6d84b6cc-c5b8-481a-9a5a-80cf523d1aa7', 'office', 'A ceremonial duty or service, particularly:', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('98690abb-c1ee-444f-af0d-2eb182d1713c', 'often', 'Frequent.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ea9a9345-2075-4cb1-a155-dc72da015826', 'oh', 'An utterance of oh; a spoken expression of surprise, acknowledgement, etc.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('44aa8167-08de-4b72-9631-44fb277bc542', 'ok', 'All right, permitted.', 'Do you think it''s OK to stay here for the night?', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4c3d2fc7-4c39-409a-a980-4ff34c19eaae', 'old', '(with the, invariable plural only) People who are old; old beings; the older generation, taken as a group.', 'A civilised society should always look after the old in the community.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('96ae1116-1d9b-4a38-b2c6-48b04d27084a', 'on', 'To switch on', 'Can you on the light?', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ae7f9343-c996-463a-ba3c-c17411262de2', 'once', '(frequency) One and only one time.', 'I have only once eaten pizza.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2accb219-1c28-411a-b461-0dd0437287c0', 'one', 'The digit or figure 1.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3997eb5c-41be-4e24-95f3-74455272a12e', 'onion', 'A monocotyledonous plant (Allium cepa), allied to garlic, used as vegetable and spice.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('92bd7100-3bd1-48a4-a588-7c52eff0b952', 'online', 'To bring (a system, etc.) online; to promote to an active or running state.', '', 'Technology', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('29859af3-6dbb-44ff-a81b-568428fe3afe', 'only', 'An only child.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c044c4a6-a5d6-4cf6-86f4-4e5b18c02209', 'open', 'Not closed', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('139092a5-a66a-4182-8432-b54e87f264e3', 'opinion', 'A subjective belief, judgment or perspective that a person has formed about a topic, issue, person or thing.', 'Every man is a fool in some man''s opinion.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('513ffc47-4f49-413d-ba14-8b1da2bf1deb', 'opposite', 'Something opposite or contrary to something else.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c44e8c0c-74d3-46d8-8230-cbe01e82b452', 'radio', 'The technology that allows for the transmission of sound or other signals by modulation of electromagnetic waves.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('95efe74c-9784-4275-be06-69a0af8111b3', 'or', 'Connects at least two alternative words, phrases, clauses, sentences, etc. each of which could make a passage true. In English, this is the "inclusive or." The "exclusive or" is formed by "either [...] or".', 'He might get cancer, or be hit by a bus, or God knows what.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c84cdb7f-4ebd-4307-a481-31d2c0e10afd', 'orange', 'An evergreen tree of the genus Citrus such as Citrus sinensis.', '', 'Colors', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e00eae1c-3ea9-4de6-afe8-c631e65cd590', 'order', 'Arrangement, disposition, or sequence.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c97a13c7-14ea-4082-893d-b307b2b59397', 'other', 'An other, another (person, etc), more often rendered as another.', 'I''m afraid little Robbie does not always play well with others.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0d5a8950-4ff8-4878-9133-279a92272fad', 'out', 'A means of exit, escape, reprieve, etc.', 'They wrote the law to give those organizations an out.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('098dff5d-d765-48b4-a80c-59a941b9a849', 'outside', 'The part of something that faces out; the outer surface.', 'He''s repainting the outside of his house.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0672525a-81f8-4c33-815e-f7e0a79b3583', 'over', 'A set of six legal balls bowled.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9409e59f-b5b6-48e2-99ee-0b797f3ee2d2', 'own', 'Belonging to; possessed; proper to. Often marks a possessive determiner as reflexive, referring back to the subject of the clause or sentence.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7b62f291-fa6c-4e68-a04e-c8d8d853d1f1', 'page', 'One of the many pieces of paper bound together within a book or similar document.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9d410f4a-ef45-40b2-b3b6-620a2aab4558', 'paint', 'A substance that is applied as a liquid or paste, and dries into a solid coating that protects or adds color/colour to an object or surface to which it has been applied.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('915a7bfc-21fc-4aa8-a543-ae0ac7342eb5', 'painting', 'To apply paint to.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('99b9196c-49ba-4074-bbca-e6ebfd45320a', 'pair', 'Two similar or identical things taken together; often followed by of.', 'I couldn''t decide which of the pair of designer shirts I preferred, so I bought the pair.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('cad40fe6-1f55-45a0-b91d-ffeb4c589cf2', 'paper', 'A sheet material used for writing on or printing on (or as a non-waterproof container), usually made by draining cellulose fibres from a suspension in water.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c57377df-6a3c-42e5-b881-86f067bbe441', 'paragraph', 'A passage in text that is about a different subject from the preceding text, marked by commencing on a new line, the first line sometimes being indented.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2c56d0e4-5868-4807-b96f-b6ebd1d67823', 'parent', 'One of the two persons from whom one is immediately biologically descended; a mother or father.', '', 'Family', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('25efe521-3f77-4e68-af4c-200ca7d6181b', 'park', 'An area of land set aside for environment preservation or recreation.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('22cb7c2b-3687-47d5-a25c-dccb680a04d7', 'part', 'A portion; a component.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('bbc5b256-bce5-411f-ba4b-e9fac3a9c9d5', 'partner', 'Someone who is associated with another in a common activity or interest.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9d56fc58-450f-4ce3-a961-3a0ba08ddc62', 'party', 'A person or group of people constituting a particular side in a contract or legal action.', 'The contract requires that the party of the first part pay the fee.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e001a6a2-2ea8-401f-8d40-d075880213bb', 'passport', 'An official document normally used for international journeys, which proves the identity and nationality of the person for whom it was issued.', 'You will have to bring your passport to prove who you are.', 'Travel', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ea06835e-2e08-456d-95bc-d269641ad917', 'past', 'To change place.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('74f255a4-cd23-45b5-9848-df1ec9f60b52', 'pay', 'Money given in return for work; salary or wages.', 'Many employers have rules designed to keep employees from comparing their pays.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9d0b70c7-b547-4587-b856-19c8ab708298', 'pen', 'An enclosure (enclosed area) used to contain domesticated animals, especially sheep or cattle.', 'There are two steers in the third pen.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f7970887-22db-42aa-a507-29549d94c162', 'pencil', 'A paintbrush.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('78f9061b-552d-4a62-9fc9-1e3b255a5bf3', 'people', 'Used as plural of person; a body of human beings considered generally or collectively; a group of two or more persons.', 'There were so many people at the restaurant last night.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4e175372-fb1a-4331-8cba-eba34e5654be', 'pepper', 'A plant of the family Piperaceae.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('69d20b68-fe6c-4a85-a327-0beb5c4cc962', 'perfect', '(grammar) The perfect tense, or a form in that tense.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a7b1fb81-1c52-491d-ac80-94557ab7c95a', 'period', 'A length of time.', 'There was a period of confusion following the announcement.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('bb6b9a43-9d46-45cb-95cd-854688161088', 'person', 'An individual; usually a human being.', 'Each person is unique, both mentally and physically.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('158782a8-3a16-4e43-8b0e-5501bf94e27c', 'personal', 'An advertisement by which individuals attempt to meet others with similar interests.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('37c9446f-2f9f-4a38-9ed8-02c94806062e', 'phone', 'A device for transmitting conversations and other sounds in real time across distances, now often a small portable unit also capable of running software etc.', '', 'Technology', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a7b9f61e-e51e-415a-8509-2395de20d629', 'photo', 'A photograph.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('338948a0-ab2d-4e03-8b34-04cd85e4ca7c', 'photograph', 'A picture created by projecting an image onto a photosensitive surface such as a chemically treated plate or film, CCD receptor, etc.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d75ce78a-da17-4f87-8d69-397982acdca9', 'phrase', 'A short written or spoken expression.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('618287ef-3a0d-4cb9-80e9-48a21c928c05', 'piano', 'A percussive keyboard musical instrument, usually ranging over seven octaves, with white and black colored keys, played by pressing these keys, causing hammers to strike strings', 'He can play "Happy Birthday" on the piano.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ea571918-934b-4cf8-b08c-5e54c93c054e', 'picture', 'A representation of anything (as a person, a landscape, a building) upon canvas, paper, or other surface, by drawing, painting, printing, photography, etc.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('60e227f3-00bf-4b20-ad32-fbd3fe21001c', 'piece', 'A part of a larger whole, usually in such a form that it is able to be separated from other parts.', 'I’d like another piece of pie.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('124595b1-49cf-4c48-a5f7-ee41003ffef6', 'rain', 'Condensed water falling from a cloud.', 'The rains came late that year.', 'Nature', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9f9e1f4e-e2c7-424a-800e-8a9699d43570', 'quit', 'To pay (a debt, fine etc.).', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a7cce04f-7924-4978-ae5b-ec05f7be960c', 'pig', 'Any of several intelligent mammalian species of the genus Sus, having cloven hooves, bristles and a nose adapted for digging; especially the domesticated animal Sus scrofa.', 'The man kept a pen with two pigs that he fed from carrots to cabbage.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f758b666-8e8a-4dfa-b98f-3e0224010f3e', 'pink', 'The common minnow, Phoxinus phoxinus.', '', 'Colors', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7b5c3e6c-59bf-432a-9465-781fd10a891c', 'place', '(physical) An area; somewhere within an area.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('41497045-a5d9-4978-9301-fe485a440343', 'plan', 'A drawing showing technical details of a building, machine, etc., with unwanted details omitted, and often using symbols rather than detailed drawing to represent doors, valves, etc.', 'The plans for many important buildings were once publicly available.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1cc49142-08d5-471e-ae46-ba21d0fed636', 'plane', 'A level or flat surface.', '', 'Travel', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7941fb3d-d0a2-44fb-bb58-b0486bb8da26', 'plant', 'An organism that is not an animal, especially an organism capable of photosynthesis. Typically a small or herbaceous organism of this kind, rather than a tree.', 'The garden had a couple of trees, and a cluster of colourful plants around the border.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('985599a2-8882-463b-900f-76f3fc2fff8b', 'play', 'Activity for amusement only, especially among the young.', 'Children learn through play.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2d1c0951-b11d-45a1-a768-fe3d09a36abf', 'player', 'One that plays', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('de85d570-d186-4724-815c-c30752bcd8d4', 'please', 'To make happy or satisfy; to give pleasure to.', 'Her presentation pleased the executives.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7f8a76a1-d8f3-4db8-a7fa-968a64fd49b9', 'point', 'A discrete division of something.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7485a0a4-e253-4a91-9c13-8f4b4968f8dd', 'police', 'A civil force granted the legal authority for law enforcement and maintaining public order.', 'Call the police!', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('10b85b09-ec69-409d-a156-8a9ba36c8104', 'policeman', 'One who enforces.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('97905b49-f04c-4ecd-ac44-a39e4fa0b0fc', 'pool', 'A small and rather deep collection of (usually) fresh water, as one supplied by a spring, or occurring in the course of a stream; a reservoir for water.', 'the pools of Solomon', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6e15a89c-1253-4472-ae1a-dcdb21877733', 'poor', '(with "the") Those who have little or no possessions or money, taken as a group.', 'The poor are always with us.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c2176685-40c7-453a-ad9d-ebd2be373a71', 'popular', 'A person who is popular, especially at a school.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0b65745f-b83f-474c-b479-2ca682013e61', 'positive', 'A thing capable of being affirmed; something real or actual.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e5a56bf2-1d28-4798-8dd0-d8c2b82437e0', 'possible', 'A possible one.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ea7ea194-e675-4790-be73-b5f43bfdc546', 'post', 'A long dowel or plank protruding from the ground; a fencepost; a lightpost.', 'ram a post into the ground', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('42217bec-69a8-4847-ace5-b82e5e70b699', 'potato', 'The tuber of a plant, Solanum tuberosum, eaten as a starchy vegetable, particularly in the Americas and Europe; this plant.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('5031840c-6e6f-4d04-baf2-ec628bcb920d', 'pound', 'A unit of mass equal to 16 avoirdupois ounces (= 453.592 37 g). Today this value is the most common meaning of "pound" as a unit of weight.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('88749408-3b1c-465d-95a1-3f64ce741cdd', 'practice', 'Repetition of an activity to improve a skill.', 'He will need lots of practice with the lines before he performs them.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d52df0f1-cb09-44a2-bae7-55839eb8f477', 'practise', 'To repeat (an activity) as a way of improving one''s skill in that activity.', 'You should practise playing piano every day.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('135c1281-4681-4c19-a9a1-1dab0cdebee4', 'prefer', 'To be in the habit of choosing something rather than something else; to favor; to like better.', 'I prefer tea to coffee.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('edc099aa-e536-4f8c-b3ec-8a8b28030112', 'prepare', 'Preparation', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e65ee606-8694-4e7a-b35c-8c581bab0be1', 'present', 'The current moment or period of time.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a0727265-60d4-4a6f-80c1-20887336400d', 'pretty', 'A pretty person; a term of address to a pretty person.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('70f7412f-5c58-4ad0-943f-2d74685d8012', 'price', 'The cost required to gain possession of something.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f525a1b6-b5ab-456e-9ddf-74e227a42e85', 'probably', 'In all likelihood.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7a7b552b-fa55-4923-ae1b-ae10a2a30657', 'problem', 'A difficulty that has to be resolved or dealt with.', 'She''s leaving because she faced numerous problems to do with racism.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6747d34d-640a-4504-80ce-9bd8dad9d1d9', 'product', 'A commodity offered for sale.', 'That store offers a variety of products.  We''ve got to sell a lot of product by the end of the month.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d6cc330a-bf3c-4c6a-8a0e-9f01da342c27', 'programme', 'A set of structured activities.', 'Our program for today’s exercise class includes swimming and jogging.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9be8a336-52f9-44a3-a453-919ac731e604', 'project', 'A planned endeavor, usually with a specific goal and accomplished in several steps or stages.', '', 'Education', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('63b05fd7-e37c-4a7c-a6e3-c0e03391ad11', 'purple', 'A colour/color that is a dark blend of red and blue; dark magenta.', '', 'Colors', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('61c0cb67-5eb0-4846-b989-c2973f5deb91', 'put', 'A right to sell something at a predetermined price.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('be563e20-fbad-4421-90a9-147b50fe25a8', 'quarter', 'A fourth part of something.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d1e7fe0e-0b70-4162-8a9c-3d91c5f95340', 'question', 'A sentence, phrase or word which asks for information, reply or response; an interrogative.', 'What is your question?', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('11c08300-57fd-4a8a-ae8c-d6ba7db18ebc', 'quick', 'Raw or sensitive flesh, especially that underneath finger and toe nails.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4d777b1c-8d5e-41ac-8776-3cde9566e592', 'quickly', 'Rapidly; with speed; fast.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('5f807fac-95d0-4f1a-9656-2488df54d8e2', 'quiet', 'The absence of sound; quietness.', 'There was a strange quiet in the normally very lively plaza.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('458e155e-5553-4f4f-b1fc-cded7f27956e', 'quite', '(heading) To the greatest extent or degree; completely, entirely.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('004a3079-09dc-430f-a9cc-cf2c98b9c7df', 'read', 'A reading or an act of reading, especially an actor''s part of a play.', '', 'Education', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('aca1c57d-ca4f-4722-90b9-281e9c59f4ab', 'reader', 'A person who reads', 'an early reader, a talented reader', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('41079b71-a854-48ce-b96c-21f834156e0c', 'reading', 'To look at and interpret letters or other information that is written.', 'Have you read this book?', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8cdba128-b135-466f-9696-467b552730dc', 'ready', 'Ready money; cash', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('80f379dd-eb43-47f2-99ef-2852b31ffce8', 'real', 'A commodity; see realty.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7159e08e-5a64-410a-8d85-806c9285c4dc', 'really', 'In a way or manner that is real, not unreal.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('977d9cf9-119e-4aa4-913a-4e3a3f2b02bf', 'reason', 'A cause:', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('deaf8e09-f034-4b3d-a438-cc1e03cb3c8b', 'red', 'Any of a range of colours having the longest wavelengths, 670 nm, of the visible spectrum; a primary additive colour for transmitted light: the colour obtained by subtracting green and blue from white light using magenta and yellow filters; the colour of blood, ripe strawberries, etc.', '', 'Colors', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f71ce7af-6b9b-4612-97e8-6abfcd386c81', 'relax', 'To calm down.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('dc0a52b4-090d-43a3-8168-226fede73b0c', 'remember', 'To recall from one''s memory; to have an image in one''s memory.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e7701496-25a2-4b79-9c0b-fd694fd9c968', 'repeat', 'An iteration; a repetition.', 'We gave up after the third repeat because it got boring.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('5be99ac7-fd7d-47b8-9ee8-a8e28d5f8880', 'report', 'A piece of information describing, or an account of certain events given or presented to someone, with the most common adpositions being by (referring to creator of the report) and on (referring to the subject).', 'A report by the telecommunications ministry on the phone network revealed a severe capacity problem.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3429bf82-0f06-4ce2-89e5-75a0207718c2', 'restaurant', 'An eating establishment in which diners are served food, usually by waiters at their tables but sometimes (as in a fast food restaurant) at a counter.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('66bf8046-99de-4143-aafb-44b74f429eb9', 'result', 'That which results; the conclusion or end to which any course or condition of things leads, or which is obtained by any process or operation; consequence or effect.', 'the result of a course of action;  the result of a mathematical operation', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('274044b6-a5f8-445e-beee-f07542c70b37', 'return', 'The act of returning.', 'I expect the house to be spotless upon my return.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('bd4c9b63-b505-4cf6-ad8a-6d1218b10a9a', 'rice', 'Cereal plants, Oryza sativa of the grass family whose seeds are used as food.', '', 'Food', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7753d9c1-5b6a-40bd-99d4-b6a50db47af1', 'rich', 'To enrich.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8f7494a6-c641-4c20-8ace-80b81898bf11', 'ride', 'An instance of riding.', 'Can I have a ride on your bike?', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c3b63c68-3616-4965-a98f-d4c6521d115b', 'right', 'Straight, not bent.', 'a right line', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('46824dd3-aa52-4edd-b8a3-f414dbdd068c', 'river', 'A large and often winding stream which drains a land mass, carrying water down from higher areas to a lower point, oftentimes ending in another body of water, such as an ocean or in an inland sea.', 'Occasionally rivers overflow their banks and cause floods.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('94dc87a7-c044-4572-baa1-342d88b0470a', 'road', 'A way used for travelling between places, originally one wide enough to allow foot passengers and horses to travel, now (US) usually one surfaced with asphalt or concrete and designed to accommodate many vehicles travelling in both directions. In the UK both senses are heard: a country road is the same as a country lane.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d76312c8-7d33-4adc-a323-5317bf8ebc35', 'room', 'Opportunity or scope (to do something).', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('894df91a-45fb-454d-b334-d07822141f1a', 'routine', 'A course of action to be followed regularly; a standard procedure.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('5652625a-bee0-4f7a-abfc-e82116441d27', 'rule', 'A regulation, law, guideline.', 'All participants must adhere to the rules.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7bce7147-6342-4026-aeee-bed7c14d54a2', 'run', 'To run.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('62243555-4e3d-4bc7-91dc-7fc47e355eef', 'sad', 'To make melancholy; to sadden or grieve (someone).', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('95cb97f1-1896-4af6-91b6-6b77f2c519a5', 'salad', 'A food made primarily of a mixture of raw or cold ingredients, typically vegetables, usually served with a dressing such as vinegar or mayonnaise.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('72b425cb-10d1-4f8c-8565-585d2874184c', 'salt', 'A common substance, chemically consisting mainly of sodium chloride (NaCl), used extensively as a condiment and preservative.', '', 'Food', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0ffe8157-b417-4c67-9ccf-9aecf8e60533', 'same', 'Not different or other; not another or others; not different as regards self; selfsame; identical.', 'Are you the same person who phoned me yesterday?', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d49dc97f-0c4a-4301-b834-98073f825b0e', 'sandwich', 'A dish or foodstuff where two or more slices of bread serve as the wrapper or container of some other food.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('74dd39b1-7fda-4c56-83dd-eccc7645a3b1', 'say', 'A chance to speak; the right or power to influence or make a decision.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('79c3603c-edfc-48cb-9be2-8d80c440efd5', 'school', '(collective) A group of fish or a group of marine mammals such as porpoises, dolphins, or whales.', 'The divers encountered a huge school of mackerel.', 'Education', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('91525394-c8cb-4579-a42d-22c70ef720a9', 'science', 'A particular discipline or branch of learning, especially one dealing with measurable or systematic principles rather than intuition or natural ability.', 'Of course in my opinion Social Studies is more of a science than an art.', 'Education', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e3a55ce9-f2f5-4dcc-96d4-988dda55c10b', 'scientist', 'One whose activities make use of the scientific method to answer questions regarding the measurable universe. A scientist may be involved in original research, or make use of the results of the research of others.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1652ba79-09af-497c-98e3-234cfefa8c1a', 'sea', 'A large body of salt water.', '', 'Nature', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('fc7a2807-108e-4dcc-bc60-66952d5f4a62', 'second', 'Something that is number two in a series.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('55c74524-06e1-489b-8549-25844def1b0e', 'section', 'A cutting; a part cut out from the rest of something.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('012f168d-6579-4649-878f-80b0cc568003', 'see', '(stative) To perceive or detect with the eyes, or as if by sight.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2e1f6614-7e62-49fd-a321-82f74bbeae6f', 'sell', 'An act of selling.', 'This is going to be a tough sell.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ae429bc3-bb49-40e6-99db-3ae10d354136', 'something', 'An object whose nature is yet to be defined.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ace6896f-af7c-4870-97ec-9fb48859a5bf', 'send', 'The rising motion of water as a wave passes; a surge; the upward angular displacement of a vessel, opposed to pitch, the correlative downward movement.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b79a6ad7-c050-4483-bf75-3247fe96f05a', 'sentence', 'The decision or judgement of a jury or court; a verdict.', 'The court returned a sentence of guilt in the first charge, but innocence in the second.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('cda92f02-be47-4861-b394-ee55e6bbdc9a', 'seven', 'The digit/figure 7 or an occurrence thereof.', 'He wrote three sevens on the paper.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('918f49ae-3a0e-4bb9-9666-ed83267e6517', 'seventeen', 'The cardinal number occurring after sixteen and before eighteen, represented in Roman numerals as XVII and in Arabic numerals as 17.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('bdf701c9-ad19-4602-9c0e-e8717ef92323', 'seventy', 'The cardinal number occurring after sixty-nine and before seventy-one, represented in Roman numerals as LXX and in Arabic numerals as 70.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('21fa503e-e688-4a1d-9f47-08c9fb3b4f72', 'share', 'A portion of something, especially a portion given or allotted to someone.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9a84cded-d909-400e-991c-13c5ce986683', 'she', 'A female.', 'Pat is definitely a she.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3efb18f3-0dcb-4054-b5ca-64bcbaced786', 'sheep', 'A woolly ruminant of the genus Ovis.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('68176dbd-7e21-4ab9-86de-b7071f601fb6', 'shirt', 'An article of clothing that is worn on the upper part of the body, and often has sleeves, either long or short, that cover the arms.', 'It can take a while to learn how to iron a shirt properly.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d3479326-1c24-464e-b6a8-96c60c5cb21d', 'shoe', 'A protective covering for the foot, with a bottom part composed of thick leather or plastic sole and often a thicker heel, and a softer upper part made of leather or synthetic material. Shoes generally do not extend above the ankle, as opposed to boots, which do.', 'Get your shoes on now, or you''ll be late for school.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('700f2a64-76cb-4145-a458-4ddd8bf4881a', 'shop', 'An establishment that sells goods or services to the public; originally only a physical location, but now a virtual establishment as well.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e4aed506-17ff-4d91-b4a8-9965d5af4722', 'shopping', 'To visit stores or shops to browse or explore merchandise, especially with the intention of buying such merchandise.', 'He’s shopping for clothes.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('43001a58-d0bd-4845-872e-670ee6645cbb', 'short', 'A short circuit.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('44cb61e8-9b9e-49d5-9580-1f72636aa1f4', 'should', '(modal, auxiliary verb, defective) Used before a verb to indicate the simple future tense in the first person singular or plural.', 'I hope that we shall win the game.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7b788f32-f432-4dc6-82c8-a05a1795184b', 'shoulder', 'The part of an animal''s body between the base of the neck and forearm socket.', '', 'Body', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0904b9d0-48fc-4dbc-bc01-a69ff8b88abc', 'show', 'A play, dance, or other entertainment.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6b99fa05-e04e-47cf-a163-18fd8b9e3e4c', 'shower', 'A brief fall of precipitation (spell of rain, or a similar fall of snow, sleet, or cascade).', 'Today there will be frequent showers and some sunny spells.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e383e72d-96c8-4759-924a-3a91050577d8', 'sick', 'Sick people in general as a group.', 'We have to cure the sick.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e6ed8c73-13aa-4137-948b-fbe6e7a208f5', 'similar', 'That which is similar to, or resembles, something else, as in quality, form, etc.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('be47bd22-b975-4089-b45c-b81986cc7e40', 'sing', 'A gathering at which people sing songs.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e9d911a9-92bd-48bb-9ba3-e2f883650590', 'singer', 'A person who sings, often professionally.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d77ce302-2374-4ec5-94e7-96e499093646', 'sister', 'A daughter of the same parents as another person; a female sibling.', 'My sister is always driving me crazy.', 'Family', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4daf1682-0279-449c-8c1e-13954087ced3', 'sit', 'Subsidence of the roof of a coal mine.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b57357bb-6a71-4f69-a010-378539512535', 'situation', 'The combination of circumstances at a given moment; a state of affairs.', 'The United States is in an awkward situation with debt default looming.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0d517336-f14a-44f4-9665-5a3f4826bfe1', 'six', 'The digit or figure 6.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9cff34d7-3ef7-43da-9a4f-8273f6e18fe7', 'sixteen', 'The cardinal number occurring after fifteen and before seventeen, represented in Arabic numerals as 16 and in Roman numerals as XVI.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('48dd43fe-1547-4156-a6be-dba099264455', 'sixty', 'The cardinal number occurring after fifty-nine and before sixty-one, represented in Roman numerals as LX and in Arabic numerals as 60.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9747b928-9f2a-4b40-b115-2d863c95b893', 'skill', 'Capacity to do something well; technique, ability. Skills are usually acquired or learned, as opposed to abilities, which are often thought of as innate.', '', 'Education', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7d7b1dce-b601-4f8c-9111-0a1be95aea58', 'skirt', 'An article of clothing, usually worn by women and girls, that hangs from the waist and covers the lower part of the body.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4ff8f625-47d7-4f22-94c7-a51392fce48f', 'sky', 'The atmosphere above a given point, especially as visible from the ground during the day.', 'That year, a meteor fell from the sky.', 'Nature', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7d62c470-6e30-4aee-8343-99ebf57aa6cf', 'sleep', 'To rest in a state of reduced consciousness.', 'You should sleep 8 hours a day.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6d0d2d4d-2c8d-4f7e-8a8d-d43bfa7da0b3', 'slow', 'Someone who is slow; a sluggard.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('842824e5-733b-4418-b7df-96ce31720acd', 'small', 'Any part of something that is smaller or slimmer than the rest, now usually with anatomical reference to the back.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('73321696-4553-4a05-9d06-d1ccc8256b2b', 'snake', 'A legless reptile of the sub-order Serpentes with a long, thin body and a fork-shaped tongue.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c7eaaa1f-825c-4d05-8aca-a627abd52adc', 'snow', 'The frozen, crystalline state of water that falls as precipitation.', '', 'Nature', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('413bb3d6-59f5-4dbb-a4a0-f8111e3bafb1', 'so', 'True, accurate.', 'That is so.  You are responsible for this, is that not so?', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c054f8fd-21bb-4fcb-bcd2-3617b632f69d', 'some', 'Of a measurement: approximately, roughly.', 'I guess he must have weighed some 90 kilos.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1c7515ef-8f4e-4f71-b793-032754e842ef', 'somebody', 'A recognised or important person, a celebrity.', 'I''m tired of being a nobody – I want to be a somebody.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c9c11579-f01e-4a59-8a59-71133655ab4a', 'someone', 'A partially specified but unnamed person.', 'Do you need a gift for that special someone?', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('dfe24972-5600-46ad-8102-881ca55f66d3', 'son', 'One''s male offspring.', 'Before the birth of the man''s child, he said: "I want a son, not a daughter."', 'Family', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('dc4adf2f-4ba8-4cc9-a296-5eb30593af95', 'song', 'A musical composition with lyrics for voice or voices, performed by singing.', 'Thomas listened to his favorite song on the radio yesterday.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2e96b3d8-77d0-4b20-9b1e-c227e3b1f9d9', 'soon', 'Short in length of time from the present.', 'I need the soonest date you have available.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2896c2a2-8473-4b7c-8cfe-8a3f4dc98a85', 'sorry', 'The act of saying sorry; an apology.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6f25afe8-953f-4501-83cb-a317d9888a21', 'sound', 'Healthy.', 'He was safe and sound.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('22205f43-642d-4928-ba14-01fbf9eb34d5', 'soup', 'Any of various dishes commonly made by combining liquids, such as water or stock with other ingredients, such as meat and vegetables, that contribute flavor and texture.', 'Pho is a traditional Vietnamese soup.', 'Food', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e785ae5a-9299-45e4-91d6-671419517ab7', 'south', 'One of the four major compass points, specifically 180°, directed toward the South Pole, and conventionally downwards on a map, abbreviated as S.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6b6074cc-d62e-4c69-b41c-18c40cab48af', 'space', '(heading) Of time.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('5d9472ba-1d83-4314-a671-e1aa3d775153', 'speak', 'A low class bar, a speakeasy.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('cc94b766-8322-4f0c-9da5-9f710a8d5727', 'special', 'A reduction in consumer cost (usually for a limited time) for items or services rendered.', 'We''re running a special on turkey for Thanksgiving.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b5aeb4a4-e179-4305-bcde-047037c7edcf', 'spell', 'Words or a formula supposed to have magical powers.', 'He cast a spell to cure warts.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('200ed741-4e9d-4e47-97f8-7628dcc374eb', 'spelling', 'To put under the influence of a spell; to affect by a spell; to bewitch; to fascinate; to charm.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9dbdc447-c31f-4f24-a620-0d8cb3596539', 'spend', 'Amount of money spent (during a period); expenditure.', 'I’m sorry, boss, but the advertising spend exceeded the budget again this month.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('500b6eaa-ef87-4c5e-bd8a-0fa6114b96b3', 'sport', 'Any activity that uses physical exertion or skills competitively under a set of rules that is not based on aesthetics.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('02e8ea07-621b-4498-8b7f-05a357a78687', 'spring', 'To weaken, as a joint, ligament, or muscle, by sudden and excessive exertion, as by wrenching; to overstrain, or stretch injuriously, but without luxation', 'to sprain one''s ankle', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4b75d7e1-26e5-4439-a9d3-54116a5a78cc', 'stand', 'The act of standing.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d29fc8ed-4349-4779-b1d3-7a2add948fe3', 'star', 'Any small luminous dot appearing in the cloudless portion of the night sky, especially with a fixed location relative to other such dots.', '', 'Nature', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('72b377e6-ea75-4a43-89a1-1c2a04b7f35a', 'start', 'The beginning of an activity.', 'The movie was entertaining from start to finish.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('28f879ad-59a1-46eb-b83f-30313dc1e518', 'statement', 'A declaration or remark.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('18406abf-db74-4071-a925-34f648067e30', 'station', 'A stopping place.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('cad65653-bc3b-4f29-b872-5b25c5ce5844', 'stay', 'Continuance or a period of time spent in a place; abode for an indefinite time; sojourn.', 'I hope you enjoyed your stay in Hawaii.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a1305bc7-65ad-4990-b72c-965fde725e44', 'still', 'A period of calm or silence.', 'the still of the night', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f43fe3b0-981f-43a4-88a5-8bf2206a088b', 'stop', 'A (usually marked) place where buses, trams or trains halt to let passengers get on and off, usually smaller than a station.', 'They agreed to meet at the bus stop.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('63f2282c-43b8-4013-9998-55e0a391f1cf', 'story', 'A sequence of real or fictional events; or, an account of such a sequence.', 'The book tells the story of two roommates.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e135ef73-47d9-4cc6-affb-ac0a0642521a', 'street', 'A paved part of road, usually in a village or a town.', 'Walk down the street until you see a hotel on the right.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0e594ac8-71cd-4d5e-a220-4a2256725192', 'strong', 'Capable of producing great physical force.', 'a big strong man; Jake was tall and strong', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('96ce9235-8422-4c87-80d9-be4d0bb0cba0', 'student', 'A person who studies or learns about a particular subject.', 'He is a student of life.', 'Education', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2f27aafe-829f-4b67-8834-98d343f4c470', 'study', '(usually academic) To review materials already learned in order to make sure one does not forget them, usually in preparation for an examination.', 'I need to study my biology notes.', 'Education', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e0d45813-1a4c-448f-bfa4-4a9770d8adc4', 'style', 'Senses relating to a thin, pointed object.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('82b12eb0-8620-4050-98e9-4102dd551e1c', 'subject', 'Likely to be affected by or to experience something.', 'He''s subject to sneezing fits.', 'Education', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('84ec173f-0908-4b89-acd1-4dd69d842375', 'success', 'The achievement of one''s aim or goal.', 'His third attempt to pass the entrance exam was a success.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a9eba89e-09e4-4f46-b601-173c1c052a89', 'sugar', 'Sucrose in the form of small crystals, obtained from sugar cane or sugar beet and used to sweeten food and drink.', '', 'Food', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('92dd1182-0206-4f26-9405-8cf36076dc87', 'summer', 'One of four seasons, traditionally the second, marked by the longest and typically hottest days of the year due to the inclination of the Earth and thermal lag. Typically regarded as being from June 21 to September 22 or 23 in parts of the USA, the months of June, July and August in the United Kingdom and the months of December, January and February in the Southern Hemisphere.', 'the heat of summer', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6c883566-c7f3-4096-9429-7034c2e9d2fd', 'sun', 'A star, especially when seen as the centre of any single solar system.', '', 'Nature', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2d95e7c5-b1b9-4401-b27e-4b72af0800bf', 'supermarket', 'A large self-service store that sells groceries and, usually, medications, household goods and/or clothing.', 'I went to the supermarket to buy some food.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('09f001d6-ce75-43a8-bb34-5aaa66cda66b', 'sure', 'Physically secure and certain, non-failing, reliable.', 'This investment is a sure thing.   The bailiff had a sure grip on the prisoner''s arm.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a3aed41e-0f85-4eb2-bedf-fa511ebf3432', 'sweater', 'A knitted jacket or jersey, usually of thick wool, worn by athletes before or after exercise.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b4c6965c-b70b-402d-9799-0f574038b8a6', 'swim', 'An act or instance of swimming.', 'I''m going for a swim.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('54baee26-9065-453d-85fe-d80919ce7b42', 'swimming', 'The act or art of sustaining and propelling the body in water.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f116b1b6-a36d-4e2e-a376-453d474f363e', 't-shirt', 'A lightweight shirt without buttons, usually with short sleeves and no collar. Often made of cotton and frequently bears a picture or slogan.', 'Many bands make more money from T-shirt sales than from sale of tickets.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2a5c27bd-350a-468e-83e9-6f86b831eebe', 'table', 'Furniture with a top surface to accommodate a variety of uses.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9c7d5e37-1413-49b7-b754-bcada00d807f', 'take', 'The or an act of taking.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('dbde13d1-9df7-4c24-a731-10da38e7227d', 'talk', 'To communicate, usually by means of speech.', 'Although I don''t speak Chinese I managed to talk with the villagers using signs and gestures.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d8f8025d-66ba-4fec-ad10-00ae4ebd159c', 'tall', '(possibly nonstandard) Someone or something that is tall.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4bfbb9ee-f1a4-412f-be6d-e3d35a6b7587', 'taxi', 'A vehicle that may be hired for single journeys by members of the public, driven by a taxi driver.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8ca81975-d7cf-4b6d-ac22-197e07201481', 'tea', 'A drug smoked or ingested for euphoric effect, cannabis.', 'After smoking a bowl of that fine marijuana, they ate some brownies.', 'Food', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('dda698ee-883f-4d8c-8d6d-5af23af6e678', 'teach', 'To show (someone) the way; to guide, conduct; to point, indicate.', '‘The bliss is there’, mumbled the old man and taught to Heaven.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6fe5ffec-dde5-4847-a603-cdca57490121', 'teacher', 'A person who teaches, especially one employed in a school.', '', 'Education', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a4c7656e-0b22-4d64-8491-08ae2e0b082d', 'team', 'A set of draught animals, such as two horses in front of a carriage.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('44b3f335-b505-46df-918a-e537358af8f2', 'teenager', 'A person between 13 and 19 years of age; an adolescent.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('bc37de00-4e60-400b-ae27-267521706c7e', 'teeth', 'The ability to be enforced, or to be enforced to any useful effect.', 'The international community''s sanctions against the regime had some teeth to them this time around.', 'Body', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('94910ce8-2391-4877-a6c4-bbe1f6bc1bea', 'telephone', 'A telecommunication device (originally mechanical, and now electronic) used for two-way talking with another person (now often shortened to phone).', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('357dccd1-0dcd-4681-9cec-d49f265f9795', 'television', 'An electronic communication medium that allows the transmission of real-time visual images, and often sound.', 'It’s a good thing that television doesn’t transmit smell.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('090d794b-9560-48a6-a317-64cd8dcc00c3', 'tell', 'A reflexive, often habitual behavior, especially one occurring in a context that often features attempts at deception by persons under psychological stress (such as a poker game or police interrogation), that reveals information that the person exhibiting the behavior is attempting to withhold.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e27a5b9e-9241-423b-b308-fc139cb0b844', 'ten', 'A set or group with ten elements.', 'We divided the chocolates into tens to hand out to Hallowe''en visitors.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ec7c3eb8-a84f-47f0-8d95-94b54be73020', 'tennis', 'A sport played by two players (or four in doubles), who alternately strike the ball over a net using racquets.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('dcce2851-1558-497a-a7b6-861d8562c71d', 'terrible', 'Dreadful; causing terror, alarm and fear; awesome', 'The witch gave him a terrible curse.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('177779ff-b3a1-4151-bf42-efde294d1038', 'test', 'A challenge, trial.', '', 'Education', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ca97f687-1b5f-405a-8b3f-50fe0ed35b44', 'text', 'A writing consisting of multiple glyphs, characters, symbols or sentences.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('5bbd5a2f-9a17-4a94-985c-2bd069b45c48', 'than', 'At that time; then.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d6f81b31-fe59-4743-bafe-a38414597de8', 'thank', 'An expression of appreciation; a thought.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e2aaaff9-b7cf-4709-a30b-03bd257cbf9a', 'thanks', 'An expression of appreciation; a thought.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('de9e140b-7475-40d2-8231-3fca47021d11', 'that', 'Something being indicated that is there; one of those.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f444347b-3fcd-4f8a-8602-cb7dcde35526', 'the', 'With a comparative or with more and a verb phrase, establishes a correlation with one or more other such comparatives.', 'It looks weaker and weaker, the more I think about it.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c767b9a0-65b7-4fe9-9f50-e186e16c4633', 'theatre', 'A place or building, consisting of a stage and seating, in which an audience gathers to watch plays, musical performances, public ceremonies, and so on.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('227d2b32-1bf3-4dc6-a807-5a551108b0a1', 'them', '(plural) Those ones.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ecd8f042-9355-4a54-b455-a360948cfe95', 'then', 'Used in comparisons, to introduce the basis of comparison.', 'she''s taller than I am;  she found his advice more witty than helpful;  we have less work today than we had yesterday;  We had no choice than to return home', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a8b1ff93-046b-4ee9-a091-e95a8df74991', 'there', 'That place.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('86065717-bf2b-4b63-ad69-883c10762354', 'they', '(the third-person plural) A group of people, animals, plants or objects previously mentioned.', 'Dogs may bark if they want to be fed.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('00edc24b-4e42-427d-b1e4-c8ca13481d44', 'thing', 'That which is considered to exist as a separate entity, object, quality or concept.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0cdd2436-6edc-4a8d-9eff-d1d624d8903d', 'think', 'An act of thinking; consideration (of something).', 'I''ll have a think about that and let you know.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('63f24a1e-c10d-407b-8214-e1d1dccada6b', 'third', 'The person or thing in the third position.', 'Jones came in third.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9a94c42e-f1be-4fca-ac07-6370aae17592', 'thirsty', 'Needing to drink.', 'After all that work I am really thirsty.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('90611498-4dcb-4a7f-bc52-3b116a178288', 'thirteen', 'The cardinal number occurring after twelve and before fourteen, represented in Roman numerals as XIII and in Arabic numerals as 13.', 'There are thirteen cards of each of the four suits in a deck of playing cards.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('be18daa8-be38-4dd5-8a04-ecaa3ff65e48', 'thirty', 'A rack of thirty beers.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('49a672b3-ccf1-46a6-9a3c-1d59ce6ac957', 'this', 'Something being indicated that is here; one of these.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('cde21d15-daff-418a-876a-404184154f43', 'thousand', 'A numerical value equal to 1,000 = 10 × 100 = 103', 'Many thousands of people came to the conference.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e6153e82-eb59-4364-a799-b5ca7aa2abbe', 'three', 'The digit/figure 3.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('229a6507-246c-4c72-9b80-9e403dcafbb9', 'through', 'A large slab of stone laid in a dry-stone wall from one side to the other; a perpend.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f21cfcca-c935-4ccf-821a-7257513f9613', 'ticket', 'A pass entitling the holder to admission to a show, concert, etc.', '', 'Travel', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a317e44e-f890-4480-8f1d-ac37b540abd3', 'time', 'The inevitable progression into the future with the passing of present and past events.', 'Time stops for nobody.   the ebb and flow of time', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('73dea4b1-377d-4a2d-8637-ae2c71e3887f', 'tired', 'To become sleepy or weary.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6ecc55da-6f0d-40aa-8954-aea733398a56', 'title', 'A prefix (honorific) or suffix (post-nominal) added to a person''s name to signify either veneration, official position or a professional or academic qualification. See also', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c2c57516-3bc9-4a6e-9450-b7c8eca6a971', 'to', 'Toward a closed, touching or engaging position.', 'Please push the door to.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7ab261ff-19f5-4d42-8054-ae1961291a74', 'today', 'A current day or date.', 'Today is the day we''ll fix this once and for all.', 'Time', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e2ccc674-b269-4a36-90dc-3610f51d2b9e', 'together', 'Coherent; well organized.', 'He''s really together.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d1b00cd0-2a44-4b4c-8663-ab3f11b564ed', 'toilet', 'A covering of linen, silk, or tapestry, spread over a dressing table in a chamber or dressing room.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('292cbe90-335d-4bfa-94a4-7ff61f1f09d6', 'tomato', 'A widely cultivated plant, Solanum lycopersicum, having edible fruit.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3d91d57b-8fde-4084-963c-4c58762519e4', 'tomorrow', 'The day after the present day.', '', 'Time', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1782f5ef-3336-4122-a81d-fd5fdc502dfb', 'tonight', 'The nighttime of the current day or date; this night.', 'I have high hopes for tonight.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f64d20c1-6dae-4fa3-958c-28cb4ee2fbd7', 'too', '(focus) Likewise.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('02558edb-486a-4bd7-be95-1efd574555ef', 'tooth', 'A hard, calcareous structure present in the mouth of many vertebrate animals, generally used for eating.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0dccb079-4ebb-4999-b3ef-37312f8185f2', 'topic', 'Subject; theme; a category or general area of interest.', 'A society where a topic cannot be discussed, does not have free speech.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d3c97183-3e3b-425e-904e-3d88ad213073', 'tourist', 'Someone who travels for pleasure rather than for business.', '', 'Travel', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8e1881f5-dbda-4e4f-8c59-7aa07c0b0a53', 'town', 'A settlement; an area with residential districts, shops and amenities, and its own local government; especially one larger than a village and smaller than a city.', 'This town is really dangerous because these youngsters have Beretta handguns.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('bda77840-d83e-40f7-83f3-42bc05324928', 'traffic', 'Pedestrians or vehicles on roads, or the flux or passage thereof.', 'The traffic is slow during rush hour.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('422da9aa-3880-4d3d-aca4-2d72f7c9ea54', 'train', 'Elongated portion.', '', 'Travel', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('cf5e813f-e8f7-4f17-9e28-8b3a2648699c', 'travel', 'The act of traveling; passage from place to place.', 'space travel', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('204e21a0-efa1-4c9e-bf66-1e8f3df6ff7a', 'tree', 'Fast growing function based on Kruskal''s tree theorem.', '', 'Nature', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('32447a46-def0-4aab-8ba8-8369dc252e9c', 'trip', 'A journey; an excursion or jaunt', 'We made a trip to the beach.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('549f6f83-acc0-44f1-9469-bb882e978ff6', 'trousers', 'An article of clothing that covers the part of the body between the waist and the ankles or knees, and is divided into a separate part for each leg.', 'The trousers need to be shortened.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('37f16094-939a-45fa-9078-c0c429ffc9fe', 'true', 'The state of being in alignment.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f12a9779-417e-4d86-9efa-b7c96abf3f68', 'try', 'An attempt.', 'I gave unicycling a try but I couldn’t do it.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a232843f-8f70-4dbe-b4dc-f54afa822d89', 'turn', '(heading) to make a non-linear physical movement.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('cecc81ed-3591-443b-9c58-bc78de8c975f', 'tv', 'The assessed value of an asset from which the tax owing is computed.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ff729bba-dca1-44cf-aecb-7fd82c87ea23', 'twelve', 'A group of twelve items.', 'Fractions would be a little easier if we counted by twelves.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('70158988-480a-4a08-9b4b-78eaf42a2c2f', 'twenty', 'A banknote with a denomination of 20.', 'The waiter’s face lit up when I gave him a twenty.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6afbba9e-36a0-4222-b4a5-e5f1f23d2c3a', 'twice', 'Two times.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ec169849-c751-423c-aa4f-d68bda9fa275', 'two', 'The digit/figure 2.', 'The number 2202 contains three twos.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b44829e8-f186-48d3-84bc-c5dc84e32a45', 'type', 'A grouping based on shared characteristics; a class.', 'This type of plane can handle rough weather more easily than that type of plane.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('eaeae246-356b-48b2-bda4-e43fb5453fc9', 'umbrella', 'Cloth-covered frame used for protection against rain or sun.', 'Quick, grab that umbrella before you get rained on!', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('cf5a857e-a54e-4f1b-8b6a-18c8f576e03f', 'uncle', 'The brother or brother-in-law of one’s parent.', '', 'Family', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c500123e-38f3-4ba8-ad24-5bab7179046f', 'under', 'Being lower; being beneath something.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b7627d2c-eff4-42fe-96de-b626cf2447d0', 'understand', 'To grasp a concept fully and thoroughly, especially (of words, statements, art, etc.) to be aware of the meaning of and (of people) to be aware of the intent of.', 'I''m sorry. I don''t understand.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('de371948-196f-460e-8f31-4a81e6cbd1be', 'university', 'Institution of higher education (typically accepting students from the age of about 17 or 18, depending on country, but in some exceptional cases able to take younger students) where subjects are studied and researched in depth and degrees are offered.', 'The only reason why I haven''t gone to university is because I can''t afford it.', 'Education', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2d6df346-8e23-4d68-ba9b-827a6c8b5710', 'until', 'Up to the time of (something happening).', 'If you can wait until after my meeting with her, we''ll talk then.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('87384e97-e707-49d8-ac1a-9de4f4abb1af', 'up', 'The direction opposed to the pull of gravity.', 'Up is a good way to go.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d8c63bb0-9e48-4beb-bbc1-8cc0a00b9135', 'upstairs', 'An upper storey.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d47e0d64-e636-4bec-824a-20c57d6d3b7c', 'us', '(personal) Me and at least one other person; the objective case of we.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b02b71df-e4be-46d0-94f8-39fa0bc0f857', 'use', 'The act of using.', 'The use of torture has been condemned by the United Nations.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c74c6d6a-209b-4961-a9f6-4210331f9bea', 'useful', 'Having a practical or beneficial use.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b873525d-948a-43ff-87a4-8f58d758bca6', 'usually', 'Most of the time; less than always, but more than occasionally.', 'Except for one or two days a year, he usually walks to work.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('01815612-7765-48af-925f-7f0ffa6233cc', 'vacation', 'Freedom from some business or activity.', '', 'Travel', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('77dd7976-eb3c-409b-a50b-2d6a6c62cc78', 'vegetable', 'Any plant.', '', 'Food', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('114707f0-8120-419a-ac1d-e527f441b82e', 'very', 'True, real, actual.', 'He tried his very best.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('54f2fc04-1f7c-4977-9c67-b51e4ef3a4e9', 'video', 'Television, television show, movie.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('38153fc6-4214-4fba-aac2-9609b95f0d72', 'village', 'A rural habitation of size between a hamlet and a town.', 'There are 2 churches and 3 shops in our village.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('627a0112-71b4-43e8-8089-551ea5b45c5e', 'visit', 'A single act of visiting.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c1b65b2b-e571-49c8-8ea4-7417dab9008a', 'visitor', 'Someone who visits someone else; someone staying as a guest.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('87072576-63cc-4913-bb07-232a0baa9629', 'wait', 'A delay.', 'I had a very long wait at the airport security check.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9a5eb0e3-b47b-40ce-b73e-ce95fffd5421', 'waiter', 'A male or female attendant who serves customers at their tables in a restaurant, café or similar.', 'Waiter! There''s a fly in my soup.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6cc42745-5902-4d2f-8d3a-34ebe14452d0', 'wake', 'The act of waking, or state of being awake.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b3f1b34a-3556-4045-b156-27dafb0eb799', 'walk', 'To move on the feet by alternately setting each foot (or pair or group of feet, in the case of animals with four or more feet) forward, with at least one foot on the ground at all times. Compare run.', 'To walk briskly for an hour every day is to keep fit.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('483b0d30-4abf-4602-ae16-19e880964207', 'wall', 'A rampart of earth, stones etc. built up for defensive purposes.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('04c14501-58fd-4661-8d5e-a74093d9fb2c', 'want', 'A desire, wish, longing.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d0b88130-06a3-428e-84e3-c2079f22a3af', 'warm', 'Having a temperature slightly higher than usual, but still pleasant; mildly hot.', 'The tea is still warm.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('28c04252-403a-4d06-9280-53db66406435', 'wash', 'The process or an instance of washing or being washed by water or other liquid.', 'I''m going to have a quick wash before coming to bed.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('91df3eae-5e81-45ec-a98a-e89b0a01d7c7', 'watch', 'A portable or wearable timepiece.', 'More people today carry a watch on their wrists than in their pockets.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('cdc9293f-a0b8-42c1-82fc-a56f36035607', 'water', 'A substance (of molecular formula H₂O) found at room temperature and pressure as a clear liquid; it is present naturally as rain, and found in rivers, lakes and seas; its solid form is ice and its gaseous form is steam.', 'By the action of electricity, the water was resolved into its two parts, oxygen and hydrogen.', 'Food', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8a25d5ff-8c9f-41d7-bc30-f3ee10302261', 'way', '(heading) To do with a place or places.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('25d23fd5-f19f-4c5d-ae4e-11ef6e81aaca', 'we', '(personal) The speakers/writers, or the speaker/writer and at least one other person (not the person being addressed). (This is the exclusive we.)', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('022b74b5-fc0a-4bb7-ba88-74fb9eaa2d5b', 'wear', '(in combination) clothing', 'footwear; outdoor wear; maternity wear', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('17972989-29f6-4fca-80be-6f60b89a153e', 'weather', 'The short term state of the atmosphere at a specific time and place, including the temperature, relative humidity, cloud cover, precipitation, wind, etc.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('90c561e9-83e4-4aa6-87f3-d30de3a55fc9', 'website', 'A collection of interlinked web pages on the World Wide Web that are typically accessible from the same base URL and reside on the same server.', '', 'Technology', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6fd03894-294c-4b83-ba64-5dc651f8aa7b', 'week', 'Any period of seven consecutive days.', '', 'Time', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('24f89424-ba17-4690-9aaa-1093b9361341', 'weekend', 'The break in the working week, usually two days including the traditional holy or sabbath day. Thus in western countries, Saturday and Sunday.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0efb1d83-d2b1-42cc-ba7c-65182f870877', 'welcome', 'The act of greeting someone’s arrival, especially by saying "Welcome!"; reception.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('070d40cd-f243-4938-a45f-488f97d7fc94', 'well', 'In good health.', 'I had been sick, but now I''m well.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('826f18fc-120b-447c-b8e2-d8d481174777', 'west', 'One of the four principal compass points, specifically 270°, conventionally directed to the left on maps; the direction of the setting sun at an equinox, abbreviated as W.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4e59ae44-a463-4fbb-8f56-78ab8765c83c', 'what', '(Singlish) Used to contradict an underlying assumption held by the interlocutor.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('fc2d5c52-677a-4ab7-8c3e-c96cd2cae272', 'when', 'The time at which something happens.', 'A good article will cover the who, the what, the when, the where, the why and the how.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('417f17b2-4a44-4777-a340-8d0a70b8acb1', 'where', 'The place in which something happens.', 'A good article will cover the who, the what, the when, the where, the why and the how.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c8c3707b-5711-47aa-8f92-13c932573867', 'which', '(interrogative) What one or ones (of those mentioned or implied).', 'By now, you must surely know which is which.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b63c843a-7f9d-44dc-a57f-e51506ba4c3d', 'white', 'The color/colour of snow or milk; the colour of light containing equal amounts of all visible wavelengths.', '', 'Colors', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('80c66871-3bd6-4b56-9528-f85efa488298', 'who', 'A person under discussion; a question of which person.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('566279d2-021d-417a-aff2-e593b1e6a36a', 'why', 'Reason', 'A good article will cover the who, the what, the when, the where, the why and the how.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('67f23ae2-de2c-4b62-9517-3c7384e2b8e5', 'wife', 'A married woman, especially in relation to her spouse.', '', 'Family', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f2270e37-2514-4db1-8681-a80d5736017a', 'will', '(now uncommon or literary) To wish, desire (something).', 'Do what you will.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('45c7ba2f-b3ac-49e3-849c-0d12dbae3e65', 'win', 'To conquer, defeat.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0b08ae6a-6d04-4eac-95ca-a0b7d429b9b5', 'wind', 'Real or perceived movement of atmospheric air usually caused by convection or differences in air pressure.', 'As they accelerated onto the motorway, the wind tore the plywood off the car''s roof-rack.', 'Nature', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('95efa972-36f1-4517-bdb6-c26346236453', 'window', 'The inedible parts of a grain-producing plant.', 'To separate out the chaff, early cultures tossed baskets of grain into the air and let the wind blow away the lighter chaff.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1c0bfb86-b7ed-4c21-9db0-af1a5be28092', 'silly', 'A silly person.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7abaa1c3-c8d8-441e-a755-177fd56752d1', 'wine', 'An alcoholic beverage made by fermenting the juice of grapes.', 'She ordered some wine for the meal.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3fbc9057-7251-4740-85c4-216c4c66d9e4', 'winter', 'Traditionally the fourth of the four seasons, typically regarded as being from December 23 to March 20 in continental regions of the Northern Hemisphere or the months of June, July and August in the Southern Hemisphere. It is the time when the sun is lowest in the sky, resulting in short days, and the time of year with the lowest atmospheric temperatures for the region.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1befc0af-f715-4067-8d9a-4b10f1776e22', 'with', 'Along, together with others, in a group, etc.', 'Do you want to come with?', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c124c342-f62b-4955-913c-810085b1af27', 'without', 'Outside, externally. This is still used in the names of some civil parishes in England, e.g. St Cuthbert Without.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a4439b57-d078-46fa-9ea0-71e54aead742', 'woman', 'An adult female human.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('fd0dd1c7-f9af-4bf5-9add-749a35f5d5f5', 'wonderful', 'Tending to excite wonder; surprising, extraordinary.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('95727702-97e4-40e4-8e13-4e20aed33a58', 'word', 'The smallest unit of language that has a particular meaning and can be expressed by itself; the smallest discrete, meaningful unit of language. (contrast morpheme.)', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('72734b47-1177-48c7-be6a-22678cc406ae', 'work', '(heading) Employment.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('24e35679-7c19-485c-b843-dc1e015ddadc', 'worker', 'A person who performs labor for a living, especially manual labor.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('19ddc384-8ace-415e-8128-e8bbb1976372', 'world', '(with "the") Human collective existence; existence in general.', 'There will always be lovers, till the world’s end.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2438b21f-58c4-4a12-bf1c-60ee5326717d', 'would', 'Something that would happen, or would be the case, under different circumstances; a potentiality.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('99ea8ca7-22c8-44cb-a33d-a9ac2dc80f57', 'write', 'The act or style of writing.', '', 'Education', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('98b36142-2ed0-40b5-a3a7-733b41ae505a', 'writer', 'A person who writes, or produces literary work.', 'Has your girlfriend written you another letter already? She’s quite a writer!', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2c7b9891-e3e3-4d44-a4be-8bb8fc38f502', 'writing', 'Graphism of symbols such as letters that express some meaning.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1998c98e-2a75-403e-b1ca-c32e04345705', 'wrong', 'Something that is immoral or not good.', 'Injustice is a heinous wrong.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f8879dad-8350-4080-84bf-07789a128de7', 'yeah', 'Expressing joy, celebration, glee, etc.', 'Yeah! We did it!', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('555ad04d-345e-49a9-99bc-3be41adb786b', 'year', 'A solar year, the time it takes the Earth to complete one revolution of the Sun (between 365.24 and 365.26 days depending on the point of reference).', 'we moved to this town a year ago;  I quit smoking exactly one year ago', 'Time', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1c97edc5-499f-46f8-a691-89ef901a3d0f', 'yellow', 'The colour of gold, butter, or a lemon; the colour obtained by mixing green and red light, or by subtracting blue from white light.', '', 'Colors', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('05f06f67-f071-4c58-9ec0-df741fb43d44', 'yes', 'An affirmative expression; an answer that shows agreement or acceptance.', 'Was that a yes?', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f76ea044-7a51-43a3-bb8b-a63908ddf9e8', 'yesterday', 'The day immediately before today; one day ago.', 'Today is the child of yesterday and the parent of tomorrow.', 'Time', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7fe3c376-0fec-41f7-a723-1a8ef9434279', 'you', 'To address (a person) using the pronoun you (in the past, especially to use you rather than thou, when you was considered more formal).', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4cbf60f4-0f8b-45f2-90b6-299ace1a14c6', 'young', 'People who are young; young people, collectively; youth.', 'The young of today are well-educated.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7f093da2-36fd-4295-b391-b7a63620e1a5', 'yourself', '(reflexive pronoun) Your own self (singular).', 'Be careful with that fire or you''ll burn yourself.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d32837a5-342a-450c-97bf-dc4177ef7ddd', 'apr', 'The fourth month of the Gregorian calendar, following March and preceding May. Abbreviation: Apr or Apr.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('487531fb-b032-4102-b34a-3ffcb34786d6', 'existence', 'The state of being, existing, or occurring; beinghood.', 'In order to destroy evil, we must first acknowledge its existence.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('885a4f23-bc19-43da-95e9-80a0dd15589f', 'candela', 'In the International System of Units, the base unit of luminous intensity; the luminous intensity, in a given direction, of a source that emits monochromatic radiation of frequency 540 × 1012 hertz and that has a radiant intensity in that direction of 1/683 watt per steradian. Symbol: cd', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1c37f7af-080e-4297-b8b8-f1a479484fc8', 'dec', 'Declared', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ee789bbc-d5bb-4271-a0a5-73c76583428b', 'disk', 'A thin, flat, circular plate or similar object.', 'A coin is a disk of metal.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3c64b7c4-caec-4918-b0fc-1ea159d4d968', 'todo', 'A fuss made over something.', 'I was embarrassed that they made such a big to-do out of my birthday.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2fdfd42d-f3a9-44af-9243-4660d34cded1', 'regarding', 'To look at; to observe.', 'She regarded us warily.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('817a376a-a57e-4db2-b6e8-5db9b44df060', 'dated', 'To note the time or place of writing or executing; to express in an instrument the time of its execution.', 'to date a letter, a bond, a deed, or a charter', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('df777e6b-328d-4848-8956-e72e01918377', 'necessitate', 'To make necessary; to require (something) to be brought about.', 'The early departure of her plane necessitated her waking up at 4 a.m.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9719be1e-4e0b-4c2d-82a4-35fd909bbdf7', 'jan', '(Muslim demonology) A genie and descendant of the jann, normally invisible to the human eye, but who may also appear in animal or human form, equivalent to demons in Jewish demonology.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e0cf3c5d-e16d-418b-ac20-ef3dab434998', 'aug', 'Increased in number, amount or strength.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('eca10ee1-6af7-439d-b5d6-d2e8916868b0', 'jun', 'A monetary unit of North Korea and formerly of South Korea, equal to one hundredth of a won.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('af2490e1-e230-4088-aa0a-0db818f324cb', 'expression', 'The action of expressing thoughts, ideas, feelings, etc.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('41850c76-4f6f-46e1-87eb-deecbece53b0', 'mon', 'The former currency of Japan until 1870, before the yen.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0ec00afe-61d4-48aa-a67a-b81bd6ea5b34', 'nov', 'A novice.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('537e6c93-bbfe-42c2-9b76-85e06574a92c', 'oct', 'The number system that uses the eight digits 0, 1, 2, 3, 4, 5, 6, 7.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f88db1f3-4af9-44c4-a43d-64ebee48ce0f', 'nous', 'The mind or intellect, reason, both rational and emotional', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3bf5084f-c17d-41c8-bc69-409d7820ff50', 'sat', '(of a person) To be in a position in which the upper body is upright and supported by the buttocks.', 'After a long day of walking, it was good just to sit and relax.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e2dc4191-1bd3-4902-a379-e755b98437f5', 'sept', 'A clan, tribe, or family, proceeding from a common progenitor (used especially of the ancient clans in Ireland).', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ce7aada2-b111-47ad-8573-ccd4736d11cb', 'aboriginal', 'An Aboriginal inhabitant of Australia, Aborigine.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d5ad6e69-ad5c-44ae-a806-3d02f61d46d5', 'th', 'Abbreviation of table header.', '', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('74773a68-d1dc-4d2e-a3d5-e20eb6bf39ee', 'wed', 'To perform the marriage ceremony for; to join in matrimony.', 'The priest wed the couple.', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1978014b-4389-42b5-ad46-94d066dd93c2', 'apply', 'To lay or place; to put (one thing to another)', 'to apply cream to a rash', 'General', 'A1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f45525b0-fe36-4579-a6ac-54b0dbe410e3', 'ability', 'Suitableness.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('001efd7c-6129-4a1f-ad7b-4c1b48330b7d', 'able', 'Easy to use.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3077c848-a984-440a-b8a8-67bcecf25182', 'abroad', 'Countries or lands abroad.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b54d1cdd-76cc-4618-94bc-a8e9d0cda356', 'accept', 'To receive, especially with a consent, with favour, or with approval.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8d71cb32-f4ed-4d08-942e-7b92dcca86c3', 'accident', 'An unexpected event with negative consequences occurring without the intention of the one suffering the consequences.', 'to die by an accident', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d4500baa-bfb7-4dc7-b9fc-be8810626727', 'achieve', 'To succeed in something, now especially in academic performance.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7b7d5ec8-f527-4b3a-bebf-a664af2fc01c', 'act', 'Something done, a deed.', 'an act of goodwill', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('03fa3553-c159-43da-a8bf-fdafb6f7dcac', 'active', 'A person or thing that is acting or capable of acting.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('30b58810-09d0-47f8-976d-3c37348f174a', 'actually', '(modal) In act or in fact; really; in truth; positively.', 'Actually, I had nothing to do with that incident.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d931a913-5ef3-4e8a-a824-e8336ed3689e', 'advantage', 'Any condition, circumstance, opportunity or means, particularly favorable to success, or to any desired end.', 'The enemy had the advantage of a more elevated position.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('02957917-ae58-4beb-8ae2-a5e2b39f9192', 'adventure', 'The encountering of risks; a bold undertaking, in which dangers are likely to be encountered, and the issue is staked upon unforeseen events; a daring feat.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('38cd8f55-a880-4780-9e6e-c0dc4c9e471f', 'advertise', 'To give (especially public) notice of (something); to announce publicly.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8b44b8bf-f590-4cd6-97dd-915cf69da1dd', 'advertisement', 'A commercial solicitation designed to sell some commodity, service or similar.', 'Companies try to sell their products using advertisements in form of placards, television spots and print publications.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d36026fa-9e1f-4dac-9a43-cbaafd895335', 'advertising', 'To give (especially public) notice of (something); to announce publicly.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2e3e4b5c-2dc1-4838-b18c-d216ffc3dd0f', 'affect', 'To influence or alter.', 'The experience affected me deeply.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('dd524787-1461-4254-9bda-4590b910d549', 'against', 'In a contrary direction to.', 'It is hard work to swim against the current.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b4226f89-eb3e-4dd7-bfd5-8367ecb7c31c', 'ah', 'The speaker or writer, referred to as the grammatical subject, of a sentence.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0eca8c5b-84aa-4621-b19c-6c04e69515da', 'airline', 'A company that flies airplanes to transport people and goods.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a0c57419-99da-4d71-a189-29a208f77935', 'alive', 'Having life; living; not dead', 'As long as the plant is alive, he will continue to water it.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8b817018-2324-4626-9751-6e0cb5f77257', 'all right', 'Good; in acceptable, if not excellent condition.', 'The car is all right. It gets me there, anyway.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('154f8e7c-d8eb-4c88-8c58-a035602d5d5c', 'allow', 'To grant, give, admit, accord, afford, or yield; to let one have.', 'to allow a servant his liberty;  to allow a free passage;  to allow one day for rest', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d0df5967-3bce-4dda-a64b-ce22337936b4', 'almost', 'Something or someone that doesn''t quite make it.', 'In all the submissions, they found four papers that were clearly worth publishing and another dozen almosts.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7717b647-6998-4aaf-8534-98b47b746b08', 'alone', 'By oneself, solitary.', 'I can''t ask for help because I am alone.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4dcf4fb5-925b-4161-9b99-966719136e03', 'along', 'In company; together.', 'John played the piano and everyone sang along.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('97d657d9-c8c9-4968-9083-8c5e9084a8a9', 'already', 'Prior to some specified time, either past, present, or future; by this time; previously.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4e96a73a-80e8-48bd-8e00-49aa8017e5c9', 'alternative', 'A situation which allows a mutually exclusive choice between two or more possibilities; a choice between two or more possibilities.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a1e5f2af-037d-4be3-ad5d-67d9619c9411', 'although', 'Though, even though, in spite of or despite the fact that: introducing a clause that expresses a concession.', 'Although it was very muddy, the football game went on.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('252528df-d068-4b8a-8962-5fd433e74daa', 'among', 'Denotes a mingling or intermixing with distinct or separable objects. (See Usage Note at amidst.)', 'How can you speak with authority about their customs when you have never lived among them?', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('925c7d31-d52b-484f-82ad-5f1bb3dc1936', 'amount', 'The total, aggregate or sum of material (not applicable to discrete numbers or units or items in standard English).', 'The amount of atmospheric pollution threatens a health crisis.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('50412c06-9b76-4c66-8c49-cb7dc2275dc6', 'ancient', 'A person who is very old.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('30e64e99-55aa-4c42-b3bd-c18565cd5519', 'ankle', 'The skeletal joint which connects the foot with the leg; the uppermost portion of the foot and lowermost portion of the leg, which contain this skeletal joint.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6cbcf084-c526-4b97-89ef-60c1ded45757', 'any more', '(in negative or interrogative constructions) From a given time onwards; longer, again.', 'They don''t make repairable radios any more.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('5f7d4387-58a3-4c92-8b60-a8fecd2b2287', 'anybody', 'Any one out of an indefinite number of persons; anyone; any person.', 'Anybody will do.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('cfccd0cb-83d7-4a61-8979-30e7de4f11a8', 'anyway', 'Regardless; anyhow.', 'He didn''t enjoy washing his car, but it was so dirty that he did it anyway.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6e303046-bd94-4fbb-bb68-22a2e58b9dd9', 'anywhere', 'In or at any location or an unknown location.', 'I don''t know where I left my keys. They could be anywhere.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6f23c12f-51d8-4e66-8409-c4cff720c560', 'app', 'An application (program), especially a small one designed for a mobile device.', '', 'Technology', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1d93a5ea-d3f3-4cdf-a064-ea5c19d9799d', 'appear', 'To come or be in sight; to be in view; to become visible.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('25f57db3-01bc-4258-9aee-01ca47c63d14', 'appearance', 'The act of appearing or coming into sight; the act of becoming visible to the eye.', 'His sudden appearance surprised me.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8c886960-d164-47c8-8697-795fecb761f5', 'architect', 'A professional who designs buildings or other structures, or who prepares plans and superintends construction.', 'Plato made the causes of things to be matter, ideas, and an efficient architect.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7f4734ce-8beb-46d9-8523-4304c6e9c8a6', 'architecture', 'The art and science of designing and managing the construction of buildings and other structures, particularly if they are well proportioned and decorated.', 'Architecture is the visual public expression of a culture’s achievements, values, and outlook. ― Max Roscoe, "How Your City Is Killing You With Ugliness"', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('cbb62d32-7c28-4962-a605-a3c9fd2c652e', 'argue', 'To show grounds for concluding (that); to indicate, imply.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('47e017d8-f615-4369-be1b-b35bf9cccb93', 'argument', 'A fact or statement used to support a proposition; a reason.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c24c4207-1b6f-4546-8c72-4d37ac2c4b94', 'army', 'A large, highly organized military force, concerned mainly with ground (rather than air or naval) operations.', 'The army was sent in to quell the uprising.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('dbe23682-7286-4699-8e34-1276f7ef9e4c', 'arrange', 'To set up; to organize; to put into an orderly sequence or arrangement.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a776e548-4bc7-4f9e-bcf9-da498985971a', 'arrangement', 'The act of arranging.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2403bfee-f261-4039-8031-6050681689d6', 'asleep', 'In a state of sleep; also, broadly, resting.', 'I was asleep when you called.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9ab7ec92-2a9c-48d4-9307-0c5fb39ad156', 'assistant', 'Someone who is present; a bystander, a witness.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('28a997c5-ec23-416e-9718-229ca614b946', 'athlete', 'A participant in a group of sporting activities which includes track and field, road running, cross country running and racewalking.', 'She''s the first athlete in her sport to obtain a corporate sponsor.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('bebb787b-ac1a-481a-8f2d-d20e55107d99', 'attack', 'An attempt to cause damage, injury to, or death of opponent or enemy.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('eb29b6e3-0278-4878-aa96-c0641f674798', 'attend', 'To listen to (something or someone); to pay attention to; regard; heed.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('58c01e78-5a5a-4dad-bdf6-0f103ef00640', 'attention', 'Mental focus.', 'Please direct your attention to the following words.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b6e278f4-cec4-4985-b3b6-79b3e6034641', 'attractive', 'Causing attraction; having the quality of attracting by inherent force.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('32a01c9c-dbe2-4848-89f5-8393020288fe', 'audience', 'A group of people within hearing; specifically, a large gathering of people listening to or watching a performance, speech, etc.', 'We joined the audience just as the lights went down.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('57ef4ede-935e-42e1-ac0b-3638d6a4bcf9', 'author', 'The originator or creator of a work, especially of a literary composition.', 'Have you read any Corinthian authors?', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('aff215a6-cb72-4491-bb83-c58d40cd57bc', 'available', 'Such as one may avail oneself of; capable of being used for the accomplishment of a purpose.', 'We have an available candidate.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b4ab0903-b5b6-403c-8789-2dae4c7aa8f9', 'average', 'The arithmetic mean.', 'The average of 10, 20 and 24 is (10 + 20 + 24)/3 = 18.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('159c5ddd-b463-42ed-aadf-031b971335d0', 'avoid', 'To try not to meet or communicate with (a person); to shun', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('700c5796-829f-4de7-9781-48da3998dcf2', 'award', 'A judgment, sentence, or final decision. Specifically: The decision of arbitrators in a case submitted.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('80647eac-5b04-4304-b97c-be4c2482141a', 'awful', 'Very bad.', 'My socks smell awful.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('52d0985a-d112-4299-a7e4-6badca42d18c', 'background', 'One''s social heritage, or previous life; what one did in the past.', 'The lawyer had a background in computer science.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('bef612cd-913a-4e27-a9b1-684aad2a62cb', 'badly', 'Ill, unwell.', 'He''s never badly.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4c191dab-c259-442d-9612-0975143ebd79', 'bar', 'A solid, more or less rigid object of metal or wood with a uniform cross-section smaller than its length.', 'The window was protected by steel bars.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8e84909a-adeb-4e3b-b3eb-014b0cce411a', 'baseball', 'A sport common in North America, the Caribbean, and Japan, in which the object is to strike a ball so that one of a nine-person team can run counter-clockwise among four bases, resulting in the scoring of a run. The team with the most runs after termination of play, usually nine innings, wins.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('58752bbb-de2c-4471-8c3b-847c7a9316cc', 'based', 'To give as its foundation or starting point; to lay the foundation of.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('079677a0-b8b3-4f26-992c-ba6333084160', 'basketball', 'A sport in which two opposing teams of five players strive to put a ball through a hoop.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0cae2fe9-c02a-4a62-b4f5-ecf46458f4a3', 'bean', 'A reusable software component written in Java.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('dc51e0af-d016-4c67-aec2-13a44dabaaef', 'comedy', 'A choric song of celebration or revel, especially in Ancient Greece.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3f8c3c78-3a65-4626-ac42-2ffcaad68d1d', 'bear', 'A large omnivorous mammal, related to the dog and raccoon, having shaggy hair, a very small tail, and flat feet; a member of family Ursidae.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('15fe114f-330b-4bbf-9722-dfd70b8a426d', 'beat', 'A stroke; a blow.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('36bf1d09-63d1-4c09-a578-2d898aa19079', 'beef', 'The meat from a cow, bull or other bovine.', 'I love eating beef.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('34aa8b45-9761-4589-af25-bd402ac42646', 'behave', 'To conduct (oneself) well, or in a given way.', 'You need to behave yourself, young lady.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('644734f1-dbce-4b80-b91a-20fc9877eb10', 'behaviour', 'The way a living creature behaves or acts.', 'She can''t stop the strange behaviour because she has OCD (obsessive-compulsive disorder).', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6fffb532-ae2d-4e35-ab45-118049b6cc1a', 'belong', 'To have its proper place.', 'Where does this document belong?', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('45ed0a78-937a-431e-bfb8-f5a66455e0b9', 'belt', 'A band worn around the waist to hold clothing to one''s body (usually pants), hold weapons (such as a gun or sword), or serve as a decorative piece of clothing.', 'As part of the act, the fat clown''s belt broke, causing his pants to fall down.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1200d97c-e6d0-412e-8c54-2c0f732bedab', 'benefit', 'An advantage; help or aid from something.', 'It was for her benefit.   His benefit was free beer.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('23e241be-1fb9-4edd-a44d-eb0caddeaec1', 'billion', '(modern British & Australian, short scale) a thousand million (logic: 1,000 × 1,000^2): 1 followed by nine zeros, 109; a milliard', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f01932ba-c1db-4199-a855-cde677958030', 'bin', 'A box, frame, crib, or enclosed place, used as a storage container.', 'a corn bin; a wine bin; a coal bin', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1a0df888-cd6a-4990-8eab-9f0a0cc734b7', 'biology', 'The study of all life or living matter.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2952af0f-1e2d-49ae-a332-4a0d6014ef58', 'birth', 'The process of childbearing; the beginning of life.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1a37e742-76c2-4168-a9b6-dc356954a130', 'biscuit', '(rare in the US) A small, flat, baked good which is either hard and crisp or else soft but firm: a cookie.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6db8ac96-9054-4865-b679-9b1aeac71b19', 'bit', 'A piece of metal placed in a horse''s mouth and connected to the reins to direct the animal.', 'A horse hates having a bit put in its mouth.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('fba5117d-9977-4b5f-b41c-ec519831c3f5', 'blank', 'A small French coin, originally of silver, afterwards of copper, worth 5 deniers; also a silver coin of Henry V current in the parts of France then held by the English, worth about 8 pence .', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a5d66bb7-d305-420a-a8b1-ba2a4b5b12cf', 'blood', 'A member of the Los Angeles gang The Bloods.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('5ab2956c-31b0-48ab-85bc-8941191023cd', 'blow', 'A strong wind.', 'We''re having a bit of a blow this afternoon.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b3a25fde-e3b8-403f-9b10-af23f6e9b600', 'board', 'A relatively long, wide and thin piece of any material, usually wood or similar, often for use in construction or furniture-making.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('cee13ce5-4291-4f5c-ac74-36dfc7449d15', 'boil', 'A localized accumulation of pus in the skin, resulting from infection.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b38363b1-3f18-4491-b5e3-ecf7a4a7924c', 'bone', 'A composite material consisting largely of calcium phosphate and collagen and making up the skeleton of most vertebrates.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('896b7377-acfd-4a47-9d5f-0abe959c678c', 'borrow', 'Deviation of the path of a rolling ball from a straight line; slope; slant.', 'This putt has a big left-to right borrow on it.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('219b3302-0ca9-499b-9eaf-18333ff3e35d', 'boss', 'A person who oversees and directs the work of others; a supervisor.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('150eeb3d-08cb-4d83-a409-f03132a28083', 'bottom', 'The lowest part of anything.', 'Footers appear at the bottoms of pages.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0a16f272-bdbd-4b62-ba4d-775622cdd351', 'bowl', 'A roughly hemispherical container used to hold, mix or present food, such as salad, fruit or soup, or other items.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f37ca1bd-4bf3-4463-9143-cb3f592be643', 'brain', 'The control center of the central nervous system of an animal located in the skull which is responsible for perception, cognition, attention, memory, emotion, and action.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('50d1947e-bd06-4df4-942b-4f19882438f1', 'bridge', 'A construction or natural feature that spans a divide.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('78869e92-3f12-4750-b7f6-312893e25560', 'bright', 'An artist''s brush used in oil and acrylic painting with a long ferrule and a flat, somewhat tapering bristle head.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('056be82d-76f7-46e9-b716-fffe131ffce6', 'brilliant', 'A finely cut gemstone, especially a diamond, cut in a particular form with numerous facets so as to maximize light return through the top (called "table") of the stone.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d64f56c8-2aad-48ec-a520-952b2f5a075d', 'broken', 'To separate into two or more pieces, to fracture or crack, by a process that cannot easily be reversed for reassembly.', 'If the vase falls to the floor, it might break.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('033b874c-1a57-4dfb-947b-f80d6ccb425f', 'brush', 'An implement consisting of multiple more or less flexible bristles or other filaments attached to a handle, used for any of various purposes including cleaning, painting, and arranging hair.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('47eb1a04-e49d-49fb-9ff3-c4dbaa4f5e2e', 'burn', 'A physical injury caused by heat, cold, electricity, radiation or caustic chemicals.', 'She had second-degree burns from falling in the bonfire.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0414787d-bab6-483f-b4d6-59519cd4f4b9', 'businessman', 'A man in business, one who works at a commercial institution.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c0181d5c-345d-4c46-903a-b5b65f6c3591', 'button', 'One who adjusts, especially for the insurance industry''s employment title "loss adjuster" (or "claims adjuster" in the United States).', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e76bc1b8-7209-49c0-a312-6a3c3345e71a', 'camp', 'An outdoor place acting as temporary accommodation in tents or other temporary structures.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c7ae74cf-eeac-4682-b46c-ea2c769ed9e0', 'camping', 'To live in a tent or similar temporary accommodation.', 'We''re planning to camp in the field until Sunday.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('98bf97ff-c11c-47e7-b8d8-eefad8410c6b', 'care', 'Grief, sorrow.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2cebc276-47f8-4880-9b65-bf10804fe104', 'comfortable', 'A stuffed or quilted coverlet for a bed; a comforter.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b243b9b7-946c-433f-99ee-070b484f69b6', 'careful', 'Taking care; attentive to potential danger, error or harm; cautious.', 'He was a slow and careful driver.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('99ae91f6-14f3-4f50-b8f4-b44106993320', 'carefully', 'Sorrowfully.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4ad216d2-3931-4a46-bb66-a501f00a9216', 'carpet', 'A fabric used as a complete floor covering.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('5358681f-c3a9-4ab1-8006-90806e2bb0a2', 'cartoon', 'A humorous drawing, often with a caption, or a strip of such drawings.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('566be229-538f-402f-8a25-8afe8b40b344', 'case', 'An actual event, situation, or fact.', 'For a change, in this case, he was telling the truth.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0f0b8feb-f495-4dcf-87e6-d0aab8407635', 'cash', 'Money in the form of notes/bills and coins, as opposed to cheques/checks or electronic transactions.', 'After you bounced those checks last time, they want to be paid in cash.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('5dd350d8-f734-4517-9a05-7406fdce7bb3', 'castle', 'A large building that is fortified and contains many defences; in previous ages often inhabited by a nobleman or king.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('935573c8-b166-418c-b6c9-ccd9566ffe3b', 'catch', 'The act of seizing or capturing.', 'The catch of the perpetrator was the product of a year of police work.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a982a1d1-8f76-40c6-bf6f-cdc4a0d9468f', 'cause', '(often with of, typically of adverse results) The source of, or reason for, an event or action; that which produces or effects a result.', 'They identified a burst pipe as the cause of the flooding.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('906c80da-d2ab-43fe-9f27-946e4edc3cc2', 'celebrate', 'To extol or honour in a solemn manner.', 'to celebrate the name of the Most High', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('88dfd742-d592-4f9e-975a-aad5ba5bec2c', 'celebrity', 'A rite or ceremony.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7c5251c8-bcad-4d20-952c-f3bed250ebbe', 'certain', '(with "the") Something certain.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('59f025ce-3a04-45a8-aa47-0c740e434433', 'certainly', 'In a way which is certain; with certainty.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8f6a265e-e7fd-4a72-9a88-ce37e200b59a', 'chance', 'An opportunity or possibility.', 'We had the chance to meet the president last week.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('95e1ba7b-b00b-4a7e-930b-5ba80459ae4d', 'character', 'A being involved in the action of a story.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('07b9b93e-1739-4ee2-9a88-4227ad2ea6d5', 'charity', 'An organization, the objective of which is to carry out a charitable purpose.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2e5d2b9c-5975-4d14-8183-cf01e41981f3', 'chat', 'Informal conversation.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d50dd402-d294-4d6e-874b-50b8d3261a82', 'chef', 'The presiding cook in the kitchen of a large household.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f89d3830-bfd7-48f0-afbc-2d46a4191fe5', 'chemistry', 'The branch of natural science that deals with the composition and constitution of substances and the changes that they undergo as a consequence of alterations in the constitution of their molecules.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3ec8e3fc-9101-48b6-855c-a2a829200b87', 'chip', 'A small piece broken from a larger piece of solid material.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('413aa089-a198-4b05-9046-30621c478a6f', 'choice', 'An option; a decision; an opportunity to choose or select something.', 'Do I have a choice of what color to paint it?', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a6b9b310-bce1-4c7e-a015-8287bc104c06', 'church', 'A Christian house of worship; a building where Christian religious services take place.', 'There is a lovely little church in the valley.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f74209a0-3d7c-4c9a-88c5-055de0be1060', 'cigarette', 'Tobacco or other substances, in a thin roll wrapped with paper, intended to be smoked.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('14f34685-bda6-41b6-8c14-4b3fac5d5001', 'circle', 'A two-dimensional geometric figure, a line, consisting of the set of all those points in a plane that are equally distant from a given point (center).', 'The set of all points (x, y) such that (x − 1)2 + y2 = r2 is a circle of radius r around the point (1, 0).', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('59594ff5-5af0-4e74-bf92-2bfd5c44eb1c', 'classical', 'One that is classical in some way; for example, a classical economist.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d2ab18b9-6d38-428b-97a7-2b0daa24eb80', 'clear', 'Full extent; distance between extreme limits; especially; the distance between the nearest surfaces of two bodies, or the space between walls.', 'a room ten feet square in the clear', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('aff72638-b3d6-457e-8abd-dbac1e6a172c', 'clearly', '(manner) In a clear manner.', 'He enunciated every syllable clearly.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2ce860d1-794c-4496-81be-32791a3f556e', 'clever', 'Nimble with hands or body; skillful; adept.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2f5dabb2-05b2-46d0-bd33-a7a281b22b4e', 'climate', 'An area of the earth''s surface between two parallels of latitude.', '', 'Environment', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('70ff2a42-f969-4873-a177-95de27e11b65', 'closed', '(physical) To remove a gap.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3bdda022-9590-4b30-a89f-121ba237d7db', 'clothing', 'To adorn or cover with clothing; to dress; to supply clothes or clothing.', 'to feed and clothe a family; to clothe oneself extravagantly', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('349b9b56-cbb5-4605-b391-564a887fd258', 'cloud', 'A rock; boulder; a hill.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ed1ceb8b-376c-494b-8e50-d66bbb8fdde1', 'cloudy', 'Covered with or characterised by clouds; overcast.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('752adc8f-6030-42df-93fa-60a50f74374b', 'coach', 'A wheeled vehicle, generally drawn by horse power.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('29169f6d-7505-4b0d-8e44-256b2bb9c769', 'coast', 'The edge of the land where it meets an ocean, sea, gulf, bay, or large lake.', 'The rocky coast of Maine has few beaches.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d2b31776-f368-42fd-ac56-929ce51ce6e3', 'code', 'A short symbol, often with little relation to the item it represents.', 'This flavour of soup has been assigned the code WRT-9.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4165a76a-6890-47a1-868d-4a6a6cb0447d', 'colleague', 'A fellow member of a profession, staff, academic faculty or other organization; an associate.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('57ea2cc7-383e-4b4b-8757-db8524ba48ca', 'collect', 'To gather together; amass.', 'Suzanne collected all the papers she had laid out.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4363d610-f3b8-409e-9488-e0f6b522fb88', 'column', 'A solid upright structure designed usually to support a larger structure above it, such as a roof or horizontal beam, but sometimes for decoration.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('599849c6-57d6-4c26-a263-e40752712950', 'comment', 'A spoken or written remark.', 'I have no comment on that.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('786cfeca-c3ee-42ad-94d1-6560669b7847', 'communicate', 'To impart', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('305c1ed9-92ca-417a-9fc6-84d12c7c0268', 'community', 'A group sharing a common understanding, and often the same language, law, manners, and/or tradition.', '', 'Society', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('eb35afd3-34c4-4fcb-9538-010219334837', 'compete', 'To be in battle or in a rivalry with another for the same thing, position, or reward; to contend', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3c4351f5-7066-4951-b300-958b1f683a5a', 'competition', 'The action of competing.', 'The competition for this job is strong.', 'Business', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('adee04e0-f073-43e6-9860-37f7e3fa4e1d', 'complain', 'To express feelings of pain, dissatisfaction, or resentment.', 'Joe was always complaining about the noise made by his neighbours.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a7346b27-1b2e-4415-945f-6cb2a1d9624a', 'completely', '(manner) In a complete manner', 'Please completely fill in the box for your answer, using a number 2 pencil.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8b8d4c5e-9b62-48d5-9bcb-d01d203a73a9', 'condition', 'A logical clause or phrase that a conditional statement uses. The phrase can either be true or false.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1aa92472-320a-4200-b74a-96dfb0faef0c', 'conference', 'The act of consulting together formally; serious conversation or discussion; interchange of views.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1a8dff20-ddc1-4920-82d8-7f95bb7001a8', 'connect', '(of an object) To join (to another object): to attach, or to be intended to attach or capable of attaching, to another object.', 'I think this piece connects to that piece over there.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f0b23831-52b2-4c8a-abb1-b0a642ff8730', 'connected', '(of an object) To join (to another object): to attach, or to be intended to attach or capable of attaching, to another object.', 'I think this piece connects to that piece over there.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('5cbe7ad1-ac2b-407b-a8eb-88fdcb0f6e44', 'consider', 'To think about seriously.', 'Consider that we’ve had three major events and the year has hardly begun.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8e44c729-3cf9-4447-86ef-6341f41b2dcd', 'contain', 'To hold inside.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c2821a5e-3e1a-461a-8777-d9400883e7d3', 'context', 'The surroundings, circumstances, environment, background or settings that determine, specify, or clarify the meaning of an event or other occurrence.', 'In what context did your attack on him happen? - We had a pretty tense relationship at the time, and when he insulted me I snapped.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('fd1d9372-12cf-41fa-9390-b34c73feae7b', 'continent', 'Each of the main continuous land-masses on the earth''s surface, now generally regarded as seven in number, including their related islands, continental shelves etc.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4739ac72-bb4a-4276-a321-8d6d355eb15b', 'continue', 'An option allowing a gamer to resume play after game over, when all lives have been lost.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('aca60f8d-d832-4c88-b033-f413f43c894f', 'control', 'Influence or authority over something.', 'The government has complete control over the situation.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9e775b78-30b6-4691-a4c1-d2f82e2b4d1a', 'cooker', 'A device for heating food, a stove.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ac587e6c-bc07-4f1c-a85f-3a1c6a2af8e1', 'copy', 'The result of copying; an identical duplicate of an original.', 'Please bring me the copies of those reports.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f5d10733-df96-438a-9c2a-692fd143345e', 'corner', 'The point where two converging lines meet; an angle, either external or internal.', 'The corners of the wire mesh were reinforced with little blobs of solder.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('51d54fe0-bbe4-4818-98fd-a73d869dcee4', 'correctly', 'In a correct manner.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3c894a3a-2e61-4e2e-a8fc-ece92fa0fa2f', 'count', 'The act of counting or tallying a quantity.', 'Give the chairs a quick count to check if we have enough.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3aabd0dd-3ae4-43c0-8ebb-d1a17cfd3f3a', 'couple', 'Two partners in a romantic or sexual relationship.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b34a922a-e99a-4eb2-b57a-c9b718f2c93c', 'cover', 'A lid.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4970fb99-0e40-492e-b9b9-92dfcf434d58', 'crazy', 'An insane or eccentric person; a crackpot.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b1fb138a-308e-4f2c-87e0-b47637409799', 'creative', 'A person directly involved in a creative marketing process.', 'He is a visionary creative.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6f7b7541-823b-4de6-b224-86a01a1cf655', 'credit', 'Reliance on the truth of something said or done; faith; trust.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7e88a0b9-91b2-4acc-b27b-6f0977a54fa7', 'crime', 'A specific act committed in violation of the law.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a8a57817-7968-4736-aa14-9781215f8231', 'criminal', 'A person who is guilty of a crime, notably breaking the law.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b78f2fb9-f6e5-423a-8e20-8319e57832b3', 'cross', 'A geometrical figure consisting of two straight lines or bars intersecting each other such that at least one of them is bisected by the other.', 'Put a cross for a wrong answer and a tick for a right one.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ec5eca0b-22f0-4ff9-8261-af353fc76082', 'crowd', 'A group of people congregated or collected into a close body without order.', 'After the movie let out, a crowd of people pushed through the exit doors.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2334ce31-985e-4789-9cde-9a5838ced3db', 'crowded', 'To press forward; to advance by pushing.', 'The man crowded into the packed room.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e173ea42-1981-4c89-896e-d598858ccdd6', 'cry', 'A shedding of tears; the act of crying.', 'After we broke up, I retreated to my room for a good cry.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('38406a72-02a6-435a-9dfe-ac4dc6b91a0c', 'cupboard', 'A board or table used to openly hold and display silver plate and other dishware; a sideboard; a buffet.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3164ce42-1757-4d63-a8f9-a309e7a20f5d', 'curly', 'A person or animal with curly hair.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0f181f9a-c040-44f9-b9d9-62e70268faa1', 'cycle', 'An interval of space or time in which one set of events or phenomena is completed.', 'the cycle of the seasons, or of the year', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('aaf18fc5-7bfa-4d41-b397-2b5772ba970f', 'daily', 'Something that is produced, consumed, used, or done every day.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e39feaf9-f3c2-4052-b26c-45aceeec5056', 'danger', 'Exposure to likely harm; peril.', 'There''s plenty of danger in the desert.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('591934cc-be54-4204-9a14-ff803912a0d7', 'data', '(plural: data) A measurement of something on a scale understood by both the recorder (a person or device) and the reader (another person or device). The scale is arbitrarily defined, such as from 1 to 10 by ones, 1 to 100 by 0.1, or simply true or false, on or off, yes, no, or maybe, etc.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('83e4cb96-8e89-4bcd-9bf1-d2097a4c3580', 'dead', '(with "the", a demonstrative, or a possessive) Those who have died.', 'Have respect for the dead.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8496ba75-80d9-4734-8cac-a5fbe81dbd6d', 'deal', 'A division, a portion, a share.', 'We gave three deals of grain in tribute to the king.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('5b43de1c-2890-481c-9028-b76df460a51a', 'death', 'The cessation of life and all associated processes; the end of an organism''s existence as an entity independent from its environment and its return to an inert, nonliving state.', 'The death of my grandmother saddened the whole family.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('5588db9b-1ed3-4c39-9b31-448ff08972cf', 'decision', 'The act of deciding.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d19548cf-b6cd-4da5-8274-a63e907ce643', 'deep', '(with "the") The deep part of a lake, sea, etc.', 'creatures of the deep', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4877f5ce-f014-44b1-9759-8967c6e4f754', 'definitely', 'Without question and beyond doubt.', 'Joe definitely doesn''t know how to drive a tractor.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('82475bf6-a317-4ad8-995a-96eef85eabbf', 'degree', 'A stage of proficiency or qualification in a course of study, now especially an award bestowed by a university or, in some countries, a college, as a certification of academic achievement. (In the United States, can include secondary schools.)', 'She has two bachelor''s degrees and is studying towards a master''s degree.', 'Education', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('51c8e6a0-8d9e-46bc-9de9-227cee8e29ed', 'dentist', 'A medical doctor who specializes in dentistry.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b5e133f0-eea2-4d07-b74b-908907f32b34', 'department', 'A part, portion, or subdivision.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('fbdf5d41-8b26-478e-a15d-29f2e99166b6', 'depend', '(followed by on or upon, formerly also by of) To be contingent or conditioned; to have something as a necessary condition; to hinge on.', 'We would like to go skiing, but it depends on the amount of snow.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9877a986-3d79-42d2-b313-7bfac6f6b590', 'desert', '(usually in the plural) That which is deserved or merited; a just punishment or reward', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('eeb90e2e-41c4-47cb-ac94-9dca7ef60142', 'designer', 'A person who designs something, or who designs things as a profession.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('00fc297d-9066-4cb6-bf4f-29ac09567df0', 'destroy', 'To damage beyond use or repair.', 'Hooligans destroy unprovoked.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('eda1ff53-f106-40c9-8a0f-421bc0777ac8', 'detective', '(law enforcement) A police officer who looks for evidence as part of solving a crime; an investigator.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('75523217-a884-4767-8201-c167263b4936', 'develop', 'To change with a specific direction, progress.', 'Let''s see how things develop and then make our decision.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('19bf4c0e-2187-42e5-b55f-a6e266347e1e', 'device', 'Any piece of equipment made for a particular purpose, especially a mechanical or electrical one.', 'There are a number of household devices in a kitchen such as a dishwasher, a garbage disposal, or an electric can opener.', 'Technology', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a136cdef-24ee-4439-a902-efc8bc9adf4d', 'diary', 'A daily log of experiences, especially those of the writer.', 'They kept separate diaries. His was on paper and her diary was on her computer''s hard drive.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1b78404d-51b4-4d59-a06e-cb01080dbd97', 'differently', '(manner) In a different way.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ddf2c4ca-56f4-4451-a409-1ba8b2282c66', 'digital', 'A digital option.', '', 'Technology', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e4ce6f08-ceaf-4331-86f2-e83c43da46ba', 'direct', 'To manage, control, steer.', 'to direct the affairs of a nation or the movements of an army', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('858a2bb6-0465-42f3-91f9-3781f07459c1', 'direction', 'A theoretical line (physically or mentally) followed from a point of origin or towards a destination. May be relative (e.g. up, left, outbound, dorsal), geographical (e.g. north), rotational (e.g. clockwise), or with respect to an object or location (e.g. toward Boston).', 'Keep going in the same direction.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('89f3941a-793c-4ae7-9ac3-b143a988c2c3', 'director', 'One who directs; the person in charge of managing a department or directorate (e.g., director of engineering), project, or production (as in a show or film, e.g., film director).', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('579f0223-fd50-44c3-ad46-880aeeda625c', 'disagree', 'To fail to agree; to have a different opinion or belief.', 'Bob says cats are friendlier than dogs, but I disagree.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('07fbee8f-13d3-40b2-9855-04f34e211ac1', 'disappear', 'To vanish.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c8473eb8-93df-487c-9afd-96f41c634d75', 'disaster', 'An unexpected natural or man-made catastrophe of substantial extent causing significant physical damage or destruction, loss of life or sometimes permanent change to the natural environment.', 'People would suffer disasters when society''s morality degenerates.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('59f17be7-2108-438a-b500-5909161d7bca', 'discover', 'To find or learn something for the first time.', 'Turning the corner, I discovered a lovely little shop. I discovered that they sold widgets.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9cefa559-321b-45a4-9ba3-89fca712624c', 'discovery', 'Something discovered.', 'This latest discovery should eventually lead to much better treatments for disease.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('08d9ffd3-bbfe-4abb-8369-9083ff9a3218', 'discussion', 'Conversation or debate concerning a particular topic.', 'My discussion with the professor was very enlightening.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4df3d691-8b9e-4517-92a4-1d827b953e85', 'disease', 'An abnormal condition of a human, animal or plant that causes discomfort or dysfunction; distinct from injury insofar as the latter is usually instantaneously acquired.', 'The tomato plants had some kind of disease that left their leaves splotchy and fruit withered.', 'Health', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3ec41765-9283-4c9c-8183-47df0d16c8ff', 'distance', 'The amount of space between two points, usually geographical points, usually (but not necessarily) measured along a straight line.', 'From Moscow, the distance is relatively short to Saint Petersburg, relatively long to Novosibirsk, but even greater to Vladivostok.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('09602725-5fd8-4fc4-a11d-91b76f379695', 'divorced', 'To legally dissolve a marriage between two people.', 'A ship captain can marry couples, but cannot divorce them.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e9ab893d-0724-4527-b598-f4178f18e8d6', 'exactly', '(manner) without approximation; precisely.', 'He divided the coins exactly in half.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4e391483-5e1b-4761-ad2d-404c1a8a67b0', 'document', 'An original or official paper used as the basis, proof, or support of anything else, including any writing, book, or other instrument conveying information pertinent to such proof or support.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e379941e-a0bd-421e-baac-31814b81099b', 'double', 'Twice the number, amount, size, etc.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('456348cf-5031-4e61-a67b-3942fefab175', 'download', 'A file transfer to the local computer.', 'The download took longer than I expected.', 'Technology', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('5c3b4292-3b58-48d7-a09f-46fe599a3b04', 'drama', 'A composition, normally in prose, telling a story and intended to be represented by actors impersonating the characters and speaking the dialogue', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('963624bf-d760-4499-b515-cd97ba45a5a5', 'drawing', 'To move or develop something.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9a6b1cbf-70ab-42fe-813f-33b63ac2b14e', 'dream', 'Imaginary events seen in the mind while sleeping.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9373a624-d9a9-46a1-ab26-5cb7c21bf0d5', 'driving', 'To provide an impetus for motion or other physical change, to move an object by means of the provision of force thereto.', 'You drive nails into wood with a hammer.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6b77b1e4-ee36-4ea0-ba84-754232295cf7', 'drop', 'A small quantity of liquid, just large enough to hold its own round shape via surface tension, especially one that falls from a source of liquid.', 'Put three drops of oil into the mixture.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('fc2a3ae3-45f3-45f3-b248-dc93c9ab2809', 'drug', 'A substance used to treat an illness, relieve a symptom, or modify a chemical process in the body for a specific purpose.', 'Aspirin is a drug that reduces pain, acts against inflammation and lowers body temperature.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('79fbc627-5f7c-438a-891f-f3b4a2d1efcd', 'dry', 'The process by which something is dried.', 'This towel is still damp: I think it needs another dry.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a2d487fe-5146-4d94-b93f-19bc81e09ff0', 'earn', 'To gain (success, reward, recognition) through applied effort or work.', 'You can have the s''mores: you earned them, clearing the walkway of snow so well.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('cc103327-4810-45f1-868b-31b5b4c85bad', 'earth', 'The third planet of the Solar System; the world upon which humans live.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('bdb4ea51-460a-422c-84fa-fbac53954629', 'easily', 'Comfortably, without discomfort or anxiety.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('51f34f2d-3603-4d4c-b4e4-ae9142cb034e', 'education', 'The process of imparting knowledge, skill and judgment.', '2016-06-17 AROP JOSEPH "Education is the slight hammer that breaks the yoke of ignorance, and moulds knowledge, skills, ideas, good moral values in a person be it a child, a youth or full grown adult. no matter a persons age learning never stops".', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e348392a-fe02-4395-85c5-ab0858fa31a0', 'effect', 'The result or outcome of a cause.', 'The effect of the hurricane was a devastated landscape.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7d5e314f-420e-4bb9-a9f2-d7545bea3f4e', 'either', '(after a negative) As well.', 'I don''t like him, and I don''t like her either.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a7597ebc-fb6d-4d69-be49-5c68b588d6a5', 'electric', '(usually with definite article) Electricity; the electricity supply.', 'We had to sit in the dark because the electric was cut off.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('50e22e3e-9122-4ceb-8e26-747d4fbcd301', 'electrical', 'An electrical engineer.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('050b9779-632d-4e45-bf66-ae2ecf439fc4', 'electricity', 'Originally, a property of amber and certain other nonconducting substances to attract lightweight material when rubbed, or the cause of this property; now understood to be a phenomenon caused by the distribution and movement of charged subatomic particles and their interaction with the electromagnetic field.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('557c52dd-0544-4a97-91b1-6fae8c78070c', 'electronic', ': Of or pertaining to an electron or electrons.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9ee28f52-7c4e-41e6-9238-81eaa23ec8fc', 'employ', 'The state of being an employee; employment.', 'The school district has six thousand teachers in its employ.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('756a02bb-3ff2-4b6e-90af-9c8f2cf1bc7d', 'employee', 'An individual who provides labor to a company or another person.', 'One way to encourage your employees to work harder is by giving them incentives.', 'Business', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c4930ab1-687c-45b3-a8f8-4ff25f5b4a59', 'employer', 'A person, firm or other entity which pays for or hires the services of another person.', '', 'Business', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1c44f3bf-08dd-487d-ade3-22865f380bb2', 'ending', 'A termination or conclusion.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f3128bde-6970-4efe-8c4e-9bc37dad4994', 'energy', 'The impetus behind all motion and all activity.', '', 'Environment', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('64bb07f9-72d4-4862-bf65-6b0573eddf71', 'engine', 'A large construction used in warfare, such as a battering ram, catapult etc.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7feaddcd-ac49-4e17-ba09-7005602c8baf', 'engineer', 'A person who is qualified or professionally engaged in any branch of engineering.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('dc558e19-07f5-4340-bd42-676a0d4b9b23', 'enormous', 'Deviating from the norm; unusual, extraordinary.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d93118c5-ca29-4d9d-8b31-7ad0ed53a7a9', 'enter', 'The "Enter" key on a computer keyboard.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3c0b5ff0-6bed-4b29-b9a9-3851a9f06a37', 'environment', 'The surroundings of, and influences on, a particular item of interest.', '', 'Environment', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a52c7437-ff05-441c-9e82-179462932ed7', 'equipment', 'The act of equipping, or the state of being equipped, as for a voyage or expedition.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1ee6bbef-9398-44f6-843a-f7704e4b0997', 'error', 'The state, quality, or condition of being wrong.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('bbd3c620-d9fe-4200-bfc4-973a8caa8d63', 'especially', '(manner) In a special manner; specially.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('48be3767-c1ad-4cf5-8669-3a71d9900e88', 'essay', '(authorship) A written composition of moderate length, exploring a particular issue or subject.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('bd6a6d1a-12f3-4947-99c8-d41d5ddf6421', 'everyday', '(rare) the ordinary or routine day or occasion', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('78ea9a9b-faa3-4c50-a958-893a2851e213', 'everywhere', 'In or to all locations under discussion.', 'He delivers the mail everywhere on this street.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('682a5317-5602-4330-8d2d-6dea43384fbc', 'evidence', 'Facts or observations presented in support of an assertion.', 'There is no evidence that anyone was here earlier.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c9d2077c-8d0e-48b4-afad-476ece9c203e', 'exact', 'To demand and enforce the payment or performance of, sometimes in a forcible or imperious way.', 'to exact tribute, fees, or obedience from someone', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('efa7ed25-6392-4d83-b487-db94624cc84c', 'excellent', 'Having excelled, having surpassed.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3fefed9c-623f-45da-adcd-1886d5ccc34d', 'except', 'To exclude; to specify as being an exception.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a81c376d-f373-4a32-b1a1-82eb71263a63', 'exist', '(stative) to be; have existence; have being or reality', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('61c1dff0-aa72-41f7-a66d-a31f6453cb87', 'expect', 'To predict or believe that something will happen', 'He never expected to be discovered.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ba343853-fb80-4d51-bc9a-237e17b156e2', 'experience', 'The effect upon the judgment or feelings produced by any event, whether witnessed or participated in; personal and direct impressions as contrasted with description or fancies; personal acquaintance; actual enjoyment or suffering.', 'It was an experience he would not soon forget.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e8a33910-daf2-4e62-a698-74ec3cea8159', 'experiment', 'A test under controlled conditions made to either demonstrate a known truth, examine the validity of a hypothesis, or determine the efficacy of something previously untried.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1f1c7358-922b-4f60-b154-577330d45025', 'expert', 'A person with extensive knowledge or ability in a given subject.', 'We called in several experts on the subject, but they couldn''t reach an agreement.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('badef378-1995-4c21-868c-051587669c11', 'explanation', 'The act or process of explaining.', 'The explanation was long and drawn-out.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3ff96beb-e416-4e3d-8203-2ce5966cd733', 'express', 'A mode of transportation, often a train, that travels quickly or directly.', 'I took the express into town.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e4c73f8e-64da-4cb5-9495-ef3329030b45', 'extreme', 'The greatest or utmost point, degree or condition.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7f31eeb2-c8a0-478e-a5dd-fa0121bc2b4f', 'extremely', '(degree) To an extreme degree.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1650ab30-e038-4674-88b2-9629baf973cb', 'factor', 'A doer, maker; a person who does things for another person or organization.', 'The factor of the trading post bought the furs.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('614b8711-06bf-42d1-8cf9-e4f07c967a6a', 'factory', 'A trading establishment, especially set up by merchants working in a foreign country.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('cbe9f026-10f7-435b-b1cd-3a3e2cbb40c3', 'fail', 'Poor quality; substandard workmanship.', 'The project was full of fail.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('00887b10-da8f-44e5-84b5-ce544d9fe9db', 'fair', 'Something which is fair (in various senses of the adjective).', 'When will we learn to distinguish between the fair and the foul?', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b5dcbeb7-8a17-4e11-9624-1afa036b88f8', 'fan', 'A hand-held device consisting of concertinaed material, or slats of material, gathered together at one end, that may be opened out into the shape of a sector of a circle and waved back and forth in order to move air towards oneself and cool oneself.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6ff180bd-08ec-48f4-9c92-16df0a4e2b8b', 'farming', 'To work on a farm, especially in the growing and harvesting of crops.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('64db96b9-c4b0-43a7-a6eb-3182a1bea392', 'fashion', 'A current (constantly changing) trend, favored for frivolous rather than practical, logical, or intellectual reasons.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('46d34685-e600-44ee-b33c-45012911bb0c', 'fear', 'A strong, uncontrollable, unpleasant emotion or feeling caused by actual or perceived danger or threat.', 'He was struck by fear on seeing the snake.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b96253b9-07c5-48ac-ac4d-bd9b76609d8a', 'feature', 'One''s structure or make-up: form, shape, bodily proportions.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7b1f6151-b6b0-453f-9442-9e37463965ad', 'feed', 'Food given to (especially herbivorous) animals.', 'They sell feed, riding helmets, and everything else for horses.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8741f1b7-48e8-4a12-9765-324927ca219f', 'female', 'One of the female (feminine) sex or gender.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('bc6fa587-b690-4774-9275-b4ab4c908145', 'fiction', 'Literary type using invented or imaginative writing, instead of real facts, usually written as prose.', 'I am a great reader of fiction.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d62194fc-ae1d-4969-8eaf-fb0b7f173386', 'field', 'A land area free of woodland, cities, and towns; open country.', 'There are several species of wild flowers growing in this field.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6a231b99-e4a8-4b7d-9af8-e80779689ffd', 'fight', 'To contend in physical conflict, either singly or in war, battle etc.', 'A wounded animal will fight like a maniac, relentless, savage and murderous.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7a163164-0e4a-4978-a388-348db3801aa7', 'figure', 'A drawing or diagram conveying information.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('44cf4c7b-dd1a-447d-bac0-92964f4ede6c', 'finally', 'At the end or conclusion; ultimately.', 'The contest was long, but the Romans finally conquered.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('97916cb1-3237-408e-af8d-d3489bd378b3', 'finger', 'A slender jointed extremity of the human hand, exclusive of the thumb.', 'Humans have two hands and ten fingers. Each hand has one thumb and four fingers.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b2eeb1ed-cbce-4e6e-aabe-42f86d860f3f', 'firstly', 'In the first place; before anything else; first.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('5c0a2ce1-2880-43f8-9cfd-b7e77292cf80', 'fishing', 'The act of catching fish.', 'We had a good day''s fishing at the weekend.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3ae7ecea-a998-4488-ade1-43fed67a8d66', 'fit', 'The degree to which something fits.', 'Since he put on weight, his jeans have been a tight fit.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('596a3dd8-86f4-4145-b83f-da2c6e213627', 'fix', 'A repair or corrective action.', 'That plumber''s fix is much better than the first one''s.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2f3d88cf-ac3b-46fa-b110-cf200d3ea112', 'flu', 'Influenza.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('bef6111a-75b0-4e5c-8cbf-7a628320b979', 'flying', 'To hit a fly ball; to hit a fly ball that is caught for an out. Compare ground (verb) and line (verb).', 'Jones flied to right in his last at-bat.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8888b013-4bd2-4ac5-a424-aeb06ee916ec', 'focus', 'A point at which reflected or refracted rays of light converge.', 'The heat of sunlight at the focus of a magnifying glass can easily set dry leaves on fire.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a31a63fc-5761-46d6-acf8-d8870fc02304', 'following', 'To go after; to pursue; to move behind in the same path or direction.', 'Follow that car!', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ce3e438c-0c71-4a57-888b-c62860035311', 'foreign', 'A foreign person, particularly:', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8463804f-137c-4c24-8120-b7026028832f', 'forest', 'A dense uncultivated tract of trees and undergrowth, larger than woods.', '', 'Environment', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('83f63239-267b-43dd-b686-a9bae4d9aaa9', 'fork', 'A pronged tool having a long straight handle, used for digging, lifting, throwing etc.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('853dcf45-3c96-4dfc-8290-afed728c7bf3', 'formal', 'Formalin.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e42536dd-d367-4b63-a59f-30739b691f31', 'fortunately', 'In a fortunate manner.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ec9024b1-ba0e-4ca8-b3f3-e5f2e48312f2', 'forward', 'One of the eight players (comprising two props, one hooker, two locks, two flankers and one number eight, collectively known as the pack) whose primary task is to gain and maintain possession of the ball (compare back).', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a24b0572-aa45-492b-90cc-a55a6728e235', 'fresh', 'A rush of water, along a river or onto the land; a flood.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1e8a748a-26b6-41d0-8c50-bedb55d714a1', 'fridge', 'A refrigerator.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f17d4915-cfda-4927-b61b-26cc4dd9b0b0', 'frog', 'A small tailless amphibian of the order Anura that typically hops.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6a1c341b-6d91-42d4-a0b9-53955ac23d7f', 'furniture', 'Large movable item(s), usually in a room, which enhance(s) the room''s characteristics, functionally or decoratively.', 'A chair is furniture. Sofas are also furniture.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2c496a9d-b348-43fd-a3fb-534bec88d100', 'further', 'To help forward; to assist.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7f5d60ed-21ba-441f-a4a1-8739db06aab2', 'gallery', 'An institution, building, or room for the exhibition and conservation of works of art.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2a409d92-fe49-4ab9-be8c-804dfcb826c8', 'gap', 'An opening in anything made by breaking or parting.', 'He made a gap in the fence by kicking at a weak spot.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7d81ea83-d52e-4141-a380-38f4e00b2576', 'gas', 'Matter in a state intermediate between liquid and plasma that can be contained only if it is fully surrounded by a solid (or in a bubble of liquid) (or held together by gravitational pull); it can condense into a liquid, or can (rarely) become a solid directly.', 'A lot of gas had escaped from the cylinder.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('aa20134b-36bc-4ea1-ae13-1a75574df96d', 'gate', 'A doorlike structure outside a house.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('530afd79-610f-4e14-987c-674e8bb643cb', 'general', 'A general fact or proposition; a generality.', 'We have dealt with the generals; now let us turn to the particulars.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('fafd5ee3-ede6-40cb-a52b-09894cfa0f11', 'gift', 'Something given to another voluntarily, without charge.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('15ad95b7-2258-408d-90ee-1bb0a5d5d64d', 'goal', 'A result that one is attempting to achieve.', 'My lifelong goal is to get into a Hollywood movie.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('07844868-3f3a-404d-a466-3232010929e3', 'god', 'A being such as a monotheistic God: a single divine creator and ruler of the universe.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('5cb2c9b7-0e94-4e90-a102-670ad01ef4e4', 'gold', 'A heavy yellow elemental metal of great value, with atomic number 79 and symbol Au.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d815ecfc-0592-424a-a37c-4d965cade85f', 'golf', 'A ball game played by individuals competing against one another in which the object is to hit a ball into each of a series of (usually 18 or nine) holes in the minimum number of strokes.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6338fd60-6838-47b1-9bd8-eb96a75c5244', 'government', 'The body with the power to make and/or enforce laws to control a country, land area, people or organization.', '', 'Society', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9f9f5ab3-0a09-4adc-b1ae-166858cbd314', 'grass', 'Any plant of the family Poaceae, characterized by leaves that arise from nodes in the stem and leaf bases that wrap around the stem, especially those grown as ground cover rather than for grain.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('751b863d-4b94-48a4-8136-bc7377708045', 'greet', 'To welcome in a friendly manner, either in person or through another means e.g. writing or over the phone/internet', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8fb24e13-dfc2-4dc2-9403-4c59c53d73e8', 'ground', 'The surface of the Earth, as opposed to the sky or water or underground.', 'Look, I found a ten dollar bill on the ground!', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('22443206-8fe7-4b19-8fe8-b440d6d58789', 'guest', 'A recipient of hospitality, specifically someone staying by invitation at the house of another.', 'The guests were let in by the butler.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6d492abc-ca78-432c-adde-4c5c227b087e', 'guide', 'Someone who guides, especially someone hired to show people around a place or an institution and offer information and explanation.', 'The guide led us around the museum and explained the exhibits.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('05bf7d07-077b-4837-bb86-a8ab11a94308', 'gun', 'A device for projecting a hard object very forcefully; a firearm or cannon.', 'Guns were considered improvements of crossbows and catapults.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('cbea0b9a-1554-4c30-b5ae-6222c584746c', 'guy', 'An effigy of a man burned on a bonfire on the anniversary of the Gunpowder Plot (5th November).', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7d91bcd4-4c7c-41d9-830a-c2843139580d', 'habit', 'An action performed on a regular basis.', 'It’s become a habit of mine to have a cup of coffee after dinner.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3a561896-6d6e-44bf-831d-2362808f4aa2', 'hall', 'A corridor; a hallway.', 'The drinking fountain was out in the hall.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('675ac4f8-adf9-407f-a560-dab20c596dc4', 'happily', 'By chance; perhaps.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8146147a-c6a6-40bb-a220-71450a927146', 'headache', 'A pain or ache in the head.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b7249b4e-5cea-4dcb-bf75-5330b233c83c', 'heart', 'A muscular organ that pumps blood through the body, traditionally thought to be the seat of emotion.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('5f087dea-261f-4f6d-afdc-9e808433b515', 'heat', 'Thermal energy.', 'This furnace puts out 5000 BTUs of heat.   That engine is really throwing off some heat.   Removal of heat from the liquid caused it to turn into a solid.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a77ad8e1-63c0-4e36-8791-54456938791e', 'heavy', 'A villain or bad guy; the one responsible for evil or aggressive acts.', 'With his wrinkled, uneven face, the actor always seemed to play the heavy in films.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b6dadb8a-002d-4b7f-94c5-45e0efbfa108', 'height', 'The distance from the base of something to the top.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1d637289-ba5c-4da7-a69c-17241186e58d', 'helpful', 'Furnishing help; giving aid; useful.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('fffc590b-2789-463e-a18e-32b3bfe97467', 'hero', 'Somebody who possesses great bravery and carries out extraordinary or noble deeds.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('894b485b-53bd-4f06-ada6-cd0dc091493b', 'hers', 'A female person or animal.', 'I think this bird is a him, but it may be a her.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e8c3fdbf-71b0-46b7-9155-0f0549284226', 'herself', '(reflexive pronoun) Her; the female object of a verb or preposition that also appears as the subject.', 'She injured herself.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d2b5caf1-51c1-4d6c-952b-682072e8ac9a', 'invitation', 'The act of inviting; solicitation; the requesting of a person''s company.', 'an invitation to a party, to a dinner, or to visit a friend', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('22df052f-41a3-42fc-bf0b-a1a0ee7aaced', 'hide', 'To put (something) in a place where it will be harder to discover or out of sight.', 'He hides his magazines under the bed.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('da475a07-eb78-45cb-8740-92d560092c90', 'hill', 'An elevated location smaller than a mountain.', 'The park is sheltered from the wind by a hill to the east.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('84d3487e-2657-44a9-98b7-e117d73d868a', 'himself', '(reflexive pronoun) Him; the male object of a verb or preposition that also appears as the subject', 'He injured himself.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('17c4c9f2-abb7-487c-bdac-3146e47329ed', 'hit', 'A blow; a punch; a striking against; the collision of one body against another; the stroke that touches anything.', 'The hit was very slight.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('33ce394b-ff10-4b4b-978b-929ca91831f9', 'hockey', 'Ice hockey, a game on ice in which two teams of six players skate and try to score by shooting a puck into the opposing team''s net, using their sticks.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('cae2a0f5-57da-4c8d-bb5b-23b061bb6f84', 'hold', 'A grasp or grip.', 'Keep a firm hold on the handlebars.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a7de7d1d-064f-47c2-a70c-c8dff60c8e12', 'hole', 'A hollow place or cavity; an excavation; a pit; an opening in or through a solid body, a fabric, etc.; a perforation; a rent; a fissure.', 'There’s a hole in my shoe.  Her stocking has a hole in it.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c4109192-ebf5-49fd-ab8c-c1c9799634ae', 'huge', 'Very large.', 'The castle was huge.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b513addd-2377-423f-afc8-3293590e9e6b', 'human', 'A human being, whether man, woman or child.', 'Humans share common ancestors with other apes.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6cb7d9bf-0a51-4f8f-8472-2129c815580f', 'hurt', 'An emotional or psychological humiliation or bad experience.', 'how to overcome old hurts of the past', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1d8bf6d8-8bb9-442d-8e7b-e46a78e7fe7d', 'ideal', 'A perfect standard of beauty, intellect etc., or a standard of excellence to aim at.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('5864583c-340e-494b-b707-d737aa9767fa', 'identify', 'To establish the identity of someone or something.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b11b77f3-fa7f-4222-a21b-240ba44acd6f', 'ill', '(often pluralized) Trouble; distress; misfortune; adversity.', 'Music won''t solve all the world''s ills, but it can make them easier to bear.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0b6a05aa-0716-4b5f-833f-593845fdfe98', 'illness', 'An instance of a disease or poor health.', 'Her grandmother had passed away after a long illness.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d628c3a4-b589-4a3a-a008-df2bdc03524c', 'image', 'An optical or other representation of a real object; a graphic; a picture.', 'The Bible forbids the worship of graven images.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('80cedf75-8f51-4ba1-baf5-bc75d2982a3f', 'immediately', 'In an immediate manner; instantly or without delay.', 'I hope we can begin immediately.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3d13cd53-16da-4933-9c36-48411e0a80bb', 'impossible', 'An impossibility', 'Late 14th century: “Madame,” quod he, “this were an impossible!” — Geoffrey Chaucer, ‘The Franklin''s Tale’, Canterbury Tales', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ec48ce97-2c53-42fb-9499-20c6100971bc', 'included', 'To bring into a group, class, set, or total as a (new) part or member.', 'I will purchase the vacation package if you will include car rental.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a32b125a-f86b-4460-8add-ac79c03bbda2', 'including', 'To bring into a group, class, set, or total as a (new) part or member.', 'I will purchase the vacation package if you will include car rental.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3673c0dd-807b-4bd0-ab0e-013ca7f4192e', 'increase', 'An amount by which a quantity is increased.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('fb2a0f8a-2a3a-4277-a087-8e9472b04f15', 'incredible', 'Too implausible to be credible; beyond belief; unbelievable.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ed4b09f6-2cec-49d5-a392-d246e97cdab5', 'independent', 'A candidate or voter not affiliated with any political party, a freethinker, free of a party platform.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('38da440b-ab94-4c0e-a325-66effb301404', 'individual', 'A person considered alone, rather than as belonging to a group of people.', 'He is an unusual individual.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('fe61d5d3-6f9b-4274-bbc1-54606da97d8f', 'industry', 'The tendency to work persistently. Diligence.', 'Over the years, their industry and business sense made them wealthy.', 'Business', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d2eb16db-f5f3-49ae-ace3-06afcc6df7fe', 'informal', 'Not formal or ceremonious.', 'an informal get-together', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('eefe325d-98cb-41ff-aeac-6653ca2190b3', 'injury', 'Damage to the body of a human or animal.', 'The passenger sustained a severe injury in the car accident.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('69960024-79f5-4b9c-8b25-850f2ba6a383', 'insect', 'An arthropod in the class Insecta, characterized by six legs, up to four wings, and a chitinous exoskeleton.', 'Our shed has several insect infestions, including ants, yellowjackets, and wasps.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('dc65b687-8a69-41b3-9f35-2136076b30c8', 'inside', 'The interior or inner part.', 'The inside of the building has been extensively restored.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('bd312335-648d-4646-b83a-bd9331a8963b', 'instead', 'In the place of something (usually mentioned earlier); as a substitute or alternative.', 'I was going to go shopping, but I went dancing instead.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8435ffc7-6d20-4a49-918a-7d458070dfda', 'instruction', 'The act of instructing, teaching, or furnishing with information or knowledge.', 'Instruction will be provided on how to handle difficult customers.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('77f9ddac-c281-46ee-92d5-5eb6950bec1c', 'instructor', 'One who instructs; a teacher.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e0bb3108-2d42-448d-bc93-01c4adb8934a', 'instrument', 'A device used to produce music.', 'The violinist was a master of her instrument.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0aa37d7e-9b08-45ac-88b3-b86010f44b96', 'intelligent', 'Of high or especially quick cognitive capacity, bright.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('07b65ed1-7ef5-4b8e-a70b-a4bfff2de548', 'international', 'Someone who has represented their country in a particular sport.', 'The United team includes five England internationals.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7fda5937-73e4-4766-84b0-bbe61f213b6b', 'introduction', 'The act or process of introducing.', 'the introduction of a new product into the market', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f5bb3213-987e-47b1-b7c6-01333c1043b0', 'invent', 'To design a new process or mechanism.', 'After weeks of hard work, I invented a new way to alphabetize matchbooks.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('bc6fde41-f05a-4874-832a-785e5429270b', 'invention', 'Something invented.', 'I''m afraid there was no burglar. It was all the housekeeper''s invention.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('5aa1adf2-a1d0-44e0-9f97-15fbff6c99ee', 'invite', 'To ask for the presence or participation of someone or something.', 'We invited our friends round for dinner.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e22913bb-f672-4ca2-8cb5-9a64a36e4ca8', 'involve', 'To roll or fold up; to wind round; to entwine.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6c8e0108-124e-41cb-9046-c4cdec7b4e95', 'item', 'A distinct physical object.', 'Tweezers are great for manipulating small items.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('34cde6b8-5578-4daa-a180-aae72b840d00', 'itself', '(reflexive pronoun) it; A thing as the object of a verb or preposition that also appears as the subject', 'The door closed by itself', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b4655d3b-9077-4e61-9874-5d9b13f19e4e', 'jam', 'A sweet mixture of fruit boiled with sugar and allowed to congeal. Often spread on bread or toast or used in jam tarts.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('064bbb08-3e36-4ae0-9c67-12e0e34fae5a', 'jazz', 'A musical art form rooted in West African cultural and musical expression and in the African American blues tradition, with diverse influences over time, commonly characterized by blue notes, syncopation, swing, call and response, polyrhythms and improvisation.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('20b4eb54-f73c-4fcc-a3fb-e644385c9726', 'jewellery', 'Collectively, personal ornamentation such as rings, necklaces, brooches and bracelets, made of precious metals and sometimes set with gemstones.', 'She had more jewellery ornamented about her than any three ladies needed.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3e76e9ce-9fb2-4839-b6cb-73de86c61ff3', 'joke', 'An amusing story.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f2e4e91e-3cda-41aa-b2ea-70385efcc24d', 'journalist', 'The keeper of a personal journal, who writes in it regularly.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d42413f8-e97b-47e1-8e18-ab470af35964', 'jump', 'The act of jumping; a leap; a spring; a bound.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2d9afe2f-4476-43fd-ac36-9d3f75cd17bb', 'kid', 'A young goat.', 'He treated the oxen like they didn''t exist, but he treated the goat kid like a puppy.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('54f9dc76-b533-42ff-b32b-d30bd6ea669e', 'kill', 'The act of killing.', 'The assassin liked to make a clean kill, and thus favored small arms over explosives.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4106149f-a7f6-4259-9e9a-6439dd35a2f0', 'king', 'A male monarch; a man who heads a monarchy. If it''s an absolute monarchy, then he is the supreme ruler of his nation.', 'Henry VIII was the king of England from 1509 to 1547.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1b285258-0974-4571-adc4-156d36f620d8', 'knee', 'In humans, the joint or the region of the joint in the middle part of the leg between the thigh and the shank.', 'Penny was wearing a miniskirt, so she skinned her exposed knees when she fell.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('61b4624d-9362-462c-8f34-46357ebd4de0', 'knife', 'A utensil or a tool designed for cutting, consisting of a flat piece of hard material, usually steel or other metal (the blade), usually sharpened on one edge, attached to a handle. The blade may be pointed for piercing.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1db76450-e365-41f6-9542-069e085ac98a', 'knock', 'Sudden fatigue as a result of glycogen depletion from not having taken in enough nutrition.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('bd34f601-31b8-4770-815a-4ce64b1f50c2', 'knowledge', 'The fact of knowing about something; general understanding or familiarity with a subject, place, situation etc.', 'His knowledge of Iceland was limited to what he''d seen on the Travel Channel.', 'Education', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9482e73a-f424-48e7-88f7-5d00e5fd34e6', 'lab', 'A laboratory.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1b78b7ab-abc9-47a5-b246-324f0e09eb2a', 'lady', 'An aristocratic title for a woman; the wife of a lord and/or a woman who holds the position in her own right; a title for a peeress, the wife of a peer or knight, and the daughters and daughters-in-law of certain peers.', 'Sir John Smith and Lady Smith.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8dc7b050-ad3a-4834-af90-422be15efe2b', 'lake', 'A small stream of running water; a channel for water; a drain.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('22472211-aaf6-4c9f-b9f5-335769f2d8eb', 'lamp', 'A device that generates heat, light or other radiation. Especially an electric light bulb.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('91e9bd60-231c-4f9f-88d1-184c0aa6fa14', 'laptop', 'A laptop computer.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('75815716-61c5-4da4-bd57-1d4e9d2621bc', 'laughter', 'The sound of laughing, produced by air so expelled; any similar sound.', 'Their loud laughter betrayed their presence.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d27c8f81-a7f9-4dd8-9f41-050a39b42ce3', 'law', 'The body of binding rules and regulations, customs and standards established in a community by its legislative and judicial authorities.', 'entrapment is against the law', 'Society', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('5f5df25b-1bd5-4505-9692-088b43af0640', 'lawyer', 'A professional person qualified (as by a law degree or bar exam) and authorized to practice law, i.e. represent parties in lawsuits or trials and give legal advice.', 'A lawyer''s time and advice are his stock in trade. - aphorism often credited to Abraham Lincoln, but without attestation', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e0461dbe-4703-48d1-a6b1-3051e40fbf30', 'lazy', 'A lazy person.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('83e52e0f-5748-45fa-9515-568f5c70feff', 'lead', 'A heavy, pliable, inelastic metal element, having a bright, bluish color, but easily tarnished; both malleable and ductile, though with little tenacity. It is easily fusible, forms alloys with other metals, and is an ingredient of solder and type metal. Atomic number 82, symbol Pb (from Latin plumbum).', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d5144b2f-2328-4f2d-85e1-9f35c355b48a', 'leader', 'Any person that leads or directs', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1e693ff0-8355-423c-8335-67b0410bd503', 'learning', 'To acquire, or attempt to acquire knowledge or an ability to do something.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c3e2f038-4d24-4d8b-b84a-c67cf41c4494', 'least', 'Something of the smallest possible extent; an indivisible unit.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f49aec7a-262a-48cd-ab72-4b7b9783536e', 'lecture', 'A spoken lesson or exposition, usually delivered to a group.', 'During class today the professor delivered an interesting lecture.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4d879282-366a-4d02-8c66-16f95ba4ba56', 'lemon', 'A yellowish citrus fruit.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('5342ecf6-8aee-4334-bcbd-7a906d8dcb50', 'lend', 'The lumbar region; loin.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8dd32bc0-5a37-4da2-87b4-21c406749f20', 'less', 'A smaller amount or quantity.', 'I have less to do today than yesterday.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0d1b433c-8d9e-48e7-bb0b-0339b5b6c753', 'level', 'A tool for finding whether a surface is level, or for creating a horizontal or vertical line of reference.', 'Hand me the level so I can tell if this is correctly installed.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3388e003-8275-4a14-b016-faefb451d5f9', 'lifestyle', 'A style of living that reflects the attitudes and values of a person or group.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('04bdb929-657a-4165-ac7f-da72bf580506', 'lift', 'An act of lifting or raising.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1a72b879-3f99-495e-ab54-092d67d86004', 'likely', 'Something or somebody considered likely.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('73049837-62ec-456e-85a8-1c261eec2f2e', 'link', 'Some text or a graphic in an electronic document that can be activated to display another document or trigger an action.', 'Click the hyperlink to go to the next page.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('17aec66f-9e93-4c1a-b2c4-34b01f9ffa0d', 'listener', 'Someone who listens, especially to a speech or a broadcast.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d2335989-6ec0-4628-bf83-0c23e3028bcf', 'lock', 'Something used for fastening, which can only be opened with a key or combination.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8e342320-5ef9-42ca-9c1a-a2f30ae5dd62', 'lorry', 'A motor vehicle for transporting goods, and in some cases people; a truck.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9c87f252-093e-40a2-97ea-10b612107cb3', 'lost', 'To cause (something) to cease to be in one''s possession or capability due to unfortunate or unknown circumstances, events or reasons.', 'He lost his hearing in the explosion.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('253ac366-c182-45ea-a982-ad7b63e4c3ac', 'loud', 'A loud sound or part of a sound.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('aa0f8cd2-75c3-4edf-b2ee-c841bb98ef84', 'loudly', 'In a loud manner; at a high volume.', 'He spoke loudly so that his brother could hear him from across the street.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('97025b20-d157-4208-97fe-301734b5de9b', 'lovely', 'An attractive, lovely person, especially a (professional) beauty.', 'a calendar depicting young lovelies in bikinis', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('642020d2-cc59-4e9d-82e1-772f4220815b', 'low', 'Something that is low; a low point.', 'Economic growth has hit a new low.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e43bbc3c-5213-4363-93a9-a8b2fe08ca19', 'luck', 'Something that happens to someone by chance, a chance occurrence, especially a favourable one.', 'Gilbert had some bad luck yesterday — he got pick-pocketed and lost fifty dollars.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0397616e-4ff1-4a57-a6b6-66bbce2138a0', 'lucky', '(of people) Favoured by luck; fortunate; having good success or good fortune', 'The downed pilot is very lucky to be alive.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8f45e4f6-dac0-4d66-b87c-b053567b2851', 'mail', 'A bag or wallet.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('496779a2-c27a-493b-b871-7339f1a3b8e5', 'major', 'A military rank between captain and lieutenant colonel.', 'He used to be a major in the army.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b1be63af-4865-4b8b-b077-34f24d79e5de', 'male', 'One of the male (masculine) sex or gender.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('312a64a7-29c1-46d3-8c58-9bd0e31ce96c', 'manage', 'The act of managing or controlling something.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('112b6454-a58c-40dc-a466-ad9edaef4faa', 'manager', 'A person whose job is to manage something, such as a business, a restaurant, or a sports team.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('39a6c1a3-0fde-4d6b-8cae-61428c42f44b', 'manner', 'Mode of action; way of performing or doing anything', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('dcd129db-0a5f-48ba-888b-9075a9075471', 'mark', '(heading) Boundary, land within a boundary.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3621915f-8604-438c-bd3b-0bd430fe0bed', 'marry', 'To enter into the conjugal or connubial state; to take a husband or a wife.', 'Neither of her daughters showed any desire to marry.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ac1a4b8c-141f-4aab-94c2-a06d872cca5e', 'material', 'Matter which may be shaped or manipulated, particularly in making something.', 'Asphalt, composed of oil and sand, is a widely used material for roads.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('96d8a1c6-6de3-408a-a490-f5a26fdfa68a', 'mathematics', 'An abstract representational system used in the study of numbers, shapes, structure, change and the relationships between these concepts.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e74e005e-f4e5-4283-9602-65488644e8c9', 'maths', 'An abstract representational system used in the study of numbers, shapes, structure, change and the relationships between these concepts.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('87cee6f6-a0c0-4aa8-91fd-065b10f61293', 'matter', 'Substance, material.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d26d8915-33b3-46dd-b977-9daad78c1488', 'media', 'The middle layer of the wall of a blood vessel or lymph vessel which is composed of connective and muscular tissue.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('943ad82c-6ac9-4e13-a39a-c1a64389177f', 'medical', 'A medical examination.', 'You''ll have to get a medical before you apply for that job.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('24aa280f-3433-4d0f-a142-d1e5902a936e', 'medicine', 'A substance which specifically promotes healing when ingested or consumed in some way.', '', 'Health', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('48a43a16-ac6e-444c-9f62-1a5b56968e57', 'memory', 'The ability of the brain to record information or impressions with the facility of recalling them later at will.', 'Memory is a facility common to all animals.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e554fdf4-0d4f-4b26-8209-1e0a339eac0c', 'mention', 'A speaking or notice of anything, usually in a brief or cursory manner. Used especially in the phrase make mention of.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8f751a33-7f34-4fd6-bc28-d5eb29dc1ae9', 'metal', '(heading) Chemical elements or alloys, and the mines where their ores come from.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c8c25b4d-e6ea-43e9-ac1a-ebda84388341', 'method', 'A process by which a task is completed; a way of doing something (followed by the adposition of, to or for before the purpose of the process):', 'If one method doesn''t work, you should ask a friend to help you.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('190922ef-6880-44b0-be91-fc8c20a03f14', 'middle', 'A centre, midpoint.', 'The middle of a circle is the point which has the same distance to every point of circle.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('582e5b25-172b-4d95-90d5-243ddc04e1a6', 'might', 'Power, strength, force or influence held by a person or group.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f292a36a-81e2-4134-b5fa-effa577e37ed', 'mind', 'The ability for rational thought.', 'Despite advancing age, his mind was still as sharp as ever.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('039b0085-fd12-4810-aef6-58f57eec0c63', 'mine', 'My; belonging to me; that which belongs to me.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7db59f7c-a5df-4d82-8b3a-448de213f209', 'mirror', 'A smooth surface, usually made of glass with reflective material painted on the underside, that reflects light so as to give an image of what is in front of it.', 'I had a look in the mirror to see if the blood had come off my face.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1983401b-30f3-4413-afff-6484267a20b4', 'missing', 'To fail to hit.', 'I missed the target.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('dc882cf0-cbdf-4e3b-a26b-ecda9e0c73c4', 'mobile', 'A kinetic sculpture or decorative arrangement made of items hanging so that they can move independently from each other.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f5a00718-dfa3-406c-b606-9789fce0788c', 'supply', 'The act of supplying.', 'supply and demand', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6094d93d-18ff-4885-8910-d9e49ee825fa', 'monkey', 'Any member of the clade Simiiformes not also of the clade Hominoidea containing humans and apes, from which they are usually, but not universally, distinguished by smaller size, a tail, and cheek pouches.', 'He had been visiting an area zoo when a monkey swung from its tree perch, swiped his glasses and hurled them into a hippo hole.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1449f3c7-e61c-4d47-b406-10ee289d019c', 'mostly', 'Mainly or chiefly; for the most part; usually, generally, on the whole.', 'They''re mostly good people, although they have made a few mistakes.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4d9e0390-c7c4-411d-be66-e73d11a1228b', 'motorcycle', 'An open-seated motor vehicle with handlebars instead of a steering wheel, and having two (or sometimes three) wheels.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e26ff302-2b4a-4034-93e3-23aaf93741e7', 'movement', 'Physical motion between points in space.', 'I saw a movement in that grass on the hill.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('43416ce8-0a38-418f-b2e4-acc78a76ce07', 'musical', 'A stage performance, show or film that involves singing, dancing and musical numbers performed by the cast as well as acting.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b5618c7e-22f2-4995-a0e0-419bb7829c07', 'musician', 'A composer, conductor, or performer of music; specifically, a person who sings and/or plays a musical instrument as a hobby, an occupation, or a profession.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9ec4d827-33dc-4773-a2b6-35040ec9d20f', 'myself', '(reflexive pronoun) Me, as direct or indirect object the speaker as the object of a verb or preposition, when the speaker is also the subject.', 'I taught myself.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('437564b2-fc7b-40c1-a145-585a6171227d', 'narrow', '(chiefly in the plural) A narrow passage, especially a contracted part of a stream, lake, or sea; a strait connecting two bodies of water.', 'the narrows of New York harbor', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f30d017f-88cf-4fe5-b52f-7b209f67831c', 'national', 'A subject of a nation.', 'The diplomats were advised not to interact with any foreign nationals except on official duty.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('74c4e0a4-a791-423b-b570-fc6634a07709', 'nature', 'The natural world; that which consists of all things unaffected by or predating human technology, production, and design. (Compare ecosystem.)', 'Nature never lies (i.e. tells untruths).', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e6df78a9-5fc0-4203-8f91-703d59673491', 'nearly', 'With great scrutiny; carefully.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('20c57347-f275-4de1-bd1b-99f1db473e52', 'necessary', '(usually with the definite article) A place to do the "necessary" business of urination and defecation: an outhouse or lavatory.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0a1285c6-e0a8-4610-8a7c-a561621a2164', 'neither', 'Similarly not.', 'Just as you would not correct it, neither would I.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f5bac227-0cf8-4ddb-a121-e14268f70506', 'nervous', 'Of sinews and tendons.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d793fb70-505a-464f-a215-604054af8a09', 'network', 'A fabric or structure of fibrous elements attached to each other at regular intervals.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9052cf06-5c9f-4e56-8e95-03729fda452c', 'noise', 'Various sounds, usually unwanted or unpleasant.', 'He knew that it was trash day, when the garbage collectors made all the noise.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e168a64d-555f-4b61-86cd-51af645f067c', 'noisy', 'Making a noise, especially a loud unpleasant sound', 'the noisy crowd.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('5af7e66a-dfd7-4938-adbd-beb0596c536f', 'none', 'A person without religious affiliation.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3bd8d59a-d0a4-45a6-9d11-b4f73495b09a', 'normal', 'A line or vector that is perpendicular to another line, surface, or plane.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('835dfad8-ec6b-4e33-b3a9-86e9aac67fa0', 'normally', 'Under normal conditions or circumstances; usually; most of the time', 'Normally, I eat breakfast at 6am, but today, I got up late and didn''t eat until 9.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('bebf43d7-0a8b-41a7-ac7b-3f856849754d', 'notice', 'The act of observing; perception.', 'He took no notice of the changes, and went on as though nothing had happened.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f13d16e1-719a-4ad3-9f86-e211a770f9cf', 'novel', 'Newly made, formed or evolved; having no precedent; of recent origin; new.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('631066d3-5db6-49ae-ab19-88f7f88d6289', 'nowhere', 'No particular place, noplace.', 'They went on a cruise to nowhere.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('cc15e969-3bc6-4c55-95db-879d46a75cfe', 'nut', 'A hard-shelled seed.', 'There are many sort of nuts: peanuts, cashews, pistachios, Brazil nuts and more.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b13dc1ad-4148-458e-86a3-81c4000b2f94', 'ocean', 'One of the large bodies of water separating the continents.', '', 'Environment', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('94004974-afc2-45a0-a452-96d040d0eef0', 'offer', 'A proposal that has been made.', 'I decline your offer to contract.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8f6b1f2e-c81c-4cc0-9613-6b238ac46c80', 'officer', 'One who has a position of authority in a hierarchical organization, especially in military, police or government organizations.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a8a59a66-36b3-4e48-8892-19d1d58e1ede', 'oil', 'Liquid fat.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c01418df-4cf9-4c84-922a-e9a52f372fdf', 'onto', '(of a function) Assuming each of the values in its codomain; having its range equal to its codomain.', 'Considered as a function on the real numbers, the exponential function is not onto.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('5cc09347-ea29-4db9-8399-8054cdcaafc4', 'opportunity', 'A chance for advancement, progress or profit.', 'The world is full of opportunities and it''s up to me to see them and pursue them.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('93e99800-32d8-4ea6-9b85-6d994455904b', 'option', 'One of a set of choices that can be made.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('bd8c70bb-2f4a-4adb-bbfd-8608830a8144', 'ordinary', 'A person with authority; authority, ordinance.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d1df3bb2-4eff-46c4-8d5c-728c3bf97755', 'organization', 'The quality of being organized.', 'This painting shows little organization at first glance, but little by little the structure becomes clear.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0c02c175-f2ca-4963-a2d6-48522dcbf746', 'organize', 'To arrange in working order.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('24ea4ec6-58cf-4975-8c49-f90062ac5a22', 'original', 'An object or other creation (e.g. narrative work) from which all later copies and variations are derived', 'This manuscript is the original.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0e0b326a-9595-49b3-98ee-e458a3239e63', 'ourselves', '(reflexive pronoun) Us; the group including the speaker as the object of a verb or preposition when that group also is the subject.', 'We should keep this for ourselves.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7f519754-b865-4f6c-a43a-ff41b81ea23b', 'oven', 'A chamber used for baking or heating.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6aded613-92c5-432b-a680-b459d61bb8aa', 'awkward', 'Someone or something that is awkward.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('19f6f8d0-1efb-4537-98e9-58ad9a228b68', 'owner', 'One who owns something.', 'The police recovered the stolen car and returned it to its owner.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ab590ea4-4149-4d55-9485-5f2c6f926e93', 'pack', 'A bundle made up and prepared to be carried; especially, a bundle to be carried on the back, but also a load for an animal, a bale.', 'The horses carried the packs across the plain.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('eeb1ec92-d281-4b17-b6a6-f7924e3f33c6', 'pain', 'An ache or bodily suffering, or an instance of this; an unpleasant sensation, resulting from a derangement of functions, disease, or injury by violence; hurt.', 'I had to stop running when I started getting pains in my feet.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c24f318b-8123-4a83-8838-ded9f3d9cbc0', 'painter', 'An artist who paints pictures.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e80935dc-b209-4836-b002-507898a5b732', 'palace', 'Official residence of a head of state or other dignitary, especially in a monarchical or imperial governmental system.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('adb287ff-ef83-4775-9b87-afb2a8c3d829', 'particular', 'A small individual part of something larger; a detail, a point.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3355ac79-bced-41d0-8c04-418e274767f4', 'pass', 'To change place.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('14b5eeb1-ac95-4ff1-be27-c415aa3aabd0', 'passenger', 'One who rides or travels in a vehicle, but who does not operate it and is not a member of the crew.', 'Somebody in a team who does not do their fair share of the work.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('36e4dc16-b812-4266-8eef-9ef48aed4d89', 'patient', 'A person or animal who receives treatment from a doctor or other medically educated person.', '', 'Health', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('832b8306-5deb-4a99-9837-29f496f139ac', 'pattern', 'Model, example.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1079f6d0-f410-49ab-92bc-e7b2539a6b09', 'peace', 'A state of tranquility, quiet, and harmony; absence of violence. For instance, a state free from civil disturbance.', 'Our lounge strives to maintain an environment of peace for the comfort of our customers.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('26aa62ae-e22c-4c1c-8db1-3b4dead507d8', 'penny', 'In the United Kingdom and Ireland, a copper coin worth 1/240 of a pound sterling or Irish pound before decimalisation. Abbreviation: d.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8773c9f6-1452-4377-9cb7-8c7e01339ca6', 'per', 'For each.', '$2.50 per dozen', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8bedcf29-50b9-4408-8c1e-2f2c50ef2ca1', 'per cent', 'A percentage, a proportion (especially per hundred).', 'only a small percent attain the top ranks', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c7a01563-ab41-4867-89fc-6931b920ea44', 'perform', 'To do something; to execute.', 'It took him only twenty minutes to perform the task.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a91d7788-3e52-4382-a7aa-ea309d285aa9', 'perhaps', 'An uncertainty.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e3f74c3f-179e-4e14-8df3-1846fcb979e6', 'permission', 'Authorisation; consent (especially formal consent from someone in authority)', 'Sire, do I have your permission to execute this traitor?', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('85d0ebc0-9d7f-4744-9aed-607a622b8cdd', 'personality', 'A set of non-physical psychological and social qualities that make a person (or thing) distinct from another.', 'The president has a unique personality.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1d98512e-49cb-476b-932c-71cd6f45c253', 'pet', 'An animal kept as a companion.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('70b196e7-9e60-46a8-a071-2670b2ffbad6', 'petrol', 'Petroleum, a fluid consisting of a mixture of refined petroleum hydrocarbons, primarily consisting of octane, commonly used as a motor fuel.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3d51ef42-4fc6-4a12-a8ae-af659dcb0b09', 'physical', 'Physical examination.', 'How long has it been since your last physical?', 'Health', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('bb9a5913-3614-49a3-be51-0f8428aa7d28', 'physics', 'A medicine or drug, especially a cathartic or purgative.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6a9aa601-7802-4a6b-929f-41797451f37b', 'pick', 'A tool used for digging; a pickaxe.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('41fdf0f2-2ac8-42c8-a321-29361d20f74c', 'pilot', 'A person who steers a ship, a helmsman.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b237896b-7db5-4685-99c0-008278ab6ece', 'planet', 'Each of the seven major bodies which move relative to the fixed stars in the night sky—the Moon, Mercury, Venus, the Sun, Mars, Jupiter and Saturn.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c12fd349-a3b5-4e5f-9a7c-7bae19dced54', 'plastic', 'A synthetic, solid, hydrocarbon-based polymer, whether thermoplastic or thermosetting.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1d80373a-5392-4950-8a9c-88b3b4f3c9b0', 'plate', 'A slightly curved but almost flat dish from which food is served or eaten.', 'I filled my plate from the bountiful table.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ca12b0c2-5116-4891-b76b-9dd7dfa243cb', 'platform', 'A raised stage from which speeches are made and on which musical and other performances are made.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7d23c7f1-a5ce-447c-a9fe-0b5017fa141c', 'pleased', 'To make happy or satisfy; to give pleasure to.', 'Her presentation pleased the executives.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('99ffdd10-36ed-41ba-8fd9-aee7d38e439f', 'pocket', 'A bag stitched to an item of clothing, used for carrying small items.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('29c8ed9a-47a0-4ffc-8954-a280941cc0af', 'polite', 'To polish; to refine; to render polite.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('36854d43-6835-428e-8fab-4967c257d831', 'pollution', 'The desecration of something holy or sacred; defilement, profanation.', '', 'Environment', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c6de2498-3519-4261-9742-1c546c7f2c84', 'pop', 'A loud, sharp sound as of a cork coming out of a bottle.', 'Listen to the pop of a champagne cork.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ca7bf1d3-70ff-4ec8-a193-8be7832c8a0c', 'population', 'The people living within a political or geographical boundary.', 'The population of New Jersey will not stand for this!', 'Society', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8bb535f6-c4f6-4a6e-b751-8903afb42ed8', 'position', 'A place or location.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('22d50a72-c108-475f-9112-e8d5d49a3513', 'possession', 'Control or occupancy of something for which one does not necessarily have private property rights.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f0971d76-02f9-47d0-b52e-63498c6777e2', 'possibility', 'The quality of being possible.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('21db336d-7962-4880-b528-9b42c57d59a6', 'poster', 'A picture of a celebrity, an event etc., intended to be attached to a wall.', 'He has posters of his favorite band, sports teams and holiday resorts up.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ce225e2e-d2a8-41f3-8ac5-6bf924e6b565', 'power', 'Ability to do or undergo something.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ce11d559-8fc6-470d-a486-0c3df2c7afae', 'predict', 'A prediction.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c3a24f7f-d72f-4b36-836d-60186ec19890', 'president', 'An act in the past which may be used as an example to help decide the outcome of similar instances in the future.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4dde9db1-8500-48ff-bfa4-9a12ebf16d64', 'prevent', 'To stop (an outcome); to keep from (doing something).', 'I brush my teeth regularly to prevent them from turning yellow.', 'Health', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d9ecb7c5-9996-43f2-b210-afd236dce136', 'print', 'Books and other material created by printing presses, considered collectively or as a medium.', 'TV and the internet haven''t killed print.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ed126b8e-d81c-48ff-b427-9025f32e2fb7', 'printer', 'One who makes prints.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('fc10c526-8ed9-4158-89d5-4adb42a44c4c', 'prison', 'A place or institution of confinement, especially of long-term confinement for those convicted of serious crimes or otherwise considered undesirable by the government.', 'The cold stone walls of the prison had stood for over a century.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e1882553-28d5-40d9-a950-0411a1b9a5d2', 'prize', 'That which is taken from another; something captured; a thing seized by force, stratagem, or superior power.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3d72cebd-857c-43a7-80be-5fd662d73678', 'process', 'A series of events which produce a result (the product).', 'This product of last month''s quality standards committee is quite good, even though the process was flawed.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('80f3667b-d6ae-477a-a581-46b9c116a874', 'produce', 'To yield, make or manufacture; to generate.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3b97934b-2508-413d-9013-973cc9e308ee', 'professional', 'A person who belongs to a profession', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ced9a0ce-7e9d-4b2d-af64-ba375c71c8f4', 'professor', 'The most senior rank for an academic at a university or similar institution, informally also known as "full professor." Abbreviated Prof.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('caeec6ca-e3bf-40e7-be09-558484260190', 'profile', 'The outermost shape, view, or edge of an object.', 'His fingers traced the profile of the handle.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('72365223-6c20-4a5f-a7a8-72c7bf10778e', 'program', 'A set of structured activities.', 'Our program for today’s exercise class includes swimming and jogging.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a262fbbe-49a8-43b9-ac89-ab53fb966876', 'progress', 'Movement or advancement through a series of events, or points in time; development through time.', 'Testing for the new antidote is currently in progress.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('eae7bf1f-ce2d-4bb7-9005-cad370a9efc7', 'promise', 'An oath or affirmation; a vow', 'if I make a promise, I always stick to it;  he broke his promise', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b4534cf2-47b2-4ebf-b186-426076b6e859', 'pronounce', 'To declare formally, officially or ceremoniously.', 'I hereby pronounce you man and wife.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('615081bb-9041-4a59-a661-871e0327ea9c', 'protect', 'To keep safe; to defend; to guard; to prevent harm coming to.', 'Condoms are designed to protect against sexually-transmitted diseases.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7e8c87f9-ff4d-4163-b7a5-aef8a2405da1', 'provide', 'To make a living; earn money for necessities.', 'It is difficult to provide for my family working on minimum wage.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('412b0085-8332-4c1d-a6b7-4e65f57badc3', 'pub', 'A public house where beverages, primarily alcoholic, may be bought and consumed, also providing food and sometimes entertainment such as live music or television.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d8b32a28-85db-447e-871b-fa5805772df2', 'public', 'The people in general, regardless of membership of any particular group.', 'Members of the public may not proceed beyond this point.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('25c9b414-5d69-4829-b89a-06efe268457d', 'publish', 'To issue (something, such as printed work) for distribution and/or sale.', 'Most of the sketches Faulkner published in 1925 appeared in the Sunday magazine section of the New Orleans Times-Picayune.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6b5720d4-3882-4edd-b949-7658914b7a45', 'pull', 'An act of pulling (applying force)', 'He gave the hair a sharp pull and it came out.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('55385866-b3d8-463e-91e3-c3660cdf3276', 'purpose', 'An objective to be reached; a target; an aim; a goal.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('12294748-20b5-4faf-bcab-aa245f4be7cf', 'push', 'A short, directed application of force; an act of pushing.', 'Give the door a hard push if it sticks.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('17268658-c557-413a-8038-8c9535aaccce', 'quality', 'Level of excellence.', 'Quality of life is usually determined by health, education, and income.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('602ca950-b96e-4c8a-aff7-94c0a5e2ae5a', 'quantity', 'A fundamental, generic term used when referring to the measurement (count, amount) of a scalar, vector, number of items or to some other way of denominating the value of a collection or group of items.', 'You have to choose between quantity and quality.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8c404a45-1451-4f11-a8e5-8427d48ede11', 'queen', 'A female monarch. Example: Queen Victoria.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('5120a93b-87d6-4cf1-98f8-7f5a76e036f6', 'quietly', 'In a quiet manner.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7abb3ef9-8a65-431f-98cf-3882dc74a29b', 'race', 'A contest between people, animals, vehicles, etc. where the goal is to be the first to reach some objective. Example: Several horses run in a horse race, and the first one to reach the finishing post wins', 'The race around the park was won by Johnny, who ran faster than the others.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('69ed5bcb-a84f-444c-acec-c22b8c36c83f', 'railway', 'A transport system using rails used to move passengers or goods.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b46f4e09-d195-498a-ace1-c8d7425be10d', 'raise', 'An increase in wages or salary; a rise (UK).', 'The boss gave me a raise.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('fa5c047c-ca29-4089-93bc-58e6f6308277', 'rate', 'The worth of something; value.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0307b1f5-3d25-4f6e-ac3a-c48e423f4f21', 'rather', 'To prefer; to prefer to.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('368fada9-79b8-4afd-b389-ec2e3d5b5589', 'reach', 'The act of stretching or extending; extension.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('717f1a06-f54f-4f2a-a28a-e8af16ac1eeb', 'react', 'An emoji used to express a reaction to a post on social media.', 'Sad reacts only', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b14bbfeb-9862-4ca8-85f7-181229c523e6', 'realize', 'To make real; to convert from the imaginary or fictitious into reality; to bring into real existence', 'The objectives of the project were never fully realized.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1cbeccf2-5b94-4be6-8095-0d77964fab94', 'receive', 'An operation in which data is received.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1a9bc1d9-6487-41f6-92da-7187f7cb1831', 'recent', 'Having happened a short while ago.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('461523d6-2745-4572-8b0e-1cd9d9575b5c', 'recently', 'In the recent past', 'a recently published book', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('5beee012-4432-4a65-ade1-08a9716144ec', 'reception', 'The act of receiving.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f01bba8a-96c0-44f5-8aec-444916bfe37c', 'bacteria', 'A type, species, or strain of bacterium.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4e45a7c9-eb1d-48ec-ae30-9674e40c4ed0', 'recipe', 'A formula for preparing or using a medicine; a prescription; also, a medicine prepared from such instructions.', '', 'Food', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c195bc4d-b1c1-4c0b-815a-b5aa8416bfac', 'recognize', 'To match (something or someone which one currently perceives) to a memory of some previous encounter with the same person or thing.', 'I recognised his face immediately.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('275ecf97-0be3-4ff4-a0fa-6923c7fa954e', 'recommend', 'To bestow commendation on; to represent favourably; to suggest, endorse or encourage as an appropriate choice.', 'The board recommends Philips, given his ample experience in similar positions.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('76115f20-e059-46e3-8b30-e1b9d0e9af69', 'record', 'A disk, usually made of a polymer, used to record sound for playback on a phonograph.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('93bf1782-a445-4c37-9990-59227b5d5381', 'recording', 'To make a record of information.', 'I wanted to record every detail of what happened, for the benefit of future generations.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('96277bc0-31b1-4b7d-9810-4747f00401b7', 'recycle', 'An act of recycling.', '', 'Environment', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('62e61069-6cc9-4a62-8adb-87b70407f398', 'reduce', 'To bring down the size, quantity, quality, value or intensity of something; to diminish, to lower.', 'to reduce weight, speed, heat, expenses, price, personnel etc.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('931bc8b1-0903-4543-b5c8-f6bd425fed2d', 'refer', 'To direct the attention of.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9e290d9c-0d1f-4809-9ebb-d3683515a42f', 'refuse', 'Collectively, items or material that have been discarded; rubbish, garbage.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b6d05f06-fa26-4c9b-b766-535dec3dc4ce', 'region', 'Any considerable and connected part of a space or surface; specifically, a tract of land or sea of considerable but indefinite extent; a country; a district; in a broad sense, a place without special reference to location or extent but viewed as an entity for geographical, social or cultural reasons.', 'the equatorial regions', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6c12a54c-6a6e-4e54-8913-1a1c4e988614', 'regular', 'A member of the British Army (as opposed to a member of the Territorial Army or Reserve).', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d8395970-4d66-4320-bc71-37013abfba87', 'relationship', 'Connection or association; the condition of being related.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4ee0f448-1a5b-43ba-9b0e-e97f727b7fea', 'remove', 'The act of removing something.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b9b8b0fc-295f-494c-bcff-7299eecded8c', 'repair', 'The act of repairing something.', 'I took the car to the workshop for repair.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('66b16f1f-1a64-466d-8922-add7046e395b', 'replace', 'To restore to a former place, position, condition, etc.; to put back', 'When you''ve finished using the telephone, please replace the handset.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d0fe6217-538f-4f1a-9163-04f37c142bd1', 'reply', 'A written or spoken response; part of a conversation.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ed0112f6-630c-4a20-80a5-b882319604e3', 'reporter', 'Someone or something that reports.', 'The reporters of important security bugs may be paid a bounty by the software developer.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('31e49d94-4cb8-4d1c-842e-df493e519490', 'request', 'Act of requesting (with the adposition at in the presence of possessives, and on in their absence).', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f3bb31b1-5b9e-4c68-bf8d-63ac59a1efb9', 'research', 'Diligent inquiry or examination to seek or revise facts, principles, theories, applications, etc.; laborious or continued search after truth.', 'The research station that houses Wang and his team is outside Lijiang, a city of about 1.2 million people.', 'Education', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('20aee280-96e1-4a4f-a85d-8e5efbe6e887', 'researcher', 'One who researches.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9efab9e7-f1a1-40ab-beb7-623d9e7bfce9', 'respond', 'A response.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d21c9ac4-8d2e-49d4-9299-017194797839', 'response', 'An answer or reply, or something in the nature of an answer or reply.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a71a99e9-40a2-449f-872f-f6de9f18971d', 'rest', '(of a person or animal) Relief from work or activity by sleeping; sleep.', 'I need to get a good rest tonight; I was up late last night.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('99b6fcc2-1084-4223-a865-c4724f94d0a7', 'review', 'A second or subsequent reading of a text or artifact in an attempt to gain new insights.', 'I need to make a review of the book before I can understand it.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7b8d10f0-2022-422f-beef-d0564f989ab0', 'ring', '(physical) A solid object in the shape of a circle.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ab3f545f-8cf8-47e2-9e7e-3c9bb3593f63', 'rise', 'To move, or appear to move, physically upwards relative to the ground.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b0ba68eb-a2ac-4c94-b97f-8873897c0b78', 'rock', 'A formation of minerals, specifically:', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ce8799fb-39b1-4eab-a9eb-dd5cf73a3f69', 'role', 'A character or part played by a performer or actor.', 'Her dream was to get a role in a Hollywood movie, no matter how small.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1129e816-3c83-4e2f-a55e-6b09aeb1755e', 'roof', 'The external covering at the top of a building.', 'The roof was blown off by the tornado.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('90892745-81f0-4310-a617-e876d6cfe23e', 'round', 'So as to form a circle or trace a circular path, or approximation thereof.', 'High above, vultures circled around.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6beab43c-82e1-4e4a-bcb8-25567d8383c0', 'route', 'A course or way which is traveled or passed.', 'The route was used so much that it formed a rut.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a6f8b269-42e1-47ce-8818-ea1149c8ecc9', 'rubbish', 'Refuse, waste, garbage, junk, trash.', 'The rubbish is collected every Thursday in Gloucester, but on Wednesdays in Cheltenham.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('079866ab-f764-408f-abea-e2bc84cd89ac', 'rude', 'Bad-mannered.', 'Karen broke up with Fred because he was often rude to her.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4ef125be-90cf-41fa-a577-9e035422bfd6', 'runner', 'Act or instance of running, of moving rapidly using the feet.', 'I just got back from my morning run.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ed2eb675-144c-414d-ac82-d442adca3a37', 'running', 'To move swiftly.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('58e7d71f-7543-40e3-aaab-4198822a5268', 'sadly', 'In a sad manner; sorrowfully.', '“Only when we climb up can we see it,” he said sadly.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('08b07b9b-e063-48ea-af12-5373ea76ddbd', 'safe', 'A box, usually made of metal, in which valuables can be locked for safekeeping.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6e1bc517-c9e2-43bd-9893-8daaa61b1311', 'sail', 'A piece of fabric attached to a boat and arranged such that it causes the wind to drive the boat along. The sail may be attached to the boat via a combination of mast, spars and ropes.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7fb85548-9a99-4814-a26c-e45a33b03c86', 'sailing', 'To be impelled or driven forward by the action of wind upon sails, as a ship on water; to be impelled on a body of water by steam or other power.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('17d234ef-cca2-43d7-b1a8-a415ff5e6502', 'salary', 'A fixed amount of money paid to a worker, usually calculated on a monthly or annual basis, not hourly, as wages. Implies a degree of professionalism and/or autonomy.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('cc6e9fb5-30cf-457c-8b29-7a4278e39731', 'sale', 'A hall.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4c9f5988-b54a-487e-8017-f1e3eab6a3be', 'sauce', 'A liquid (often thickened) condiment or accompaniment to food.', 'apple sauce; mint sauce', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8d50c521-b621-48fc-b498-aa7e13452c01', 'save', 'In various sports, a block that prevents an opponent from scoring.', 'The goaltender made a great save.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a723bd23-5410-43d4-bee9-9aa72a819ec1', 'scared', 'To frighten, terrify, startle, especially in a minor way.', 'Did it scare you when I said "Boo!"?', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('5774ff89-f307-4926-bfac-7906d0a7cbc0', 'scary', 'Causing or able to cause fright.', 'She was hiding behind her pillow during the scary parts of the film.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8ded12c0-219e-4a84-853d-a2288f0cb4a6', 'scene', 'The location of an event that attracts attention.', 'the scene of the crime', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0aec1f2c-42b1-4bea-927c-227058ff20ac', 'schedule', 'A slip of paper; a short note.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d20d8b0d-8eb6-415c-a0c0-bc3e8eef85f7', 'score', 'The total number of goals, points, runs, etc. earned by a participant in a game.', 'The player with the highest score is the winner.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('df8e7e6b-bc0c-4abd-97e9-e315e01e93d0', 'screen', 'A physical divider intended to block an area from view, or provide shelter from something dangerous.', 'a fire screen', 'Technology', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('024b67d6-0cab-436f-9cb1-6b004cc2a515', 'search', 'An attempt to find something.', 'With only five minutes until we were meant to leave, the search for the keys started in earnest.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b6b35097-f4a8-4060-b495-b13aecf2ba8c', 'season', 'Each of the four divisions of a year: spring, summer, autumn (fall) and winter', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('fb8cdffa-719c-461a-98e6-aea3be8c2b5a', 'seat', 'Something to be sat upon.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('5f06b964-9675-4a59-9a1b-6f52a42f0288', 'secondly', 'In the second place.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('908aeca6-821a-4225-95be-cc15141a2859', 'secret', 'A piece of knowledge that is hidden and intended to be kept hidden.', '"Can you keep a secret?" "Yes." "So can I."', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6c398d3f-7ae2-42df-b7ac-29b124d3e98c', 'secretary', 'Someone entrusted with a secret; a confidant.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('105bb37a-91de-4d51-b16f-bc453cc582ed', 'seem', 'To appear; to look outwardly; to be perceived as.', 'He seems to be ill.   Her eyes seem blue.   It seems like it is going to rain later.   How did she seem to you?', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4cd16925-2f6c-42a6-8563-3888117e95f4', 'sense', 'Any of the manners by which living beings perceive the physical world: for humans sight, smell, hearing, touch, taste.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('19904478-d053-4295-b0aa-f3976e87171b', 'separate', '(usually in the plural) Anything that is sold by itself, especially an article of clothing.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('fdc7dfe1-7a3d-4e3f-aee1-2334971e0c84', 'series', 'A number of things that follow on one after the other or are connected one after the other.', 'A series of seemingly inconsequential events led cumulatively to the fall of the company.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9aedd62a-9a60-40b7-a97e-020f105e5324', 'serious', 'Without humor or expression of happiness; grave in manner or disposition', 'It was a surprise to see the captain, who had always seemed so serious, laugh so heartily.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6ffb4ca3-419c-4651-af97-f697d2d38f2a', 'serve', 'An act of putting the ball or shuttlecock in play in various games.', 'Whose serve is it?', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('284c6473-2c51-4db6-824e-5ee923ba2f47', 'service', 'An act of being of assistance to someone.', 'I say I did him a service by ending our relationship – now he can freely pursue his career.', 'Business', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ff9143d7-ab0e-4cad-a74c-fd22d9f4ad11', 'several', 'An area of land in private ownership (as opposed to common land).', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0def96af-eccc-42b7-92c8-6f7689e678fc', 'shake', 'The act of shaking or being shaken; tremulous or back-and-forth motion.', 'She replied in the negative, with a shake of her head.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('866b5ba4-0f38-4117-948e-a892f95f77f0', 'shall', '(modal, auxiliary verb, defective) Used before a verb to indicate the simple future tense in the first person singular or plural.', 'I hope that we shall win the game.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('98b86326-b60b-4909-ad62-2f57a54156dc', 'shape', 'The status or condition of something', 'The used bookshop wouldn''t offer much due to the poor shape of the book.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('5532c5f4-0a51-4362-a07a-98962413ec59', 'sheet', 'A thin bed cloth used as a covering for a mattress or as a layer over the sleeper.', 'Use the sheets in the hall closet to make the bed.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1c0ac531-ec86-496e-8015-9ee13780cf9c', 'ship', 'A water-borne vessel generally larger than a boat.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('957ff1ff-fef5-4d83-a16c-053328188bf2', 'shout', 'A loud burst of voice or voices; a violent and sudden outcry, especially that of a multitude expressing joy, triumph, exultation, anger, or animated courage.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b180d3bf-1742-498e-990c-7d40dfeb3224', 'shut', 'Closed, shut.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f53397dc-7063-4dc3-ab5b-22e6d1190cb7', 'side', 'A bounding straight edge of a two-dimensional shape.', 'A square has four sides.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6b551c46-3249-4763-8690-621d93a34b13', 'sign', '(sometimes also used uncountably) A visible indication.', 'I gave them a thumbs-up sign.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ac0e713f-cdfe-4947-afb9-9c33ab29d332', 'silver', 'A lustrous, white, metallic element, atomic number 47, atomic weight 107.87, symbol Ag.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('57a1cfef-1db9-46f5-ad60-da5d6b542261', 'simple', 'A herbal preparation made from one plant, as opposed to something made from more than one plant.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8f57d9c8-6533-498e-950f-5da883cb010b', 'since', 'From a specified time in the past.', 'A short/long time since', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('266ee4d7-5d6e-44f6-a430-e2ea2f504ae2', 'singing', 'To produce musical or harmonious sounds with one’s voice.', '"I really want to sing in the school choir," said Vera.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d2ebabdb-3840-4c8b-a223-a449432efcbe', 'single', 'A 45 RPM vinyl record with one song on side A and one on side B.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('5ec3de74-cb76-4b12-b988-a02c66b772dc', 'sir', 'A man of a higher rank or position.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c69a24ac-b52b-4f12-a5e1-e37ddf45cf0a', 'site', 'Sorrow, grief.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7dfb784f-cbcc-46e6-b002-6b557be7deec', 'size', '(obsolete outside dialectal) An assize.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('aae20149-934f-40ff-a0a6-2b6b13dacbd7', 'ski', 'One of a pair of long flat runners designed for gliding over snow or water', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('80d63021-b09f-4c57-9e0f-ebb78b76a897', 'skiing', 'To move on skis', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a46c405b-1840-46d4-9654-2a140b013730', 'skin', 'The outer protective layer of the body of any animal, including of a human.', 'He is so disgusting he makes my skin crawl.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0f365420-24e5-4ef4-966e-4ada941c09dc', 'slowly', '(manner) At a slow pace.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d84d62b7-fd21-4656-80fc-4f33ac1d2cbd', 'smartphone', 'A mobile phone with more advanced features and greater computing capacity than a featurephone.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('de3b2a01-e7b8-4aba-8426-e7f74fd15065', 'smell', 'A sensation, pleasant or unpleasant, detected by inhaling air (or, the case of water-breathing animals, water) carrying airborne molecules of a substance.', 'I love the smell of fresh bread.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f420c422-7000-4880-b637-22c3960d7b5c', 'smile', 'A facial expression comprised by flexing the muscles of both ends of one''s mouth, often showing the front teeth, without vocalisation, and in humans is a common involuntary or voluntary expression of happiness, pleasure, amusement or anxiety.', 'He always puts a smile on my face.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6c9bb125-6110-420c-b29c-0eaf17e41cb5', 'smoke', 'The visible vapor/vapour, gases, and fine particles given off by burning or smoldering material.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('095375d3-1265-4ef0-8181-da16c3d30b55', 'smoking', 'To inhale and exhale the smoke from a burning cigarette, cigar, pipe, etc.', 'He''s smoking his pipe.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('194c2a8c-21e4-4c9f-ba9b-709bd42bd4df', 'soap', 'A substance able to mix with both oil and water, used for cleaning, often in the form of a solid bar or in liquid form, derived from fats or made synthetically.', 'I tried washing my hands with soap, but the stain wouldn''t go away.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f9213f5c-e168-4fb5-ae92-9ba655914629', 'soccer', 'Association football', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a74b9709-cbb9-4f4d-bf57-a4c96dcd91f4', 'social', 'A festive gathering to foster introductions.', 'They organized a social at the dance club to get people to know each other.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2c08351b-35f6-4aee-b6e8-1abebe096aaa', 'society', 'A long-standing group of people sharing cultural aspects such as language, dress, norms of behavior and artistic forms.', 'This society has been known for centuries for its colorful clothing and tight-knit family structure.', 'Society', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0eda4049-ad57-45fe-860c-1de6c8c6ed59', 'sock', 'A knitted or woven covering for the foot.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3f3e041b-2ec6-434e-a7a3-b6790069c0c3', 'soft', 'A soft or foolish person; an idiot.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('98c1fb2d-2dd0-4558-a661-976669219b9f', 'soldier', 'A member of an army, of any rank.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e2f13f19-570f-4d22-8854-dca054f29031', 'solution', 'A homogeneous mixture, which may be liquid, gas or solid, formed by dissolving one or more substances.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b065ad2a-b2e0-4ac1-969b-f9651fb2e5aa', 'solve', '(chiefly law enforcement) A solution; an explanation.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('62477750-c98b-4502-96f2-c6c15240063a', 'somewhere', 'Unspecified or unknown (unlocated) place or location.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7b855bf9-df74-4df1-8ebc-c286c5e91dc2', 'sort', 'A general type.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ac64b97e-ec19-41f0-af9f-8ce78dc381f5', 'source', 'The person, place or thing from which something (information, goods, etc.) comes or is acquired.', 'The accused refused to reveal the source of the illegal drugs she was selling.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7f9f6fc8-62da-42d5-9a01-a437abee6d7a', 'speaker', 'One who speaks.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a768286f-535d-497a-8ac7-af68bd958514', 'specific', 'A distinguishing attribute or quality.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('21cf8a98-ad3a-4b25-bfad-86092a6087d0', 'speech', 'The faculty of uttering articulate sounds or words; the ability to speak or to use vocalizations to communicate.', 'It was hard to hear the sounds of his speech over the noise. He had a bad speech impediment.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f0630fcb-254f-42a4-8251-a5e82862ecc5', 'speed', 'The state of moving quickly or the capacity for rapid motion; rapidity.', 'How does Usain Bolt run at that speed?', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('60b47974-f75c-4ea0-a4b2-9cd88841b0a3', 'spider', 'Any of various eight-legged, predatory arthropods, of the order Araneae, most of which spin webs to catch prey.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1eae507b-91e3-4a74-8781-9ab08d16e878', 'spoon', 'An implement for eating or serving; a scooped utensil whose long handle is straight, in contrast to a ladle.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a9b2033d-4c4a-4d30-8613-c610c7f955f1', 'square', 'A polygon with four sides of equal length and four right angles; an equilateral rectangle; a regular quadrilateral.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f0a5ad1b-e02d-4401-94ff-8772aa695bdc', 'stage', 'A phase.', 'Completion of an identifiable stage of maintenance such as removing an aircraft engine for repair or storage.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('fa5aa16a-eebc-47a5-ad6f-5536b9394a3f', 'stair', 'A single step in a staircase.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('681ab0ed-d563-4aad-a6df-d8eff6b83121', 'stamp', 'An act of stamping the foot, paw or hoof.', 'The horse gave two quick stamps and rose up on its hind legs.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('022c12b0-c93a-4ccd-98f0-cff4cf8b9ed2', 'state', 'A condition; a set of circumstances applying at any given time.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0486eab5-d9d3-4887-a802-ae8fbbe077e9', 'steal', 'The act of stealing.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9e01d569-2086-47c4-9473-588324abbe2a', 'step', 'An advance or movement made from one foot to the other; a pace.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('aea95cc3-a0a7-4879-81f6-0284a5fe4584', 'stomach', 'An organ in animals that stores food in the process of digestion.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('5ee79760-a5db-4950-be31-00f455513394', 'stone', 'A hard earthen substance that can form large rocks.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('519a91f9-84a2-4e43-9838-3c7b41d787ee', 'broadcaster', 'An organisation that engages in the activity of broadcasting.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b4d66e49-fdf3-4a20-8712-f964ce3dc508', 'store', 'A place where items may be accumulated or routinely kept.', 'This building used to be a store for old tires.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('02ac9402-de4e-4bac-a0d9-da66408b1d03', 'storm', 'Any disturbed state of the atmosphere, especially as affecting the earth''s surface, and strongly implying destructive or unpleasant weather.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('324377fb-0f5b-4548-a1f8-9a15333a7314', 'straight', 'Something that is not crooked or bent such as a part of a road or track.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8b2d4cc5-b9dd-495f-a043-a137a1867b6f', 'strange', 'Vagina', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7d64a66a-d751-426d-af70-3b3c941ff80b', 'strategy', 'The science and art of military command as applied to the overall planning and conduct of warfare.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('128f83f1-3d81-4228-bb19-a53d367784b4', 'stress', '(Cause of) discomfort.', '', 'Health', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e8136831-c4cd-46aa-898a-22780b1e29bd', 'structure', 'A cohesive whole built up of distinct parts.', 'The birds had built an amazing structure out of sticks and various discarded items.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('96a4ab34-fe80-4aca-9702-4fe3296cd07c', 'stupid', 'A stupid person; a fool.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('749d745e-3449-4674-90c9-5c22cd28b0ef', 'succeed', 'To follow in order; to come next after; hence, to take the place of.', 'Autumn succeeds summer.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c6fa9355-3a44-4e86-96a6-ec08d83af357', 'successful', 'Resulting in success; assuring, or promoting, success; accomplishing what was proposed; having the desired effect', 'a successful use of medicine;  a successful experiment;  a successful enterprise', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a8af703c-ea7e-429a-a594-ccb769f556f5', 'such', 'Something being indicated that is similar to something else.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8517702d-a1c8-4f06-8cc0-3609af6406d7', 'suddenly', 'Happening quickly and with little or no warning; in a sudden manner.', 'Suddenly, the heavens opened and we all got drenched.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b863eb91-0744-4fab-8d9b-c07fa97db9b2', 'suggest', 'To imply but stop short of saying explicitly.', 'Are you suggesting that I killed my wife?', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4767e5d8-2f05-4697-bd0e-cb9577161d0d', 'suggestion', 'Something suggested (with subsequent adposition being for)', 'I have a small suggestion for fixing this: try lifting the left side up a bit.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('71cc44c1-fe7e-43c0-83df-3c4f6a14c55f', 'suit', 'A set of clothes to be worn together, now especially a man''s matching jacket and trousers (also business suit or lounge suit), or a similar outfit for a woman.', 'Nick hired a navy-blue suit for the wedding.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('96538d86-3e79-4ac0-ac64-c93e46ee353c', 'support', '(sometimes attributive) Something which supports.', 'Don''t move that beam! It''s a support for the whole platform.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('cd74f5a7-0e89-4340-880a-25b5edd37823', 'suppose', 'To take for granted; to conclude, with less than absolute supporting data; to believe.', 'Suppose that A implies B and B implies C. Then A implies C.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d632a142-1cb8-4c2b-9f32-b64f464896e8', 'surprise', 'Something unexpected.', 'It was a surprise to find out I owed twice as much as I thought I did.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('04ba0430-08bd-48bf-8619-c9132654f380', 'surprised', 'To cause (someone) to feel unusually alarmed or delighted by something unexpected.', 'It surprises me that I owe twice as much as I thought I did.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('de0a37f9-c271-4b33-9df2-91a9a0081640', 'surprising', 'To cause (someone) to feel unusually alarmed or delighted by something unexpected.', 'It surprises me that I owe twice as much as I thought I did.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1768a80b-7ad9-46a4-9dbf-c81def99acf9', 'survey', 'The act of surveying; a general view.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ef8bebde-2f5c-4acf-a845-3461f58b3461', 'sweet', 'The basic taste sensation induced by sugar.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('afff0f70-2e7e-488c-8b6f-9f8290bbef71', 'symbol', 'A character or glyph representing an idea, concept or object.', '$ is the symbol for dollars in the US and some other countries.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('55979461-e276-40c3-ac56-ba119884290f', 'system', 'A collection of organized things; a whole composed of relationships among its members.', 'There are eight planets in the solar system.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('dd2d9808-14a7-4568-bde8-faee23d491a5', 'tablet', 'A slab of clay used for inscription.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('be1151ac-ac9c-4f10-88be-00d591b71f32', 'target', 'A butt or mark to shoot at, as for practice, or to test the accuracy of a firearm, or the force of a projectile.', 'Take careful aim at the target.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('97e019ed-f185-4df7-b8da-b146c44ceca2', 'task', 'A piece of work done as part of one’s duties.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('648f484b-e0d0-4c67-b7a6-233c2fd0253f', 'taste', 'One of the sensations produced by the tongue in response to certain chemicals; the quality of giving this sensation.', 'He had a strange taste in his mouth.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('371ef781-7145-488d-a846-13e68e81c351', 'teaching', 'Something taught by a religious or philosophical authority.', 'Many follow the teachings of Confucius.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9fa419cf-c355-48de-99fc-d9da98be9751', 'technology', 'The organization of knowledge for practical purposes.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('37c28175-aeaa-4131-b1ab-62758f09360d', 'teenage', 'Brushwood for fences and hedges.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3d5d6f98-0727-4f7f-bae6-8f4a6999611b', 'temperature', 'A measure of cold or heat, often measurable with a thermometer.', 'The temperature in the room dropped nearly 20 degrees; it went from hot to cold.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('31e0a9d8-8111-448e-8138-02ca25ea7c55', 'term', 'That which limits the extent of anything; limit, extremity, bound, boundary.', '"Alright, look...we can spend the holidays with your parents, but this time it will be on my terms."', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ec19ef52-03cc-4e2f-addb-e9b69ee3067c', 'themselves', 'The reflexive case of they, the third-person plural personal pronoun. The group of people, animals or objects previously mentioned, as the object of a verb or following a preposition (also used for emphasis).', 'They are going to try climbing Mount Everest themselves.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9e114f83-2ac1-43ff-b71f-c272a9fc9bd7', 'thick', 'The thickest, or most active or intense, part of something.', 'It was mayhem in the thick of battle.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('5a86154d-66bd-4e71-bb3d-ea9111b7b4a9', 'thief', 'One who carries out a theft.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0e01434a-7c1d-4bda-8317-4d245ed4054f', 'broadly', 'Widely and openly.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a3ae012e-754e-4215-8f09-7c6b7ad272b7', 'thin', 'A loss or tearing of paper from the back of a stamp, although not sufficient to create a complete hole.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4c8bf38a-bb8a-4a7e-9cc0-9e5619f07232', 'thinking', 'Thought; gerund of think.', 'What is your thinking on this subject?', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('342d988e-28b7-4113-a773-40b927b460c6', 'thought', 'To ponder, to go over in one''s head.', 'Idly, the detective thought what his next move should be.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('5b133e3b-7238-467c-b29f-6d58ddced2f9', 'throw', 'To change place.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e42fce34-78a0-4794-b4fe-4ceae3eaba90', 'tidy', 'A tabletop container for pens and stationery.', 'a desk tidy', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('09a9d452-dee7-4cd1-b07b-f2811e2a73b2', 'tie', 'A knot; a fastening.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('afe3e11c-c2c5-47ed-801c-e98e601951c0', 'tip', 'The tip of the external ear.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b8df0846-0115-4f95-8055-7ca754a71534', 'tool', 'A mechanical device intended to make a task easier.', 'Hand me that tool, would you?   I don''t have the right tools to start fiddling around with the engine.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7c2df60d-9c4c-430e-8c24-2fc6cf12b08a', 'top', 'The highest or uppermost part of something.', 'His kite got caught at the top of the tree.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1b21da3c-acc4-436a-8212-ee10df4132ea', 'tour', 'A journey through a particular building, estate, country, etc.', 'On our last holiday to Spain we took a tour of the wine-growing regions.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9a6a49c0-c82c-4bd3-8c68-550eb229b705', 'tourism', 'The act of travelling or sightseeing, particularly away from one''s home.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('783b4284-1fd2-4f3b-9409-419c3556389e', 'towards', 'In the direction of.', 'She moved toward the door.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('83dcaae4-9335-4e7a-8fc6-5c58a5ee368d', 'towel', 'A cloth used for wiping, especially one used for drying anything wet, as a person after a bath.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ad32d0e1-3e8a-46c6-968c-e6d9e16b57eb', 'tower', 'A very tall iron-framed structure, usually painted red and white, on which microwave, radio, satellite, or other communication antennas are installed; mast.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('aa812b7d-e633-4a6c-ac55-aa6989b88560', 'toy', 'Something to play with, especially as intended for use by a child.', 'A grown man does not play with a child’s toy.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4dc69571-6f5d-4213-af84-f80617b5cc9c', 'track', 'A mark left by something that has passed along.', 'Can you see any tracks in the snow?', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0b0ba32b-561f-4af2-ab95-a008b6f47a59', 'tradition', 'A part of culture that is passed from person to person or generation to generation, possibly differing in detail from family to family, such as the way to celebrate holidays.', '', 'Society', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9c0c3ea7-a0d1-44de-a8f2-cc552c7e3625', 'traditional', 'A person with traditional beliefs.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('05d4b78f-df3c-4136-af08-fda540132e72', 'trainer', 'A person who trains another; a coach.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b8e6b9e8-2bc2-4393-8144-170efc995c52', 'training', 'To practice an ability.', 'She trained seven hours a day to prepare for the Olympics.', 'Education', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('75ad1d1b-e017-4209-be38-0babbc89180c', 'transport', 'An act of transporting; conveyance.', 'The transport of goods is not included in the price given on the website.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('164efe22-f709-4a4d-8892-42e4259e6ef7', 'traveller', 'A member of a particular nomadic ethnic minority in Ireland, the Pavee.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9d3567c2-646f-49bf-811a-8a71e6b337c5', 'trouble', 'A distressing or dangerous situation.', 'He was in trouble when the rain started.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c7a4820b-113d-4add-8751-f1dd72358742', 'truck', 'A small wheel or roller, specifically the wheel of a gun carriage.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6cfd1f18-11d7-4d24-8fb6-8e7672c7505c', 'twin', 'Either of two people (or, less commonly, animals) who shared the same uterus at the same time; one who was born at the same birth as a sibling.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3f450cea-8111-41d9-8ce3-784c30233233', 'typical', 'Anything that is typical, normal, or standard.', 'Among the moths, typicals were more common than melanics.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('297bb24c-b473-41d0-ad89-016ea917c9cc', 'underground', 'An underground railway, especially for mass transit of people in urban areas.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ca7a961c-342f-400d-803a-e77985cb5363', 'understanding', 'To grasp a concept fully and thoroughly, especially (of words, statements, art, etc.) to be aware of the meaning of and (of people) to be aware of the intent of.', 'I''m sorry. I don''t understand.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9aa2b86b-997a-49f0-a4e4-3e802019985b', 'unfortunately', 'Happening through bad luck, or because of some unfortunate event.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('617bde53-ba13-4494-805f-3325a2522bbf', 'unhappy', 'An individual who is not happy.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('5ae18998-9724-4043-9ec1-c0767900bd10', 'uniform', 'A distinctive outfit that serves to identify members of a group.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2718445e-620d-41b4-b9d4-cf449a75dd9b', 'unit', 'A particular, minute unit of mass, defined differently for different substances, but so that varying substances of the same general type have the property that one international unit of the one has the same effect on the human body as one international unit of the other.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c5690e5d-e14f-4a12-b54c-1bf712aaf8da', 'united', 'To bring together as one.', 'I hope this song can unite people from all different cultures.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('cbefdfce-b78a-4d0b-a334-59a461d6616c', 'unusual', 'Something that is unusual; an anomaly.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9db6d0a9-8a5f-4c9f-8272-c7dc9cf1db57', 'user', 'One who uses or makes use of something, a consumer/client or an express or implied licensee (free user) or a trespasser.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8c91822e-3af9-48a9-ae61-21a067e444c3', 'usual', 'The typical state of something, or something that is typical.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('fd55785c-ece2-45b8-a195-e0420d1d686d', 'valley', 'An elongated depression between hills or mountains, often with a river flowing through it.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8c77d0f9-0f0c-423a-9041-103b87b4da34', 'van', 'A covered vehicle used for carrying goods or people, usually roughly cuboid in shape, longer and higher than a car but smaller than a truck/lorry.', 'The van sped down the road.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('968129dd-8388-4789-9c58-bd5c065f3c8d', 'variety', 'The quality of being varied; diversity.', 'Variety is the spice of life.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('518ee923-369c-44cd-bbee-08d1616dd3c6', 'vehicle', 'A conveyance; a device for carrying or transporting substances, objects or individuals.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('89ec35f3-52b9-4649-a86a-b30e1754ed7a', 'view', '(physical) Visual perception.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8a65c09f-bf71-4482-b4c8-24331c5de8e5', 'virus', 'A submicroscopic, non-cellular structure consisting of a core of DNA or RNA surrounded by a protein coat, that requires a living host cell to replicate, and often causes disease in the host organism.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('5cdf10b4-65fc-41be-931e-122b4802620f', 'voice', 'Sound uttered by the mouth, especially by human beings in speech or song; sound thus uttered considered as possessing some special quality or character', 'His low voice allowed him to become a bass in the choir.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4fcb6059-c9c6-4434-afd7-6b9ed112bdb4', 'war', 'Organized, large-scale, armed conflict between countries or between national, ethnic, or other sizeable groups, usually involving the engagement of military forces.', 'The war was largely between Sunni and Shia militants.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('45c6080a-ba47-4cbd-9be1-726bc197c479', 'washing', 'To clean with water.', 'Dishwashers wash dishes much more efficiently than most humans.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8b42b08c-925b-4c17-af23-2efc07baab82', 'wave', 'To move back and forth repeatedly and somewhat loosely.', 'The flag waved in the gentle breeze.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9772e0dc-e95a-40aa-9670-f3a969038abe', 'weak', 'Lacking in force (usually strength) or ability.', 'The child was too weak to move the boulder.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('18eb2d04-d6b3-4cd9-99fe-9db5b38a8c19', 'web', 'The World Wide Web.', 'Some of that content is now only available on the Web.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c47bafbc-00be-4a85-9b8e-cb4bf677b999', 'wedding', 'To perform the marriage ceremony for; to join in matrimony.', 'The priest wed the couple.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('81ad9b34-54dd-4c70-a2d3-f73c3467f744', 'weight', '(physical) Matter, material.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('635b28f5-172c-48b4-bfde-a217880cb22e', 'wet', 'Liquid or moisture.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4ceded5c-f022-4cf6-8d5b-bc754fddc30f', 'wheel', 'A circular device capable of rotating on its axis, facilitating movement or transportation or performing labour in machines.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8f7c6d98-41e1-4ad3-be34-41fa2de58ba3', 'while', 'An uncertain duration of time, a period of time.', 'He lectured for quite a long while.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1e497d17-b4cf-454b-a471-0cf3e1b1e2ce', 'whole', 'Something complete, without any parts missing.', 'This variety of fascinating details didn''t fall together into an enjoyable, coherent whole.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7e49e0e7-5e2f-43c5-b8f2-2f865bafa8f9', 'whose', '(interrogative) That or those of whom or belonging to whom.', 'Several people have lost their suitcases. Whose have you found?', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('acb6d8d6-05eb-49c7-a594-20334fe69eeb', 'wide', 'A ball that passes so far from the batsman that the umpire deems it unplayable; the arm signal used by an umpire to signal a wide; the extra run added to the batting side''s score', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3cb0fee5-9f35-4651-a4a3-3b4a3e7a1aa6', 'wild', 'The undomesticated state of a wild animal', 'After mending the lion''s leg, we returned him to the wild.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3c2f3820-6b8c-4fb1-b19d-05f3679e178c', 'winner', 'One who has won or often wins.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0ce554fd-77ec-49e7-a651-a616547091e4', 'wish', 'A desire, hope, or longing for something or for something to happen.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('901fcf37-f845-4a37-b131-4346ffaefb19', 'wood', 'The substance making up the central part of the trunk and branches of a tree. Used as a material for construction, to manufacture various items, etc. or as fuel.', 'There was lots of wood on the beach.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('48f1cbc0-4c7f-4eca-a69d-62f10014597e', 'wooden', 'Made of wood.', 'On a recent windy day, hundreds of visitors climbed wooden stairs to take pictures in front of the glacier.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('08acb6c1-d324-469d-9ee4-96fecdce44a3', 'working', '(usually in the plural) Operation; action.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('17fec113-b500-4222-9caf-1d71664f9efb', 'worried', 'Thinking about unpleasant things that have happened or that might happen; feeling afraid and unhappy.', 'She was worried about her son who had been sent off to fight in the war.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d5b66ced-1b17-48a0-ac30-d313aa8ccf4c', 'worry', 'A strong feeling of anxiety.', 'I''m afflicted by worry throughout the night.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1e909261-444c-47aa-8416-25011cf5c4b9', 'worse', 'Unfavorable; negative; not good.', 'Abducting children is bad for mothers.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8128d60c-94a7-43a5-a349-3e39e1d3fb4a', 'worst', 'Unfavorable; negative; not good.', 'Abducting children is bad for mothers.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ca3465ab-52eb-48a6-9615-bd67a393860a', 'wow', 'Anything exceptionally surprising, unbelievable, outstanding, etc.', 'He did? That''s a wow!', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8585d68a-ed5f-45e0-879d-e30d9f1ba375', 'yet', '(usually with negative) Thus far; up to the present; up to some specified time; still', 'He has never yet been late for an appointment;   I’m not yet wise enough to answer that;   Have you finished yet?', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b1abae42-bb89-43e9-91af-a9b3c461130c', 'yours', 'That which belongs to you (singular); the possessive second-person singular pronoun used without a following noun.', 'If this edit is mine, the other must be yours.  Their encyclopedia is good, but yours is even better.  It’s all yours.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8bf0e5af-f571-49dd-87d2-e5ed588e675c', 'zero', 'The numeric symbol that represents the cardinal number zero.', 'In unary and k-adic notation in general, zero is the empty string.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('efc784d0-3215-4cb2-a812-1e9cf9c291e3', 'apparently', 'Plainly; clearly; manifestly; evidently.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2d1c7af9-276c-4c9d-9da3-2dafa24b491c', 'aspect', 'Any specific feature, part, or element of something.', 'Japan''s aging population is an important aspect of its economy.', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6b391ffc-dcdd-4342-9bda-12d9fd3435ea', 'bloomers', 'An ironworker.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('78f8a86f-7965-4dc1-8ed7-2ec2d33a8eec', 'commons', 'Mutual good, shared by more than one.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('78d90324-bd06-4f0d-a73e-5de120e7b403', 'ballpark', 'A field, stadium or park where ball, especially baseball, is played.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3d73d395-1143-4365-b454-a2ae20ccc7fb', 'contact', 'The act of touching physically; being in close association.', '', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ba06792b-c3bd-4f93-ae7a-1d451c933877', 'accustomed', '(of a person) Familiar with something through repeated experience; adapted to existing conditions.', 'accustomed to cold', 'General', 'A2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1991bcfb-fbdc-4581-bdc2-aae416e1c02a', 'industrial', '(19th-mid 20th century) An employee in industry.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('669e3c00-235c-4f41-a3ff-0a3f7f1666c9', 'absolutely', 'In an absolute or unconditional manner; utterly, positively, wholly.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('fca3c0a6-ed84-45d5-8f0c-4db7d8fc4b1b', 'academic', '(usually capitalized) A follower of Plato, a Platonist.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9ccfbcfd-ebee-4860-97e8-22bf9a5d4660', 'access', 'A way or means of approaching or entering; an entrance; a passage.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d0747009-b326-4a94-8571-46aef6d60f29', 'accommodation', '(usually a mass noun) Lodging in a dwelling or similar living quarters afforded to travellers in hotels or on cruise ships, or prisoners, etc.', '', 'Travel', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('79d08ace-3600-4613-8f2f-2d6848bc09af', 'account', 'A registry of pecuniary transactions; a written or printed statement of business dealings or debts and credits, and also of other things subjected to a reckoning or review.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('cad5a24e-315b-4c3a-9d12-148fd63f7d35', 'achievement', 'The act of achieving or performing; a successful performance; accomplishment', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0ba20502-88c3-4023-aada-4fd97e21f438', 'ad', 'Advertisement.', 'I have placed both of the ads in the newspaper as instructed.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e5647042-c352-4ebd-a897-5b8b3a772478', 'addition', 'The act of adding anything.', 'The addition of five more items to the agenda will make the meeting unbearably long.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ca195878-99b8-4d84-b0ce-e91e6e8d6ac9', 'admire', 'To be amazed at; to view with surprise; to marvel at.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9f9d7294-6e44-4c46-9354-4b9dd37e7170', 'admit', 'To allow to enter; to grant entrance (to), whether into a place, into the mind, or into consideration', 'A ticket admits one into a playhouse.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0bf29c24-ed5f-422b-9774-975a077659f1', 'advanced', 'To promote or advantage.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0a5fa51c-e379-4e0a-a563-6edc8f9cb51f', 'advise', 'To give advice to; to offer an opinion to, as worthy or expedient to be followed.', 'The dentist advised me to brush three times a day.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8799b3c9-74b8-4bf4-aa79-57b6322d7a1b', 'afford', 'To incur, stand, or bear without serious detriment, as an act which might under other circumstances be injurious;—with an auxiliary, as can, could, might, etc.; to be able or rich enough.', 'I think we can afford the extra hour it will take.  We can only afford to buy a small car at the moment.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('61813ab4-0205-4dbf-9113-83e181edc9e6', 'aged', 'To cause to grow old; to impart the characteristics of age to.', 'Grief ages us.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7768934b-b2e6-47e4-96ea-971b9a155503', 'agent', 'One who exerts power, or has the power to act', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7111ce4b-5003-401f-87d2-4e79e5cc9dab', 'agreement', 'An understanding between entities to follow a specific course of conduct.', 'to enter an agreement;  the UK and US negotiators nearing agreement;  he nodded his agreement.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6f8ba349-ad84-4a3e-9239-232e59bc26f8', 'ahead', 'In or to the front; in advance; onward.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('51d3fc32-4057-4284-9b7c-0cba2ffb114e', 'aim', 'The pointing of a weapon, as a gun, a dart, or an arrow, or object, in the line of direction with the object intended to be struck; the line of fire; the direction of anything, such as a spear, a blow, a discourse, a remark, towards a particular point or object, with a view to strike or affect it.', 'Take time with the aim of your gun.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e832f033-5e1e-4575-a5ca-cd74721a2dd5', 'alarm', 'A summons to arms, as on the approach of an enemy.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('664758f6-8dbb-441a-8c2f-7729bdea189b', 'album', 'A book specially designed to keep photographs, stamps, or autographs.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ae925318-d57e-46ee-adb9-1c6f2716e02b', 'alcohol', 'Any of a class of organic compounds (such as ethanol) containing a hydroxyl functional group (-OH).', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e8b688c4-b7f2-40d7-8723-d12a25955c33', 'alcoholic', 'A person addicted to alcohol.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f5fa506b-14db-4bc7-84b1-cbc31231dd36', 'amazed', 'To fill with wonder and surprise; to astonish, astound, surprise or perplex.', 'He was amazed when he found that the girl was a robot.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e5deaa61-e574-4e1f-a77b-41d5190ff532', 'ambition', 'Eager or inordinate desire for some object that confers distinction, as preferment, honor, superiority, political power, or literary fame; desire to distinguish one''s self from other people.', 'My son, John, wants to be a firefighter very much. He has a lot of ambition.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('260a2f5e-1315-41da-aec8-78dd650e49ab', 'ambitious', '(of a person or their character) Having or showing ambition; wanting a lot of power, honor, respect, superiority, or other distinction.', 'an ambitious person', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4adeb4d7-4cd6-4f6b-a894-a197569dc9cd', 'analyse', 'To subject to analysis.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6e193ef3-d0e2-43dc-8bd0-860e3917a736', 'analysis', 'Decomposition into components in order to study (a complex thing, concept, theory etc.).', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2ff66593-792d-405b-adad-ad96773177b3', 'announce', 'To give public notice, especially for the first time; to make known', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('61e008bf-947f-43b0-adaa-f1611b09ac9d', 'announcement', 'An act of announcing, or giving notice.', 'He raised his hand to make his announcement and said "Excuse me everyone, I have an announcement to make.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('536563af-adae-48f6-8047-ff764ffded9e', 'annoy', 'A feeling of discomfort or vexation caused by what one dislikes.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c9da0086-b201-4e69-97df-d563c44ad201', 'annoyed', 'To disturb or irritate, especially by continued or repeated acts; to bother with unpleasant deeds.', 'Marc loved his sister, but when she annoyed him he wanted to switch her off.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('fa18cf30-8ddf-436d-a3a6-f5e3d8232520', 'annoying', 'To disturb or irritate, especially by continued or repeated acts; to bother with unpleasant deeds.', 'Marc loved his sister, but when she annoyed him he wanted to switch her off.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0bad73ce-b19a-4c28-98e2-3f55ccef0291', 'apart', '(Used after a noun or in the predicate) Exceptional, distinct.', 'a world apart', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('26058c18-e7fd-4023-8d01-d44863ede1e0', 'apologize', '(often followed by “for”) To make an apology or excuse; to acknowledge some fault or offense, with expression of regret for it, by way of amends', 'My correspondent apologized for not answering my letter.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('cf90dba0-34ad-41b1-9f44-71d4da5920d2', 'application', 'The act of applying or laying on, in a literal sense', 'The application of this cream should reduce the swelling.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('54ed0b82-f380-4b5f-821a-8d60beb7cf97', 'appointment', 'The act of appointing a person to hold an office or to have a position of trust', 'His appointment was deemed suitable', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c2f1546e-6492-4faf-a70f-1ee18bc18c65', 'appreciate', 'To be grateful or thankful for.', 'I appreciate your efforts', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0303c236-7d62-44e6-b703-05426a9561d4', 'approximately', 'Imprecise but close to in quantity or amount.', '...approximately 60 beats per minute.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f820134c-b51d-4411-9e2e-f5140df9af3a', 'arrest', 'A check, stop, an act or instance of arresting something.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('919dd53d-a120-4abd-84a4-2f147fa32bc4', 'arrival', 'The act of arriving or something that has arrived.', 'The early arrival of the bride created a stir.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('932cbb5c-b16b-411a-acde-5c82ef6eb8b5', 'assignment', 'The act of assigning; the allocation of a job or a set of tasks.', 'This flow chart represents the assignment of tasks in our committee.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('60f0c378-0b09-43d0-901d-9ac22990204c', 'assist', 'A helpful action or an act of giving.', 'The foundation gave a much needed assist to the shelter.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c32e1337-bec8-497b-b153-a285876d8cb4', 'atmosphere', 'The gases surrounding the Earth or any astronomical body.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('fa68a7c1-de9e-4cf9-8039-8b043be7d9cf', 'attach', 'To fasten, to join to (literally and figuratively).', 'An officer is attached to a certain regiment, company, or ship.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('40f6d676-8db2-463e-8efb-5d4c703731ea', 'attitude', 'The position of the body or way of carrying oneself.', 'The ballet dancer walked with a graceful attitude.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('58630516-9f7d-4c8b-88c3-fe786e57e70e', 'attract', 'To pull toward without touching.', 'A magnet attracts iron filings.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0c253377-18be-4b0d-a137-0cce4db99298', 'attraction', 'The tendency to attract.', 'The Moon is held in its orbit by the attraction of the Earth''s gravity.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('733a837b-5c32-4d38-94fb-08a604202922', 'authority', 'The power to enforce rules or give orders.', 'I have the authority to penalise the staff in my department, but not the authority to sack them.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('58515617-259d-4b33-aab1-be1a4a8c40dc', 'aware', 'Vigilant or on one''s guard against danger or difficulty.', 'Stay aware! Don''t let your guard down.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ba83f3ca-654e-4f5f-85e7-d91b539066d5', 'backwards', 'Oriented toward the back.', 'The battleship had three backwards guns at the stern, in addition to the primary complement.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ac61be01-ff7e-46be-8be7-690b5f2a1bf1', 'bake', 'The act of cooking food by baking.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b52e46c5-8997-4303-9c07-d51837aef384', 'balance', 'A state in which opposing forces harmonise; equilibrium.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('cef4bb6b-4768-4f9f-828e-fa358f32dd2c', 'ban', 'Prohibition.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('5fed2f1f-55cf-46fe-add8-ba7a7834dd6e', 'base', 'Something from which other things extend; a foundation.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('101309c7-7549-42c6-9bd1-9833f948c985', 'basic', 'A necessary commodity, a staple requirement.', 'Rice is a basic for many Asian villagers.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('120c333c-a773-4ffb-9312-486a35c052b0', 'basis', 'A physical base or foundation.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2360d7b7-4f83-4615-8371-00bac5429ad3', 'battery', 'A device used to power electric devices, consisting of a set of electrically connected electrochemical or, archaically, electrostatic cells. A single such cell when used by itself.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8d8b576c-1278-469f-ad44-f465ed519c74', 'battle', 'A contest, a struggle.', 'the battle of life', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d7358c59-e73c-4784-b1c0-1a002f19e2ac', 'beauty', 'The quality of being (especially visually) attractive, pleasing, fine or good-looking; comeliness.', '1988, "… beauty and recollection, like danger, glamour, greed, hunger- everything but disappointment and desire- were concepts belonging to other people.” -Second Son, Robert Ferro', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1b25da35-2be6-44be-8254-c1a2d730b24a', 'bee', 'A flying insect, of the clade Anthophila within the hymenopteran superfamily Apoidea, known for its organised societies (though only a minority have them), for collecting pollen and (in some species) producing wax and honey.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('63f52ba7-a544-486d-9b0b-102dccfa1877', 'belief', 'Mental acceptance of a claim as true.', 'It''s my belief that the thief is somebody known to us.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('625e5ac4-d04e-485f-a607-67b747ff27bb', 'bell', 'A percussive instrument made of metal or other hard material, typically but not always in the shape of an inverted cup with a flared rim, which resonates when struck.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('68753621-9083-4a62-95ef-c6ecedd63ff8', 'bend', 'A curve.', 'There''s a sharp bend in the road ahead.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('aad590d9-8d2f-4714-8d36-a65579847258', 'bite', 'The act of biting.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8f802f5b-8087-4ea3-8908-a8a1a034e7f1', 'block', 'A substantial, often approximately cuboid, piece of any substance.', 'a block of ice', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('03bbebd2-6a2d-4aa7-b652-cec052ce2806', 'bomb', 'An explosive device used or intended as a weapon.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e26358a2-b236-45ea-93fe-1587e505d2bb', 'border', 'The outer edge of something.', 'the borders of the garden', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8e0bd5e3-9e22-4cae-95c2-43f0030a58aa', 'bother', 'Fuss, ado.', 'There was a bit of bother at the hairdresser''s when they couldn''t find my appointment in the book.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f611c7fd-e210-4961-8f64-284b72e06496', 'branch', 'The woody part of a tree arising from the trunk and usually dividing.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e619f009-9509-40f6-bbfe-3edc2293378d', 'brand', 'A conflagration; a flame.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c0228e57-27d4-41b1-b4e7-8540c7cc7073', 'brave', 'A Native American warrior.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('92a4ee6e-20dd-4638-bdec-7df8c33ceeff', 'breath', 'The act or process of breathing.', 'I could hear the breath of the runner behind me.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('cec8a99c-deb6-4199-9a20-2f601a8e2c8b', 'combine', 'A combine harvester', 'We can''t finish harvesting because our combine is stuck in the mud.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('73d3c7ee-bac6-4bf2-a653-1156c04036ab', 'breathe', 'To draw air into (inhale), and expel air from (exhale), the lungs in order to extract oxygen and excrete waste gases.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('643a0e21-57db-47e9-8d92-6fc8de16ad3d', 'breathing', 'To draw air into (inhale), and expel air from (exhale), the lungs in order to extract oxygen and excrete waste gases.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6150d759-1d1d-47aa-80c0-453e7a47a0e1', 'bride', 'A woman in the context of her own wedding; one who is going to marry or has just been married.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8dc195b5-683c-423a-a854-3346ec04e049', 'bubble', 'A spherically contained volume of air or other gas, especially one made from soapy liquid.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('81d1ea31-0f9e-4eaf-b606-b8c3b3496305', 'bury', 'A burrow.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0e61e272-1eeb-4fc1-91d8-0d14d4349b70', 'calm', '(in a person) The state of being calm; peacefulness; absence of worry, anger, fear or other strong negative emotion.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('12be3589-478b-47e2-9c31-bbf61b4ec22c', 'campaign', 'A series of operations undertaken to achieve a set goal.', 'The company is targeting children in their latest advertising campaign.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('dddc54b6-e31d-4711-adc6-df22804051e4', 'campus', 'The grounds or property of a school, college, university, business, church, or hospital, often understood to include buildings and other structures.', 'The campus is sixty hectares in size.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c078f134-ab6c-4e72-95de-583b393da7e9', 'candidate', 'A person who is running in an election.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('79d08e1d-c171-4d41-9250-ecc75daa658e', 'cap', 'A close-fitting hat, either brimless or peaked.', 'The children were all wearing caps to protect them from the sun.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8102fd3f-5791-4edd-806c-5c4cce2eae2e', 'captain', 'A chief or leader.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('cf6580a5-f790-4767-8a6a-409a68f2780f', 'careless', 'Not concerned or worried (about).', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1ef73acd-98cf-4083-b1d6-d124777b8f7d', 'category', 'A group, often named or numbered, to which items are assigned based on similarity or defined criteria.', 'I wouldn''t put this book in the same category as the author''s first novel.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6d079258-511b-4b7a-8fca-3da832972a6a', 'ceiling', 'To line or finish (a surface, such as a wall), with plaster, stucco, thin boards, or similar.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('99a3fa0c-367a-441f-93d0-0aa90d1a746c', 'celebration', 'The formal performance of a solemn rite, such as Christian sacrament.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('864e7af3-7133-4554-8192-d6677bcf2379', 'central', 'Being in the centre.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8b5e0784-0129-458e-9d8b-dc2a0d7d81b2', 'ceremony', 'A ritual, with religious or cultural significance.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('cfcd92ea-6e36-42ac-b2eb-798538f02ebe', 'certificate', 'A document containing a certified statement.', '', 'Education', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e4f42aff-e922-4c4a-b82c-0430200a29c4', 'chain', 'A series of interconnected rings or links usually made of metal.', 'He wore a gold chain around the neck.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('66b2e6d8-5986-4088-bcc6-ce8d1adadaec', 'challenge', 'A confrontation; a dare.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('977c40fb-1675-4634-8892-a5a6c4bce165', 'champion', 'An ongoing winner in a game or contest.', 'The defending champion is expected to defeat his challenger.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('621370a0-6a8e-47de-9148-41b165c4a6a9', 'channel', 'The physical confine of a river or slough, consisting of a bed and banks.', 'The water coming out of the waterwheel created a standing wave in the channel.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e673ee3f-59b9-4f44-a56a-862370c2c9e7', 'chapter', '(authorship) One of the main sections into which the text of a book is divided.', 'Detective novel writers try to keep up the suspense until the last chapter.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3b0a87d9-0eb5-4158-afae-62aa500d471e', 'charge', 'The amount of money levied for a service.', 'There will be a charge of five dollars.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('85b939ce-5f77-4bb8-b527-0b182ef6c25c', 'cheat', 'To violate rules in order to gain advantage from a situation.', 'My brother flunked biology because he cheated on his mid-term.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c3f685a3-bd5c-4348-960e-80475f4a00cf', 'cheerful', 'Noticeably happy and optimistic.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('30b860aa-10d8-4288-ad57-8510bda3cc2e', 'chemical', 'Any specific chemical element or chemical compound or alloy.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6c60bfae-0468-40e7-bc71-d8abd7589e7b', 'chest', 'A box, now usually a large strong box with a secure convex lid.', 'The clothes are kept in a chest.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4142a474-27e6-4bac-b448-53ca40154c32', 'childhood', 'The state of being a child.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('00c2438b-941b-424b-86c3-bdf2c5d2ba62', 'claim', 'A demand of ownership made for something.', 'a claim of ownership', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('54bc6dbc-e64b-4fdb-97fe-0540a510e5fa', 'clause', '(grammar) A verb, its necessary grammatical arguments, and any adjuncts affecting them.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3d1a135c-9bd0-4b6f-b602-a1f7a84957be', 'click', 'A brief, sharp, not particularly loud, relatively high-pitched sound produced by the impact of something small and hard against something hard, such as by the operation of a switch, a lock or a latch, or a finger pressed against the thumb and then released to strike the hand.', 'I turned the key, the lock gave a click and the door opened;  a click of one’s fingers', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d3fef602-85b4-4d69-b0ea-a9bda899ae74', 'client', 'A customer, a buyer or receiver of goods or services.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1c585dcd-c2f1-4b95-a9cf-c684e01fe6b3', 'cloth', 'A woven fabric such as used in dressing, decorating, cleaning or other practical use.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b3d51215-fec3-462c-8c90-6e758d3625bc', 'clue', 'A strand of yarn etc. as used to guide one through a labyrinth; something which points the way, a guide.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('44775f6e-6e28-4da4-8df0-3b20798590bc', 'coal', 'A black rock formed from prehistoric plant remains, composed largely of carbon and burned as a fuel.', 'Put some coal on the fire.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b2e5ff31-1c65-4ba9-9c2f-a3285ed6f7d5', 'coin', '(money) A piece of currency, usually metallic and in the shape of a disc, but sometimes polygonal, or with a hole in the middle.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('45360721-3c36-4078-9714-7832985160aa', 'collection', 'A set of items or amount of material procured or gathered together.', 'The asteroid belt consists of a collection of dust, rubble, and minor planets.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d14f5629-f22b-45eb-8980-0605ee13d838', 'coloured', 'To give something color.', 'We could color the walls red.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0bea926e-9f49-459b-876d-48002c7698b4', 'commercial', 'An advertisement in a common media format, usually radio or television.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2d22802f-9ec7-4b96-8add-a830374bec42', 'commit', 'The act of committing (e.g. a database transaction or source code into a source control repository), making it a permanent change.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c3f80b6d-8ebb-46a2-889e-39e98715ecc3', 'communication', 'The act or fact of communicating anything; transmission.', 'communication of a secret', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('01861b23-b544-4a34-9a0b-41380e84f6be', 'comparison', 'The act of comparing or the state or process of being compared.', 'to bring a thing into comparison with another;  there is no comparison between them', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0350218f-0971-446b-8015-1c4a539174ea', 'competitive', 'Capable of competing successfully', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('26f55665-a8a8-4b95-a722-16485670a9f7', 'competitor', 'A person or organization against whom one is competing.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f968b06c-29fb-4722-90e2-92f9b2b30499', 'complaint', 'The act of complaining.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('644d6b65-fa21-4432-9356-5dc16e909a69', 'complex', 'A network of interconnected systems.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('605e6020-727d-4e13-a842-9413f83d0db0', 'concentrate', 'A substance that is in a condensed form.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('64e5328f-86d5-4cda-a0a4-f4c65f46ecee', 'conclude', 'To end; to come to an end.', 'The story concluded with a moral.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('72a6dc1a-3a55-40e7-9c1f-8cd585e56828', 'conclusion', 'The end, finish, close or last part of something.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('59b79186-ec6b-4930-aaf9-cfd1dae5051c', 'confident', 'A person in whom one can confide or share one''s secrets: a friend.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('031b9635-906a-4ae1-9c79-e93d2faee207', 'confirm', 'To strengthen; to make firm or resolute.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('28a1d3c1-ed58-4478-bc4d-d56a60c3fd37', 'confuse', 'To puzzle, perplex, baffle, bewilder (somebody).', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f2f51ae3-6147-4924-b2db-d244766c3433', 'confused', 'To puzzle, perplex, baffle, bewilder (somebody).', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('11315945-6e36-4f76-b01d-a20d847ede4c', 'connection', 'The act of connecting.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2b8a034a-7759-4ff8-ae4e-30d75c3ea196', 'consequence', 'That which follows something on which it depends; that which is produced by a cause.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b014ed35-b105-4d77-9320-fdccd4d319d4', 'consist', 'To be.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b2ab0222-067c-4ee4-a9ce-2c17b115b63e', 'consume', 'To use up.', 'The power plant consumes 30 tons of coal per hour.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7af048d0-bd2c-4430-b7ba-afcebe82e8fc', 'consumer', 'One who, or that which, consumes.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1821d5ed-fda2-4fd7-b961-d6924f839d91', 'container', 'Someone who contains; something that contains.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7abc4c76-d56e-4b7f-aaeb-d44bbe7955b2', 'content', '(except in phrases) Satisfaction, contentment; pleasure.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('40a27c92-51c8-465c-b758-0cb8e23cfd1d', 'continuous', 'Without stopping; without a break, cessation, or interruption', 'a continuous current of electricity', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b098f7a4-9175-49bd-80ff-13f0768b9769', 'contract', 'An agreement between two or more parties, to perform a specific job or work order, often temporary or of fixed duration and usually governed by a written agreement.', 'Marriage is a contract.', 'Business', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('14b0e836-9b70-4671-ac11-4f90efeeae19', 'contrast', 'A difference in lightness, brightness and/or hue between two colours that makes them more or less distinguishable.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('578427a9-c959-428f-9b5e-291978eea6d3', 'convenient', 'Serving to reduce a difficulty, or accessible with minimum difficulty; expedient.', 'Fast food might be convenient, but it''s also very unhealthy.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('445436d8-15cf-4246-b49c-e115f21815ee', 'convince', 'To make someone believe, or feel sure about something, especially by using logic, argument or evidence.', 'I wouldn''t have or do something, unless I''m convinced that it''s good.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a69bf249-0a7a-42a1-9595-4e90cb1ae7ca', 'costume', 'A style of dress, including garments, accessories and hairstyle, especially as characteristic of a particular country, period or people.', 'The dancer was wearing Highland costume.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('5c87ab0a-b156-4bb0-ab16-5c5f55474938', 'cottage', 'A small house.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('06d49b7d-3d0d-47ca-86c7-0f772ba9a700', 'cotton', 'Gossypium, a genus of plant used as a source of cotton fiber.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('099aa810-bdac-4122-8f1a-7a8b44dda73c', 'countryside', 'A rural area, or the rural part of a larger area.', 'We live in the Swedish countryside.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d3c0f88e-4922-4159-a23a-8879f01fb2e4', 'court', 'An enclosed space; a courtyard; an uncovered area shut in by the walls of a building, or by different buildings; also, a space opening from a street and nearly surrounded by houses; a blind alley.', 'The girls were playing in the court.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8ee9f195-037e-42dc-92a2-111e02ca407b', 'covered', 'To place something over or upon, as to conceal or protect.', 'He covered the baby with a blanket.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b73236ba-e70f-4dd5-88e2-1259d11bc99f', 'cruel', 'To spoil or ruin (one''s chance of success)', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('028f0fa0-6077-4783-bdc2-494736e3e3cc', 'cultural', 'Pertaining to culture.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('eede1e7d-fdf2-4db6-8f59-7175cfe827a6', 'cure', 'A method, device or medication that restores good health.', '', 'Health', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2f445052-5aff-4785-8127-2f1750631632', 'currency', 'Money or other items used to facilitate transactions.', 'Wampum was used as a currency by Amerindians.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8d8a3827-3db3-4cf8-8ce9-a1271bb9b1fa', 'current', 'The generally unidirectional movement of a gas or fluid.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8d551962-ce82-46ad-9127-c627d59202d6', 'currently', 'At this moment, at present, now.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('19c50a24-2650-41f6-b0f3-076d09a6710e', 'curtain', 'A piece of cloth covering a window, bed, etc. to offer privacy and keep out light.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('28e2e70b-6026-4108-af48-45e1f3a6b197', 'editor', 'A person who edits or makes changes to documents.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('78a22754-6023-436c-af3b-592040b39721', 'custom', 'Frequent repetition of the same behavior; way of behavior common to many; ordinary manner; habitual practice; method of doing, living or behaving.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('be7a3f01-7fb9-4d7f-bcc0-57ee8e0aca8c', 'damage', 'Injury or harm; the condition or measure of something not being intact.', 'The storm did a lot of damage to the area.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e3a550fa-8729-4bb2-b3dd-fb7983fc4f1a', 'decade', 'A group, set, or series of ten , particularly:', 'a decade of soldiers', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9ac77815-6bb8-4cde-90ed-e432711bce60', 'decorate', 'To furnish with decorations.', 'We decorated the Christmas tree with tinsel and baubles.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2563b2dd-6c01-494d-81d2-53b31ac60686', 'define', 'A kind of macro in source code that replaces one text string with another wherever it occurs.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('fc765e70-88ea-4cbe-9eb2-a9f34d7537b0', 'definite', '(grammar) A word or phrase that designates a specified or identified person or entity.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('cb2805cb-0f36-4187-b72d-06ff3e693324', 'definition', 'A statement of the meaning of a word or word group or a sign or symbol (dictionary definitions).', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('420e33c2-b83f-41ad-a589-0482ab2d6855', 'deliver', 'To set free from restraint or danger.', 'deliver a captive from the prison', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('29cd3266-a9a8-42b4-bfd7-f4e485f164d2', 'departure', 'The act of departing or something that has departed.', 'The departure was scheduled for noon.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2b5183f9-844b-4aac-aeab-7b81e918e662', 'despite', 'Disdain, contemptuous feelings, hatred.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e7c82f9f-2f99-44f5-ad09-393cf618ae2c', 'destination', 'The act of destining or appointing.', '', 'Travel', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ce6381ba-0b50-48ec-9e0a-cd0d5a5dbe5f', 'determine', 'To set the boundaries or limits of.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0905bd46-15c3-40b5-97ad-a294241c6279', 'determined', 'To set the boundaries or limits of.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d340e5c0-d287-4d9a-a32d-f9d3f433ee27', 'development', 'The process of developing; growth, directed change.', 'The development of this story has been slow.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('97a84fc4-11fd-4342-9c0e-abdbe9c19ae2', 'diagram', 'A plan, drawing, sketch or outline to show how something works, or show the relationships between the parts of a whole.', 'Electrical diagrams show device interconnections.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('427bae03-c7ed-4e69-93d3-799b05d2054f', 'diamond', 'A glimmering glass-like mineral that is an allotrope of carbon in which each atom is surrounded by four others in the form of a tetrahedron.', 'The saw is coated with diamond.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b8bcb311-2639-4483-bdd4-2f10f264350c', 'difficulty', 'The state of being difficult, or hard to do.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('18d8dcb0-fe1f-4e59-8a4d-d1bd5e3817b9', 'directly', 'In a direct manner; in a straight line or course.', 'He drove directly to the office, and didn''t stop off at the petrol station.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8aa5d617-dfc8-456f-9d19-b74ec08d15a0', 'dirt', 'Soil or earth.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('5552b357-e782-49f3-b777-cd84e2fd2e1a', 'disadvantage', 'A weakness or undesirable characteristic; a con.', 'The disadvantage to owning a food processor is that you have to store it somewhere.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d7aa58c7-83c7-48cb-81bf-7ed11c234fb9', 'disappointed', 'To sadden or displease (someone) by underperforming, or by not delivering something promised or hoped for.', 'His lack of respect disappointed her.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4b950fe0-7dd2-4259-8933-f71ccb228083', 'disappointing', 'To sadden or displease (someone) by underperforming, or by not delivering something promised or hoped for.', 'His lack of respect disappointed her.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('da9c1ea1-6057-4cf1-bb3c-bfa8677f0918', 'discount', 'A reduction in price.', 'This store offers discounts on all its wares. That store specializes in discount wares, too.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c158ba21-dbab-4f81-99e1-c8bdf763679b', 'dislike', 'An attitude or a feeling of distaste or aversion.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7d65fa84-e535-4f9b-b8b2-3c1437f23c46', 'divide', 'A thing that divides.', 'Stay on your side of the divide, please.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1290e28d-21f9-43c2-993e-abba2e0cb3a0', 'documentary', 'A film, TV program, publication etc. which presents a social, political, scientific or historical subject in a factual or informative manner.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2530564e-92dd-43cc-a9fa-71ba3bb900cb', 'donate', 'To make a donation; to give away something of value to support or contribute towards a cause or for the benefit of another.', 'He donated an etching from his own collection to the new art gallery.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ed5daa69-0af6-4f52-ba86-ca9e0da64e99', 'doubt', 'Disbelief or uncertainty (about something); a particular instance of such disbelief or uncertainty.', 'I have doubts about how to convert this code to JavaScript.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3ba710e0-af83-4958-a2e2-007fc25be3a2', 'dressed', 'To fit out with the necessary clothing; to clothe, put clothes on (something or someone).', 'He was dressed in the latest fashions.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('fedf4fc9-6285-46b7-abd7-a7ce159d2f6e', 'drum', 'A percussive musical instrument spanned with a thin covering on at least one end for striking, forming an acoustic chamber, affecting what materials are used to make it; a membranophone.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('77a706ae-7dd0-40f0-8f41-ee81786da19b', 'drunk', 'To consume (a liquid) through the mouth.', 'He drank the water I gave him.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c74ec123-3a3b-40d2-8017-e848d5c34e97', 'due', 'Deserved acknowledgment.', 'Give him his due — he is a good actor.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('88463e1d-bed1-4c59-9620-2b195610c160', 'dust', 'Fine particles', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('5ebd338d-3333-48ee-88ac-bbb714e3c6a0', 'duty', 'That which one is morally or legally obligated to do.', 'We don''t have a duty to keep you here.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('79d99b69-3e68-48ac-9ce1-f6b47b2c8497', 'earthquake', 'A shaking of the ground, caused by volcanic activity or movement around geologic faults.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('16f08780-4c2d-4dae-81e3-1e01da646665', 'eastern', 'Of, facing, situated in, or related to the east.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('89931f73-2b04-43ed-a478-d46c30838335', 'economic', 'Pertaining to an economy.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('39b0f9be-6e7f-4c9b-8997-1dbd376a24b0', 'economy', 'Effective management of a community or system, or especially its resources.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e5f8a9fb-ae2a-4f9b-84b2-2ea1fedc0d7b', 'edge', 'The boundary line of a surface.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('21cee8ea-8113-4c77-8143-496669093b5d', 'educate', 'To instruct or train', 'Wang said such changes to the Baishui glacier provide the chance to educate visitors about global warming.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3e3d1044-f608-4dd5-baf9-f92e0dd0e9a3', 'educated', 'To instruct or train', 'Wang said such changes to the Baishui glacier provide the chance to educate visitors about global warming.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d5053d98-877c-4c37-b6e2-fbc32b96e341', 'educational', 'A free (or low cost) trip for travel consultants, provided by a travel operator or airline as a means of promoting their service. A fam trip', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9d1b745f-0543-4e47-8065-d91364999352', 'effective', 'A soldier fit for duty', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('bc6321f6-4ac0-4227-a3c6-86aeb853fbf7', 'effectively', 'In an efficient or effective manner; with powerful effect.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('95a187e6-ef48-446a-a5fe-96039f2fda95', 'effort', 'The work involved in performing an activity; exertion.', 'It took a lot of effort to find a decent-sized, fully-furnished apartment within walking distance of the office.   He made a conscious effort to not appear affected by the stories in the paper.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b2a4556b-2185-4afa-afc1-bdfd65a1d425', 'election', 'A process of choosing a leader, members of parliament, councillors or other representatives by popular vote.', 'How did you vote in (UK also: at) the last election?', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b89d9b28-8f02-48fc-8f94-35a3fcd58510', 'element', 'One of the simplest or essential parts or principles of which anything consists, or upon which the constitution or fundamental powers of anything are based.', 'Letters are the elements of written language.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('62ce04ed-63da-41b8-8c1c-0e5e61fe03f9', 'embarrassed', 'To humiliate; to disrupt somebody''s composure or comfort with acting publicly or freely; to disconcert; to abash', 'The crowd''s laughter and jeers embarrassed him.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('153074b2-5d73-4f6c-922d-3d76b3c1d0d7', 'embarrassing', 'To humiliate; to disrupt somebody''s composure or comfort with acting publicly or freely; to disconcert; to abash', 'The crowd''s laughter and jeers embarrassed him.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1f45f52e-64fa-418b-9a3b-dfa7a9274760', 'emergency', 'A situation which poses an immediate risk and which requires urgent attention.', 'Cardiac arrest is an emergency and if you find someone in cardiac arrest you should call 999 immediately.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('94ad0a4c-05dc-4934-be60-e460cb6c7946', 'emotion', 'A person''s internal state of being and involuntary physiological response to an object or a situation, based on or tied to physical state and sensory data.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b2ae0f99-2031-4468-b5a6-b6ebce46d4e4', 'employment', 'The work or occupation for which one is used, and often paid', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9fbdaa7a-3f69-4c6b-9f37-7d068713fd6a', 'encourage', 'To mentally support; to motivate, give courage, hope or spirit.', 'I encouraged him during his race.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6b4e4db6-f186-48fe-99f5-defe99af2725', 'enemy', 'Someone who is hostile to, feels hatred towards, opposes the interests of, or intends injury to someone else.', 'Crush the enemy!', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('84090bc4-f043-42ae-8226-99a4114cccfb', 'engaged', '(heading) To interact socially.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('93c45e30-29e3-44c7-925e-c959c93c7402', 'engineering', 'To design, construct or manage something as an engineer.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1435db5c-f5ff-4879-b8fe-10397f22ce36', 'entertain', 'Entertainment; pleasure.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d2720f6a-a352-4c60-a650-f4ef88645ca1', 'entertainment', 'An activity designed to give pleasure, enjoyment, diversion, amusement, or relaxation to an audience, no matter whether the audience participates passively as in watching opera or a movie, or actively as in games.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7ab62241-a7bd-4918-a64e-ef7bfc37b5af', 'entrance', 'The action of entering, or going in.', 'Her entrance attracted no attention whatsoever.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c89f5cf5-322c-4612-a2af-43b6c50a0fab', 'entry', 'The act of entering.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1f73581c-4ef9-4d6a-aa2c-9d374078662b', 'environmental', 'Pertaining to the environment.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('595d2d9b-07c2-41c5-b97f-5b5b812ecdb7', 'episode', 'An incident, action, or time period standing out by itself, but more or less connected with a complete series of events.', 'It was a most embarrassing episode in my life.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d098541f-8d54-4e13-b220-5ee11e5ef5fe', 'equal', 'A person or thing of equal status to others.', 'This beer has no equal.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('16ef42b4-7179-4263-b554-39765e323b66', 'equality', 'The fact of being equal.', '', 'Society', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('759d0ece-e49f-46dd-a9ab-9ddca42d007a', 'equally', '(manner) In an equal manner; in equal shares or proportion; with equal and impartial justice; evenly', 'All citizens are equally taxed.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('87dbe6ce-26b1-402d-afd2-fb622f5076a9', 'escape', 'The act of leaving a dangerous or unpleasant situation.', 'The prisoners made their escape by digging a tunnel.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('5bc15d5b-005d-48aa-b825-8292aacd8fe1', 'essential', 'A necessary ingredient.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f3b6a913-9303-4aee-beb3-4ef3be3b2840', 'eventually', 'In the end; at some later time, especially after a long time, a series of problems, struggles, delays or setbacks.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('086dca7a-e35f-4009-9029-135ba3cf4250', 'examine', 'To observe or inspect carefully or critically', 'He examined the crime scene for clues.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2648a7b0-ea12-4b90-a86a-ab37a7d2b6d5', 'exchange', 'An act of exchanging or trading.', 'All in all, it was an even exchange.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f22b0a94-9246-40ff-8cfb-803d18a1308f', 'excitement', 'The state of being excited (emotionally aroused).', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e3d38fe1-c81f-4a18-8219-6159d3551190', 'exhibition', 'An instance of exhibiting, or something exhibited.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0487f927-9029-470d-9ce7-b8595e82e655', 'expand', 'To change (something) from a smaller form and/or size to a larger one; to spread out or lay open.', 'You can expand this compact umbrella to cover a large table.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('61e7440f-7486-48a1-be59-920c36c8541c', 'expected', 'To predict or believe that something will happen', 'He never expected to be discovered.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2ccbb60e-dbab-493a-9f2f-1068448d2ad0', 'expedition', 'The act of expediting something; prompt execution.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b8a83709-3742-41af-9540-4c0ef2d38ef8', 'experienced', 'To observe certain events; undergo a certain feeling or process; or perform certain actions that may alter one or contribute to one''s knowledge, opinions, or skills.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('fd55fb1e-fae1-40b8-9fb9-975b53e1b3f3', 'explode', 'To destroy with an explosion.', 'The assassin exploded the car by means of a car bomb.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('74e3889f-042b-4917-b032-4060a30d7b21', 'explore', 'An exploration; a tour of a place to see what it is like.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4de30bd7-6f04-438f-8ed1-365f7bd40dec', 'explosion', 'A violent release of energy (sometimes mechanical, nuclear, or chemical.)', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c9a6b197-2776-407b-96cd-9224ec74baf7', 'export', 'Something that is exported', 'Oil is the main export of Saudi Arabia.', 'Business', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('27e22982-10c3-48bc-897e-231f57b49c3d', 'fairly', '(manner) In a fair manner; fair; not biased or skewed or favouring a certain party', 'A jury is expected to ensure that the accused is fairly judged.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3a81c291-f221-4746-8ab6-409f603e7b62', 'familiar', 'An attendant spirit, often in animal or demon form.', 'The witch’s familiar was a black cat.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('997102df-b69e-406a-a81a-f6b660e6eeaf', 'fancy', 'The imagination.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6af8e3ee-ef0c-4626-b7a8-995058c78bba', 'fascinating', 'To evoke an intense interest or attraction in someone.', 'The flickering TV fascinated the cat.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4bbef26d-9f81-4ed8-9a76-ba2bdaa759c2', 'fashionable', 'A fashionable person; a fop', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('10a3c947-9062-4337-8b5f-df3c12cf4378', 'fasten', 'To attach or connect in a secure manner.', 'Can you fasten these boards together with some nails?', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0557d901-2e90-41cd-a0e4-faf5e083c86e', 'favour', 'A kind or helpful deed; an instance of voluntarily assisting (someone).', 'He did me a favor when he took the time to drive me home.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d44f309e-a9a3-4b96-80b6-b8328ef20908', 'fence', 'A thin artificial barrier that separates two pieces of land or a house perimeter.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f7503bbe-5412-426c-b959-b16586adf439', 'fighting', 'To contend in physical conflict, either singly or in war, battle etc.', 'A wounded animal will fight like a maniac, relentless, savage and murderous.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2a441c2a-9cac-4e61-a062-7511893c8b9d', 'file', 'A collection of papers collated and archived together.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('26d2dd8a-eefd-47e4-95d0-389ec31dd92a', 'finance', 'The management of money and other assets.', '', 'Business', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('cf24edd1-5008-4f35-8e94-f069cd2e4cdd', 'financial', 'Related to finances.', 'For financial reasons, we''re not going to be able to continue to fund this program.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e2203600-16cb-41d4-b1dc-72dbc906cee6', 'fitness', 'The condition of being fit, suitable or appropriate.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('046f2af2-f3fd-49a7-9995-9c62dde20d1a', 'fixed', 'To pierce; now generally replaced by transfix.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b0a1d039-6bb2-4a80-b7ec-9bb56a4b38e9', 'flag', 'A piece of cloth, often decorated with an emblem, used as a visual signal or symbol.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('966675da-dcf6-4851-a05a-fb266d527a2f', 'flood', 'A (usually disastrous) overflow of water from a lake or other body of water due to excessive rainfall or other input of water.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b1038bd1-0ada-49bf-94b4-2dd8d60bdca3', 'flour', 'Powder obtained by grinding or milling cereal grains, especially wheat, or other foodstuffs such as soybeans and potatoes, and used to bake bread, cakes, and pastry.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b9edffc5-f10b-4786-9baa-264653cdcff4', 'flow', 'A movement in people or things with a particular way in large numbers or amounts', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('320742d5-8f7b-4e57-9a68-78088720b475', 'fold', 'An act of folding.', 'After two reraises in quick succession, John realised his best option was probably a fold.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b012726c-5c5b-47ec-bc7e-fb7afa217cec', 'folk', 'A grouping of smaller peoples or tribes as a nation.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a0407b77-a43f-4aa2-b5cb-5bfe0b16c5fb', 'force', 'Strength or energy of body or mind; active power; vigour; might; capacity of exercising an influence or producing an effect.', 'the force of an appeal, an argument, or a contract', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('680bfc85-469c-4cf0-9dc3-747cf5ea0565', 'forever', 'An extremely long time.', 'I haven''t seen him in forever!', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9109fbac-35d1-488a-9fa6-4329acdb6f1b', 'frame', 'The structural elements of a building or other constructed object.', 'Now that the frame is complete, we can start on the walls.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4591ac88-1a78-47fa-9018-25f1ffe64d6c', 'freedom', 'The state of being free, of not being imprisoned or enslaved.', 'Having recently been released from prison, he didn''t know what to do with his newfound freedom.', 'Society', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7ae3974b-83f6-4f35-961d-0aa4e0c4fcf6', 'freeze', 'Especially of a liquid, to become solid due to low temperature.', 'The lake froze solid.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d7547715-6dd4-47dc-8908-a31911f7658c', 'frequently', 'At frequent intervals.', 'This question arises frequently.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1d47a8ca-e64f-4399-9e84-40e941e1dc4e', 'friendship', 'The condition of being friends.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0d48a5aa-25d1-4562-871c-f361676cb322', 'frighten', 'To cause to feel fear; to scare; to cause to feel alarm or fright.', 'Avery puts a sheet over her head, pretending to be a ghost to frighten Emily.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('080b2eea-b54d-4c12-8438-edbacf3cefe0', 'frightened', 'To cause to feel fear; to scare; to cause to feel alarm or fright.', 'Avery puts a sheet over her head, pretending to be a ghost to frighten Emily.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6c7b66e6-8633-4cf6-acc5-c257941ecb25', 'frightening', 'To cause to feel fear; to scare; to cause to feel alarm or fright.', 'Avery puts a sheet over her head, pretending to be a ghost to frighten Emily.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('09db2a3f-94d4-41f6-a997-2b148ce5cf73', 'frozen', 'Especially of a liquid, to become solid due to low temperature.', 'The lake froze solid.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('80ec236a-fd29-4e0d-9d97-ad3c0ea151a4', 'fry', '(usually in the plural, fries) A fried strip of potato.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6fba464f-4fb3-4204-91ef-513a8ea5a664', 'fuel', 'Substance consumed to provide energy through combustion, or through chemical or nuclear reaction.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e8956a17-567b-4480-8f38-0948c1386659', 'function', 'What something does or is used for.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e5c819a1-c8c6-4f5f-b404-9a3d5a0f875f', 'fur', 'The hairy coat of various mammal species, especially when fine, soft and thick.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f5dbfa8c-a99c-47fe-bfb6-f17fbccb877f', 'garage', 'A building (or section of a building) used to store a car or cars, tools and other miscellaneous items.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8b0fd429-d788-4bbc-9ab7-bbc4ecc8ccdb', 'gather', 'A plait or fold in cloth, made by drawing a thread through it; a pucker.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('038cbd41-809c-449d-8a2d-addadbea51e0', 'generally', 'Popularly or widely.', 'It is generally known that the Earth is round.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ce4905a0-6bb8-44cb-b2d4-e844581cd2ae', 'generation', 'The fact of creating something, or bringing something into being; production, creation.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('62bdb003-c01a-48e3-ba61-4200ebe84d31', 'generous', 'Noble in behaviour or actions; principled, not petty; kind, magnanimous.', 'Thank you for your generous words.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('330ed0fd-6374-4857-8767-4941960b987b', 'gentle', 'A person of high birth.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('cc93ff83-44cd-4a0c-a8d3-afad64ee432d', 'gentleman', 'A man of gentle but not noble birth, particularly a man of means (originally ownership of property) who does not work for a living but has no official status in a peerage; an armiferous man ranking below a knight.', 'Being a gentleman, Robert was entitled to shove other commoners into the gongpit but he still had to jump out of the way of the knights to avoid the same fate himself.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d8bc6b4e-4aa7-42a8-bc92-0ed3b64a9665', 'ghost', 'The spirit; the soul of man.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c932cb16-4674-4d0c-a8da-aa4f69af157a', 'giant', 'A mythical human of very great size.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('58604032-f1af-41ad-a48c-e66934aeabbb', 'glad', 'To make glad', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b400ee11-829f-408b-a541-a364bad4cced', 'global', 'A globally scoped identifier.', '', 'Environment', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('458635b3-874d-4de6-b5f1-90b332b74ad0', 'glove', 'An item of clothing other than a mitten, covering all or part of the hand and fingers, but usually allowing independent movement of the fingers.', 'I wore gloves to keep my hands warm.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ea217af1-8022-403f-9394-11959207ec3b', 'goods', 'The forces or behaviours that are the enemy of evil. Usually consists of helping others and general benevolence.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('381eadf6-433e-49c5-90f4-50e8552240cf', 'grade', 'A rating.', 'I gave him a good grade for effort.', 'Education', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ee2b35d0-a43b-45e3-83f5-666bff4e8659', 'graduate', 'A person who is recognized by a university as having completed the requirements of a degree studied at the institution.', 'If the government wants graduates to stay in the country they should offer more incentives.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1eb9460c-aaab-4050-b6c8-7eee73ee44f0', 'grain', 'The harvested seeds of various grass food crops eg: wheat, corn, barley.', 'We stored a thousand tons of grain for the winter.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e68d06f5-eaf1-4850-a560-73c5af0e96f6', 'grateful', 'Appreciative; thankful.', 'I''m grateful that you helped me out.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3cdb1be5-d9b1-4c19-8389-da7ff2e3732b', 'growth', 'An increase in size, number, value, or strength.', 'Growth was dampened by a softening of the global economy in 2001, but picked up in the subsequent years due to strong growth in China.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e8c0370f-fc54-4ccf-86fe-9fa20750d2e2', 'guard', 'A person who, or thing that, protects or watches over something.', 'The prison guard unlocked the door of the cell.   After completing the repairs, he replaced the sump guard.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9e8362e9-4dc8-444c-b69b-94538748d027', 'guilty', 'A plea by a defendant who does not contest a charge.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9817cc41-793e-41de-bf0b-b0f33a331aa6', 'hang', 'The way in which something hangs.', 'This skirt has a nice hang.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f5512d4d-cec8-4e3f-a19f-5f448aa51ba0', 'happiness', 'The emotion of being happy; joy.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d2557ac2-fb5c-4177-b3b2-8a5ce9dbde56', 'hardly', '(manner) Firmly, vigorously, with strength or exertion.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0714ec30-1b50-4447-8213-14c7bbb3d1c2', 'headline', 'The heading or title of a magazine or newspaper article.', 'The headline on today''s newspaper reads "John Doe Wins Wood-Splitting Competition."', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('92370c5b-66e6-4970-90ee-ba30b407dda4', 'heating', 'To cause an increase in temperature of (an object or space); to cause to become hot (often with "up").', 'I''ll heat up the water.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f3808d69-59ca-4a9a-9d08-cec76c91347b', 'heavily', 'In a heavy manner.', 'He clomped heavily up the stairs in his boots.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('df6acbc7-d51a-4bd2-8fb6-88a0bdf58e1d', 'helicopter', 'An aircraft that is borne along by one or more sets of long rotating blades which allow it to hover, move in any direction including reverse, or land; and typically having a smaller set of blades on its tail that stabilize the aircraft.', 'We flew over the city in a helicopter.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f93a6bab-0a68-4d68-be93-1a25fc4595ad', 'highlight', 'An area or a spot in a drawing, painting, or photograph that is strongly illuminated.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('27e859f3-88c0-44d0-b173-8bca23221e6a', 'highly', 'In a high or esteemed manner.', 'He spoke highly of you.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9b641377-9e9b-498b-a4fb-003794adb3c7', 'hire', 'Payment for the temporary use of something.', 'The sign offered pedalos on hire.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3470d64f-9363-462c-bfac-d71f06d7839f', 'historic', 'A history, a non-fiction account of the past.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('49de0acb-99a1-431b-b8c5-b8022ccaa2d5', 'historical', 'A historical romance.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('15a3a39c-0b34-40b0-8186-c8e753ec72b9', 'honest', 'To adorn or grace; to honour; to make becoming, appropriate, or honourable.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9bbfa034-27e9-4405-af98-1235cc9af971', 'horrible', 'A thing that causes horror; a terrifying thing, particularly a prospective bad consequence asserted as likely to result from an act.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2a621aac-0b83-4ec5-8bd8-ae93d4731aa2', 'horror', 'An intense distressing emotion of fear or repugnance.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('846a744e-461a-4026-82d1-687e693ea5be', 'host', 'One which receives or entertains a guest, socially, commercially, or officially.', 'A good host is always considerate of the guest’s needs.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('dcb4418e-1e20-46ef-acbf-cf5619181cb1', 'hunt', 'The act of hunting.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d7762176-bd39-4ce1-bbad-0680939f5936', 'hurricane', 'A severe tropical cyclone in the North Atlantic Ocean, Caribbean Sea, Gulf of Mexico, or in the eastern North Pacific off the west coast of Mexico, with winds of 119 km/h (74 miles per hour) or greater accompanied by rain, lightning, and thunder that sometimes moves into temperate latitudes.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8a0c5e41-b3c1-4236-ab9c-3f31c08e047a', 'hurry', 'Rushed action.', 'Why are you in such a big hurry?', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('59db692a-76ef-4ea0-95b6-c686b02c5ff9', 'identity', 'Sameness, identicalness; the quality or fact of (several specified things) being the same.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9b6077ec-354d-459d-b160-c759d4aa44b5', 'ignore', 'To deliberately not listen or pay attention to.', 'A problem ignored is a problem doubled.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('57f17520-f3bb-47e4-9ea4-7850bf0cb076', 'illegal', 'An illegal act or technique.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ba6fdfa6-45f9-4c90-9d1f-b4cd671cdbdf', 'imaginary', 'Imagination; fancy.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('5343639d-f0a4-444b-a8a5-8de2eafb4dd4', 'immediate', 'Happening right away, instantly, with no delay.', 'Computer users these days expect immediate results when they click on a link.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('69bb03ae-945b-4b8f-9175-84cafee3a43c', 'immigrant', 'A non-native person who comes to a country from another country in order to permanently settle there.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2f615500-82a3-4f4a-adfe-b1a2572766d9', 'impact', 'The striking of one body against another; collision.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8213e9e8-d854-466c-86be-9ebe26341a1e', 'import', 'Something brought in from an exterior source, especially for sale or trade.', '', 'Business', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('65daca91-4568-49e4-ae65-7c3ca497339c', 'importance', 'The quality or condition of being important or worthy of note.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c144597d-2fd3-4fec-9b01-6be81be155cc', 'impression', 'The indentation or depression made by the pressure of one object on or into another.', 'His head made an impression on the pillow.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a4a364da-4922-4ed7-9c29-94f5e870ddb4', 'impressive', 'Making, or tending to make, a positive impression; having power to impress', 'an impressive movie', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('aa2a827a-6538-4a73-9534-cd64d83d9751', 'improvement', 'The act of improving; advancement or growth; a bettering', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('17000f9d-318d-439c-a19a-d669f5521838', 'incredibly', '(manner) In an incredible manner; not to be believed.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('98cb0506-eced-4bf2-a1a2-63528e392a6c', 'indeed', '(modal) Truly; in fact; actually.', 'Indeed, he made several misplays.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7347220b-3276-4855-8c89-70e5e1759256', 'indicate', 'To point out; to discover; to direct to a knowledge of; to show; to make known.', 'The guard blew his whistle to indicate imminent departure.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4dcb5ddf-1206-4fff-9f9c-4333cea82de8', 'indirect', 'An indirect cost.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('73f2a78c-8d1c-4ebf-9ed1-0ef023697a2e', 'indoor', 'Situated in, or designed to be used in, or carried on within, the interior of a building.', 'These fireworks are not for indoor use!', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('907ff227-2733-494f-8ea6-73a02e60c7fd', 'indoors', 'The interior of a building; the space inside buildings generally.', 'I prefer the indoors to the outdoors.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3ea9752a-3dbd-4f5f-a139-023b4247e62f', 'infection', 'The act or process of infecting.', '', 'Health', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('41df041a-1119-47e2-8f1c-eeead9c1c7d7', 'influence', 'The power to affect, control or manipulate something or someone; the ability to change the development of fluctuating things such as conduct, thoughts or decisions.', 'I have absolutely no influence over him.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6357f871-a478-435c-ae72-e7f7424931f7', 'ingredient', 'One of the substances present in a mixture, especially food.', '', 'Food', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('84aa573a-62a8-47a8-a97e-0bcc0b95b7d8', 'injure', 'To wound or cause physical harm to a living creature.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('907858c8-010a-4250-8dea-f4c3b240a0d8', 'injured', 'To wound or cause physical harm to a living creature.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2ba3b382-2cd4-42ec-9d0c-b8f7efe02275', 'innocent', 'One who is innocent, especially a young child.', 'The slaughter of the innocents was a significant event in the New Testament.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('acba7e81-5500-46c8-bc1c-ef917652abc2', 'intelligence', 'Capacity of mind, especially to understand principles, truths, facts or meanings, acquire knowledge, and apply it to practice; the ability to comprehend and learn.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0e3d68d4-4d05-4161-a277-8e7b9afb7ee7', 'intend', '(usually followed by the particle "to") To hope; to wish (something, or something to be accomplished); be intent upon', 'He intends to go to university.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f26f623f-2544-4ad8-b9ce-65919a24ce55', 'intention', 'The goal or purpose behind a specific action or set of actions.', 'It’s easy to promise anything when you have no intention of fulfilling any of it.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d6d82a85-be89-4475-b4d5-22f6acc7bbc6', 'invest', 'To spend money, time, or energy on something, especially for some benefit or purpose; used with in.', 'We''d like to thank all the contributors who have invested countless hours into this event.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3effc5f1-e508-4c45-aebc-7b67401526c3', 'investigate', 'To inquire into or study in order to ascertain facts or information.', 'to investigate the causes of natural phenomena', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('954b3d68-2b0c-4e7f-b354-43cda6b04250', 'investment', 'The act of investing, or state of being invested.', 'Giving your children a good education is a wise long-term investment.', 'Business', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c51ac437-ca83-4730-9f3f-6232b3b6b74e', 'involved', 'To roll or fold up; to wind round; to entwine.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1a7991e4-7aaf-4d46-9fa8-4d82ac7fc72f', 'iron', 'A common, inexpensive metal, silvery grey when untarnished, that rusts, is attracted by magnets, and is used in making steel.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a694b2bc-b7db-4b2e-8238-5f628c389acf', 'issue', 'The action or an instance of flowing or coming out, an outflow, particularly:', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1fc093f8-d444-485b-b3ee-7ba0fe9b474b', 'journal', 'A diary or daily record of a person, organization, vessel etc.; daybook.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('89616827-cad1-44dc-b794-4f3cbf547dd2', 'judge', 'A public official whose duty it is to administer the law, especially by presiding over trials and rendering judgments; a justice.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f900c305-f5e7-4bb3-b3df-aec580afc014', 'justice', 'The state or characteristic of being just or fair.', 'the justice of a description', 'Society', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d8b7a7f1-b409-4b98-9ce4-8929b6f3bda7', 'keen', 'To make cold, to sharpen.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e3bfde76-7e7b-4dd3-8ad6-fce202e978e2', 'keyboard', '(etc.) A set of keys used to operate a typewriter, computer etc.', '', 'Technology', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('63d9296e-fc31-40f4-8fed-3244d57df114', 'kick', 'A hit or strike with the leg, foot or knee.', 'A kick to the knee.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('aaa33757-b269-42bb-bba9-3c47080a3e5a', 'killing', 'To put to death; to extinguish the life of.', 'Smoking kills more people each year than alcohol and drugs combined.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('31141da2-81be-4288-b891-bbfe2df783b4', 'kiss', 'To touch with the lips or press the lips against, usually to show love or affection or passion, or as part of a greeting.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('aacef152-86ed-4411-829d-00e8d5922433', 'label', 'A small ticket or sign giving information about something to which it is attached or intended to be attached.', 'Although the label priced this poster at three pounds, I got it for two.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1fdb76bb-582e-4f83-bf7c-ee8636b3600d', 'laboratory', 'A room, building or institution equipped for scientific research, experimentation or analysis.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3bc0677e-0027-4ac0-bf8a-c5b0e55fe7f6', 'lack', 'A defect or failing; moral or spiritual degeneracy.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('097d59b2-5ebd-4a16-a1ac-cab5097a244b', 'latest', 'Near the end of a period of time.', 'It was late in the evening when we finally arrived.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('80aca69d-5b06-4730-8653-f862eabae711', 'lay', 'Arrangement or relationship; layout.', 'the lay of the land', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c8e5ad16-000c-4bf2-9c83-18d3645de8b3', 'layer', 'A single thickness of some material covering a surface.', 'After the first coat of paint dried, he applied another layer.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9e72f044-c3fc-4ec9-b884-6e883e500c0c', 'leading', 'To cover, fill, or affect with lead', 'continuous firing leads the grooves of a rifle.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('aa89e7ca-c58c-4a7e-b725-f571f84f48fd', 'leaf', 'The usually green and flat organ that represents the most prominent feature of most vegetative plants.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8430ebc0-0150-4bf4-adbc-52c2b11b39ec', 'leather', 'A tough material produced from the skin of animals, by tanning or similar process, used e.g. for clothing.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8bdf8e2a-a62d-4ac7-8f10-50f01b6b68f4', 'legal', 'The legal department of a company.', 'Legal wants this in writing.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('bbcd8002-2a54-486f-840b-770ac1e926be', 'leisure', 'Freedom provided by the cessation of activities.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('721b301f-d7d6-4c2d-8f12-79eb351243e3', 'length', 'The distance measured along the longest dimension of an object.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b07ea12e-fd88-42da-9754-727abdb72408', 'limit', 'A restriction; a bound beyond which one may not go.', 'There are several existing limits to executive power.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b521f536-dbd1-47f7-aa33-0db352ddfb9b', 'lip', 'Either of the two fleshy protrusions around the opening of the mouth.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('50da34cd-687b-4eba-850a-84a8ac84ed45', 'liquid', 'A substance that is flowing, and keeping no shape, such as water; a substance of which the molecules, while not tending to separate from one another like those of a gas, readily change their relative position, and which therefore retains no definite shape, except that determined by the containing receptacle; an inelastic fluid.', 'A liquid can freeze to become a solid or evaporate into a gas.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d1e75a0f-8c79-4c96-8c86-32324d6a2389', 'literature', 'The body of all written works.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6bffa891-54a7-4bed-88d3-0023e24e283f', 'living', 'To be alive; to have life.', 'He''s not expected to live for more than a few months.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e078b44a-19e8-4f3d-8eba-7a6bb8b79a53', 'locate', 'To place; to set in a particular spot or position.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('77a89f51-ea51-496d-8767-c2985174a5cd', 'located', 'To place; to set in a particular spot or position.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0866b86e-da67-47be-b0c0-18e0923d24d9', 'location', 'A particular point or place in physical space.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4cb0b10b-76ef-43fd-810f-06fbfdc28c0b', 'lonely', 'Unhappy because of feeling isolated from contact with other people.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7a546fcb-cc43-410a-bc9f-9db18d07352f', 'loss', 'The result of no longer possessing an object, a function, or a characteristic due to external causes or misplacement.', 'In other areas, glacier loss creates serious risk of a dry period across the Third Pole, Wang said.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b85b4061-8b4f-426b-b953-a4819cb9dc97', 'luggage', 'The bags and other containers that hold a traveller''s belongings.', '', 'Travel', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7af96c9f-2035-4339-8164-855abb148d04', 'luxury', 'Very wealthy and comfortable surroundings.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ce109a8a-b005-4d14-a128-7355dcd8e628', 'mad', 'To be or become mad.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c60dde5c-319e-440c-be45-7e8f580972f0', 'magic', 'The application of rituals or actions, especially those based on occult knowledge, to subdue or manipulate natural or supernatural beings and forces in order to have some benefit from them', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e66a011a-f3c9-4bde-87c6-91f8cf745e9a', 'mainly', 'Forcefully, vigorously.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8c51d98e-de01-4641-8420-8353f28cb17e', 'mall', 'A pedestrianised street, especially a shopping precinct.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b5b5a4b5-eb56-4406-9f14-68b8f9d97100', 'management', 'Administration; the use of limited resources combined with forecasting, planning, leadership and execution skills to achieve predetermined specific goals.', '', 'Business', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6f81cb1c-0b97-438a-a7c1-059cdab8db3a', 'marketing', 'To make (products or services) available for sale and promote them.', 'We plan to market an ecology model by next quarter.', 'Business', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d7fa90e2-5d8c-4cf0-b0ee-f8270f883e3c', 'marriage', 'The state of being married.', 'You should enter marriage for love.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('dd89391c-22bb-4b1e-a22b-ad4661028a32', 'math', 'A mowing; what is gathered from mowing.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8b7a9557-50bc-491d-b0f9-cb039369d793', 'meanwhile', 'The time between two events.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('eb18ba62-c310-44a0-a307-c91077485405', 'measure', 'A prescribed quantity or extent.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7f1e0bfe-7623-4017-8500-44d77fdb03ce', 'medium', '(plural media or mediums) The chemistry of the surrounding environment, e.g. solid, liquid, gas, vacuum, or a specific substance such as a solvent.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b07bee29-c324-4a43-a97b-89046e038e9e', 'mental', 'Of or relating to the mind or an intellectual process.', '', 'Health', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2844d14a-43e6-489d-a1a1-3bf07f343d8d', 'mess', 'A disagreeable mixture or confusion of things; hence, a situation resulting from blundering or from misunderstanding; disorder.', 'He made a mess of it.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0f2900c8-df7f-4c1f-a9d3-7c6bcaaa36d4', 'mild', 'A relatively low-gravity beer, often with a dark colour; mild ale', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('eafb49a9-7d7f-4db8-b319-64fead162334', 'mix', 'To stir together.', 'Mix the eggs and milk with the flour until the consistency is smooth.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d1a9caf5-72fe-4336-afab-967e3a1b0625', 'mixture', 'The act of mixing.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('da25a15d-03b8-4895-bc01-cdc53d358e88', 'mood', 'A mental or emotional state, composure.', 'I''ve been in a bad mood since I dumped my boyfriend.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b7896cf5-218b-4e30-8872-01564ab47170', 'mud', 'A mixture of water and soil or fine grained sediment.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('92bfbfff-0b5b-47c2-b3c2-b5e1828a629d', 'murder', 'The crime of deliberately killing another person without justification.', 'The defendant was charged with murder.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b45f3e65-7543-4e1d-88b2-fae86867dba8', 'muscle', 'A contractile form of tissue which animals use to effect movement.', 'Muscle consists largely of actin and myosin filaments.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('992ba458-e9d0-408a-b7d2-eac51c272a6a', 'mystery', 'Something secret or unexplainable; an unknown.', 'The truth behind the events remains a mystery.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6bb226c5-af61-44c1-8662-82e22e7a7a24', 'nail', 'The thin, horny plate at the ends of fingers and toes on humans and some other animals.', 'When I''m nervous I bite my nails.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ff1cbbbc-3aa7-4a92-8b01-43b9f050a26d', 'narrative', 'The systematic recitation of an event or series of events.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('712a6a81-aa8f-4000-a377-84547b9e161d', 'nation', 'A historically constituted, stable community of people, formed on the basis of a common language, territory, economic life, ethnicity and/or psychological make-up manifested in a common culture.', 'The Kurdish people constitute a nation in the Middle East', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8612e101-a018-43f7-ba8d-c8f4f0cde5e6', 'native', 'An aboriginal inhabitant of a region colonized by English-speaking people; in particular:', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('03d31a6c-fd4a-4911-9bcf-dd0008dbd852', 'naturally', 'In a natural manner.', 'Although he was unused to the situation, he tried to act naturally.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('cd5989c0-6584-4117-b6f8-004e742df0a9', 'necessarily', 'Inevitably; of necessity.', 'It is not necessarily true that children get their morals from their parents.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('25f7df4d-aa1d-4775-849c-dc63ad5bdb7f', 'needle', 'A fine, sharp implement usually for piercing such as sewing, or knitting, acupuncture, tattooing, body piercing, medical injections, etc.', 'The seamstress threaded the needle to sew on a button.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7714335f-f4f0-4a7a-93df-4cafa76a4426', 'neighbourhood', 'The quality of being a neighbor, of living nearby, next to each-other; proximity.', 'Our neighborhood was our only reason to exchange hollow greetings.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('03c369e7-5fef-4f39-8f2e-abb57f2da240', 'nor', 'And not (introducing a negative statement, without necessarily following one).', 'Nor did I stop to think, but ran.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('515093ea-abb8-487f-bb6d-c30e4c1056d2', 'northern', 'An inhabitant of the northern regions.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('48eb1e1d-29fb-4e72-b3d5-93d3b3d5e702', 'nuclear', 'Nuclear power', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1dbda8a1-6586-4ac0-b44d-4d82b730e67d', 'nutrition', 'The organic process by which an organism assimilates food and uses it for growth and maintenance.', '', 'Food', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('92259358-9fae-4b80-adc6-9345ee096c0f', 'obvious', 'Easily discovered, seen, or understood; self-explanatory.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8e7d5af9-bbf6-4507-a79e-a88446b9bc5f', 'obviously', 'In an obvious or clearly apparent manner.', 'She was in floods of tears and obviously very upset.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2632fd3b-8efe-4dde-a422-ee05817b6130', 'occasion', 'A favorable opportunity; a convenient or timely chance.', 'At this point, she seized the occasion to make her own observation.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('46a6d87f-9253-4087-8163-bd1fb4674949', 'occur', 'To happen or take place.', 'The liftoff will occur in exactly twelve seconds.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3e1bbc8c-f716-4c14-b684-1765aaca51b8', 'odd', '(diminutive) An odd number.', 'So let''s see. There are two evens here and three odds.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('34a26819-0ed3-4e11-a28d-f27090720479', 'official', 'An office holder invested with powers and authorities.', 'David Barnes was the official charged with the running of the sports club.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('08705d47-f2ac-405b-bc4b-23970137414d', 'old-fashioned', 'A cocktail made by muddling sugar with bitters and adding whiskey or, less commonly, brandy, served with a twist of citrus rind.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('378e3239-c474-43c9-9ed8-9abb64cc40cc', 'operation', 'The method by which a device performs its function.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('011c1e96-c087-46ac-850e-dc97cf741d7a', 'organized', 'To arrange in working order.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e9c02cbc-dbda-4d2b-8193-6646dccff3ba', 'organizer', 'A person who arranges the details of a public event.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d95a6fcc-6fee-42dc-b754-b6b1747fdeff', 'originally', 'As it was in the beginning.', 'Originally, this paper was white, but over the years it has yellowed with age.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3ad2690d-e1e8-4766-8af4-0b56bf3cc06e', 'ought', 'Property; possession', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4113f509-59fc-4f54-9861-d5a5f448d0ba', 'ours', 'That which belongs to us; the possessive case of we, used without a following noun.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('acd3d024-62e1-48ec-a23f-35b484b73d42', 'qualify', 'An instance of throwing and catching each prop at least twice.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1518ee98-0914-4111-aab8-e6b88ce469df', 'outdoor', '(in some African communities) To publicly display a child after it has been named', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d2625015-fa52-4894-b8cf-6d5a88451999', 'outdoors', '(often preceded by "the") The environment outside of enclosed structures.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c94d67e3-3bd6-4a6f-8061-7c1878382bac', 'package', 'Something which is packed, a parcel, a box, an envelope.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('912fcfda-bc24-4ffe-97f4-39bc4ace45ec', 'painful', 'Causing pain or distress, either physical or mental.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('51809b39-ce8c-4f9c-8a94-b4a4dc749685', 'pale', 'Paleness; pallor.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('70b52fe9-555d-4666-b471-339f34ba6281', 'pan', 'A wide, flat receptacle used around the house, especially for cooking.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3193332a-737d-42b9-b5ec-5b60c0d0a0e5', 'participate', 'To join in, to take part, to involve oneself (in something).', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8c4e2044-8881-42a2-bfdf-c3bc8d9d08dc', 'particularly', '(focus) Especially, extremely.', 'The apéritifs were particularly stimulating.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('115da61c-3421-449e-abdc-99a5e1c903ca', 'passion', 'Any great, strong, powerful emotion, especially romantic love or extreme hate.', 'We share a passion for books.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('80fff3a4-d103-4613-ac4a-a51ca54216be', 'path', 'A trail for the use of, or worn by, pedestrians.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0c385172-2dfa-4e9c-aa5f-96714d256559', 'payment', 'The act of paying.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a947635d-485a-4cfb-bffa-368744e7f9a3', 'peaceful', 'Not at war or disturbed by strife or turmoil.', 'peaceful protest', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d7482a40-466b-4123-a2ed-d4279385423b', 'percentage', 'The amount, number or rate of something, regarded as part of a total of 100; a part of a whole.', 'A high percentage of secondary school leavers take a gap year.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3b3d1ee2-9435-4630-b26b-64d60054eeef', 'perfectly', 'With perfection.', 'They completed the first series perfectly.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2641152b-466b-403b-8acb-2e5793b6c5f9', 'performance', 'The act of performing; carrying into execution or action; execution; achievement; accomplishment; representation by action.', 'the performance of an undertaking or a duty', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0b6f652d-709e-40ab-90a9-469689468913', 'personally', 'In a personal manner.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e5bdf47d-375f-4511-9448-7635dca073fd', 'persuade', 'To successfully convince (someone) to agree to, accept, or do something, usually through reasoning and verbal influence.', 'That salesman was able to persuade me into buying this bottle of lotion.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('be105d0c-762c-4e38-aaee-e69eb19dfe53', 'photographer', 'One who takes photographs, typically as an occupation.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('15577267-b4e8-470d-aaf3-61dde949ccf6', 'photography', 'The art and technology of producing images on photosensitive surfaces, and its digital counterpart.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7817e450-7602-4fc8-a6ba-66b04afe685d', 'pin', 'A needle without an eye (usually) made of drawn-out steel wire with one end sharpened and the other flattened or rounded into a head, used for fastening.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('819ad6af-e58c-40c0-8fd8-b403ca2c64fb', 'pipe', 'Meanings relating to a wind instrument.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('25616c76-d494-4896-be8f-71803a906479', 'planning', 'To design (a building, machine, etc.).', 'The architect planned the building for the client.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f9acd474-7ea3-4d00-ad3c-6121a39b2f59', 'pleasant', 'A wit; a humorist; a buffoon.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('730545c8-26f4-400a-bd26-95753a3f5101', 'pleasure', 'A state of being pleased or contented; gratification.', 'He remembered with pleasure his home and family.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('34294867-c8df-4a4a-be5b-9d1f07569cda', 'plenty', 'A more-than-adequate amount.', 'We are lucky to live in a land of peace and plenty.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8a1191bb-168a-4644-9a37-c5890278fce1', 'plot', '(authorship) The course of a story, comprising a series of incidents which are gradually unfolded, sometimes by unexpected means.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('22f3160d-8297-4d90-96bc-a2655d8c92da', 'plus', 'A positive quantity.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8440407a-ae09-4306-b45a-16311f6c9465', 'poem', 'A literary piece written in verse.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('46f4fc08-554f-4171-8594-6659d9cea874', 'poet', 'A person who writes poems.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8b835014-5557-4744-a243-5922a0e39ea0', 'poetry', 'Literature composed in verse or language exhibiting conscious attention to patterns and rhythm.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('5126b36e-f40a-47e1-b342-c00fe12c01c1', 'poison', 'A substance that is harmful or lethal to a living organism.', 'We used a poison to kill the weeds.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c3626708-057d-4b35-b702-b8a4e69a6400', 'poisonous', 'Containing sufficient poison to be dangerous to touch or ingest.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c8d7569e-fdea-446e-8998-ccd189dd75fc', 'policy', 'A principle of behaviour, conduct etc. thought to be desirable or necessary, especially as formally expressed by a government or other authoritative body.', 'The Communist Party has a policy of returning power to the workers.', 'Society', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('edb3806e-053e-442a-a883-4f19374a4ffb', 'political', 'A political agent or officer.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('42eda206-eb2c-4f49-9191-b43cf8039d83', 'politician', 'One engaged in politics, especially an elected or appointed government official.', 'Politicians should serve the country''s interest.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('da9fb5bf-71e5-44bc-9a29-f56757124de3', 'politics', 'To engage in political activity; politick.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e9f17175-cf60-438f-a41a-02506eb1fe5f', 'port', 'A place on the coast at which ships can shelter, or dock to load and unload cargo or passengers.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('cb96e5f8-0254-42d5-b5c2-c1c3b8c173f1', 'portrait', 'A painting or other picture of a person, especially the head and shoulders.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7842f5a4-8fd0-45ee-9097-283370ad872f', 'possibly', '(modifying a clause or predicate) Perhaps; indicates that the proposition may be true (is not certainly false) regardless of any facts or circumstances known to, stated by or implied by the speaker.', 'It was possibly the costliest mistake in the organization''s history.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f464714c-2de0-4a87-b46b-0b3ac5107313', 'pot', 'A flat-bottomed vessel (usually metal) used for cooking food.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a9954982-6fb1-4ca7-9c83-001fc5194899', 'pour', 'The act of pouring.', 'The bartender''s inexpert pour left me with a pint of beer that was half foam.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d8dc72d1-6453-4fe8-ad9c-d72c3a226d18', 'poverty', 'The quality or state of being poor; lack of money', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8aff3993-bda9-489b-a97a-6a55bec77575', 'powder', 'The fine particles which are the result of reducing dry substance by pounding, grinding, or triturating, or the result of decay; dust.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9723151e-2450-4338-aab4-3fcb9877e9ed', 'powerful', 'Having, or capable of exerting power, potency or influence.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8d307f8e-0516-4993-9bd8-92f66fc877cc', 'practical', 'A part of an exam or series of exams in which the candidate has to demonstrate their practical ability', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8cd26c25-364c-4b36-ba2b-0c8b42219b0f', 'pray', 'To direct words and/or thoughts to God or any higher being, for the sake of adoration, thanks, petition for help, etc.', 'Muslims pray in the direction of Mecca.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ccf16599-5e0c-46e3-9137-32ec1ef81feb', 'prayer', 'A practice of communicating with one''s God.', 'Through prayer I ask for God''s blessings.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('85cd6b50-ea64-44b4-b2c0-3ce5779e4366', 'prediction', 'A statement of what will happen in the future.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('71a94bf5-3e9f-4cc8-8314-726a78491c78', 'prepared', 'To make ready for a specific future purpose; to set up; to assemble or equip.', 'We prepared the spacecraft for takeoff.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8c87b703-7186-4184-822a-1d8e875e0405', 'presentation', 'The act of presenting, or something presented', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('cc409926-d77c-47d3-bd85-807fe3c9b023', 'press', 'A device used to apply pressure to an item.', 'a flower press', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2b955bec-339c-4bf0-9938-9a28f2505df1', 'pressure', 'A pressing; a force applied to a surface.', 'Apply pressure to the wound to stop the bleeding.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d563ad1d-dd17-4ed1-9dd4-542e944dda89', 'pretend', 'To claim, to allege, especially when falsely or as a form of deliberate deception.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8253a690-19fc-440d-8195-e2f5a5af93c6', 'previous', 'An existing criminal record (short for "previous convictions")', 'It turned out the shoplifter had a lot of previous.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3e0b5942-9344-4ee6-bc10-00db51aa751d', 'previously', '(with present-tense constructions) First; beforehand, in advance.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('903e56db-b33e-4d49-982b-7ae0ee204412', 'priest', 'A religious clergyman (clergywoman, clergyperson) who is trained to perform services or sacrifices at a church or temple', 'The Israelite priests were descended from Moses'' brother Aaron.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('be9a29fa-6075-469a-91d0-815b6ce45ae0', 'primary', 'A primary election; a preliminary election to select a political candidate of a political party.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1546831c-0944-4b58-8142-baa0db15e594', 'prince', 'A (male) ruler, a sovereign; a king, monarch.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1bfe7ab1-484f-4dd5-b838-3e340a59b46e', 'princess', 'A female member of a royal family other than a queen, especially a daughter or granddaughter.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0bb98228-4097-496d-acdc-9aacb612e044', 'printing', 'To produce one or more copies of a text or image on a surface, especially by machine; often used with out or off: print out, print off.', 'Print the draft double-spaced so we can mark changes between the lines.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c14cb808-5e9f-4ab8-882b-c75aeb3f10bd', 'prisoner', 'A person incarcerated in a prison, while on trial or serving a sentence.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a135aac1-20a3-4cb5-a2e1-4809081b8285', 'private', 'A soldier of the lowest rank in the army.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ec3c810c-50ad-4146-b9e6-c54b48723a78', 'producer', 'An individual or organization that creates goods and services.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1ca22803-d029-48cb-945b-93d81e4fbcd4', 'production', 'The act of producing, making or creating something.', 'The widget making machine is being used for production now.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('eb9c98be-717d-4c55-891e-a0f4bb140635', 'profession', 'A declaration of belief, faith or one''s opinion, whether genuine or pretended.', 'Despite his continued professions of innocence, the court eventually sentenced him to five years.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0a3375da-3dd2-449e-afeb-e0bb62c21940', 'profit', 'Total income or cash flow minus expenditures. The money or other benefit a non-governmental organization or individual receives in exchange for products and services sold at an advertised price.', '', 'Business', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9800b255-2541-40bc-953b-1af5fa5c411b', 'promote', 'To raise (someone) to a more important, responsible, or remunerative job or rank.', 'He promoted his clerk to office manager.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('04358ca8-85e1-470f-b16b-84a9fa473017', 'proper', 'Something set apart for a special use.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('41a133e8-11a0-4595-8e8d-34c6c0a99d78', 'properly', 'In a proper manner, appropriately, suitably; correctly, justifiably', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b545fe3e-bea7-467a-ab82-e15ac87987e6', 'property', 'Something that is owned.', 'Important types of property include real property (land), personal property (other physical possessions), and intellectual property (rights over artistic creations, inventions, etc.).', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0332dd01-d2e0-48a5-bd87-da164910b7f7', 'protest', 'A formal objection, especially one by a group.', 'They lodged a protest with the authorities.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3fff4b07-c34b-44c0-b981-f742e0b21f0f', 'proud', 'Feeling honoured (by something); feeling happy or satisfied about an event or fact; gratified.', 'I am proud of Sivu’s schoolwork.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ede57006-96a6-402f-90c8-a94ab7b70dd1', 'prove', 'To proofread.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9d1a427c-b94c-44f5-b7aa-b31387e742b9', 'punish', 'To cause to suffer for crime or misconduct, to administer disciplinary action.', 'If a prince violates the law, then he must be punished like an ordinary person.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('61fa3a23-0357-465a-815c-bad1bef83fbc', 'punishment', 'The act or process of punishing, imposing and/or applying a sanction.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2bd13769-1cf2-4200-b64b-f0243e34bb60', 'qualification', 'The act or process of qualifying for a position, achievement etc.', 'Qualification for this organization is extraordinarily difficult.', 'Education', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c1b3cbed-a0af-4c8d-a689-b1fcc39438b2', 'qualified', 'Meeting the standards, requirements, and training for a position.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c8133f0f-5c64-45db-a06f-f442e43cf4ed', 'quotation', 'A fragment of a human expression that is repeated by somebody else. Most often a quotation is taken from literature or speech, but also scenes from a movie, elements of a painting, a passage of music, etc., may be quoted.', '"Where they burn books, they will also burn people" is a famous quotation from Heinrich Heine.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a73af912-c37c-4aba-903e-40c4a2a07fff', 'quote', 'A quotation; a statement attributed to a person.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('80f3d36b-7bb1-466e-9714-0aa397dea7a6', 'racing', 'To take part in a race (in the sense of a contest).', 'The drivers were racing around the track.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('dc415169-3313-4afd-b607-86a284c84a30', 'range', 'A line or series of mountains, buildings, etc.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('86701d02-7cbe-41b1-a33d-dcad00f80175', 'rare', 'A scarce or uncommon item.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6c3f87df-7c5b-4cae-beef-21b91641c3e9', 'rarely', 'Not occurring at a regular interval; seldom; not often.', 'Rarely do you ever find an eagle this far up the river.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('462d19d4-3be2-4b4e-a4de-e10e4213b594', 'reaction', 'An action or statement in response to a stimulus or other event.', 'The announcement of the verdict brought a violent reaction.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0bc8d001-aba6-4fe5-9995-337a510e5c53', 'reality', 'The state of being actual or real.', 'The reality of the crash scene on TV dawned upon him only when he saw the victim was no actor but his friend.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b1238e82-6475-48f9-9421-4a6fce97139b', 'receipt', 'The act of receiving, or the fact of having been received.', 'A balance payable on receipt of the goods.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7590c9e0-6795-4bce-98dd-c234262ad5d1', 'recommendation', 'An act of recommending.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0d778b9d-a5c5-4004-9572-1d09d85fdcfc', 'recover', 'Recovery.', '', 'Health', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('eb7521f6-b538-4ea2-a572-09bfce7147c0', 'reference', 'A relationship or relation (to something).', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7b43a064-8799-43dd-a476-a6e6e60aebc4', 'reflect', 'To bend back (light, etc.) from a surface.', 'A mirror reflects the light that shines on it.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('129386dc-bdcf-4854-86b8-8d7a083d1981', 'regularly', 'With constant frequency or pattern.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('cf95cdfe-9f01-4fc6-be9d-da5c0442ac3c', 'reject', 'Something that is rejected.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d72a8560-7f80-47f0-a209-e227f2b39183', 'relate', 'To tell in a descriptive way.', 'Please relate the circumstances of your journey here today.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('732b6470-733c-4f14-a0c3-ac5ee09b4ef0', 'related', 'To tell in a descriptive way.', 'Please relate the circumstances of your journey here today.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a1b28547-06da-4a13-885a-2ada7993ea48', 'relation', 'The manner in which two things may be associated.', 'The relation between diet and health is complex.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a827211f-c4bd-4ff0-9b9b-7ff37dc4ed0b', 'relative', 'Someone in the same family; someone connected by blood, marriage, or adoption.', 'Why do my relatives always talk about sex?', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('47133c38-3420-4284-8bcb-3db3257b4268', 'relaxed', 'To calm down.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b4c4c079-8f64-4e82-82a9-2ad11ec343dd', 'relaxing', 'To calm down.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('eb2a5204-f888-40d3-b9f4-6ff8cef0b601', 'release', 'The event of setting (someone or something) free (e.g. hostages, slaves, prisoners, caged animals, hooked or stuck mechanisms).', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e48ea16c-3ebe-49ed-bb83-afb7d5227614', 'reliable', 'Something or someone reliable or dependable', 'the old reliables', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('fd5c7a3a-74aa-4acb-89bc-b39f6a62e38c', 'religion', 'Belief in a spiritual or metaphysical reality (often including at least one deity), accompanied by practices or rituals pertaining to the belief.', 'My brother tends to value religion, but my sister not as much.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8b850b19-82b8-4274-acda-d20a81ece873', 'religious', 'A member of a religious order, i.e. a monk or nun.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('84509cbe-ec95-46cc-96f7-7da687dcf613', 'remain', '(chiefly in the plural) That which is left; relic; remainder.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e80c907f-e407-4b6d-9012-c0a862a2dca8', 'remind', 'To cause one to experience a memory (of someone or something); to bring to the notice or consideration (of a person).', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ded96e10-3167-4249-bed9-c3663d5ea467', 'remote', 'An element of broadcast programming originating away from the station''s or show''s control room.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f73c6410-dd58-41f5-99b8-e45dd475785a', 'rent', 'A payment made by a tenant at intervals in order to occupy a property.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9be9c30c-5f1b-4290-b952-a30e87a592fe', 'repeated', 'To do or say again (and again).', 'The scientists repeated the experiment in order to confirm the result.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3458ca20-1f2d-41e9-a760-2105707192d9', 'represent', 'To present again or anew; to present by means of something standing in the place of; to exhibit the counterpart or image of; to typify.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('03a23378-4690-4c1e-95e0-66266c3b5b09', 'require', 'To ask (someone) for something; to request.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8833d668-b61b-43ac-ac00-5442e0ae340c', 'reservation', 'The act of reserving, withholding or keeping back.', 'The committee authorised the reservation of funds.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9193b43d-1a27-433c-9ce6-d067cd3cf6c8', 'resource', 'Something that one uses to achieve an objective, e.g. raw materials or personnel.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('55a4aef4-f22c-4e9a-81d1-a892358a8ad0', 'respect', 'An attitude of consideration or high regard', 'He is an intellectual giant, and I have great respect for him.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('77c2f8e0-9ae8-4890-9ecd-13351a038035', 'responsibility', 'The state of being responsible, accountable, or answerable.', 'Responsibility is a heavy burden.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9fc476f2-09a9-4525-9d75-a81fba1f0aa2', 'responsible', 'The individual who bears the responsibility for something.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('646a951e-eac2-401b-876d-e190fb9a8bc2', 'retire', 'The act of retiring, or the state of being retired.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('be473057-3344-4737-aa89-c43085e8cac5', 'retired', 'To stop working on a permanent basis, usually because of old age or illness.', 'Having made a large fortune, he retired.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9071cb2a-c394-4f1b-b0de-b92eecaa5d1c', 'revise', 'A review or a revision.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d6f1370b-52de-4fb9-af3a-b5158410ef9f', 'rights', 'That which complies with justice, law or reason.', 'We''re on the side of right in this contest.', 'Society', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b4400205-bc78-4aba-a075-a131252e8252', 'risk', 'A possible adverse event or outcome', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0877e79e-4d06-42f4-85b5-c090f012ce1c', 'robot', 'A machine built to carry out some complex task or group of tasks by physically moving, especially one which can be programmed.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('bc5ec9fa-9c70-4ea6-b546-1170073d5495', 'roll', 'The act or result of rolling, or state of being rolled.', 'Look at the roll of the waves.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8320ebaa-b712-4a8b-97b6-c3e1fe57f83c', 'romantic', 'Of or dealing with languages or cultures derived from Roman influence and Latin: Italian, French, Portuguese, Spanish, Romanian, Catalan, Occitan, Corsican, etc.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a9dfdf13-b42f-46e4-b619-09df1b246f9a', 'rope', 'Thick strings, yarn, monofilaments, metal wires, or strands of other cordage that are twisted together to form a stronger line.', 'Nylon rope is usually stronger than similar rope made of plant fibers.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('dd262608-5a29-4ef4-83b3-27fc31ba39a0', 'rough', 'The unmowed part of a golf course.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0f9a3d12-da91-46f6-b9af-97d49f174a64', 'row', 'A line of objects, often regularly spaced, such as seats in a theatre, vegetable plants in a garden etc.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a392a694-cfef-4762-8459-516f03ffbffa', 'royal', 'A royal person; a member of a royal family.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('24fafc8b-b941-4b57-b320-b54671f386a6', 'rugby', '(usually uncountable) A form of football in which players can hold or kick an ovoid ball. The ball cannot be handled forwards and points are scored by touching the ball to the ground in the area past their opponent’s territory or kicking the ball between goalposts and over a crossbar.', 'The scrum is a distinctive element of rugby.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ac1baaa7-56cd-4c7b-ab09-1c3f524dbb4b', 'safety', 'The condition or feeling of being safe; security; certainty.', 'If you push it to the limit, safety is not guaranteed.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ddd00859-5336-4b13-ab83-a29963413963', 'sailor', 'A person in the business of navigating ships or other vessels', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('27ea62df-1950-4dc4-b2ae-20d9cefd00ff', 'sample', 'A part or snippet of something taken or presented for inspection, or shown as evidence of the quality of the whole; a specimen.', 'a blood sample', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('cb687345-d543-43c1-a4f1-22037cc96958', 'sand', 'Rock that is ground more finely than gravel, but is not as fine as silt (more formally, see grain sizes chart), forming beaches and deserts and also used in construction.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0b5c5735-c8ef-4d0d-991b-8e3143773b06', 'scan', 'Close investigation.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('99ab23d6-f818-4f8d-8893-8b8a721a40b9', 'scientific', 'Of, or having to do with science.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('65e79cea-48ba-4b4d-9a20-bb72c8da0783', 'script', 'A writing; a written document.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('47050ab1-e30f-4e02-aee1-21b6fdee2f8f', 'sculpture', 'A three dimensional work of art created by shaping malleable objects and letting them harden or by chipping away pieces from a rock (sculpting).', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f0fde6f3-8f59-44d0-a2ea-242181d237e9', 'secondary', 'Any flight feather attached to the ulna (forearm) of a bird.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3938ef71-56e2-4cd3-ac27-f93a0ea209fd', 'security', 'The condition of not being threatened, especially physically, psychologically, emotionally, or financially.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6c9fcda8-6bb7-4645-9e2f-b3fafaa37ac8', 'seed', 'A fertilized and ripened ovule, containing an embryonic plant.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9c96dc03-d02c-4110-a8b1-600a0240818c', 'sensible', 'Sensation; sensibility.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('06cc29f1-bdbc-4ac7-8e74-ddfa77ecaecb', 'seriously', '(manner) In a serious or literal manner.', 'He was hoping that we would take him seriously.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('5f6a701e-1e69-4d8c-8e41-6c2b3cda79a8', 'servant', 'One who is hired to perform regular household or other duties, and receives compensation. As opposed to a slave.', 'There are three servants in the household, the butler and two maids.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c9d52067-8679-42c1-8e24-674908c38260', 'set', 'To put (something) down, to rest.', 'Set the tray there.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1175bcbf-f787-4a7b-9f03-8d543b0f960c', 'setting', 'To put (something) down, to rest.', 'Set the tray there.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0384cda5-b566-4adb-83c5-79415fde9f97', 'sex', 'A category into which sexually-reproducing organisms are divided on the basis of their reproductive roles in their species.', 'The effect of the medication is dependent upon age, sex, and other factors.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a9db9c06-ce98-47fd-ae03-024a7b3d510a', 'sexual', 'A species which reproduces by sexual rather than asexual reproduction, or a member of such a species.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('10fd7907-97b1-4ba8-89a9-e5510773fceb', 'sharp', 'The symbol ♯, placed after the name of a note in the key signature or before a note on the staff to indicate that the note is to be played a semitone higher.', 'The pitch pipe sounded out a perfect F♯ (F sharp).', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a55683cc-6e64-43a7-b481-67c19d3ed712', 'shelf', 'A flat, rigid structure, fixed at right angles to a wall or forming a part of a cabinet, desk etc., and used to support, store or display objects.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ba01cce5-2dda-4155-bf47-7048a5e52067', 'shell', 'A hard external covering of an animal.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('be8b4e75-2637-4006-a8e4-d316abae4b21', 'shift', 'A modifier key whose main function is shifting between two or more functions of any of certain other keys (usually by pressing Shift and the other button simultaneously).', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('59bc47b3-e2a2-487c-a1f5-419faed557c2', 'shine', 'Brightness from a source of light.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1ccc2dc1-7abb-4224-a31b-02c674a3f01a', 'shiny', 'Anything shiny; a trinket.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ac05a2be-3c4f-4e81-a893-e938b5120828', 'shoot', 'The emerging stem and embryonic leaves of a new plant.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2ad5306a-8427-4d08-b2ec-b95a0cc56ce9', 'shy', 'An act of throwing.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4d357caa-3083-4dfa-bf51-539b38c3c1b3', 'sight', '(in the singular) The ability to see.', 'He is losing his sight and now can barely read.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4fcd36b7-3da9-460d-818b-53386d739d02', 'signal', 'A sequence of states representing an encoded message in a communication channel.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9e2223a1-bbd4-44c0-b68a-505e30cd1e72', 'silent', 'That which is silent; a time of silence.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('36e1a755-96ea-4f42-a141-fa06d030ab0f', 'similarity', 'Closeness of appearance to something else.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('08a05386-218a-4699-9438-f87bf2f91149', 'similarly', '(manner) In a like style or manner.', 'The sisters dressed similarly.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('59681e54-47fc-440b-8dd0-2f0620c2bb34', 'simply', '(manner) In a simple way or state; considered in or by itself; without addition; alone.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7d2bbb67-3a61-42a5-a7c4-a3c2720d7447', 'sink', 'A basin used for holding water for washing.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('aa254c24-7b14-40eb-af43-0084cdb02b30', 'slice', 'That which is thin and broad.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('54eb7cef-8657-43ab-a4dd-66db0e3b9902', 'slightly', 'Slenderly; delicately.', 'He was slightly built, but tall.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f4d999ee-0182-4418-9078-ae085d24d084', 'smart', 'To hurt or sting.', 'After being hit with a pitch, the batter exclaimed "Ouch, my arm smarts!"', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6a347820-12c7-4b37-8132-27e3b30d268d', 'smooth', 'Something that is smooth, or that goes smoothly and easily.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8b1705fd-2ec0-43f9-8c5d-271e94315fbf', 'software', 'Encoded computer instructions, usually modifiable (unless stored in some form of unalterable memory such as ROM).', '', 'Technology', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f01dedfe-acd6-4054-812a-b2c196c17820', 'soil', 'A mixture of mineral particles and organic material, used to support plant growth.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9b52efcf-1e2e-4638-a11b-bcbf511cafb9', 'solid', 'A substance in the fundamental state of matter that retains its size and shape without need of a container (as opposed to a liquid or gas).', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7f8b6ccd-d0d8-4d10-9ea8-cad1dbe3d353', 'southern', 'Someone from one of the states which seceded in 1861 and briefly formed the Confederate States of America, or, more broadly, from some neighboring states as well (but excluding geographically-southerly states like Arizona); compare the South.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('026c4d36-1562-44e0-b714-30caf5d55471', 'species', 'Type or kind. (Compare race.)', 'the male species', 'Environment', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('26c961cd-0724-4faf-9163-2b4c072ddb2a', 'specifically', 'In a specific manner, applying to or naming a particular thing or things, expressly, explicitly', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('bda0bc5e-441d-40c5-8833-c79929439a62', 'spending', 'Present participle of spend, expenditure.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('64316acd-fe52-42a1-b65c-d45809436c94', 'spicy', 'Of, pertaining to, or containing spice.', 'He prepared a spicy casserole.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('25da277c-b944-4688-b8e6-25c021aba008', 'spirit', 'The soul of a person or other creature. What moves through experience into self-definition as souls purpose.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('64edaae0-1df2-4023-8c36-23e7387ddc22', 'spoken', 'To communicate with one''s voice, to say words out loud.', 'I was so surprised I couldn''t speak.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('bfc57070-4493-4a09-b23d-a3c1b60a0b69', 'spot', 'A round or irregular patch on the surface of a thing having a different color, texture etc. and generally round in shape.', 'The leopard is noted for the spots of color in its fur.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('5a1681e3-8101-4a3a-b473-9bf59a5fb275', 'spread', 'The act of spreading.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1138da84-0f60-4179-be04-d50aef2ee71c', 'stadium', 'A venue where sporting events are held.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('07a35e20-4c5a-400e-8845-88c9d1dd274b', 'staff', '(plural staffs or staves) A long, straight, thick wooden rod or stick, especially one used to assist in walking.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('00fc957d-cac0-4aa7-9460-092a636e061c', 'standard', 'A principle or example or measure used for comparison.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('09790318-c2f4-4803-a391-aa589f16a205', 'statistic', 'A single item in a statistical study.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4520ab5a-b770-435a-845d-813bbecc5c0a', 'statue', 'A three-dimensional work of art, usually representing a person or animal, usually created by sculpting, carving, molding, or casting.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('cc6043a0-940e-4021-9d90-14461a780cc8', 'stick', 'An elongated piece of wood or similar material, typically put to some use, for example as a wand or baton.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('845b4a1a-bc70-47f9-a1b8-898c94aafc87', 'stranger', 'Not normal; odd, unusual, surprising, out of the ordinary.', 'He thought it strange that his girlfriend wore shorts in the winter.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('68a1fcb5-b3cc-487a-a272-9133509c7bd4', 'strength', 'The quality or degree of being strong.', 'It requires great strength to lift heavy objects.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4bcd5f4e-e68f-449a-adda-4e93b343f99e', 'string', 'A building, wing or dependency set apart and adapted for lodging and feeding (and training) animals with hoofs, especially horses.', 'There were stalls for fourteen horses in the squire''s stables.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a2ad1931-01e4-4934-8cd6-4e906293e664', 'strongly', 'In a strong or powerful manner.', 'In the third race, Renowned Blaze finished strongly to win, paying sixteen dollars.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('5a69790b-e01a-42de-b83f-37fcb3416655', 'studio', 'An artist’s or photographer’s workshop or the room in which an artist works.', 'His studio was cramped when he began as an artist.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e5402995-479d-48d5-8000-1cd9ed0466bb', 'stuff', 'Miscellaneous items or objects; (with possessive) personal effects.', 'What is all that stuff on your bedroom floor?  He didn''t want his pockets to bulge so he was walking around with all his stuff in his hands.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ceae2bf6-1b46-45a1-8be8-62c1ac7a1892', 'substance', 'Physical matter; material.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1872534a-4fba-44aa-8bcf-abc6999c51a8', 'successfully', 'In a successful manner; with success; without failing.', 'He successfully climbed the mountain.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('aac373d5-8a10-4b87-ba45-1cfd23bced3f', 'sudden', 'An unexpected occurrence; a surprise.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('54bcfad4-2e96-43cd-9fa8-ec097ed3b7e5', 'suffer', 'To undergo hardship.', 'Is anyone here afraid of suffering hardship?', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('96298e86-4f51-4a57-b363-cd252954547c', 'suitable', 'Having sufficient or the required properties for a certain purpose or task; appropriate to a certain occasion.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('44edefdf-39d5-4640-a5f0-ef898527afb3', 'summarize', 'To prepare a summary of (something).', 'Jim was asked to summarize the document by Wednesday.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('5d545227-db43-48d0-b188-7d037e98508e', 'summary', 'An abstract or a condensed presentation of the substance of a body of material.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('df78d899-b6f3-48e9-9e05-a342ef4660dd', 'supporter', 'A person who gives support to someone or something.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('efc290cf-b049-4265-88e6-08b61e945ba3', 'surely', 'Without fail.', 'slowly but surely', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b6a80253-b3ef-42ab-bf6f-15a2954e3769', 'surface', 'The overside or up-side of a flat object such as a table, or of a liquid.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('dacf1eeb-dcc7-4c03-939c-238adc659a08', 'surgery', 'A procedure involving major incisions to remove, repair, or replace a part of a body.', 'Many times surgery is necessary to prevent cancer from spreading.', 'Health', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('340d24be-d598-4e64-8e45-826954183117', 'survive', 'Of a person, to continue to live; to remain alive.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('04cd34c9-1b4c-4dd1-a35b-f9343fa11632', 'switch', 'A bundle of thin sticks, typically made of wood, sometimes bond in such a way that binding can be moved so that it varies the tightness of the binding.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('dc2afbf4-62da-4310-896f-44f74edd8da8', 'symptom', 'A perceived change in some function, sensation or appearance of a person that indicates a disease or disorder, such as fever, headache or rash.', '', 'Health', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('5a7b9037-9475-44fd-9a4f-208abefa152d', 'tail', 'The caudal appendage of an animal that is attached to its posterior and near the anus.', 'Most primates have a tail and fangs.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b707442d-eab2-420b-bb1e-614af89dfefd', 'talent', 'A marked natural ability or skill.', 'He has a real talent for drawing.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('96b494e7-8b21-4ea5-b38a-31de677f349b', 'talented', 'Endowed with one or more talents.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2706805c-08da-4ede-a985-c77a650e5fcd', 'tape', 'Flexible material in a roll with a sticky surface on one or both sides; adhesive tape.', 'Hand me some tape. I need to fix a tear in this paper.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('77c6b0ce-9a2c-49d6-a5fe-e668e72e4c7a', 'tax', 'Money paid to the government other than for transaction-specific goods and services.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('87bdec2c-9fab-4d3b-b7a5-cd919f64c329', 'technical', 'A pickup truck with a gun mounted on it.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b1d5ec67-82f6-49c3-9279-be545963ed52', 'technique', 'The practical aspects of a given art, occupation etc.; formal requirements.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6b33c16e-d489-440f-a686-f671d7f79a66', 'tend', '(Old English law) To make a tender of; to offer or tender.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('fb2b9e65-1455-4107-8773-c90ce790f130', 'tent', 'A pavilion or portable lodge consisting of skins, canvas, or some strong cloth, stretched and sustained by poles, used for sheltering people from the weather.', 'We were camping in a three-man tent.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('132b3cba-f118-4dc9-a9a3-cb407f139d35', 'theirs', 'That which belongs to them; the possessive case of they, used without a following noun.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('83731259-4456-4f5b-94c9-2e7816c67162', 'theme', 'A subject of a talk or an artistic piece; a topic.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('81803b3e-16bd-4fa2-9ca2-f2e79a4db432', 'theory', 'A description of an event or system that is considered to be accurate.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a454ef73-3680-464d-85cb-f2ce81415541', 'therefore', 'For that or this purpose, referring to something previously stated.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('09b42f80-b2c8-495f-a271-fbf7941a5190', 'though', 'Despite that; however.', 'I will do it, though.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('fd120a67-02c4-4e87-9d56-664c855421cf', 'throat', 'The front part of the neck.', 'The wild pitch bounced and hit the catcher in the throat.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('30080097-ec0d-47f2-8bb1-0787c17dc358', 'throughout', 'Completely through, right the way through.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('72a45c3c-43c6-449e-bf83-806a62dde526', 'till', 'Until; to, up to; as late as (a given time).', 'I have to work till eight o''clock tonight.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1d7870dd-9511-487e-818a-a90deaf1a4b4', 'tin', 'A malleable, ductile, metallic element, resistant to corrosion, with atomic number 50 and symbol Sn.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('5eab1da1-6a2c-4096-a9e0-0d8afcdb93f6', 'tiny', 'A small child; an infant.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7d1d12ce-e872-4078-b197-47ea9c230100', 'toe', 'Each of the five digits on the end of the foot.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7936c2dc-58f7-4479-b6fa-023f99c3781d', 'tongue', 'The flexible muscular organ in the mouth that is used to move food around, for tasting and that is moved into various positions to modify the flow of air from the lungs in order to produce different sounds in speech.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('04c35f7d-cf86-4cde-9ec5-91544a63bfb0', 'total', 'An amount obtained by the addition of smaller amounts.', 'A total of £145 was raised by the bring-and-buy stall.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1e3e188c-3719-48d9-868a-75490e6f2ff8', 'totally', 'To the fullest extent or degree.', 'They''ve totally demolished the bank on Main Street.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('92dcbea6-4399-4078-ad64-e95a82d29a3c', 'trade', 'Buying and selling of goods and services on a market.', '', 'Business', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('479b9649-07c7-49b5-868f-17a530137d78', 'translate', 'In Euclidean spaces: a set of points obtained by adding a given fixed vector to each point of a given set.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('33d6145d-b7e2-4212-a8a0-3291351abda2', 'translation', 'The act of translating, in its various senses:', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('654ae502-7de6-46bf-894e-add4131d87db', 'treat', 'An entertainment, outing, food, drink, or other indulgence provided by someone for the enjoyment of others.', 'Here are some healthy Halloween treats for ghouls and witches of all ages.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('cb4e2b84-40ee-4c6f-985e-007a3a91801a', 'treatment', 'The process or manner of treating someone or something.', 'He still has nightmares resulting from the treatment he received from his captors.', 'Health', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2a924aa0-90b8-41be-8107-8966f804e5cc', 'trend', 'An inclination in a particular direction.', 'the trend of a coastline', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e4eb2812-b9ae-4ed9-8556-225f06ef7566', 'trick', 'Something designed to fool or swindle.', 'It was just a trick to say that the house was underpriced.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c859335b-3f95-4e0c-ac78-f12503d47860', 'truth', 'True facts, genuine depiction or statements of reality.', 'The truth is that our leaders knew a lot more than they were letting on.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('046dd77e-17fc-4e0a-9d72-e31ff4b355c8', 'tube', 'Anything that is hollow and cylindrical in shape.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b9ff84e9-ac2d-412e-9c1f-22adfc37755d', 'typically', 'In a typical or common manner.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('35a95890-b9c7-4438-9450-1734838a754d', 'tyre', 'The ring-shaped protective covering around a wheel which is usually made of rubber or plastic composite and is either pneumatic or solid.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('42e28745-e77d-45b0-b2aa-d34a81da5ac2', 'ugly', 'Ugliness.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('64955ef4-1506-4078-83ee-cccb03a933a2', 'unable', 'Not able; lacking a certain ability.', 'Are you unable to mind your own business or something?', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3a13560c-7701-47fb-96d8-5f07a341316d', 'uncomfortable', 'Not comfortable; causing discomfort.', 'The class squirmed and fidgeted in the uncomfortable new chairs.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4b7c6da0-7be6-4f8c-8c12-55d529ed664e', 'underwear', 'Clothes worn next to the skin, underneath outer clothing.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('be20072f-8b4f-4baa-9593-7c8a52eb59fe', 'unemployed', 'Unemployed people.', 'The unemployed are a growing portion of the population.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('34ab28dc-a428-48f9-9c09-1efbc7dcb45f', 'unemployment', 'The state of having no job; joblessness.', 'Unemployment made Jack depressed.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ef4b3970-c7a5-432d-ac75-a8c3da10a2c4', 'unfair', 'To make ugly', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('75a85004-0d8b-4652-9cc7-45beb0f6ff69', 'union', 'The act of uniting or joining two or more things into one.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('625b89af-0776-4436-bae1-445ae94fac9b', 'unless', 'Except on a specified condition; if not.', 'I’m leaving unless I get a pay rise (AmE: raise).', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('5d143802-c214-4f29-81b4-bd8fc38ecf4b', 'unlike', 'Something that is not like something else; something different.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('109f92c2-ccf2-4c23-bfdd-23a49c9b0d77', 'unlikely', 'Something or somebody considered unlikely.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7bec6966-3c03-4e5c-a8a1-3d24cc810429', 'unnecessary', 'Not needed or necessary.', 'The automatic child-frightener made clowns unnecessary.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7ee66b29-6560-478e-8b40-688d1e2871ab', 'unpleasant', 'Not pleasant.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('5087296c-9b37-4ab4-9cc7-df9d4f7630b9', 'update', 'An advisement providing more up-to-date information than currently known.', 'He gave me an update on the situation in New York.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f881cafe-1b00-4fc9-b916-f5ddf811b02f', 'upload', 'Such a file transfer.', '', 'Technology', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('98c079dc-9edc-4264-9280-3081033aeb2d', 'upon', 'Being the target of an action.', 'He was set upon by the agitated dogs', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('5da10355-e3e8-4163-9d09-a803e038c827', 'upset', 'Disturbance or disruption.', 'My late arrival caused the professor considerable upset.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d11f1ee6-f3b5-47f8-9aee-27e33232889f', 'used', 'To utilize or employ.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e95d72f5-140f-4111-a5f6-a2c64f312bbd', 'valuable', 'A personal possession such as jewellery, of relatively great monetary value; — usually used in plural form.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('fb348a95-95d9-4400-a8fd-7b1dc25c8668', 'value', 'The quality (positive or negative) that renders something desirable or valuable.', 'The Shakespearean Shylock is of dubious value in the modern world.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('dd51a4bc-5569-4a67-976e-58e102b9d3bf', 'various', 'Having a broad range (of different elements).', 'The reasons are various.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c2cd47f8-8f78-4142-a522-7f67d07713c6', 'version', 'A specific form or variation of something.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3220775a-4241-4a35-b612-5e6be879b251', 'victim', 'One that is harmed—killed, injured, subjected to oppression, deceived, or otherwise adversely affected—by someone or something, especially another person or event, force, or condition; in particular:', 'the youngest victims of the brutal war', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6a212514-ae68-40ff-87a1-ad6db1959dea', 'viewer', 'Someone who views a spectacle; an onlooker or spectator.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('808e587b-fc16-4c36-872f-2fbf8a71f283', 'violent', 'An assailant.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('5cc7fff3-4e59-4a47-8d41-1cb65246e4c9', 'visa', 'A permit to enter and leave a country, normally issued by the authorities of the country to be visited.', '', 'Travel', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1a63f055-ad84-4de3-988b-5c0209b83f54', 'volunteer', 'One who enters into, or offers for, any service of his/her own free will, especially when done without pay.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('730495f4-ca73-46b5-88a7-bb19914cd05d', 'vote', 'A formalized choice on matters of administration or other democratic activities', 'One occasion indicative votes were used was in 2003 when MPs were presented with seven different options on how to reform the House of Lords.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('28987003-f287-40c3-bc96-d6656af4fef7', 'warn', 'To make (someone) aware of (something impending); especially:', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2f5692c7-a9eb-48e2-b24a-f30e36dc5598', 'warning', 'To make (someone) aware of (something impending); especially:', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0e7989a3-f390-4dfc-ae10-a2051f80a3f5', 'waste', 'Excess of material, useless by-products or damaged, unsaleable products; garbage; rubbish.', '', 'Environment', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8bb8c0cb-e944-4d53-bbaf-41e837cabd91', 'weapon', 'An instrument of attack or defense in combat or hunting, e.g. most guns, missiles, or swords.', 'The club that is now mostly used for golf was once a common weapon.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('38b103ee-5bbf-42d3-bd4e-3c800baf5e19', 'weigh', 'To determine the weight of an object.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c4b39d4a-bb92-4cc8-8caf-16251c7ee1e8', 'western', 'A film, or some other dramatic work, set in, the historic (c. 1850-1910) American West (west of the Mississippi river) focusing on conflict between whites and Indians, lawmen and outlaws, ranchers and farmers, or industry (railroads, mining) and agriculture.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('165cf9b9-a0d2-4007-83ef-80e510a00c3d', 'whatever', 'Unexceptional or unimportant; blah.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('dbeb35db-b821-4705-9e6a-9c26cbead49b', 'whenever', '(interrogative) When ever: emphatic form of when.', 'Whenever will I find time to finish that jigsaw?', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('485f2777-6c88-4658-ab41-56f3639c35a3', 'whether', 'Which of two.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('bbf75e73-b680-4776-8d19-4d876cec80ab', 'wing', 'An appendage of an animal''s (bird, bat, insect) body that enables it to fly; a similar fin at the side of a ray or similar fish', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('243f3803-a98f-463a-b80f-5b565585eaec', 'within', 'In the context of which the present document or ruling is made.', 'the within appeal', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('cb2e6f5d-fe75-46b4-809b-c927502caaf9', 'wonder', 'Something that causes amazement or awe; a marvel.', 'Wonders of the World seem to come in sevens.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4d1a773b-ceea-4f93-83d7-2062a13e71da', 'wool', 'The hair of the sheep, llama and some other ruminants.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7da9fe36-218c-48e3-bd58-36a5cef82755', 'worldwide', 'Spanning the world; global.', 'A large meteorite impact would cause worldwide extinction of life.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a1006051-909f-48ed-973b-01cd79cd447a', 'worth', 'Value.', 'I’ll have a dollar''s worth of candy, please.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('5f768255-9cc8-4d4e-ad7e-4ca13ec3d578', 'written', 'To form letters, words or symbols on a surface in order to communicate.', 'The pupil wrote his name on the paper.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6b7ffa2a-c39e-41bf-ae3e-d45cb7fee57a', 'yard', 'A small, usually uncultivated area adjoining or (now especially) within the precincts of a house or other building.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('632b942a-e005-43fa-b892-41cbbcdcc4cb', 'youth', 'The quality or state of being young.', 'Her youth and beauty attracted him to her.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e5ce6f55-58fe-43c0-aa52-3f4453f0fd80', 'meshwork', 'A net; an assembly of meshes.', 'A dense meshwork structure is formed.', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9ed09e43-057f-41a7-ba10-c7adfdb403ff', 'taut', 'To make taut; to tauten, to tighten.', '', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d152b03d-e9a5-4630-8cf7-bbbbbf30989a', 'stir', 'The act or result of stirring (moving around the particles of a liquid etc.)', 'Can you give the soup a little stir?', 'General', 'B1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ebdd7398-fd7b-4ab9-821f-c163dc2ea51f', 'abandon', 'To give up or relinquish control of, to surrender or to give oneself over, or to yield to one''s emotions.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('99b1f7c4-94a0-41fe-8f17-0a48b76943e0', 'absolute', 'That which is independent of context-dependent interpretation, inviolate, fundamental.', 'moral absolutes', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2a9bad42-89b2-48ed-86e1-5b278bb4ee65', 'absorb', 'To include so that it no longer has separate existence; to overwhelm; to cause to disappear as if by swallowing up; to incorporate; to assimilate; to take in and use up.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('149610b3-2450-41b6-96db-191cac793edb', 'abstract', 'An abridgement or summary of a longer publication.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('05fbbb11-1a49-4b68-b978-6cd1734d80ba', 'accent', 'A higher-pitched or stronger articulation of a particular syllable of a word or phrase in order to distinguish it from the others or to emphasize it.', 'In the word "careful", the accent is placed on the first syllable.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a64459f5-9b51-4476-bddf-a7e952cd954f', 'acceptable', 'Worthy, decent, sure of being accepted or received with at least moderate pleasure', 'We need to find an acceptable present for Jeff.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4a004ddc-7610-454f-b3fb-6cdce39df80b', 'accidentally', 'In an accidental manner; by chance, unexpectedly.', 'He discovered penicillin largely accidentally.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('91825e0d-9bbc-4ea6-bed0-4b0c7e41b629', 'accommodate', 'To render fit, suitable, or correspondent; to adapt.', 'to accommodate ourselves to circumstances', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4aa6f852-4fd8-4447-b53c-e836fba47b63', 'accompany', 'To go with or attend as a companion or associate; to keep company with; to go along with.', 'Geoffrey accompanied the group on their pilgrimage.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8563646f-2e18-419c-8787-2d272b624092', 'accomplish', 'To finish successfully.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b58a60f8-da42-4b06-9797-fd8b345f2d21', 'accountability', 'The state of being accountable; liability to be called on to render an account; accountableness; responsible for; answerable for.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e3a14ab9-ef4c-4f0c-9cce-88efacf22c0d', 'accountant', 'One who renders account; one accountable.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6d47c071-d0fe-48dd-8c03-1e9f2e00a3e3', 'accuracy', 'The state of being accurate; being free from mistakes, this exemption arising from carefulness; exactness; correctness', 'The value of testimony depends on its accuracy.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9a552d58-7753-42ff-8ca0-e42b2b813770', 'accurate', 'Telling the truth or giving a true result; exact; not defective or faulty', 'accurate knowledge', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c63f5895-8d19-42af-8d89-7838524f0c89', 'accurately', 'In an accurate manner; exactly; precisely; without error or defect.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('fd8f377a-87d9-4c4a-b06a-bae11d875a8e', 'accusation', 'The act of accusing.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c4f11abe-f5bb-423b-9084-ba7ccccf82c0', 'accuse', 'Accusation.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('bb28c052-f077-4aa1-bcd1-e76c0e09ef0b', 'acid', 'A sour substance.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a2804b42-15c9-4017-b580-faf37c77362c', 'acknowledge', 'To admit the knowledge of; to recognize as a fact or truth; to declare one''s belief in', 'to acknowledge the being of a god', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0cb3cb92-cd74-405f-8e9a-8fc5d4d34504', 'acquire', 'To get.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9b132ad6-8a8a-4c5b-a65b-4fe0a4977f64', 'acquisition', 'The act or process of acquiring.', 'The acquisition of sports equipment can be fun in itself.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('62cc5b13-b572-452a-8ea1-dabf7eac5650', 'activate', 'To encourage development or induce increased activity; to stimulate.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('5d49185c-81c9-4c97-b1c6-168541951f7b', 'actual', 'An actual, real one; notably:', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2f234ef5-e68d-4208-b067-27ee6bd6c4fe', 'acute', 'A person who has the acute form of a disorder, such as schizophrenia.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d577a715-8e5a-468b-9566-f79f35b70239', 'adapt', 'To make suitable; to make to correspond; to fit or suit', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7163d3b9-616e-4c7a-ba58-0f1c9ca1559f', 'addiction', 'A state that is characterized by compulsive drug use or compulsive engagement in rewarding behavior, despite negative consequences.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2c34c6c5-eb6f-4989-967b-4159b06db531', 'additional', 'Something added.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d15c327e-57e0-421f-a5a4-5ea94f8ae28d', 'additionally', 'By way of addition; in addition to; also.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('931f0cc2-3957-40b3-8d89-4804279dd3ab', 'adequate', 'To equalize; to make adequate.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('fd028a4d-0f34-4aae-a477-3762f8a7196d', 'adequately', 'In an adequate manner.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('5358e38c-4345-42b6-ab19-e68bcf48a563', 'adjust', 'To modify.', 'Morimoto''s recipes are adjusted to suit the American palate.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('902fad39-3cea-49c0-8c9d-b14acaca7bab', 'budget', 'The amount of money or resources earmarked for a particular institution, activity or time-frame.', '', 'Business', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8a764f10-af9e-4a7d-ab79-93e9144afd40', 'administration', 'The act of administering; government of public affairs; the service rendered, or duties assumed, in conducting affairs; the conducting of any office or employment; direction.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('186116ea-feb7-4b15-a683-c30b06e03e35', 'adopt', 'To take by choice into relationship (a child, heir, friend, citizen, etc.)', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b18b5dbb-8521-4afe-99d7-85131576b2dc', 'advance', 'A forward move; improvement or progression.', 'an advance in health or knowledge', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f1dc0500-7669-48ec-9ae7-3d5d801208ff', 'aesthetic', 'The study of art or beauty.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('90264bd3-eade-4069-99b6-ce9829d90a3e', 'affair', '(often in the plural) Something which is done or is to be done; business of any kind, commercial, professional, or public.', 'a difficult affair to manage', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('83533849-c7d0-4586-acac-c05552755e58', 'affordable', 'Able to be afforded; inexpensive or reasonably priced.', 'an affordable vacation in the local area', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4e7e2864-1e4e-4b6e-b563-d70bb42b4f80', 'afterwards', '(temporal location) At a later or succeeding time.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('aee963a4-7410-4129-a4bd-fa201d7ef10f', 'agency', 'The capacity, condition, or state of acting or of exerting power.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('db2fd767-e33d-4dbb-acdf-063f14fd6cb0', 'agenda', 'A temporally organized plan for matters to be attended to.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('5d020c24-16a8-435e-9a62-9fa7eee454c6', 'aggressive', 'Characterized by aggression; unjustly attacking; prone to behave in a way that involves attacking or arguing.', 'an aggressive policy, war, person, nation', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b585185d-2683-464a-affa-d68edea4779b', 'agriculture', 'The art or science of cultivating the ground, including the harvesting of crops, and the rearing and management of livestock', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7cd47979-a326-4b22-90a0-a35ce09b39c5', 'aid', 'Help; assistance; succor, relief.', 'He came to my aid when I was foundering.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4c0561ea-407f-422f-95d5-ef4589c06e48', 'aids', 'Help; assistance; succor, relief.', 'He came to my aid when I was foundering.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('99633405-cae5-4375-b659-202d466aa12d', 'aircraft', 'A vehicle capable of atmospheric flight due to interaction with the air, such as buoyancy or lift', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ea8a8dfd-fb10-4e9c-905f-51174925bbba', 'algorithm', 'A collection of ordered steps that solve a mathematical problem. A precise step-by-step plan for a computational procedure that possibly begins with an input value and yields an output value in a finite number of steps.', '', 'Technology', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('bcecf2ef-b440-4f68-af31-81ba9f47d34d', 'alien', 'Any life form of extraterrestrial or extradimensional origin.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('34d53954-2dec-47c7-982f-b94f898ee6c4', 'allegation', 'An assertion, especially an accusation, not necessarily based on facts.', 'She put forth several allegations regarding her partner in hopes of discrediting his actions.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a28824eb-2de6-43fe-9cbb-7a45c700deab', 'alongside', 'Along the side; by the side; side by side with.', 'Ahoy! Bring your boat alongside mine.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2c6457fa-bdf3-4299-97c5-7bbb6a5b97c8', 'alter', 'To change the form or structure of.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8c721f2f-e951-493e-a0bf-afa25879e11b', 'altogether', 'Without exception; wholly; completely.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1d9f044b-d48b-44bd-bec9-f67f68583360', 'ambulance', 'An emergency vehicle designed for transporting seriously ill or injured people to a hospital.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7710ccea-90cd-472a-a80a-af92ac422609', 'amusing', 'To entertain or occupy in a pleasant manner; to stir with pleasing emotions.', 'I watch these movies because they amuse me.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b09763d6-a1a2-4dfa-b322-35783f189379', 'analyst', 'Someone who analyzes.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d8867144-a16f-4fc3-8602-8ce4062d65a6', 'ancestor', 'One from whom a person is descended, whether on the father''s or mother''s side, at any distance of time; a progenitor; a forefather.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3b8ca702-b2d9-4f77-8323-850b40bd48ec', 'anger', 'A strong feeling of displeasure, hostility or antagonism towards someone or something, usually combined with an urge to harm.', 'You need to control your anger.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f9732564-311c-4d4a-a319-5c78e9549b7d', 'angle', 'A figure formed by two rays which start from a common point (a plane angle) or by three planes that intersect (a solid angle).', 'the angle between lines A and B', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0ea2d8e7-c7a9-4c4a-a4a5-d24c0ac2e9e9', 'animation', 'The act of animating, or giving life or spirit.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b0f32c77-208b-433f-9bd3-200b60250204', 'anniversary', 'A day that is an exact number of years (to the day) since a given significant event occurred. Often preceded by an ordinal number indicating the number of years.', 'Today is the fiftieth anniversary of the end of the war.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c005037e-95de-41e4-8f12-8e2d4d0f408f', 'annual', 'An annual publication; a book, periodical, journal, report, comic book, yearbook, etc., which is published serially once a year, which may or may not be in addition to regular weekly or monthly publication.', 'I read the magazine, but I usually don''t purchase the annuals.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ae3c519d-db46-4367-bb26-70b1cc87687e', 'annually', 'Once every year without fail, yearly', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a85c04a8-a9af-4de9-a49b-401eb83732db', 'anonymous', 'Lacking a name; not named, for example an animal not assigned to any species.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7b5919e4-357e-48f2-96ef-e86d190cd654', 'anticipate', 'To act before (someone), especially to prevent an action.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c1a67220-6189-41f0-ba6f-716c22413469', 'anxiety', 'An unpleasant state of mental uneasiness, nervousness, apprehension and obsession or concern about some uncertain event.', '', 'Psychology', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c0a88213-d88b-4f05-b6a0-a06a63bafbc5', 'anxious', 'Nervous and worried.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('572027ea-f8c4-4ec8-a3c9-7343c31f58f2', 'apology', 'An expression of remorse or regret for having said or done something that harmed another: an instance of apologizing (saying that one is sorry).', 'The CEO made a public apology for the scandal, and promised full cooperation with the authorities.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ec745c40-0ef9-4b2c-9724-8f72f53de99b', 'apparent', 'Capable of being seen, or easily seen; open to view; visible to the eye, eyely; within sight or view.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('db8264bc-2f62-4c6e-9e6f-f0bbc6b8a58c', 'appeal', 'An application for the removal of a cause or suit from an inferior to a superior judge or court for re-examination or review.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a4e1e231-1d67-498c-a994-17bc91e0033c', 'applicant', 'One who applies for something; one who makes a request; a petitioner.', 'Our job advertisement attracted seven applicants.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('06805677-0d01-4cc3-bcb0-05625e884b94', 'approach', 'The act of drawing near; a coming or advancing near.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0079f1f6-d02d-4d38-b5b9-df1bb15ee5f9', 'appropriate', 'To make suitable; to suit.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('331a364d-ef86-4cc5-93b7-eb27ca49ae48', 'appropriately', 'In an appropriate manner; properly; suitably.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c209b5b0-64da-4a04-910e-af14c2cb2dab', 'approval', 'An expression granting permission; an indication of agreement with a proposal; an acknowledgement that a person, thing or event meets requirements.', 'I need to get an approval on this purchase order.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ad46660a-ee88-4fcc-a5ac-e643b34f3212', 'approve', 'To sanction officially; to ratify; to confirm; to set as satisfactory.', 'Although we may disagree with it, we must nevertheless approve the sentence handed down by the court-martial.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('66748f39-fc2a-4da5-af25-541701fdcb1f', 'arbitration', 'The act or process of arbitrating.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('5a280bcd-57f9-4ca4-9c13-bca5c525e8ad', 'arise', 'To come up from a lower to a higher position.', 'to arise from a kneeling posture', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e3a9c5a8-eeb3-4629-ae0a-982d70637c15', 'armed', 'To take by the arm; to take up in one''s arms.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('43d5807b-7997-4b7a-9eb4-9d5aca285590', 'arms', 'The portion of the upper human appendage, from the shoulder to the wrist and sometimes including the hand.', 'She stood with her right arm extended and her palm forward to indicate “Stop!”', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('61496490-b4c3-429c-bf33-8273879c4944', 'arrogance', 'The state of being arrogant; a type of extreme or foolish pride in which someone feels much superior to another', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('411693a8-832e-4682-bf1d-29540dff1739', 'arrow', 'A projectile consisting of a shaft, a point and a tail with stabilizing fins that is shot from a bow.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7de6f4af-373f-47e7-a20b-cf2af94e1d01', 'artificial', 'Man-made; of artifice.', 'The flowers were artificial, and he thought them rather tacky.', 'Technology', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('20c120ce-1973-4b1a-b42c-f69a5d52cd94', 'artistic', 'Having or revealing creative skill.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('06c7aeed-56d6-41a5-be86-681fdfd773df', 'artwork', 'A painting, drawing, sculpture or other piece of creative, visual art', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('87a8f3a1-9a38-49ed-81af-6705721e9016', 'ashamed', 'To feel shame; to be ashamed.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9768695c-4033-4411-bb3c-596e843fdbab', 'aside', 'An incidental remark made quietly so as to be heard by the person to whom it is said and not by any others in the vicinity.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('327ab7b6-30a2-4eff-8428-a74bf449d8e4', 'assess', 'To determine, estimate or judge the value of; to evaluate', 'He assessed the situation.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('eecc0522-0a83-4096-b1a1-ca9648c4e48e', 'assessment', 'The act of assessing or an amount (of tax, levy or duty etc) assessed.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6b7c021e-7f1b-4c7c-91b2-35f437ffcb21', 'asset', 'Something or someone of any value; any portion of one''s property or effects so considered.', 'These shares are a valuable asset.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2bb468f3-5278-4e40-9a93-809369e0c7d8', 'assign', 'An assignee.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9593289f-1581-4db0-8b17-fd0186507db1', 'assistance', 'Aid; help; the act or result of assisting.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1f80737b-65a1-4262-9336-540d1e2a23da', 'associate', 'A person united with another or others in an act, enterprise, or business; a partner.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d69b115c-5ffd-494c-967c-83efeb4cfc99', 'associated', 'To join in or form a league, union, or association.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('dc8be145-9418-4b31-85b9-6b9c7d5f0915', 'association', 'The act of associating.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ee89a97a-56e9-432b-8d15-be0d5dc7dcc6', 'assume', 'To authenticate by means of belief; to surmise; to suppose to be true, especially without proof', 'We assume that, as her parents were dentists, she knows quite a bit about dentistry.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('473c35fb-b869-4a2b-be6b-f0a518ddcded', 'assumption', 'The act of assuming, or taking to or upon oneself; the act of taking up or adopting.', 'His assumption of secretarial duties was timely.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ef453f9c-4a10-464c-905c-e1cdb2507427', 'assure', 'To make sure and secure.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8ee61438-65ad-43e1-964a-aab91579fee7', 'astonishing', 'To surprise greatly.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a2e05f24-4ffb-4d71-8ef9-587624f63717', 'atmospheric', 'Of, relating to, produced by, or coming from the atmosphere.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2d83b3ec-ec0b-4a65-865d-fb3d40f97439', 'attachment', 'The act or process of (physically or figuratively) attaching.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0431e863-7565-44cf-bc4a-414a52e86803', 'attempt', 'The action of trying at something.', 'It was worth the attempt.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f6bcf892-065f-4773-8a9e-6159cf14d2a9', 'auction', 'A public event where goods or property are sold to the highest bidder.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('373528fa-e807-4d59-8155-ca599c7b1732', 'audio', 'A sound, or a sound signal', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('337913bb-1d37-40e5-a6d4-1c74611014aa', 'authenticity', 'The quality of being genuine or not corrupted from the original.', 'I hereby certify the authenticity of this copy.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('46b248fc-5299-4f4c-bc4a-8e8786758e9a', 'automatic', 'A car with automatic transmission.', 'I never learned to drive a stick. I can only drive an automatic.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('76e5c5ac-f63e-4f6e-89e9-58f0f8dd749b', 'automatically', 'In an automatic manner.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('36ac5daf-0533-4806-a90e-b36e9a28fe97', 'automation', 'The act or process of converting the controlling of a machine or device to a more automatic system, such as computer or electronic controls.', '', 'Technology', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('854c2ecb-cf92-44ad-a8c7-4068d7c7b601', 'awareness', 'The state or level of consciousness where sense data can be confirmed by an observer.', 'I gradually passed from sleep to full awareness.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('bdba8b5b-eb24-4d35-9dc0-e14aab0f932f', 'badge', 'A distinctive mark, token, sign, emblem or cognizance, worn on one''s clothing, as an insignia of some rank, or of the membership of an organization.', 'the badge of a society; the badge of a policeman', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('5743770c-c080-4533-a2fe-a37c5e057aaf', 'balanced', 'To bring (items) to an equipoise, as the scales of a balance by adjusting the weights.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('cefb2290-7715-44e5-b826-0796e09011d4', 'ballet', 'A classical form of dance.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('55853a19-bbf0-4b38-ae6d-036f9769ecfd', 'balloon', 'An inflatable buoyant object, often (but not necessarily) round and flexible.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a4548535-3249-4e38-8cf3-1d62d7e80102', 'barely', '(degree) By a small margin.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0c17dd8c-5f5c-4b17-8cfa-4146a81e2b04', 'bargain', 'An agreement between parties concerning the sale of property; or a contract by which one party binds himself to transfer the right to some property for a consideration, and the other party binds himself to receive the property and pay the consideration.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2cb7dd37-acf0-4e73-aa3a-ba442802b7ff', 'barrier', 'A structure that bars passage.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('839ba668-33ac-46d9-9f31-154625a39ad1', 'basement', 'A floor of a building below ground level.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f056473a-8987-4913-9117-40f9211388db', 'basically', 'In a fundamental, essential or basic manner', 'They''ve added some fancy features, but it''s basically still a car.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ebfa5c98-8574-4789-b95b-1fa705562a90', 'basket', 'A lightweight container, generally round, open at the top, and tapering toward the bottom.', 'A basket of fake fruit adorned the table.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('5bfcb7c4-59c9-43c9-98bc-6e5309831d74', 'bat', 'Any of the flying mammals of the order Chiroptera, usually small and nocturnal, insectivorous or frugivorous.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('751b20ee-0d14-47cc-9f56-bede11010c05', 'beg', 'The act of begging; an imploring request.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('24ff8e90-f49d-4758-89b7-e69a83ad86e6', 'being', 'A living creature.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a277e0ff-bde6-4194-8941-aca0784e562c', 'beneficial', 'Something that is beneficial.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('71ddb392-771b-44c2-9a98-ccbc71fd1177', 'bent', 'To cause (something) to change its shape into a curve, by physical force, chemical action, or any other means.', 'Don’t bend your knees.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('fccff700-ef64-4bce-bc93-db134ec80d69', 'beside', 'Otherwise; else.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('63607f40-4832-4986-8e9e-a74b7fe7c44d', 'besides', 'Also; in addition.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('74fea477-9e27-41e1-a84c-96a7e1598980', 'bet', 'A wager, an agreement between two parties that a stake (usually money) will be paid by the loser to the winner (the winner being the one who correctly forecast the outcome of an event).', 'Dylan owes Fletcher $30 from an unsuccessful bet.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('19ee3a84-22c3-447f-b662-3c361d995922', 'beyond', 'The unknown.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a51b27a2-36e5-4f82-92ed-d8bcdad58b4a', 'bias', 'Inclination towards something; predisposition, partiality, prejudice, preference, predilection.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c58bc80e-4217-4b93-bf3e-3a893792aca9', 'bid', 'To issue a command; to tell.', 'He bade me come in.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a64b4ab3-ed43-45b7-95d4-a3576c94325a', 'biodiversity', 'The diversity (number and variety of species) of plant and animal life within a region.', '', 'Environment', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a675ae58-4d92-4054-9a10-8be95767ca00', 'biological', 'A biological product.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('5358eb16-7f6d-4955-932b-25898f5ced2d', 'biotechnology', 'The use of living organisms (especially microorganisms) in industrial, agricultural, medical and other technological applications.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1444f017-ddc4-4ed2-b796-e950538ee193', 'bitter', '(usually in the plural bitters) A liquid or powder, made from bitter herbs, used in mixed drinks or as a tonic.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d83e9e0c-2a8d-43f5-ae4f-1cc802bffb82', 'blame', 'Censure.', 'Blame came from all directions.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8b02d133-14f8-41a8-9f25-bbe8d060596b', 'blanket', 'A heavy, loosely woven fabric, usually large and woollen, used for warmth while sleeping or resting.', 'The baby was cold, so his mother put a blanket over him.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('466bf0fd-5c84-4e6c-90c0-9cb1ba5aca29', 'blind', 'A covering for a window to keep out light. The covering may be made of cloth or of narrow slats that can block light or allow it to pass.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('01dd14bc-eef2-4447-a7ab-c7297217dc21', 'bold', 'A dwelling; habitation; building.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('bd8e9b80-dce6-4b10-affb-3f2f963b5c43', 'bombing', 'To attack using one or more bombs; to bombard.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('919524af-e3fe-44ef-ab59-aa3741a53d40', 'bond', 'Evidence of a long-term debt, by which the bond issuer (the borrower) is obliged to pay interest when due, and repay the principal at maturity, as specified on the face of the bond certificate. The rights of the holder are specified in the bond indenture, which contains the legal terms and conditions under which the bond was issued. Bonds are available in two forms: registered bonds, and bearer bonds.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2841bf34-b1c7-449b-8837-6f4c8939e9d0', 'booking', 'To reserve (something) for future use.', 'I can book tickets for the concert next week.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f8f4d3ca-bbe9-44f0-af95-2cb9349e7a70', 'boost', 'A push from behind, as to one who is endeavoring to climb.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8a6b5056-4819-4068-8b41-65e102856f11', 'bound', 'To tie; to confine by any ligature.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('50f91ffe-958e-405e-811e-84bfcccebeb3', 'breast', 'Either of the two organs on the front of a female human''s chest, which contain the mammary glands; also the analogous organs in males.', 'Tanya''s breasts grew remarkably during pregnancy.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4a60e568-1d1e-4541-b03b-74bb441d8e2c', 'brick', 'A hardened rectangular block of mud, clay etc., used for building.', 'This wall is made of bricks.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('fbd18aaf-75d0-434a-8169-a3f75aa4d46f', 'brief', 'A writ summoning one to answer to any action.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('df13acbf-aa34-4226-bdae-6b178ebef18c', 'briefly', '(manner) In a brief manner, summarily.', 'He covered the subject briefly in his book.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('94b0969a-61b5-4ae6-88e5-398e7a06180f', 'broad', 'A shallow lake, one of a number of bodies of water in eastern Norfolk and Suffolk.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('08567f8d-85c9-4fa4-94ff-1503947641b7', 'broadcast', 'A transmission of a radio or television programme intended to be received by anyone with a receiver.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6c395f2d-8169-4852-8fa7-f7ae62530f74', 'bug', 'An insect of the order Hemiptera (the “true bugs”).', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('33dc4efb-2c08-47a4-95f2-e32352738473', 'bullet', 'A projectile, usually of metal, shot from a gun at high speed.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3b619666-bd36-4547-bf37-4881782c4220', 'bunch', 'A group of similar things, either growing together, or in a cluster or clump, usually fastened together.', 'a bunch of grapes;  a bunch of bananas;  a bunch of keys;  a bunch of yobs on a street corner', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('dfef4d33-5ba6-440c-a699-b1ee0d54700c', 'bureaucracy', 'Government by bureaus or their administrators or officers.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3c0872a5-4b65-405a-b7ce-ce814f8d5bd4', 'bush', 'A woody plant distinguished from a tree by its multiple stems and lower height, being usually less than six metres tall; a horticultural rather than strictly botanical category.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4ce15bd3-f33e-4b62-8b08-d354a4d63a03', 'cabin', 'A small dwelling characteristic of the frontier, especially when built from logs with simple tools and not constructed by professional builders, but by those who meant to live in it.', 'Abraham Lincoln was born in a log cabin.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('694ee655-9c84-47c0-972f-fcf7911676df', 'cable', '(material) A long object used to make a physical connection.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('eec5e346-60b1-4953-b42c-acfeaaa30c6f', 'calculate', 'To determine the value of something or the solution to something by a mathematical process.', 'Calculate the square root of 3 to 10 decimal places.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d2dd9b68-738e-49c7-b001-93d047ad05d8', 'canal', 'An artificial waterway or artificially improved river used for travel, shipping, or irrigation.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('846cafd5-c728-411a-a24d-8cde33668b84', 'cancel', 'A cancellation (US); (nonstandard in some kinds of English).', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('fed933e4-eb54-404a-865b-79660a803420', 'cancer', 'A disease in which the cells of a tissue undergo uncontrolled (and often rapid) proliferation.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('bd9ff492-c47d-415b-ab8c-e2fcc98bfdab', 'candle', 'A light source consisting of a wick embedded in a solid, flammable substance such as wax, tallow, or paraffin.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8f693674-84f9-4ce8-89eb-30f867c3a92f', 'capable', 'Able and efficient; having the ability needed for a specific task; having the disposition to do something; permitting or being susceptible to something.', 'As everyone knew, he was capable of violence when roused.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('06d4b7a4-cd22-4b67-9b8f-11fd722e435e', 'capacity', 'The ability to hold, receive or absorb', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3623e219-de60-4606-99e3-57fcc46ebdac', 'capture', 'An act of capturing; a seizing by force or stratagem.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a6cbcc7c-a62c-453f-a724-6386eb0e4f41', 'carbon', 'The chemical element (symbol C) with an atomic number of 6. It can be found in pure form for example as graphite, a black, shiny and very soft material, or diamond, a colourless, transparent, crystalline solid and the hardest known material.', '', 'Environment', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6ec75535-e37d-4a67-b8a8-85ecc5686933', 'cardiovascular', 'Relating to the circulatory system, that is the heart and blood vessels.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('bade7bbe-025a-43e4-8240-bfa7e96e9ad9', 'cast', 'An act of throwing.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e272913a-9bd6-4949-ac8d-0a9060f029d6', 'casual', 'A worker who is only working for a company occasionally, not as its permanent employee.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d14655f8-3230-463e-a806-4c9f144dbb8f', 'catastrophe', 'Any large and disastrous event of great significance', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('efebdb35-b623-4bc8-bc58-85df820cf899', 'cave', 'A large, naturally-occurring cavity formed underground or in the face of a cliff or a hillside.', 'We found a cave on the mountainside where we could take shelter.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('124ee27d-6c59-460f-b856-ef6d5fbf881c', 'cell', 'A single-room dwelling for a hermit.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('72bd3d82-ef7c-4b8c-a1e9-370aac156aad', 'censorship', 'The use of state or group power to control freedom of expression or press, such as passing laws to prevent media from being published or propagated.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c3abc6ee-6a27-4205-9c9d-35e620de3258', 'censure', 'The act of blaming, criticizing, or condemning as wrong; reprehension.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('5a994014-664e-4270-9120-421311c6f2bd', 'certainty', 'The state of being certain.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d19d4a6a-4220-4197-9802-108c3dfe31e3', 'chairman', 'A person presiding over a meeting.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c18329f6-eb00-4fe1-a7f1-ab88249f4cb6', 'challenging', 'To invite (someone) to take part in a competition.', 'We challenged the boys next door to a game of football.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('53be3af2-c87c-4cf3-8e14-a55b3ec089a2', 'championship', 'A competition to determine a champion, especially the final of a series of competitions.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('20e296cf-5152-4ed3-94d1-1e5efce3f632', 'characteristic', 'A distinguishing feature of a person or thing.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('501e29d8-b073-40c9-b4b7-b34d17fe3982', 'charming', 'To seduce, persuade or fascinate someone or something.', 'He charmed her with his dashing tales of his days as a sailor.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('be16db03-0cb5-4046-815a-c27007c6bdbe', 'chase', 'The act of one who chases another; a pursuit.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c39cee2e-f075-46cd-9f51-1290ac363eb6', 'cheek', 'The soft skin on each side of the face, below the eyes; the outer surface of the sides of the oral cavity.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6b0ac22a-bece-4d7f-b573-852abea57de5', 'cheer', 'A cheerful attitude; happiness; a good, happy, or positive mood.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('631eca43-54ef-49a4-affe-95dea352adff', 'chief', 'A leader or head of a group of people, organisation, etc.', 'All firefighters report to the fire chief.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e9f8ab06-dc9c-4df9-a0af-2d8b4b9094cf', 'choir', 'Singing group; group of people who sing together; company of people who are trained to sing together.', 'The church choir practices Thursday nights.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0d7c3fba-eb34-4a33-bae1-6601ebb85cb3', 'chop', 'A cut of meat, often containing a section of a rib.', 'I only like lamb chops with mint jelly.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('5deadec2-158f-4e02-a76e-9b131528579d', 'choreography', 'The art of creating, arranging and recording the dance movements of a work, such as a ballet.', 'She has staged many successful ballets, so her choreography skills must be excellent.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('38f2e4b0-d513-4d73-ad7b-0c5563163f13', 'chronic', 'Marijuana, typically of high quality.', '', 'Health', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9724da6d-84f8-41e8-94c6-23fd8343031a', 'circuit', 'The act of moving or revolving around, or as in a circle or orbit; a revolution', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('60ea90c3-a1e6-4733-b410-d4374afb3521', 'circumstance', 'That which attends, or relates to, or in some way affects, a fact or event; an attendant thing or state of things.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6e017e78-e04b-4fdd-be09-bf4c98b04c19', 'cite', 'To quote; to repeat, as a passage from a book, or the words of another.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8df52590-a490-4bbd-ae0e-16a2e3fdc71a', 'citizen', 'A resident of a city or town, especially one with legally-recognized rights or duties.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e5e6e4dc-77a8-4c87-b52f-218b7f9d7eb8', 'civil', 'Having to do with people and government office as opposed to the military or religion.', 'She went into civil service because she wanted to help the people.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ea53a350-7361-47cc-ac89-0c90f203c803', 'civilization', 'An organized culture encompassing many communities, often on the scale of a nation or a people; a stage or system of social, political or technical development.', 'Modern civilization is a product of industrialization and globalization.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d12b0974-35f1-4b7a-a5a3-df3aff5722f3', 'clarify', '(of liquids, such as wine or syrup) To make clear or bright by freeing from feculent matter', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a1bfe7d2-7880-4599-9149-0c6a0c917d01', 'classic', 'A perfect and/or early example of a particular style.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7d84c963-e7b4-4b98-9c8d-34024a9bc0d5', 'classify', 'To identify by or divide into classes; to categorize', 'Should we classify "make up" as an idiom or as a phrasal verb?', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('96689714-1c50-426e-a263-78ea57bce295', 'clerk', 'One who occupationally works with records, accounts, letters, etc.; an office worker.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2fdbd3ac-fe81-45ef-9f8a-b619e91873bb', 'cliff', 'A vertical (or nearly vertical) rock face.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0fbb3c1e-5468-4b0d-a558-0e208bdbdfdb', 'clinic', 'A medical facility, such as a hospital, especially one for the treatment and diagnosis of outpatients.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('44cdf606-a983-4ec8-af0c-96069ab9f24d', 'clinical', 'A medical student''s session spent in a real-world nursing environment.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('bacc990f-3952-48fc-9e12-17d6bf101132', 'clip', 'Something which clips or grasps; a device for attaching one object to another.', 'Use this clip to attach the check to your tax form.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('14b0a376-bf0c-465a-9130-11ee28307656', 'closely', 'In a close manner.', 'Finnish and Estonian are closely related languages.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a79f8cd8-f096-4477-aa33-48ad081c2c87', 'cognition', 'The process of knowing, of acquiring knowledge and understanding through thought and through the senses.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('553509ce-74c7-43e4-9e2d-947d08b20f2b', 'coincidence', 'Of objects, the property of being coincident; occurring at the same time or place.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a64a324c-b3d3-4a87-ba41-d249092b5d4e', 'collapse', 'The act of collapsing.', 'She suffered a terrible collapse after slipping on the wet floor.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('33357524-ce6a-4544-b824-d528ea16c978', 'collector', 'A person who or thing that collects, or which creates or manages a collection.', 'He is an avid collector of nineteenth-century postage stamps.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('252d83ca-a0fa-4a95-b046-063511ecfee7', 'colony', 'A governmental unit created on land of another country owned by colonists from a country.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('89afcf38-b0b4-489e-808e-cdd48d9679d5', 'colourful', 'Possessing prominent and varied colors.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6b133b44-fd82-414d-a704-08135f0c0fb1', 'combination', 'The act of combining, the state of being combined or the result of combining.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9fbc5b3b-23cd-4fc7-8d3c-2264e2ae45e9', 'comfort', 'Contentment, ease.', 'Sleep in comfort with our new mattress.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('cdd83ee5-38f1-4471-a15c-ecd678a5a90f', 'comic', 'A comedian.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f0f3a678-7116-4395-89df-090ed4d2c077', 'command', 'An order to do something.', 'I was given a command to cease shooting.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a65ead5f-de0a-472f-90af-5e055dfbc2a2', 'commander', 'One who exercises control and direction of a military or naval organization.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0dc2c224-bb68-40ef-9815-ea632d3ee58f', 'commission', 'A sending or mission (to do or accomplish something).', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9b0aa64c-46a2-422e-b4c2-5b6fd9c01708', 'commitment', 'The act or an instance of committing, putting in charge, keeping, or trust, especially:', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('518d182c-735c-4134-9c8f-64eae5929487', 'committee', 'A body of one or more persons convened for the accomplishment of some specific purpose, typically with formal protocols.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c5f8015e-66fe-42e6-a5d3-c249a3873f8c', 'commodity', 'Anything movable (a good) that is bought and sold.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b4f987a6-97dc-42bf-9f6c-8766fe51d165', 'commonly', 'As a rule; frequently; usually', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('17704a8d-4174-472d-826e-e91bded60865', 'comparative', '(grammar) A construction showing a relative quality, in English usually formed by adding more or appending -er. For example, the comparative of green is greener; of evil, more evil.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('85f3cda2-8912-4607-9b06-3df9e919e9b6', 'compassion', 'Deep awareness of the suffering of another, coupled with the wish to relieve it.', '', 'Psychology', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d80a2227-fe20-459e-be02-1539f38def47', 'completion', 'The act or state of being or making something complete; conclusion, accomplishment.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('57649826-acfa-47a6-b50c-77eb5eda95b8', 'complicated', 'To make complex; to modify so as to make something intricate or difficult.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('430391b2-3fb4-4dd0-baa2-8985b6250e10', 'component', 'A smaller, self-contained part of a larger entity. Often refers to a manufactured object that is part of a larger device.', 'A CPU is a component of a computer.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ac966309-45b3-4474-9962-a50df64b62bc', 'compose', 'To make something by merging parts.', 'The editor composed a historical journal from many individual letters.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e4191e66-a2fe-4b7e-9bd1-2656b70a19a8', 'composer', 'One who composes; an author.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e36753f5-e1dd-41fc-b6c8-aafb4a24db05', 'contribution', 'Something given or offered that adds to a larger whole.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('532fc425-d213-41be-8435-9f5f5026777c', 'compound', 'An enclosure within which workers, prisoners, or soldiers are confined', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('fad7a6cb-c0e7-4ed4-b398-e9318c5ab8ce', 'comprehensive', 'A comprehensive school.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('98112ca2-1bd7-49a9-8b02-3cc2b911857b', 'comprise', 'To be made up of; to consist of (especially a comprehensive list of parts).', 'The parts are comprised by the whole.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c7b45b6c-2eef-4fb3-9916-7a346f3d911d', 'compulsory', 'Something that is compulsory or required.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('970d9752-cf8c-4450-84b6-565d99ba1bb2', 'concentration', 'The act, process or ability of concentrating; the process of becoming concentrated, or the state of being concentrated.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('43342107-e694-4462-804a-ccf3c5d85f92', 'concept', 'An abstract and general idea; an abstraction.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ed185134-5f3c-4fca-bac3-d3d725100257', 'concern', 'That which affects one’s welfare or happiness. A matter of interest to someone. The adposition before the matter of interest is usually over, about or for.', 'Judy''s eyes filled with concern as she listened to the news report.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('af66397f-8048-4a14-b4f9-b27087a587ad', 'concerned', 'To relate or belong to; to have reference to or connection with; to affect the interest of; to be of importance to.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b9a1bc26-014a-46f1-b837-f72c7dd45599', 'concrete', 'A solid mass formed by the coalescence of separate particles; a compound substance, a concretion.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('cdfca580-cd8a-4fd2-8ae9-dfca35848f37', 'conduct', 'The act or method of controlling or directing', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('bce35069-4da6-4a6e-8161-7b8d4b4c6394', 'confess', 'To admit to the truth, particularly in the context of sins or crimes committed.', 'I confess to spray-painting all over that mural!', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('44bddc50-1c3d-4484-b704-44abe989a3d3', 'confidence', 'Self-assurance.', '', 'Psychology', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('eae6a01b-1182-46a8-96fa-e04aa90eb89c', 'conflict', 'A clash or disagreement, often violent, between two or more opposing groups or individuals.', 'The conflict between the government and the rebels began three years ago.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a2b3fee3-6e2a-4a35-b24f-8764b71330b1', 'confusing', 'To puzzle, perplex, baffle, bewilder (somebody).', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4cf4d91e-237d-42cc-b997-301a638ffbc5', 'confusion', 'A lack of clarity or order.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a77a701b-b307-40bd-bd95-5296eb486a92', 'conscious', 'The part of the mind that is aware of itself; the consciousness.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d5f0a9ab-37ba-4d04-b6da-d0ed77dc30b1', 'consciousness', 'The state of being conscious or aware; awareness.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8e335be3-4d13-4f3d-98bd-e680778920f7', 'consent', 'Voluntary agreement or permission.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('61be44dd-7f97-445f-bf96-6628645cdcba', 'consequently', 'As a result or consequence of something.', 'He didn''t wake up early. Consequently, he was late to work.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e7a3a12f-cd56-4a2e-a623-27c79a77a493', 'conservation', 'The act of preserving, guarding, or protecting; the keeping (of a thing) in a safe or entire state; preservation.', '', 'Environment', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4f71a3bc-cd1f-488d-a75f-503a8457ca3a', 'conservative', 'A person who favors maintenance of the status quo.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c02b50d7-f4d8-43f0-b00a-e0030b103d7e', 'considerable', 'A thing to be considered, consideration.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d89c0f96-ea82-46fd-a414-1ba54feee1ad', 'considerably', 'Significantly; to a degree worth considering.', 'The situation has improved considerably.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('30412d30-6454-4777-a466-bf20df783601', 'consideration', 'The thought process of considering, of taking multiple or specified factors into account (with of being the main corresponding adposition).', 'After much consideration, I have decided to stay.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3912f5ca-2a2b-4a5a-8b54-14aa6599c524', 'consistent', '(in the plural) Objects or facts that are coexistent, or in agreement with one another.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6e8b6ef3-fb8e-4aab-9c92-ed189c07db20', 'consistently', '(manner) In a consistent manner.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('50299773-09e8-4edd-a188-e77d8558427d', 'conspiracy', 'The act of two or more persons, called conspirators, working secretly to obtain some goal, usually understood with negative connotations.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('fb6f17a1-39c1-4b6d-8dff-eb1e85c0d1a1', 'constant', 'That which is permanent or invariable.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a6b2cf0c-0372-486c-8017-bf2a9b5a7acd', 'constantly', 'With steadfastness; with resolve; in loyalty, faithfully.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2f013857-bdc5-47af-9e50-2ee0275c4e53', 'constitution', 'The act, or process of setting something up, or establishing something; the composition or structure of such a thing; its makeup.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('abb1e024-2a0d-4548-b793-9b4d50d9738d', 'construct', 'Something constructed from parts.', 'Loops and conditional statements are constructs in computer programming.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d966b47a-d2d1-49d8-aad0-bd9b418acb8f', 'construction', 'The process of constructing.', 'Construction is underway on the new bridge.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('163b033a-9229-44fb-9b3c-4e78bac5188a', 'consult', 'The act of consulting or deliberating; consultation', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('804e7a85-9823-4fdc-b223-39fe288fa80d', 'consultant', 'A person or party that is consulted', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('874dc235-32ab-4cb7-a815-6e4b8f2278a7', 'consumption', 'The act of eating, drinking or using.', 'The consumption of snails as food is more common in France than in England.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('5fee6a91-fef5-4dc9-ab20-e5d57c3684fb', 'contamination', 'The act or process of contaminating', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9b83b7b2-39ab-4e31-8d58-4b1637c10efd', 'contemporary', 'Someone or something living at the same time, or of roughly the same age as another.', 'Cervantes was a contemporary of Shakespeare.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('edd724a8-d278-4d02-9508-f4653acd7b1f', 'contest', 'Controversy; debate.', 'no contest', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('5f14553d-16e0-46be-ba76-c432c9ae7f54', 'contribute', 'To give something that is or becomes part of a larger whole.', 'to contribute articles to a journal', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('72ffb835-407d-463c-894b-2da8d543466d', 'found', 'To encounter or discover by accident; to happen upon.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c0a52de3-376e-4563-95f8-03c3ad39e39d', 'controversial', 'Arousing controversy—a debate or discussion of opposing opinions.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('5eb195df-72ef-4bac-b125-9cda7d9bb2c2', 'controversy', 'A debate or discussion of opposing opinions; (generally) strife.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c5237cb5-5a5e-4ded-8b14-10e526a4ea6c', 'convenience', 'The quality of being convenient.', 'Fast food is popular because of its cost and convenience.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('61869489-00b1-42ed-b178-609f5e341038', 'convention', 'A meeting or gathering.', 'The convention was held in Geneva.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3f8dd01e-a874-414d-a979-9a4cce8cd42f', 'conventional', 'A conventional gilt-edged security, a kind of bond paying the holder a fixed cash payment (or coupon) every six months until maturity, at which point the holder receives the final payment and the return of the principal.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8f27d5f9-7cd9-4dd3-a840-70cd81ac9df8', 'convert', 'A person who has converted to a religion.', 'They were all converts to Islam.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('026f8a0d-2aa3-4589-a20b-611aa8aa13f7', 'convey', 'To move (something) from one place to another.', 'Air conveys sound. Water is conveyed through the pipe.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('19fa780b-c97e-4eaf-b47a-0a7f5233eaa5', 'convinced', 'To make someone believe, or feel sure about something, especially by using logic, argument or evidence.', 'I wouldn''t have or do something, unless I''m convinced that it''s good.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7fe39071-010a-4d07-b0df-181dac8d778d', 'convincing', 'To make someone believe, or feel sure about something, especially by using logic, argument or evidence.', 'I wouldn''t have or do something, unless I''m convinced that it''s good.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3822c47c-d6d8-4faa-a80b-b2a58317633f', 'cope', 'To deal effectively with something, especially if difficult.', 'I thought I would never be able to cope with life after the amputation, but I have learned how to be happy again.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('09644325-68b5-4319-b1aa-8ee360b45281', 'core', 'The central part of fruit, containing the kernels or seeds.', 'the core of an apple or quince', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('99688973-9536-4b61-b9f0-7c7f96e008d8', 'corporate', 'A bond issued by a corporation.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('90412919-fc2a-4222-b387-c96eba1b9767', 'corporation', 'A body corporate, created by law or under authority of law, having a continuous existence independent of the existences of its members, and powers and liabilities distinct from those of its members.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('25f8ab25-f524-45d7-96a4-18d598858786', 'corridor', 'A narrow hall or passage with rooms leading off it, as in a building or in a railway carriage.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('52997f47-435b-4183-9835-cbc00cee352f', 'corruption', 'The act of corrupting or of impairing integrity, virtue, or moral principle; the state of being corrupted or debased; loss of purity or integrity', '', 'Society', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('44c77f67-5e8a-43ea-a6a5-d570591f7720', 'council', 'A committee that leads or governs (e.g. city council, student council).', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e9259a5e-a129-417c-86d5-357b0143419c', 'counter', 'One who counts', 'He''s only 16 months, but is already a good counter – he can count to 100.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f856f210-0212-4724-a449-fcbe12655445', 'county', 'The land ruled by a count or a countess.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('99e7658c-ca37-4f00-931f-4f1086b13506', 'courage', 'The quality of being confident, not afraid or easily intimidated, but without being incautious or inconsiderate.', 'It takes a lot of courage to be successful in business.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('26ec9b55-22b1-47fa-93a5-ef7b2986724b', 'coverage', 'An amount by which something or someone is covered.', 'Before laying sod on that clay, the ground needs two inches of coverage with topsoil.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2944a66b-67b5-427b-a6de-b7de508f3580', 'crack', 'A thin and usually jagged space opened in a previously solid material.', 'A large crack had formed in the roadway.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7f4f99fa-1e93-4511-853b-c9cbc12a856a', 'craft', 'Strength; power; might; force .', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('afb3746b-8ad2-4e2d-971d-0a3b20986393', 'crash', 'A sudden, intense, loud sound, as made for example by cymbals.', 'After the lightning came the crash of thunder.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b16e6d74-d9d4-4627-98af-43499b82cc59', 'creation', 'Something created such as an invention or artwork.', 'I think the manufacturer was so ashamed of its creation that it didn''t put its name on it!', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('165d1299-3f62-4390-8b68-7d09a9b30fcf', 'creativity', 'The ability to use imagination to produce a novel idea or product that is useful to society.', 'His creativity is unsurpassed by his fellow students in the art class.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f1eddfda-688c-4150-b23b-dc20e79d9189', 'creature', 'A living being; an animal or (sometimes derogatory) a human.', 'He''s a creature of habit.   insects and other creatures', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('533e6bb9-daf0-479b-816b-c76810b63c9a', 'credibility', 'Reputation impacting one''s ability to be believed.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('18a539a4-9bd6-4094-97ed-f58a4bc36ba4', 'crew', 'To make the shrill sound characteristic of a rooster; to make a sound in this manner, either in gaiety, joy, pleasure, or defiance.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('702ff6f7-b9bb-4e03-9169-9b370a4ac7e3', 'crisis', 'A crucial or decisive point or situation; a turning point.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('5485f936-c786-47e9-8d94-c8aa4ee0674e', 'criterion', 'A standard or test by which individual things or people may be compared and judged.', 'Criterion of choice, of decision, of selection', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('92abc217-3b71-4edb-a214-6898c5956e2f', 'critic', 'A person who appraises the works of others.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1893d645-1fd6-463d-9f85-59f5ad173655', 'critical', 'A critical value, factor, etc.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('bcf32400-13f1-4fc2-8268-9b8922df45ee', 'critically', 'In a critical manner; with, or in terms of, criticism.', 'I looked critically at the frayed carpet of the hotel room.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('cece6806-a8cb-46f1-b03e-13545ab3e48e', 'criticism', 'The act of criticising; a critical judgment passed or expressed', 'The politician received a lot of public criticism for his controversial stance on the issue.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('fdeba46b-0e7e-4955-9161-f60021f55af0', 'criticize', 'To find fault (with something).', 'They criticized him for endangering people''s lives.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('5f4683f5-5821-4397-a845-93f3caee5a09', 'crop', 'A plant, especially a cereal, grown to be harvested as food, livestock fodder or fuel or for any other economic purpose.', 'the farmer had lots of crops to sell at the market', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d835bd59-8b2e-4c2f-bcb6-2d824cbde036', 'crucial', 'Essential or decisive for determining the outcome or future of something; extremely important.', 'A secure supply of crude oil is crucial for any modern nation, let alone a superpower.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3aaa3d0a-32c7-4586-9b14-dde00e21c45d', 'cruise', 'A sea or lake voyage, especially one taken for pleasure.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0d21a8f7-ea05-4919-a7bc-4f3e3a1784c1', 'curious', 'Tending to ask questions, or to want to explore or investigate; inquisitive; (with a negative connotation) nosy, prying.', 'Young children are naturally curious about the world and everything in it.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7fff3096-b90f-48d5-b693-220cb23b0ccd', 'curriculum', 'The set of courses, coursework, and their content, offered at a school or university.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7ed92eaa-f36d-4251-98f0-b943a3c65f4a', 'curve', 'A gentle bend, such as in a road.', 'You should slow down when approaching a curve.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('cc08cae1-8ef8-4e7f-9b3e-022e198a37cc', 'curved', 'To bend; to crook.', 'to curve a line', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('cf8c122e-a84b-4c19-83e0-41c99ad4bdba', 'cute', 'Possessing physical features, behaviors, personality traits or other properties that are mainly attributed to infants and small or cuddly animals; e.g. fair, dainty, round, and soft physical features, disproportionately large eyes and head, playfulness, fragility, helplessness, curiosity or shyness, innocence, affectionate behavior.', 'Our reaction to cute attributes is understood as the way nature ensures mammals care for their young.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('99a0a1a8-1a85-4ed3-80d6-d897927594d5', 'cybersecurity', 'Security against electronic attacks such as cyberwarfare.', '', 'Technology', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d3beab30-5cc8-4db0-aeb6-50f1752e2cd7', 'dairy', '(also dairy products or dairy produce) Products produced from milk.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1345812a-cb69-4a9c-9cd6-7134292fa67b', 'dare', 'A challenge to prove courage.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f70835c2-fdfe-4bc5-816d-b36774be7a6b', 'darkness', 'The state of being dark; lack of light.', 'The darkness of the room made it difficult to see.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('be86227b-7bbe-455a-b5c4-302bc8fff99c', 'database', '(general) A collection of (usually) organized information in a regular structure, usually but not necessarily in a machine-readable format accessible by a computer.', 'I have a database of all my contacts in my personal organizer.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('5dc99e2a-d718-42a0-be4c-32890e7df4c4', 'deadline', 'A time limit in the form of a date on or before which something must be completed.', 'I must make this deadline or my boss will kill me!', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('112cb993-f0ea-48b9-846c-3e64e7f71e97', 'deadly', 'Subject to death; mortal.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c61efeb0-904c-42dc-a56e-a4bc8faee0a4', 'dealer', 'One who deals in goods, especially automobiles; a middleman.', 'That used car dealer gave me a great deal on my 1962 rusted-out Volkswagen bug!', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ff5f0736-83de-43c4-8e8a-9ec396110c8a', 'debate', 'An argument, or discussion, usually in an ordered or formal setting, often with more than two people, generally ending with a vote or other decision.', 'After a four-hour debate, the committee voted to table the motion.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('eb2f69cc-8ad3-4c7b-9541-50f34473e501', 'debt', 'An action, state of mind, or object one has an obligation to perform for another, adopt toward another, or give to another.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('38bda307-de4a-4266-902c-26a6dd99ecec', 'decent', 'Appropriate; suitable for the circumstances.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('76d871af-c661-478a-a476-0c7102027ad2', 'deck', 'Any raised flat surface that can be walked on: a balcony; a porch; a raised patio; a flat rooftop.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('fe42040e-4846-471c-b6cf-a432dbb9c292', 'declare', 'To make clear, explain, interpret.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3c20c146-c7ff-4b81-b3fc-f07d65d921f2', 'decline', 'Downward movement, fall.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ce68f91e-88b9-453a-bd5b-ce0bfc37ee97', 'decoration', 'The act of adorning, embellishing, or honoring; ornamentation.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('76af9903-d577-42af-a54d-f4ef1ceb7338', 'decrease', 'An amount by which a quantity is decreased.', 'One research team has recorded Baishui’s decrease at about 27 meters per year over the last 10 years.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6bb21436-1916-4103-9787-450eb8bf4a86', 'deeply', 'At depth, in a deep way.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('fe7e65b6-5c8e-4f3c-9842-bebbce8bf2e5', 'defeat', 'To overcome in battle or contest.', 'Wellington defeated Napoleon at Waterloo.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7d0d7030-fdec-488b-b3c2-87719b475c1d', 'defence', 'The action of defending, of protecting from attack, danger or injury.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('eb07f181-a7b3-49b2-8b7b-c5119ab0f355', 'defend', 'To ward off attacks against; to fight to protect; to guard.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ac516847-df61-434a-866e-b538ff49b144', 'defendant', 'Serving, or suitable, for defense; defensive, defending.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e402b319-c1b5-400d-8d00-59f1c872847f', 'defender', 'Someone who defends people or property', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('341700f0-2fea-4111-94df-a16b529ce13a', 'deflation', 'An act or instance of deflating.', 'The loss caused utter deflation and disappointment among the fans.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d99b9a23-75d7-4f0d-a03b-205fb75eef7b', 'deforestation', 'The process of destroying a forest and replacing it with something else, especially with an agricultural system.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0a213107-0ced-4213-b388-b655c3752912', 'delay', 'A period of time before an event occurs; the act of delaying; procrastination; lingering inactivity.', 'the delay before the echo of a sound', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('803f9edc-86fa-4228-89ac-11c8d99892c3', 'delete', 'A key that may be pressed to delete something (such as text or files) from a computer.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d7be6f79-5a7c-4585-9afc-2034a63d6bc4', 'deliberate', 'To consider carefully; to weigh well in the mind.', 'It is now time for the jury to deliberate the guilt of the defendant.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('84305e9c-783d-4d3b-aa21-7d46fdaf4b41', 'deliberately', 'Intentionally, or after deliberation; not accidentally.', 'He deliberately broke that, didn''t he?', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c2cb4078-5f27-41cb-b327-52d505c29129', 'delight', 'Joy; pleasure.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('26c0e194-acb1-41ba-a415-d87dcfe79c44', 'delighted', 'To give delight to; to affect with great pleasure; to please highly.', 'A beautiful landscape delights the eye.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b4ca1648-772f-447d-8b53-68beadd047c7', 'delivery', 'The act of conveying something.', 'The delivery was completed by four.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7cb71dd7-f33a-4b97-b90f-e849f5b532d9', 'govern', 'The act of governing', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('79d6b0c0-0f94-4a39-956e-ccbf456216c9', 'demand', 'The desire to purchase goods and services.', 'Prices usually go up when demand exceeds supply.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('bcb90105-ff7f-4752-9e60-6e9c102d6cf8', 'democracy', 'Rule by the people, especially as a form of government; either directly or through elected representatives (representative democracy).', '', 'Society', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('acd4d1fc-faec-4ad6-bc2e-be842a03065a', 'democratic', 'Pertaining to democracy; favoring democracy, or constructed upon the principle of government by the people.', 'The United States is a democratic country, as the citizens are allowed to choose leaders to represent their interests.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('56872973-6f2b-46f8-a3a9-2ab45c7fa453', 'demonstrate', 'To show how to use (something).', 'Can you demonstrate the new tools for us?', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('86b2cdcc-e202-4248-8008-5e142167d5a2', 'demonstration', 'The act of demonstrating; showing or explaining something.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c8c5f2cf-8f01-4768-bc44-2264db0b1bf0', 'deny', 'To disallow or reject.', 'I wanted to go to the party, but I was denied.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d4d60041-f9c0-479e-8435-7e8bba16e394', 'depart', 'Division; separation, as of compound substances.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7ed9caf8-d24c-4e50-bf2d-018e664d205e', 'dependent', 'One who relies on another for support', 'With two children and an ailing mother, she had three dependents in all.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('58640c9c-260d-40be-9dbe-abda69bf7e8c', 'deposit', 'Sediment or rock that is not native to its present location or is different from the surrounding material. Sometimes refers to ore or gems.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('33c14939-1804-4bec-9b43-8c097509e563', 'depressed', 'To press down.', 'Depress the upper lever to start the machine.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('694e0651-6a7e-44ea-a972-e272013f9076', 'depressing', 'To press down.', 'Depress the upper lever to start the machine.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('111e979c-7e8c-4afb-b670-e4bf185d3bd3', 'depression', 'In psychotherapy and psychiatry, a state of mind producing serious, long-term lowering of enjoyment of life or inability to visualize a happy future.', 'I used to suffer from depression, but now I''m mostly content with my life.', 'Psychology', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9bf08873-7b9a-494d-ac67-f514ef2ddb0b', 'depth', 'The vertical distance below a surface; the degree to which something is deep', 'Measure the depth of the water in this part of the bay.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1a3570b8-4294-4b42-a0b4-021065fe4f5b', 'derive', 'To obtain or receive (something) from something else.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('cc4e3f0a-e1e9-48d7-bc59-6b9c92773b97', 'deserve', 'To be entitled to, as a result of past actions; to be worthy to have.', 'After playing so well, the team really deserved their win.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ac3efe70-ea71-43a6-921b-b53125b2abde', 'desire', 'Someone or something wished for.', 'It is my desire to speak with you.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1c2abd43-ddb8-463c-9e27-aafe4d3384e7', 'desperate', 'A person in desperate circumstances or who is at the point of desperation, such as a down-and-outer, addict, etc.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6b8113c9-9f57-46ed-8413-e7e179a958a0', 'desperately', 'In a desperate manner; without regard to danger or safety; recklessly.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('82bd4703-5308-4699-b40e-9be12a603d2c', 'destruction', 'The act of destroying.', 'The destruction of the condemned building will take place at noon.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('031a1bcf-76ea-4060-afc8-f52c1a032954', 'detailed', 'To explain in detail.', 'I''ll detail the exact procedure to you later.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7767cf94-c583-47bb-9750-e688925a3dab', 'detect', 'To discover or find by careful search, examination, or probing', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3c703927-560d-4211-ba0a-65c1035512b7', 'determination', 'The act of determining, or the state of being determined.', 'Through sheer determination, we managed to escape from the tornado.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2c2dd436-50e1-40e8-a065-daa1841da9d8', 'devote', 'To give one''s time, focus one''s efforts, commit oneself, etc. entirely for, on, or to a certain matter', 'I devoted this afternoon to repainting my study, and nothing will get in my way.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('08228911-3c37-4d49-8c5e-22dce83f1b49', 'diagnosis', 'To determine which disease is causing a sick person''s signs and symptoms; to find the diagnosis.', '', 'Health', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0ee24c15-cd63-4e60-8d86-d800df8121e7', 'differ', 'Not to have the same traits or characteristics; to be unalike or distinct.', 'These shoes only differ from those ones in having slightly longer laces.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('45af810c-124a-4046-827d-14c9c43af8da', 'dig', 'An archeological or paleontological investigation, or the site where such an investigation is taking place.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ff7cf999-58cd-4a14-8b6b-a26d96b21310', 'dilemma', 'A circumstance in which a choice must be made between two or more alternatives that seem equally undesirable.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('39e74ec4-6c4a-4fad-a94c-a3114cb88f93', 'disability', 'State of being disabled; deprivation or want of ability; absence of competent physical, intellectual, or moral power, means, fitness, and the like.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b9c2f9b9-65dd-48fa-b933-1f2aea2cbb9e', 'disabled', 'To render unable; to take away an ability of, as by crippling.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ebcfeb60-b2b2-49ba-9452-50afd574aa5c', 'disagreement', 'An argument or debate.', 'They had a bit of a disagreement about what color to paint the bedroom, but they have reached a compromise.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f37e8077-f452-42c6-88b1-aec4869c6062', 'disappoint', 'To sadden or displease (someone) by underperforming, or by not delivering something promised or hoped for.', 'His lack of respect disappointed her.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('35b8b964-3841-4c10-8c86-cbba2785c7e0', 'disappointment', 'A feeling of sadness or frustration when a strongly held expectation is not met.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3d0b6490-0d3d-4eb6-bcfc-c5dcd033e681', 'disc', 'A thin, flat, circular plate or similar object.', 'A coin is a disc of metal.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('da55a33d-be28-4602-9e12-24caa79c4b61', 'discipline', 'A controlled behaviour; self-control.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2da024af-6b13-48cc-9e62-1627b45fd589', 'discourage', 'Lack of courage', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e5f20b94-ca9b-4511-a4f9-2263db60c28f', 'discrimination', 'Discernment, the act of discriminating, discerning, distinguishing, noting or perceiving differences between things, with intent to understand rightly and make correct decisions.', '', 'Society', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('401702d4-27bc-4773-97db-c8f1ae1a8d28', 'dishonest', 'Not honest.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('061674ee-5955-4644-a40d-890b6641fac7', 'dismiss', 'To discharge; to end the employment or service of.', 'The company dismissed me after less than a year.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6eb9a8db-01e6-4e2d-ac06-5ca46e493c16', 'disorder', 'Absence of order; state of not being arranged in an orderly manner.', 'After playing the children left the room in disorder.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9e8b9ee1-d8d8-4865-915e-b0ee939e4149', 'display', 'A show or spectacle.', 'The trapeze artist put on an amazing acrobatic display.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('74f5cb90-c6ba-41b1-8cd4-f6e8053df3ab', 'distant', 'Far off (physically, logically or mentally).', 'We heard a distant rumbling but didn''t pay any more attention to it.   She was surprised to find that her fiancé was a distant relative of hers.   His distant look showed that he was not listening to me.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('71a1a399-f6a0-4b0a-b8a6-f17b20144e66', 'distinct', 'Capable of being perceived very clearly.', 'Her voice was distinct despite the heavy traffic.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a051becc-9ce9-46d4-aecd-bb71d486ed66', 'distinguish', 'To recognize someone or something as different from others based on its characteristics.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a8f50251-d821-4e95-a8dd-09031d3b5821', 'distract', 'To divert the attention of.', 'The crowd was distracted by a helicopter hovering over the stadium when the only goal of the game was scored.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('876e3dcc-b30c-4927-a7c4-27abc19efcdf', 'distribute', 'To divide into portions and dispense.', 'He distributed the bread amongst his followers.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d9ad58f3-7df9-462b-803f-2ede7cd77cf0', 'distribution', 'An act of distributing or state of being distributed.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('29a98b67-ab93-4207-9294-a29b21edb49d', 'district', 'An administrative division of an area.', 'the Soho district of London', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d39ebb4f-c564-49a9-9725-999c43e92b70', 'disturb', 'Disturbance', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('616454c1-f8a8-4e2b-9d28-390d6eb222db', 'dive', 'A jump or plunge into water.', 'the dive of a hawk after prey', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ed42e45d-ce85-4453-ab45-c8221416374d', 'diverse', 'Consisting of many different elements; various.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ba613e29-aeb0-4903-a987-4fb6d580ff70', 'diversity', 'The quality of being diverse or different; difference or unlikeness.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f7e1872d-474d-4d70-b98b-cb467b9785ff', 'dividend', 'A number or expression that is to be divided by another.', 'In "42 ÷ 3" the dividend is the 42.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('392e42ad-dfdc-4c73-b644-d3c6981630f4', 'division', 'The act or process of dividing anything.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('00c1f2de-3945-46d0-b93c-fa8a6b7fc5ad', 'divorce', 'The legal dissolution of a marriage.', 'Richard obtained a divorce from his wife some years ago, but hasn''t returned to the dating scene.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('41917dca-67d9-4cae-8346-84f101aa5185', 'domestic', 'A house servant; a maid; a household worker.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ccafb514-36b4-4bc5-bb42-a1c2281d61e0', 'dominant', 'The fifth major tone of a musical scale (five major steps above the note in question); thus G is the dominant of C, A of D, and so on.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2c3b19ed-d306-45df-b7df-67a94422e86a', 'dominate', 'Ruling; governing; prevailing', 'The dominant party controlled the government.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ef7c817c-e79e-4341-96a2-b1ae7e764d65', 'donation', 'A voluntary gift or contribution for a specific cause.', 'They were collecting donations for the elderly at Christmas.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('cde956bd-9750-42a7-ad10-788011a93340', 'dosage', 'The administration of a medication etc, in a measured amount; dosing.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ee602cc3-9e2c-4f89-8e00-be8446ee204f', 'dot', 'A small, round spot.', 'a dot of colour', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('529211c7-dfde-4b43-b27d-3b6fee1f2d4d', 'downtown', 'The main business part of a city or town, usually located at or near its center.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a8cdaa12-3fcd-41e9-af3d-c93c34938f65', 'downwards', 'Towards a lower place; towards what is below.', 'Gravity pulls everything downwards.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('92d187e8-ccac-4c7e-b633-0d4a4aaa867f', 'dozen', 'A set of twelve.', 'Can I have a dozen eggs, please?', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('42101bad-ba18-4a86-b769-8bcebb40781e', 'draft', 'A current of air, usually coming into a room or vehicle.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('5e2376e4-7e96-46b0-ac5b-c0b58e131b86', 'drag', 'Resistance of the air (or some other fluid) to something moving through it.', 'When designing cars, manufacturers have to take drag into consideration.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0b3447f9-caea-454b-bfe3-75cbfcfd55af', 'dramatic', 'Of or relating to the drama.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('033653be-ba50-4f43-8508-c7bcaa28bb7c', 'dramatically', 'In a dramatic manner.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1479d233-85ca-4d61-b8f0-8d69c77a3f9a', 'drought', 'A period of unusually low rainfall, longer and more severe than a dry spell.', '', 'Environment', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b677dedd-f453-49f5-a8cc-58eb55a9d50c', 'dull', 'To render dull; to remove or blunt an edge or something that was sharp.', 'Years of misuse have dulled the tools.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b70f3203-2332-41d2-8587-3395f6f17045', 'dump', 'A place where waste or garbage is left; a ground or place for dumping ashes, refuse, etc.; a disposal site.', 'A toxic waste dump.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0b8b117e-1d96-49c7-ab61-60d398673f8a', 'duration', 'An amount of time or a particular time interval.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6a452122-b283-4b95-86ad-af4e3cdd03f2', 'dynamic', 'A characteristic or manner of an interaction; a behavior.', 'Watch the dynamic between the husband and wife when they disagree.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e7f4f1eb-7e83-4730-929c-c952e969b7d9', 'economics', 'The study of resource allocation, distribution and consumption; of capital and investment; and of management of the factors of production.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f297752f-0fc3-487d-85b2-c6aa5bbda2dc', 'economist', 'An expert in economics, especially one who studies economic data and extracts higher-level information or proposes theories.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1b91f0b2-3f90-4037-9728-f474f999f4a4', 'ecosystem', 'A system formed by an ecological community and its environment that functions as a unit.', '', 'Environment', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('78d49aa6-d3d1-46e2-a2fd-9455cb9ae77f', 'edit', 'A change to the text of a document.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a6bc96d1-81ef-4831-8933-3323c07ef978', 'edition', 'A written work edited and published, as by a certain editor or in a certain manner.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1b9d284a-06d2-4e7e-8611-e7ad5efa3b76', 'editorial', 'An article in a publication giving the opinion of its editors on a given topic or current event.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('04cee077-31b9-4484-91da-91da734fda2a', 'efficient', 'A cause; something that causes an effect', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b31da794-60e9-4f2f-9a2f-3b0879840102', 'efficiently', 'In an efficient manner.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('eb781640-fb2d-43da-9792-2607ca6c9e4b', 'elbow', 'The joint between the upper arm and the forearm.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('289a2b6c-f437-4541-96d2-61077221a9c2', 'elderly', 'An elderly person', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('44208aa0-dd15-4e85-a49f-4e9fd7b0601f', 'elect', 'One chosen or set apart.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ef4d4476-e61d-4d50-9eeb-4b90033d48f0', 'electronics', 'The study and use of electrical devices that operate by controlling the flow of electrons or other electrically charged particles or by converting the flow of charged particles to or from other forms of energy.', 'Electronics is a popular subject.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8fb9bdc7-775b-4072-a981-c8a67499612f', 'elegant', 'Characterised by or exhibiting elegance.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0d074fb8-e4d7-476d-818a-93d3cc4bf376', 'elementary', 'An elementary school', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a7645ed9-dc25-4618-a1e1-8e0f777f5ad9', 'eliminate', 'To completely remove, get rid of, put an end to.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e383d7ef-8ac7-4898-8894-aedfce009399', 'elsewhere', 'A place other than here.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e8635de9-964c-4670-b309-50f1c6b5dfbe', 'embrace', 'An act of putting arms around someone and bringing the person close to the chest; a hug.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8c95417d-f89c-43d3-b73f-972e72c186f8', 'emerge', 'To come into view.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c1595ae1-de3e-4fb9-a050-786f102a636c', 'emission', 'Something which is emitted or sent out; issue.', 'the emission was mostly blood', 'Environment', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1ae64780-4f7d-4782-9ee8-9343a5a6a1a7', 'emotional', 'Of or relating to the emotions.', 'emotional crisis', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('bb7c104d-6441-4e14-b9e4-80f9b2e4447f', 'emotionally', 'In an emotional manner; displaying emotion.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('63d54265-5209-4667-93cb-81b844b1627f', 'empathy', 'Identification with or understanding of the thoughts, feelings, or emotional state of another person.', 'She had a lot of empathy for her neighbor; she knew what it was like to lose a parent too.', 'Psychology', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b962bfb6-4855-461a-80d6-bf1196918710', 'emphasis', 'Special weight or forcefulness given to something considered important.', 'He paused for emphasis before saying who had won.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('144795cc-6bf2-44ed-b9ec-b09f8647174e', 'emphasize', 'To stress, give emphasis or extra weight to (something).', 'His two-fingered gesture emphasized what he had told his boss to do with his job.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ac2afa40-8f8d-4662-beda-999e5ef4fcd0', 'empire', '(furniture) Following or imitating a style popular during the First French Empire (1804–1814).', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('bc817726-4fa5-4ca8-a452-44aa5795449b', 'empirical', 'Pertaining to or based on experience.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2c45d583-2294-4807-afa7-38b38d084a0c', 'enable', 'To make somebody able (to do, or to be, something); to give sufficient ability or power to do or to be; to give strength or ability to.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ac1d7981-c4c9-41d8-90a3-79271889d9d2', 'encounter', 'A meeting, especially one that is unplanned or unexpected.', 'Their encounter was a matter of chance.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('fa52e0b3-2f95-4515-9cfd-08b2012618de', 'engage', '(heading) To interact socially.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('43ffcee0-4716-433e-9171-f78725b1708c', 'enhance', 'To lift, raise up.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3f6a6c5a-4391-47bd-bb5f-e5a7db8f6b64', 'enjoyable', 'Pleasant, capable of giving pleasure.', 'That was an enjoyable day; I had a lot of fun.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('83e2de35-10c8-4d61-afbe-746ab88e709f', 'enquiry', 'A question.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('844eb364-d143-4a13-b4c9-114074b58c28', 'ensure', 'To make a pledge to (someone); to promise, guarantee (someone of something); to assure.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3980404f-3b11-4212-a7de-203f6fce623e', 'entertaining', 'To amuse (someone); to engage the attention of agreeably.', 'The motivational speaker not only instructed but also entertained the audience.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7aa005cf-f70a-4e69-89c0-fd4598f4956e', 'enthusiasm', 'Possession by a god; divine inspiration or frenzy.', '', 'Psychology', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('89426e29-6b48-4d3b-a187-89f3b57d4e8d', 'enthusiastic', 'With zealous fervor; excited, motivated.', 'an enthusiastic lover of art', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f04fa6dc-b91f-4392-adf5-bd87497b3255', 'entire', 'The whole of something; the entirety.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('033e0475-128f-4074-b00b-9fd671f4462a', 'entirely', 'To the full or entire extent.', 'It is entirely up to you where we go, as I’ll be happy with anywhere.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0d747850-b682-4ddf-be77-dcc2296040f1', 'entrepreneur', 'A person who organizes and operates a business venture and assumes much of the associated risk.', '', 'Business', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0c228647-82dd-420a-8f77-923667215a2a', 'envelope', 'A paper or cardboard wrapper used to enclose small, flat items, especially letters, for mailing.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('74bf96e9-5543-4b01-b2e7-171082bce861', 'epidemic', 'A widespread disease that affects many individuals in a population.', '', 'Health', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('722817e7-0f6b-44aa-ac2f-c86edc4e1099', 'equip', 'To supply with something necessary in order to carry out a specific action or task; to provide with (e.g. weapons, provisions, munitions, rigging)', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('931e151c-f2c0-4842-811b-a71cae903151', 'equivalent', 'Anything that is virtually equal to something else, or has the same value, force, etc.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e48eb3fa-ce0e-4ebf-9bab-00e12564cc28', 'era', 'A time period of indeterminate length, generally more than one year.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('44320955-31c2-4813-b0ee-a2b99cd8cda5', 'erosion', 'The result of having been worn away or eroded, as by a glacier on rock or the sea on a cliff face.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('943042ab-3a0f-411e-b323-265b2b2f8f66', 'erupt', 'To eject something violently (such as lava or water, as from a volcano or geyser).', 'The volcano erupted, spewing lava across a wide area.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3af0bd9b-ddcc-4aec-b767-9d9ca3b19891', 'essentially', 'In an essential manner; in essence', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('69a0d86c-51b9-45f5-be6d-29ce4261cc33', 'establish', 'To make stable or firm; to confirm.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7eba3588-4643-4a62-a10b-8b12bcd11615', 'estate', 'The collective property and liabilities of someone, especially a deceased person.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a17c82e1-ed23-4224-893f-4724e8db154d', 'estimate', 'A rough calculation or assessment of the value, size, or cost of something.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('40c10a21-0b65-4674-a05c-7777016848fa', 'ethic', 'A set of principles of right and wrong behaviour guiding, or representative of, a specific culture, society, group, or individual.', 'I think the golden rule is a great ethic.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a1995795-eebd-4074-9365-3898fc54dc62', 'ethical', 'An ethical drug, one only dispensed on the prescription of a physician.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1d72aa0c-ef68-48d6-80c0-857b432e2e55', 'ethnic', 'An ethnic person, especially a foreigner or member of an immigrant community.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('117af642-8da3-4c69-852c-2f734a0c4949', 'evaluate', 'To draw conclusions from examining; to assess.', 'It will take several years to evaluate the material gathered in the survey.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('990226a2-73b0-4dbb-a226-9b91fe1771a7', 'evaluation', 'An assessment, such as an annual personnel performance review used as the basis for a salary increase or bonus, or a summary of a particular situation.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('caa78073-0f44-4d97-ae7c-945f41d06c2d', 'evident', 'Obviously true by simple observation.', 'It was evident she was angry, after she slammed the door.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('92b752f2-ac1f-41ac-8d36-e22cc8da24e1', 'evil', 'Moral badness; wickedness; malevolence; the forces or behaviors that are the opposite or enemy of good.', 'Evil lacks spirituality, hence its need for mind control.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6270e201-1a8b-40f7-a97c-dc4762888471', 'evolution', 'A change of position.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ce6b3f43-b7e5-4f04-9bc9-27ee6e8fd368', 'evolve', 'To move in regular procession through a system.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('bd64f604-6d8a-4849-a3cb-ff595913cf6b', 'examination', 'The act of examining.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a1283ec2-e13d-4e93-940c-a70a76d8e0da', 'exceed', 'To be larger, greater than (something).', 'The company''s 2005 revenue exceeds that of 2004.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0fe3a6ee-a735-4007-9aed-1297b993cda1', 'exception', 'The act of excepting or excluding; exclusion; restriction by taking out something which would otherwise be included, as in a class, statement, rule.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('335f9158-f9bb-4517-8587-30425115e348', 'excessive', 'Exceeding the usual bounds of something; extravagant; immoderate.', 'Putting a wide vibrato on a single 16th triplet note at 160 beats per minute seems rather excessive.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ea18f2cf-6f92-449f-8b23-8ead079c1cb8', 'exclude', 'To bar (someone) from entering; to keep out.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c729fc00-29e8-4e43-a6ca-d29f10be4c8a', 'excuse', 'Explanation designed to avoid or alleviate guilt or negative judgment; a plea offered in extenuation of a fault.', 'Tell me why you were late – and I don''t want to hear any excuses!', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('616431f7-1bf5-4000-9fe1-88c1b98489fd', 'executive', 'A chief officer or administrator, especially one who can make significant decisions on their own authority.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2d04159f-4b4e-48d3-934a-8de7337bea15', 'exhibit', 'An instance of exhibiting.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('30273323-278e-48d1-90ae-d93d526295da', 'exit', 'An act of going out or going away, or leaving; a departure.', 'He made his exit at the opportune time.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('060bdde6-8cad-47d5-bd85-630127c51500', 'exotic', 'An organism that is exotic to an environment.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('27bb74fd-cf1d-4d30-8c34-7d5a907eac59', 'expansion', 'The act or process of expanding.', 'The expansion of metals and plastics in response to heat is well understood.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6314fcde-ac2a-48c8-85e8-9701b6888424', 'expectation', 'The act or state of expecting or looking forward to an event as about to happen.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0127dd08-7d56-4ad3-a518-cf4d3d2928e7', 'expenditure', 'Act of expending or paying out.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('073b9b87-30ab-43af-883e-32c441f83f87', 'expense', 'A spending or consuming, often a disbursement of funds.', 'Buying the car was a big expense, but will be worth it in the long run.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b70ac0cc-7384-4d17-9b66-42a626d5c0b1', 'expertise', 'Great skill or knowledge in a particular field or hobby.', 'The scientist has expertise in the field of nuclear fusion.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3ff26bcb-92ea-4628-8ea4-639b50462566', 'exploit', 'A heroic or extraordinary deed.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b5094a9a-9c38-42f2-a227-879b0acb4e92', 'exploration', 'The process of exploring.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('55f45b69-28c5-4314-9139-333025daf73b', 'expose', 'To reveal, uncover, make visible, bring to light, introduce to.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3f4d25e1-836d-4eeb-b03b-a29931009f03', 'exposure', 'The condition of being exposed, uncovered, or unprotected.', 'Limit your exposure to harsh chemicals.   Get as much exposure to a new language as you can.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('fbaeaadb-5389-4244-9c3c-4b7e2e6b25c8', 'extend', 'To increase in extent.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2bc8881f-f3bc-4ab2-83d1-de115bc1b0f2', 'extension', 'The act of extending; a stretching out; enlargement in length or breadth; an increase', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('60d848e0-9b29-4a66-8961-e2d4962f495a', 'extensive', 'Having a great extent; covering a large area; vast', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c5eb82bc-8721-4c5a-9fda-f61b2bdb6e0a', 'extensively', 'In an extensive manner, widely.', 'He has read and traveled extensively.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7f788df6-c7b6-4499-932b-ad1d0ce8cd24', 'extent', 'A range of values or locations.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4ad21e0e-1951-4417-8afe-9702785bdbf3', 'external', '(chiefly in the plural) The exterior; outward features or appearances.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e5520cb1-a7cd-4ad3-85e9-c15647a047dd', 'extinction', 'The action of making or becoming extinct; annihilation.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('32e05f7b-7980-4739-9150-32ffb4ba9759', 'extract', 'Something that is extracted or drawn out.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('98cf4a94-63a3-4d8c-8e7e-68e92e477ef3', 'extraordinary', 'Anything that goes beyond what is ordinary.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('94f43020-7ebb-4713-bc94-8e2bfb3c93f9', 'fabric', 'An edifice or building.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('299a2721-7d96-4d71-bda8-5cbb44194a6a', 'fabulous', 'Of or relating to fable, myth or legend.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('03f1f621-68a5-43ba-aa1f-3b3770b673ba', 'facility', 'The fact of being easy, or easily done; absence of difficulty, simplicity.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e1bae84e-5d67-4584-b991-28960dfeb6c9', 'failed', 'To be unsuccessful.', 'Throughout my life, I have always failed.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('78e702aa-1bba-4016-a986-7235f24a2525', 'failure', 'State or condition of not meeting a desirable or intended objective, opposite of success.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a8f6dd20-2f12-4ef9-b5fe-67ec13c415ce', 'faith', 'A trust or confidence in the intentions or abilities of a person, object, or ideal from prior empirical evidence.', 'I have faith in the goodness of my fellow man.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c014ab37-8c8d-44d0-9a09-3492f020f0d4', 'fake', 'Something which is not genuine, or is presented fraudulently.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d95c1f10-09d0-4b88-9c5b-e299e078a8d2', 'fame', 'What is said or reported; gossip, rumour.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2a7bc27d-e623-4186-b661-d81e3ce52214', 'fantasy', 'That which comes from one''s imagination.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('25fcdccf-b3ac-42a1-8660-8d6409047849', 'fare', 'A going; journey; travel; voyage; course; passage.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c9a18dc3-d3d3-48bc-9443-a1be5303c149', 'fault', 'A defect; something that detracts from perfection.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('bf0c295f-061d-4201-9664-e683dfc2a679', 'feather', 'A branching, hair-like structure that grows on the bodies of birds, used for flight, swimming, protection and display.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7c4bede9-4f62-43f1-a61b-fb0616719c9f', 'federal', 'A law-enforcement official of the FBI; a federal agent.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a7607a0c-7a67-42d4-9875-c4706efcd896', 'fee', '(feudal law) A right to the use of a superior''s land, as a stipend for services to be performed; also, the land so held; a fief.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2181c53b-9bd6-42dd-92c4-2679360356c8', 'feedback', 'Critical assessment of a process or activity or of their results.', 'After you hand in your essays, I will give both grades and feedback.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('974c43d3-5a93-422b-835d-c4e6181fd842', 'fellow', 'A colleague or partner.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('39cfedaf-6371-49c2-9d3c-cc2fe2d325f4', 'fever', 'A higher than normal body temperature of a person (or, generally, a mammal), usually caused by disease.', '"I have a fever. I think I''ve the flu."', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('070035a4-61f1-43ee-b2dc-88d082163bec', 'finding', 'To encounter or discover by accident; to happen upon.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('467ff818-9fa1-4563-bb8d-24f6ede14962', 'firefighter', 'A person who puts out fires.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('261b13a1-f161-4562-af6f-6843f90930ac', 'firework', 'A device using gunpowder and other chemicals which, when lit, emits a combination of coloured flames, sparks, whistles or bangs, and sometimes made to rocket high into the sky before exploding, used for entertainment or celebration.', 'Commercial firework displays are commonly launched from boats or other vessels', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a0a477a6-aed2-4bf7-a6e4-ea27f2359063', 'firm', 'A business partnership; the name under which it trades.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f2ce6ffb-4a54-4f2f-82a0-63da420ac5a5', 'firmly', '(manner) In a firm or definite or strong manner.', 'She corrected him firmly but gently.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('5a636885-3041-4e38-bd1a-3db7cd766fe0', 'fiscal', 'A public official in certain countries having control of public revenue.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0a2448cf-69d2-4f75-a79e-80e10a7b75a9', 'flame', 'The visible part of fire; a stream of burning vapour or gas, emitting light and heat.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4222c4b8-0a58-424d-8393-4bab16dc7fe8', 'flash', 'A device that produces a short flash of light to help illuminate a scene, mostly for night-time or indoors photography.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('45b463b9-3456-4b70-a8ec-4862aa39424f', 'flavour', 'The quality produced by the sensation of taste or, especially, of taste and smell in combined effect.', 'The flavor of this apple pie is delicious.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('69996940-e0d2-4f8e-8d04-d0a38e0994a3', 'flexible', 'Something that is flexible.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('453d7edc-c436-493c-beee-7529f45f81bf', 'float', 'A buoyant device used to support something in water or another liquid.', 'Attach the float and the weight to the fishing line, above the hook.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6e5ebc53-c6ab-4b31-9244-6247607dccd4', 'folding', 'To bend (any thin material, such as paper) over so that it comes in contact with itself.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('844b8722-fbb4-493b-b7a4-c3cd1ad21751', 'folklore', 'The tales, legends and superstitions of a particular ethnic population.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ff2df61c-5827-49be-a9e2-00310d2b0849', 'fond', 'To have a foolish affection for, to be fond of.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('63f0f9d3-aa9d-4e80-b90a-0aa1f8870494', 'fool', 'A person with poor judgment or little intelligence.', 'The village fool threw his own shoes down the well.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('67efd3af-7e0e-4d53-b10d-3d3376036080', 'forbid', 'To disallow; to proscribe.', 'Smoking in the restaurant is forbidden.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e8350915-9744-4129-9585-36e6440b9995', 'forecast', 'An estimation of a future condition.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c6843a03-67e1-4fa3-89b7-b44a29bc5e0a', 'forgive', 'To pardon; to waive any negative feeling or desire for punishment, retribution, or compensation.', 'Forgive others, not because they deserve forgiveness, but because you deserve peace.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b10c0645-a5cc-4fdf-a933-a0d0892f9c49', 'format', 'The layout of a publication or document.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('183577ab-9c58-4b66-9da2-841a50b03d02', 'formation', 'Something possessing structure or form.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('966e24f9-15c1-4cd3-a37b-bd15a47822ca', 'former', 'Previous.', 'A former president;  the former East Germany', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d4b89e1b-b311-4268-9fc2-1014b3ca9d43', 'formerly', 'At some time in the past', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('71b20be7-be70-40b5-a120-86d00d1ee9b9', 'fortunate', 'Auspicious.', 'It is a fortunate sign if the sun shines on a newly wedded couple.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('dd8a0b93-0542-4f95-aa7a-7cc5519893a4', 'fortune', 'Destiny, especially favorable.', 'She read my fortune. Apparently I will have a good love life this week, but I will have a bad week for money.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('444f8c09-5912-45e2-9ea7-cc967628036a', 'forum', 'A place for discussion.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('98150cf5-0ab6-411f-85b2-f54fda2c3bf9', 'fossil', 'The mineralized remains of an animal or plant.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e89c4267-4e10-4888-a5af-3966b5e66c01', 'foundation', 'The act of founding, fixing, establishing, or beginning to erect.', 'The foundation of his institute has been wrought with difficulty.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6225521d-79b2-4833-b116-15eb86723f40', 'founder', 'One who founds or establishes (especially said of a company, project, organisation, state)', 'the founder of Facebook, Mark Zuckerberg', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('90f94b89-aec6-4aea-ad91-9729351ad1c5', 'fraction', 'A part of a whole, especially a comparatively small part.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('52dc086b-5054-40d5-b0bd-f26857ce3ff4', 'fragment', 'A part broken off; a small, detached portion; an imperfect part, either physically or not', 'I heard a small fragment of the conversation.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4b00cbb5-3058-47f4-aca1-b2f6c4622f0c', 'framework', 'A support structure comprising joined parts or conglomerated particles and intervening open spaces of similar or larger size.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6fbc102b-b075-49bc-880b-60e60429d553', 'fraud', 'The crime of stealing or otherwise illegally obtaining money by use of deception tactics.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('68e4cb70-c03c-4437-a05a-9feb40bb344c', 'freely', 'Free; frank.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a1fc04f4-e867-48ca-8118-11da826b5054', 'frequency', 'The rate of occurrence of anything; the relationship between incidence and time period.', 'The frequency of bus service has been improved from one every 15 to one every 12 minutes.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ee2cdeae-dfad-493e-9225-76ffab56152b', 'frequent', 'Done or occurring often; common.', 'I am a frequent visitor to that city.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6c8ac6a8-16fa-4635-9423-d5f992c4e511', 'frustration', 'The feeling of annoyance when one''s actions are criticized or hindered', '', 'Psychology', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7b282a3d-1dae-45e3-920d-fccca2162f63', 'fulfil', 'To satisfy, carry out, bring to completion (an obligation, a requirement, etc.).', 'You made a promise, son, and now you must fulfill it.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d8331f81-90d4-4851-8f47-3ad73a34a9ec', 'full-time', 'Involving a full amount of time spent on some activity, especially a job.', 'Bringing up a child is a full-time activity.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('62ee8207-c9c6-481c-9ed6-b72220fba57e', 'fully', 'In a full manner; without lack or defect.', 'He fully met his responsibilities.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c36f4fa4-7986-4e70-8c0e-6cc12c9f9b96', 'fund', 'A sum or source of money.', 'a fund for the maintenance of underprivileged students', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3ddb403f-0287-4e83-a1c2-59ead237544b', 'fundamental', '(usually in the plural) A leading or primary principle, rule, law, or article, which serves as the groundwork of a system; an essential part', 'one of the fundamentals of linear algebra', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('171225f8-38d0-4f64-ac75-405842c1a27c', 'fundamentally', 'In a fundamental or basic sense; reaching the very core of the matter.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c6e06352-776c-4eba-9da0-fe113f7a1118', 'funding', 'To pay for.', 'He used his inheritance to fund his gambling addiction.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('faacc518-6c43-4615-8b19-29715944ad97', 'furious', 'Feeling great anger; raging; violent.', 'a furious animal; parent furious at their child''s behaviour', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b03c7924-648a-4f10-9336-845e90937a0e', 'furthermore', 'In addition; besides; what''s more; used to denote additional information.', 'He skillfully took charge of the event, and furthermore, he stayed late after it to clean up.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1a72b97b-752a-49dc-ad24-cf829824bf68', 'gain', 'The act of gaining; acquisition.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('76b775b0-0a9e-44ca-a28f-bb34f18f38cf', 'gaming', 'To gamble.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0d92aa33-ca84-43bb-baee-015c11ba491c', 'gang', 'To go; walk; proceed.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ac6ba315-ca71-4d2f-8efd-c64fa2f15512', 'gay', '(chiefly in plural or attributive) A homosexual, especially a male homosexual; see also lesbian.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f6bfc095-286b-4729-b1f0-f181082d6aab', 'gender', 'Class; kind.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('cbee86eb-67ac-4078-8511-efac2a9dd776', 'gene', 'A theoretical unit of heredity of living organisms; a gene may take several values and in principle predetermines a precise trait of an organism''s form (phenotype), such as hair color.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d672383d-c1bd-46e9-a345-9c83d820f3f1', 'generate', 'To bring into being; give rise to.', 'The discussion generated an uproar.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7c31b5dd-9448-41cc-b51a-c931abc6d4df', 'genetic', 'Relating to genetics or genes.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9119c5a2-5ae3-45e0-9f99-3dae1fb0ce9c', 'genius', 'Someone possessing extraordinary intelligence or skill; especially somebody who has demonstrated this by a creative or original work in science, music, art etc.', 'I think that would qualify as not smart, but genius... and a very stable genius at that!', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('18fcc927-be19-4214-84cc-d381cd0fff07', 'genre', 'A kind; a stylistic category or sort, especially of literature or other artworks.', 'The computer game Half-Life redefined the first-person shooter genre.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('063f1b17-fdb5-44a0-ae5b-668d94ac9a43', 'genuine', 'Belonging to, or proceeding from the original stock; native', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c5830c36-d329-4509-8f82-9cae5b4b7fa6', 'genuinely', 'In a genuine manner; truthfully, truly.', 'I thought they were joking at first, but it seemed they were genuinely interested in the talk about glaciers.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a4153740-e2c0-428a-bd1a-073065489df9', 'geological', 'Of, or relating to geology or a geologic time scale.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6849ef6c-5995-4f3c-8cbe-cba7f5f644f5', 'gesture', 'A motion of the limbs or body, especially one made to emphasize speech.', 'The middle-finger gesture is really a nonverbal swear.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('196b591c-bf06-4aaf-8f6f-5e66ad00616e', 'gig', 'A performing engagement by a musical group; or, generally, any job or role, especially for a musician or performer.', 'Hey, when are we gonna get that hotel gig again?', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('564640fc-bd28-4a66-a280-a60f41080bf4', 'globalization', 'The process of becoming a more interconnected world.', '', 'Society', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e1ef480f-34e1-46c2-ae0a-43f5a9beeb7e', 'globe', 'Any spherical (or nearly spherical) object.', 'the globe of the eye; the globe of a lamp', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('46285d8a-c245-4924-8d6d-e38d3c576dd2', 'golden', 'Kyphosus vaigiensis, a fish found in southeast Asia.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2b17e2d6-e248-4795-88f6-b28dbb5322fd', 'goodness', 'The state or characteristic of being good.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a5581de3-83c7-4f68-bd31-1dcfda3524c6', 'gorgeous', '(of a person or place) Very beautiful.', 'All the contest judges agreed that Brigitt was absolutely gorgeous.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4dec476c-c65f-41ca-a947-6b0a6461f26c', 'governor', 'The chief executive officer of a first-level division of a country.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('32eb8bc4-9a85-4c6c-b336-3da6445e36df', 'grab', 'A sudden snatch at something.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('fd73937a-76d0-42f7-86a5-614d0038f196', 'gradually', 'In a gradual manner; making slow progress; slowly.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('bf9f1a12-c116-48d6-a81e-c385e35baf46', 'grand', '(plural "grand") A thousand of some unit of currency, such as dollars or pounds. (Compare G.)', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0825248d-092d-4a49-9ff4-3b600e05039b', 'grant', 'The act of granting; a bestowing or conferring; concession; allowance; permission.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a589ec8a-9d84-4ae0-8706-3c5cf5a08df4', 'graphic', 'A drawing or picture.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b4c7e786-a5dc-48e3-86a6-21c9e0da7540', 'graphics', 'The making of architectural or design drawings.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('911ecbfe-0232-43e4-80ed-684c263080e7', 'gratitude', 'The state of being grateful.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b4ed9252-d247-4335-a82b-f34365ff3738', 'greatly', 'To a great extent or degree.', 'Expenses greatly exceeded revenues this year.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0f9227a4-2d30-47f1-aacd-15d16cb93b35', 'greenhouse', 'A building used to grow plants, particularly one with large glass windows or plastic sheeting to trap heat from sunlight even in intemperate seasons or climates.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8a213ca9-8ba5-4113-bbab-e002ec5d04f1', 'grocery', '(usually groceries) retail foodstuffs and other household supplies.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a35baf4d-d933-44fa-a758-4c0db24c1188', 'guarantee', 'Anything that assures a certain outcome.', 'Can you give me a guarantee that he will be fit for the match?', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c0261420-9aef-494c-b97d-98403e92d8b0', 'guideline', 'A non-specific rule or principle that provides direction to action or behaviour.', 'He considered the Ten Commandments more a guideline than a requirement.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('bacb5922-7245-4fd8-9824-a219492ecb00', 'habitat', 'Conditions suitable for an organism or population of organisms to live.', 'This park offers important amphibian habitat and breeding area.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a2bdf4f6-2747-4deb-91ef-508a26042bce', 'handle', 'The part of an object which is (designed to be) held in the hand when used or moved.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a294893f-c580-4284-8812-4f29fb737a4e', 'harbour', 'Any place of shelter.', 'The neighborhood is a well-known harbor for petty thieves.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('cf366f12-da57-42c8-bd46-2b289c51fb0d', 'harm', 'Physical injury; hurt; damage', 'No harm came to my possessions.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('fae39364-8efd-4769-8b4c-be42d6a6ca36', 'harmful', 'Of a kind likely to be damaging; injurious', 'Wear a hat to protect your skin from harmful sunlight.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('161a654d-7fd7-4375-8381-9cb258448dac', 'headquarters', 'The military installation from which troops are commanded and orders are issued; the military unit consisting of a commander and his support staff.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('99cddb2b-c581-4fb5-a6c0-5f4effd3243a', 'heal', 'A spell or ability that restores hit points or removes a status ailment.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3d5c9c19-8071-4ac1-943f-5d97f46c3342', 'healthcare', 'The prevention, treatment, and management of illness or the preservation of mental and physical well-being through the services offered by the medical, nursing, and allied health professions.', 'I think free health care should also cover nearsightedness.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('66d1ca07-4b6e-4b6c-b5f4-0269d2c7b991', 'hearing', '(stative) To perceive sounds through the ear.', 'I was deaf, and now I can hear.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('341e45f3-fec4-42ae-9c3e-a828e150459d', 'heaven', 'The sky, specifically:', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6b8f132d-06f8-4211-9aa3-2f90c87bcb37', 'heel', 'The rear part of the foot, where it joins the leg.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4cb769da-a65c-4717-9e5a-9cdf25acfd05', 'helmet', 'A protective head covering, usually part of armour.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ba27b996-bb99-43b9-b681-d80f1f302557', 'hence', 'From here, from this place, away', 'Get thee hence, Satan!', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2e811950-b1b4-4065-82a4-076c58eabcb8', 'herb', 'Any green, leafy plant, or parts thereof, used to flavour or season food.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('93ae1580-9ca3-4b36-b4e1-43eb9afc3754', 'heritage', 'An inheritance; property that may be inherited.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('92cbcb07-6311-49cf-b1c3-99160193401b', 'hesitate', 'To stop or pause respecting decision or action; to be in suspense or uncertainty as to a determination.', 'He hesitated whether to accept the offer or not; men often hesitate in forming a judgment.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('dc852483-0a91-4236-aab3-0a2fe3325ca2', 'hidden', 'Located or positioned out of sight; not visually apparent.', 'hidden treasure; hidden talents', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9221b20d-2ab1-4874-b5fd-a8dbba3b4433', 'highway', 'A motor vehicle for transporting large numbers of people along roads.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0f37e3c0-7d5b-4e6b-ad0b-6c17f7be0f62', 'hilarious', 'Very funny; causing great merriment and laughter.', 'a hilarious joke', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('30598277-4d27-4e94-9698-6bea00a9d9fa', 'hip', 'The outward-projecting parts of the pelvis and top of the femur and the overlying tissue.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('293fc80e-9313-4e02-b39c-35a439524d9e', 'historian', 'A writer of history; a chronicler; an annalist.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2ba2fc5a-ef93-4ea5-9ec5-2b113d291942', 'hollow', 'A small valley between mountains.', 'He built himself a cabin in a hollow high up in the Rockies.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4a1c4700-4e4b-4675-8d8e-b3db7e4a69b5', 'holy', 'A thing that is extremely holy; used almost exclusively in Holy of Holies.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('40b6f7c7-c31c-4855-b3c3-e2ae77941b47', 'homeless', 'Lacking a permanent place of residence.', 'Whenever I pass the park, I see the homeless people sleeping on the benches.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('07ebf06c-9bed-4e8a-9b0a-229182b281f2', 'honesty', 'The act, quality, or condition of being honest.', 'academic / artistic / emotional / intellectual honesty', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('00111d30-8d78-42fc-b9f2-fa09aed21c20', 'honour', 'Recognition of importance or value; respect; veneration (of someone, usually for being morally upright or successful)', 'The crowds gave the returning general much honor and praise.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('45f918b5-e298-41cf-9a83-3c5815a2b884', 'indication', 'Act of pointing out or indicating.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('11d57da4-a139-4639-b8c1-a5b3de9e96e1', 'hook', 'A rod bent into a curved shape, typically with one end free and the other end secured to a rope or other attachment.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a6f43627-3664-4acb-b8ba-49a2a235a863', 'hopefully', 'In a hopeful manner.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6e539f0c-78bc-4d98-801a-0d477f125172', 'household', 'Collectively, all the persons who live in a given house; a family including attendants, servants etc.; a domestic or family establishment.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9224fadb-8cb5-4d32-9ae0-660a30dec878', 'housing', 'To keep within a structure or container.', 'The car is housed in the garage.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('289596ec-3ce7-4659-9faf-0c4d59c5b5af', 'humorous', 'Full of humor or arousing laughter; funny.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8a333e8b-c1af-4c88-9511-b6d6c10012d4', 'humour', 'The quality of being amusing, comical, funny.', 'She has a great sense of humour, and I always laugh a lot whenever we get together.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('bdd95249-1a90-47b4-b4fe-3210ca0bf5a7', 'hunger', 'A need or compelling desire for food.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('549b2aa7-0259-4ad4-8464-1403fe6570c0', 'hunting', 'The act of finding and killing a wild animal, either for sport or with the intention of using its parts to make food, clothes, etc.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4c945909-3a20-462a-90ea-16072981dd2c', 'hypothesis', 'Used loosely, a tentative conjecture explaining an observation, phenomenon or scientific problem that can be tested by further observation, investigation and/or experimentation. As a scientific term of art, see the attached quotation. Compare to theory, and quotation given there.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('761ea9bd-d8ff-4207-8ceb-51b2ce02f93a', 'icon', 'An image, symbol, picture, or other representation usually as an object of religious devotion.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9d339018-9da4-4f1b-ac55-22389c76449e', 'id', 'The unconscious impulsive component of the personality in the Freudian psychoanalytic model.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('cbf88d09-7584-4954-8f7a-e964098107da', 'identical', '(usually pluralized) Something which has exactly the same properties as something else.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('96f3d4b2-14e2-4564-ab97-1ceb99e1f91b', 'ideology', 'Doctrine, philosophy, body of beliefs or principles belonging to an individual or group.', 'A dictatorship, in order to secure its reign, bans things that do not conform to its ideology.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2d3c6c40-d9aa-43b5-8175-6ac9f9360fa5', 'illusion', 'Anything that seems to be something that it is not.', 'Using artificial additives, scientists can create the illusion of fruit flavours in food.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7507c1cf-3d73-4527-a2c3-16b6f6022628', 'illustrate', 'To shed light upon.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f71c9866-fdf6-4e9c-8c2d-1637174ece75', 'illustration', 'The act of illustrating; the act of making clear and distinct; education; also, the state of being illustrated, or of being made clear and distinct.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('cdf76364-7dca-4653-86de-dadcc76084fc', 'imagination', 'The image-making power of the mind; the act of mentally creating or reproducing an object not previously perceived; the ability to create such images.', 'Imagination is one of the most advanced human faculties.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c366b919-1464-4e22-abfa-e9f93653e2e5', 'immigration', 'The act of immigrating; the passing or coming into a country of which one is not native born for the purpose of permanent residence.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a1cd0fb4-8c8d-48a3-80ca-03f66d216915', 'immune', 'A person who is not susceptible to infection by a particular disease', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6d041151-88ef-41e8-9cd6-c2d4b56882d4', 'immunity', 'The state of being insusceptible to something; notably:', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('962027b4-65b2-4bdf-86a5-e876b45ee002', 'impatient', 'Restless and intolerant of delays.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('17d8ec0f-c3b3-400c-aa6a-b303be71d7e0', 'implement', 'A tool or instrument for working with.', 'They carried an assortment of gardening implements in the truck.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('231602f7-9b84-47d9-bc38-11ad7fad59f3', 'implementation', 'The process of moving an idea from concept to reality. In business, engineering and other fields, implementation refers to the building process rather than the design process.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a16ff603-3638-4491-8622-7ace236d1714', 'implication', 'The act of implicating.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b42abeed-346b-44d5-892c-cdb0530551e8', 'imply', '(of a proposition) to have as a necessary consequence', 'The proposition that "all dogs are mammals" implies that my dog is a mammal', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('30e85ad1-33d9-43d3-b252-cad3c340d25e', 'impose', 'To establish or apply by authority.', 'Congress imposed new tariffs.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('38584fc1-10d5-4a7c-9419-3edd9f22abee', 'impress', 'The act of impressing.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('52532446-4327-448a-a5c6-75ee0441b767', 'impressed', 'To affect (someone) strongly and often favourably.', 'You impressed me with your command of Urdu.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('058b0fcc-e218-4546-9380-41aa0e87b179', 'improvisation', 'The act or art of composing and making music, poetry, and the like, extemporaneously', 'He played a quick improvisation on the keyboard.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c850ee77-dcdd-4078-bd3f-64be98136919', 'incentive', 'Something that motivates, rouses, or encourages.', 'I have no incentive to do housework right now.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8be215ff-8fe3-4034-844a-c1f853973ae1', 'inch', 'A unit of length equal to one twelfth of a foot, or exactly 2.54 centimetres.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9bece54a-4fd8-43c8-b1cb-19a0a42fb794', 'incident', 'An event or occurrence.', 'It was an incident that he hoped to forget.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('620c7a9e-4de6-4574-a9e3-5ca42a79afab', 'income', 'Money one earns by working or by capitalising on the work of others.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2c33e779-e861-4bed-b508-a9082d7d6f92', 'incorporate', 'To include (something) as a part.', 'The design of his house incorporates a spiral staircase.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('71b99c58-564a-42b0-9902-2d073f9bfb09', 'incorrect', 'Not correct; erroneous or wrong.', 'He gave an incorrect answer to a simple question.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('aa094bdd-f66f-480b-8ec7-cf32eb7489e4', 'increasingly', 'Increasing in amount or intensity', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6bc164d9-60e5-422b-8160-52f56ed0e469', 'independence', 'The state or quality of being independent; freedom from dependence; exemption from reliance on, or control by others; self-subsistence or maintenance; direction of one''s own affairs without interference.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('723c4222-8d75-4f8e-81a9-2d5ff19eda28', 'index', 'An alphabetical listing of items and their location.', 'The index of a book lists words or expressions and the pages of the book upon which they are to be found.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3c6f1108-d911-410a-8b06-4d5340b98c6a', 'inequality', 'An unfair, not equal, state.', '', 'Society', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ca85bf5d-11e9-4f58-b4f3-a20b57619d5e', 'inevitable', 'Something that is predictable, necessary, or cannot be avoided.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('86d449c4-269e-4de2-acf8-499aedf0f806', 'inevitably', 'In a manner that is impossible to avoid or prevent.', 'Despite the town''s best efforts, the dam inevitably gave way.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f63dff7d-adb4-4295-83e3-f62244b9df55', 'infer', 'To introduce (something) as a reasoned conclusion; to conclude by reasoning or deduction, as from premises or evidence.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('febf806e-612f-4d72-9440-606668c5eb11', 'inflation', 'An act, instance of, or state of expansion or increase in size, especially by injection of a gas.', 'The inflation of the balloon took five hours.', 'Business', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b131b442-278c-412e-882c-7e06cf37c99e', 'info', 'Information.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('13649cc2-bc30-4ff1-abf9-a1458178938a', 'inform', 'To instruct, train (usually in matters of knowledge).', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b4e483e9-eb44-453a-a74e-48bc427dc0ba', 'infrastructure', '(systems theory) An underlying base or foundation especially for an organization or system.', 'The parasitic tyranny''s infrastructure depends on secrecy in order to be effective.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('308bb2fc-ea54-4851-8bd5-ac4b58055ed6', 'infringement', 'A violation or breach, as of a law.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('84acc514-e42f-4653-814b-8863f228b984', 'inhabitant', 'Someone or thing who lives in a place.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('342328d6-649d-4f55-9751-161609523454', 'inherent', 'Naturally as part or consequence of something.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('eef04259-777e-4182-accf-2f2749de2298', 'inherit', 'To take possession of as a right (especially in Biblical translations).', 'Your descendants will inherit the earth.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('afaa7ed1-bb73-4a4a-9fda-0702eecad514', 'initial', 'The first letter of a word or a name.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ee681065-ca78-4811-bd5b-1d214f846583', 'initially', 'At the beginning.', 'Initially, I found city life incredibly difficult, but now I''m used to it.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ff093b04-3429-4359-a4c7-88a7fc56f409', 'initiative', 'A beginning; a first move.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0a584302-f04b-4301-a0aa-33ea7e4a61d3', 'ink', 'A pigment (or dye)-based fluid used for writing, printing etc.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3eca4799-ded1-4516-bb72-ed5ce3755be8', 'inner', 'An inner part.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('597929fc-375b-4cda-86a0-78488b3a9a0b', 'innovation', 'The act of innovating; the introduction of something new, in customs, rites, etc.', '', 'Technology', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2612ac9e-56ad-4155-b7b7-c22203485051', 'innovative', 'Characterized by the creation of new ideas or inventions.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6a660f32-efe2-4ec2-9f52-d10e9ce926ae', 'input', 'The act or process of putting in; infusion.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('02af015c-4913-45cf-a5e1-6dbd125105af', 'inquiry', 'The act of inquiring; a seeking of information by asking questions; interrogation; a question or questioning.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e9998f00-2a84-4a8c-81aa-98cc34dafef6', 'insert', 'An image inserted into text.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c44f7cbf-2f6b-4472-b232-5c7d626edec5', 'insight', 'A sight or view of the interior of anything; a deep inspection or view; introspection; frequently used with into.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('201de1b1-1ab9-48dc-ae87-3506f56dd668', 'insist', '(with on or upon or (that + ordinary verb form)) To hold up a claim emphatically.', 'I insist that my secretary dresses nicely.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('aa2000d3-6364-4128-99d5-b9f8cb631b2e', 'inspector', 'A person employed to inspect something.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('584098c2-d44b-41af-8616-c9a86bc7ab53', 'inspire', 'To infuse into the mind; to communicate to the spirit; to convey, as by a divine or supernatural influence; to disclose preternaturally; to produce in, as by inspiration.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7abee9ed-6aba-44db-8757-7ab8e3389ac4', 'install', 'Installer. A software utility that installs an application.', 'After inserting the disk, you need to run the install.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c0e4b119-e098-46c1-b8ff-6aa47015425b', 'installation', 'An act of installing.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f01b527a-5520-4a23-99ec-99dd0a427569', 'instance', 'Urgency of manner or words; an urgent request; insistence.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4564c16c-8eeb-4149-9ae0-d30980b46dca', 'instant', 'A very short period of time; a moment.', 'She paused for only an instant, which was just enough time for John to change the subject.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e9df63bd-e96a-4e6b-85df-df2d3bc25c9c', 'instantly', 'At once; without delay.', 'When the neighbours'' dog barked, ours instantly replied with a howl.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ccacf9a2-2816-43a2-a82c-46b4824cf385', 'institute', 'An organization founded to promote a cause', 'I work in a medical research institute.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1944b42e-b5ce-45c4-b5a8-acd8b82ffc82', 'institution', 'A custom or practice of a society or community.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('cf299979-b552-4faf-9287-81bcdd7dca90', 'insurance', 'A means of indemnity against a future occurrence of an uncertain event.', 'The car was totalled, but fortunately I had insurance.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2ab1219a-1de3-45c5-8172-f49b496fa321', 'integrate', 'To form into one whole; to make entire; to complete; to renew; to restore; to perfect.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ab538028-c8d1-42e8-bf89-10cbc82fa7b5', 'integration', 'The act or process of making whole or entire.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('12da72bb-308c-4be2-8f32-d6404a4253e5', 'intellectual', 'An intelligent, learned person, especially one who discourses about learned matters.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('510147fe-d0ed-49d1-a16b-5afd81b1aed9', 'intended', '(usually followed by the particle "to") To hope; to wish (something, or something to be accomplished); be intent upon', 'He intends to go to university.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('fffc6c0f-1d15-437e-8f14-a280c58aec4a', 'intense', 'Strained; tightly drawn.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d1a6f630-2605-42a1-be01-6cadc6e82149', 'interact', 'A short act or piece between others, as in a play; a break between acts.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2219733b-5b9e-423b-98e9-23c3ef4f5aa2', 'interaction', 'The situation or occurrence in which two or more objects or events act upon one another to produce a new effect; the effect resulting from such a situation or occurrence.', 'Be aware of interactions between different medications.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2a824bb9-ca00-44b4-a81e-479e00c5fa75', 'internal', 'Inside of something', 'We saw the internal compartments.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c894df5a-2797-4cc7-ba73-bda2f7b1d584', 'interpret', 'To explain or tell the meaning of; to translate orally into intelligible or familiar language or terms. applied especially to language, but also to dreams, signs, conduct, mysteries, etc.', 'to interpret an Indian speech', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0a23ae29-8f48-4305-bf24-4c708c325332', 'interpretation', 'An act of interpreting or explaining what is obscure; a translation; a version; a construction.', 'the interpretation of a dream, or of an enigma.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4b026a3b-f5f5-44f8-9904-b6fc74814038', 'interrupt', 'An event that causes a computer or other device to temporarily cease what it was doing and attend to a condition.', 'The interrupt caused the packet handler routine to run.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('21d3edd0-48e8-4c6b-8718-63248f26b7d7', 'interval', 'A distance in space.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('67074deb-1bbc-4ba3-8a3d-996e26657c27', 'invade', 'To move into.', 'Under some circumstances police are allowed to invade a person''s privacy.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ac4fdb26-7fd4-4120-ad82-53469ab1c63b', 'invasion', 'A military action consisting of armed forces of one geopolitical entity entering territory controlled by another such entity, generally with the objective of conquering territory or altering the established government.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a42fbefb-9cec-40b1-9e4a-4ac9515a7e00', 'investigation', 'The act of investigating; the process of inquiring into or following up; research, especially patient or thorough inquiry or examination', 'Despite thorough investigation, the perpetrator of the attacks remains unknown.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ec8d4a44-b00d-4f3d-a554-a3b5cb566cd1', 'investor', 'A person who invests money in order to make a profit.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('00f5d4f0-887e-44eb-9bf1-8e4292dbeaac', 'irrigation', 'The act or process of irrigating, or the state of being irrigated; especially, the operation of causing water to flow over lands, for nourishing plants.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('15d5e517-250d-4b35-90ec-69d9e0dd189b', 'isolate', 'Something that has been isolated.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('bf686d6d-99e0-4632-8451-dc26b3a2e0e2', 'isolated', 'To set apart or cut off from others.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('77171b80-2970-46a2-8355-e50065c6bae4', 'jail', 'A place or institution for the confinement of persons held in lawful custody or detention, especially for minor offenses or with reference to some future judicial proceeding.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e1c09f77-3a89-461b-b287-2bbab65f78d3', 'jealousy', 'A state of suspicious guarding towards a spouse, lover etc., from fears of infidelity.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('104b293c-8c7d-4ccd-a00b-4988be6a344b', 'jet', 'A collimated stream, spurt or flow of liquid or gas from a pressurized container, an engine, etc.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4ebaacbd-ad1e-49f8-a700-1ba0d218205e', 'joint', 'The point where two components of a structure join, but are still able to rotate.', 'This rod is free to swing at the joint with the platform.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('96c175e1-c551-4724-9b10-3cbba85f504b', 'journalism', 'The activity or profession of being a journalist.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7b4c8bd5-7bae-4191-9aba-ba8f0393962a', 'joy', 'A feeling of extreme happiness or cheerfulness, especially related to the acquisition or expectation of something good.', 'They will be a source of strength and joy in your life.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('dde4f57e-e768-41c1-8bd3-4af226bbcfcb', 'judgement', 'The act of judging.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('87299875-10ce-4847-95ea-0c7c9d10ddf2', 'junior', 'A younger person.', 'four years his junior', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9ac055b6-3683-4051-b710-22de8b341b40', 'jurisdiction', 'The power, right, or authority to interpret and apply the law.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ef9bfb90-2c25-4181-90dc-c83e89fe3a56', 'jury', 'A group of individuals chosen from the general population to hear and decide a case in a court of law.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8a6f5edb-da19-4781-b560-9b933f99fa8f', 'justify', 'To provide an acceptable explanation for.', 'How can you justify spending so much money on clothes?', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('67551238-247f-400a-8b4d-79869d17bbdc', 'kit', 'A circular wooden vessel, made of hooped staves.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f5c0c261-db72-42d9-899c-151b11e5f063', 'labour', 'Effort expended on a particular task; toil, work.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6d368857-a376-47de-a186-69d4b8ebb885', 'ladder', 'A frame, usually portable, of wood, metal, or rope, used for ascent and descent, consisting of two side pieces to which are fastened rungs (cross strips or rounds acting as steps).', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9b938a6c-b68b-4c3e-9b0a-02c549811ff8', 'landing', 'To descend to a surface, especially from the air.', 'The plane is about to land.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e26a2fb3-007e-494c-b1ba-0969ce5c8816', 'landscape', 'A portion of land or territory which the eye can comprehend in a single view, including all the objects it contains.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0f56301c-6c7e-45af-9405-e92169473529', 'lane', '(used in street names) A road, street, or similar thoroughfare.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('112d4f45-c4b4-43e2-87e0-4beb95236064', 'largely', 'In a widespread or large manner.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('99b2abf1-65a4-47c6-bc98-a1ec625d411c', 'lately', 'Recently; not long ago; of late.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a70c68e1-ebce-4926-91d7-86752ddbd108', 'launch', 'The movement of a vessel from land into the water; especially, the sliding on ways from the stocks on which it is built. (Compare: to splash a ship.)', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1be2c8d2-af03-4515-93a0-a9359d8cd1e5', 'leadership', 'The capacity of someone to lead others.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6a77aec7-4e72-49a4-8c59-c93902f47f7b', 'leaflet', 'One of the components of a compound leaf.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a6c87d90-f381-46ae-83bc-4ff03f00607b', 'league', 'A group or association of cooperating members.', 'the League of Nations', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('20f7b9a4-8f64-4cd9-9d33-5c39633dfe28', 'lean', '(of an object taller than its width and depth) An inclination away from the vertical.', 'The trees had various leans toward gaps in the canopy.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('48a7f0a9-f4a1-413a-8f28-747eb399bb40', 'legend', 'An unrealistic story depicting past events.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('14c2adf0-4b34-49e9-ab94-c889d89ae5a7', 'legislation', 'The act of legislating; preparation and enactment of laws; the laws enacted.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('62dbed56-d016-4480-b4ad-3dc70aa57805', 'lens', 'An object, usually made of glass, that focuses or defocuses the light that passes through it.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('df4f8aba-7040-45d5-8be8-4da9429d7e5c', 'liability', 'An obligation, debt or responsibility owed to someone.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2baeb761-109f-47a0-958d-a3596c7a25b0', 'licence', 'A legal document giving official permission to do something; a permit.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ca44135a-bb06-4a98-9890-48ec28cc680a', 'lifetime', 'The duration of the life of someone or something.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0d9edafa-46ef-41f0-a78e-089fb07e2da8', 'lighting', 'To start (a fire).', 'We lit the fire to get some heat.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('56409c2d-db41-454b-9496-ab081b08ff13', 'likewise', '(manner) In a similar manner.', 'Public transportation is virtually inaccessible in this country; likewise, its hospitals are also not very user-friendly.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('338cf454-b0fa-4ca6-b72a-3dfff0804816', 'limitation', 'The act of limiting or the state of being limited.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a24da036-12e9-4819-b397-3d58f848f765', 'limited', 'To restrict; not to allow to go beyond a certain bound, to set boundaries.', 'I''m limiting myself to two drinks tonight.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3bd75c11-f9ef-40e6-9e19-f0b997ce30c0', 'literally', 'Word for word; not figuratively; not as an idiom or metaphor', 'When I saw on the news that there would be no school tomorrow because of the snowstorm, I literally jumped for joy, and hit my head on the ceiling fan.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('830be677-c2c1-45e3-9f9f-a9b9699cfb8f', 'literary', 'Relating to literature.', 'a literary history', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('882c9fa7-f74c-4ec5-aebe-df58687630cd', 'litre', 'The metric unit of fluid measure, equal to one cubic decimetre. Symbols: l, L, ℓ', 'You should be able to fill four cups with one litre of water.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('429892dc-f80d-4762-9f6b-b827792f1502', 'litter', 'A platform mounted on two shafts, or a more elaborate construction, designed to be carried by two (or more) people to transport one (in luxury models sometimes more) third person(s) or (occasionally in the elaborate version) a cargo, such as a religious idol.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('75344de7-a812-4840-b74d-5f5c02d7b677', 'lively', 'Term of address.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('35751c2d-3543-41c3-84b6-f4130f011755', 'load', 'A burden; a weight to be carried.', 'I struggled up the hill with the heavy load in my rucksack.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2cae4381-0fa0-4d8a-a545-c8a19a736ef4', 'loan', 'An act or instance of lending, an act or instance of granting something for temporary use.', 'Because of the loan that John made to me, I was able to pay my tuition for the upcoming semester.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9824984f-3036-4945-8a45-854d6da8e004', 'logical', 'In agreement with the principles of logic.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2cc2580f-322a-412a-86f3-730146303d44', 'logo', 'A visual symbol or emblem that acts as a trademark or a means of identification of a company or organization.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('dc78d1c2-742d-47eb-b6cc-10b3e9b61bce', 'long-term', 'Becoming evident after a relatively long time period.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('43b4c079-79c1-45d3-9c59-fa114ecdd299', 'loose', 'The release of an arrow.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('513e4e1f-df07-4a5c-a1b6-f42f8fb59143', 'lord', 'The master of the servants of a household; the master of a feudal manor', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('262bd80f-69cc-4d0e-9e16-918cb81b3599', 'lottery', 'A scheme for the distribution of prizes by lot or chance, especially a gaming scheme in which one or more tickets bearing particular numbers draw prizes, the other tickets are blanks.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('bb8cd5d4-6f6f-454a-a107-93a249521126', 'lower', 'Situated close to, or even below, the ground or another normal reference plane; not high or lofty.', 'a low wall  a low shelf', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e6f9eca2-b21f-4f52-814f-a69e9191695f', 'loyal', 'Having or demonstrating undivided and constant support for someone or something.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e4577033-de78-4603-913a-6a5fb8566be2', 'lung', 'A biological organ of vertebrates that controls breathing and oxygenates the blood.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('072e3724-618b-4cfc-af16-df5e83745285', 'lyric', 'A lyric poem.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6efafcff-2b9d-4eaf-8d00-9ba3455d62fa', 'magnificent', 'Grand, elegant or splendid in appearance.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f0ddf3be-6aeb-4a0f-a34f-3282b04c9736', 'maintain', 'To support (someone), to back up or assist (someone) in an action.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e217e201-68ca-4ffb-966b-b7f8fa0b46da', 'majority', 'More than half (50%) of some group.', 'The majority agreed that the new proposal was the best.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c3adffd4-8993-499f-b811-578781916764', 'make-up', 'Made-up, false, imaginary, fabricated.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e47805f2-e309-4fd2-85a8-9b4878da0e4f', 'making', 'The act of forming, causing, or constituting; workmanship; construction.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7325c87d-df20-4940-9f8a-6cb1bdb90758', 'manipulation', 'The practice of manipulating or the state of being manipulated.', 'The dealer''s manipulations could have removed cards from the deck.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0d7ea96b-0002-47f4-9164-41c4d77b385a', 'manufacture', 'The action or process of making goods systematically or on a large scale.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('650db01b-906b-42b5-b672-d3977ebc2e82', 'manufacturing', 'To make things, usually on a large scale, with tools and either physical labor or machinery.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('94f078e8-1a6c-444d-8a49-4c07946aefdc', 'manuscript', 'A book, composition or any other document, written by hand (or manually typewritten), not mechanically reproduced.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('39477d63-5d2c-4527-a38d-38e7704af763', 'marathon', 'A 42.195 kilometre (26 mile 385 yard) road race.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('21e355d1-b06b-4b7c-a1da-d75fe72337aa', 'margin', 'The edge of the paper, typically left blank when printing but sometimes used for annotations etc.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0d15e314-7f48-4c24-9a35-5c9528d2dd5f', 'marker', 'An object used to mark a location.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('208a83c9-c450-4f80-8700-a75f1a95d53f', 'martial', 'A person under the astrological influence of the planet Mars.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c19969ff-29f1-4c7a-8eef-fd93f7347d07', 'mass', '(physical) Matter, material.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4e0684de-ade6-41a3-a8a0-ca5f2ec242b3', 'massive', 'A homogeneous mass of rock, not layered and without an obvious crystal structure.', 'karst massives in western Georgia', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c2028777-23ae-4b0b-aebb-bfce5f0c6247', 'master', 'Someone who has control over something or someone.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a78bf415-a091-463f-9bed-d6818f3ac80e', 'matching', 'To agree; to be equal; to correspond.', 'Their interests didn''t match, so it took a long time to agree what to do together.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('993abac9-ef7f-4867-b12c-8e7eb57ea85c', 'mate', 'A fellow, comrade, colleague, partner or someone with whom something is shared, e.g. shipmate, classmate.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c119e16c-4439-4611-a5f1-00d6affcb94a', 'maximum', 'The highest limit', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('96aa08e6-9460-4f63-a433-1ec41a1dd0c4', 'mayor', 'The chief executive of the municipal government of a city, borough, &c., formerly usually appointed as a caretaker by European royal courts but now usually appointed or elected locally.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('eee9a91e-a93a-4fca-a8bd-2c66233974a4', 'means', 'To lament.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('64a96fec-486e-42f8-b6ba-ed8136b5d800', 'measurement', 'The act of measuring.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('99862c13-09d7-4995-a325-3e3b32df8f20', 'mechanic', 'A manual worker; a labourer or artisan.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3c0cc4fe-c281-4934-9794-85c0a7ad4de4', 'mechanical', 'Manually created layout of artwork that is camera ready for photographic reproduction.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2a1c4ce5-9968-4dbd-bb47-f01bda24d49c', 'mechanism', '(within a machine or machinery) Any mechanical means for the conversion or control of motion, or the transmission or control of power.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7d6af4bf-bf41-4bd0-873d-5fb01ebe8d74', 'medal', 'A stamped metal disc used as a personal ornament, a charm, or a religious object.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ca31db64-03c2-4251-8767-32979155b17a', 'medication', 'A medicine, or all the medicines regularly taken by a patient.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a04eb0fa-67ea-47dc-8332-2a1aa5150200', 'melt', 'Molten material, the product of melting.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('206e4809-55b4-472c-9521-9975d62dc952', 'membership', 'The state of being a member of a group or organization.', 'He has memberships in clubs in three cities.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('185e7679-f5f7-4784-897f-c1e250ed2aa3', 'memorable', 'Worthy to be remembered; very important or remarkable.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('bff1bce8-d626-4955-96b3-5d3b17fc2c53', 'merger', 'One that merges.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('585e0f7a-10bb-4aa6-8b4b-6e3550df27c5', 'metabolism', 'The chemical processes that occur within a living organism in order to maintain life.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('09e2ee5f-f033-47be-a65e-6f5a4d99e08c', 'metaphor', 'The use of a word or phrase to refer to something that it is not, invoking a direct similarity between the word or phrase used and the thing described (but in the case of English without the words like or as, since use of those words would imply a simile); the word or phrase used in this way; an implied comparison.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('bd10fad3-f0dc-4c72-a930-088d71fea62e', 'methodology', '(originally science) The study of methods used in a field.', 'research methodology', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7bdac97a-cc68-484a-b18a-60a18db36238', 'military', 'Armed forces.', 'He spent six years in the military.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ee92e760-afef-4ca3-8e10-b76d1a7ec1ce', 'miner', 'A person who works in a mine.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('df9c6a23-958b-4412-b886-abf6ab0b412f', 'mineral', 'Any naturally occurring inorganic material that has a (more or less) definite chemical composition and characteristic physical properties.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('24004038-8c73-433a-a6e3-76bb52530bb0', 'minimum', 'The lowest limit.', 'We need a minimum of three staff members on duty at all time.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e5c03e08-0c05-49c6-891c-78300a60d706', 'minister', 'A person who is trained to preach, to perform religious ceremonies, and to afford pastoral care at a Protestant church.', 'The minister said a prayer on behalf of the entire congregation.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('41886b99-1b3f-4bd3-90a9-69416eec906d', 'minor', 'A person who is below the age of majority, consent, criminal responsibility or other adult responsibilities and accountabilities.', 'It is illegal to sell weapons to minors under the age of eighteen.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('955579e1-5761-4671-97f0-1155e431da55', 'minority', 'The state of being a minor; youth, the period of a person''s life prior to reaching adulthood.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d4ebaab0-713b-4ee5-bbc5-1a108f6069f0', 'miserable', 'A miserable person; a wretch.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e645c6c0-67d2-45e1-91d2-d52c08e8321c', 'misinformation', 'Information that is incorrect.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('bd59cc4d-6953-4b78-9dee-8a706d13d6dd', 'mission', 'A set of tasks that fulfills a purpose or duty; an assignment set by an employer, or by oneself.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4be07df7-0fa9-4642-b10f-fbb63d58b8c9', 'mixed', 'To stir together.', 'Mix the eggs and milk with the flour until the consistency is smooth.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8a61de74-c008-49d0-8768-bbbd15ee5ec4', 'mode', 'One of several ancient Greek scales.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('fb650dff-ec17-4920-a62a-464a096b093f', 'modest', 'Not bragging or boasting about oneself or one''s achievements; unpretentious, humble.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7aa5e5b9-e193-4e00-83e2-4ebf0359d847', 'modify', 'To change part of.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('33a78cde-3ffc-449f-8651-05dfe8daf448', 'molecule', 'The smallest particle of a specific element or compound that retains the chemical properties of that element or compound; two or more atoms held together by chemical bonds.', 'Hydrogen chloride is a diatomic molecule, consisting of a hydrogen atom and a chlorine atom.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2add17a7-b37a-49d4-b72f-629873760a9c', 'monetary', 'Of, pertaining to, or consisting of money.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('50daa8e0-d2bb-447f-a7ab-b2c20bc99a60', 'monitor', 'Someone who watches over something; a person in charge of something or someone.', 'The camp monitors look after the children during the night, when the teachers are asleep.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7eb978e0-bd98-4c27-b05b-8fa23acf842b', 'monster', 'A terrifying and dangerous creature.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e811ee55-9b26-4060-ae95-46a3afd4290b', 'monthly', 'A publication that is published once a month.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('fca81146-7f6b-4a88-a64f-5407582a4529', 'monument', 'A structure built for commemorative or symbolic reasons, or as a memorial; a commemoration.', 'There is a monument on the town green to the soldiers who died in World War I.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('47f830ca-e45d-4943-b7dc-750c839a19d1', 'moral', '(of a narrative) The ethical significance or practical lesson.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7f66cf34-b3c1-4ee8-9828-a404cd4b1581', 'moreover', 'In addition to what has been said; furthermore; additionally.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('27ad6dbe-dbea-4cb0-b8f4-e1aa1aa9bb15', 'obesity', 'The state of being obese due to an excess of body fat.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6bf748d1-b549-4b05-873d-6fdd0c3d3e86', 'mortgage', 'A special form of secured loan where the purpose of the loan must be specified to the lender, to purchase assets that must be fixed (not movable) property, such as a house or piece of farm land. The assets are registered as the legal property of the borrower but the lender can seize them and dispose of them if they are not satisfied with the manner in which the repayment of the loan is conducted by the borrower. Once the loan is fully repaid, the lender loses this right of seizure and the assets are then deemed to be unencumbered.', 'We''re renting a property in the city centre because we can''t afford to get a mortgage yet.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d4489c80-88de-456d-a0b1-1157588343e1', 'mosque', 'A place of worship for Muslims, often having at least one minaret; a masjid.', 'There''s a mosque near where I live.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8d2f8a7f-3791-4b07-8c24-d33d41557ae4', 'motion', 'A state of progression from one place to another.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('190b1ab0-6c85-4fde-965b-5805edb153c9', 'motivate', 'To provide someone with an incentive to do something; to encourage.', 'The weekly staff meeting was meant to motivate employees.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('5331df2b-eb1a-48d0-a6e8-e5599293345a', 'motivation', 'Willingness of action especially in behavior.', '', 'Psychology', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ad7336ec-04e8-4a27-b948-afffb358e6df', 'motor', 'A machine or device that converts other energy forms into mechanical energy, or imparts motion.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f1d00a8a-5f7b-465f-b42e-1b3f1e9ba7fd', 'mount', 'A hill or mountain.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('aa630c9f-abd4-49ec-9512-e6f6b202b392', 'moving', 'To change place or posture; to go, in any manner, from one place or position to another.', 'A ship moves rapidly.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3a582ac1-4ac2-42bb-8377-dd68b04c7267', 'multiple', 'A whole number that can be divided by another number with no remainder.', '14, 21 and 70 are multiples of 7', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('459f623e-1642-447a-b631-84f8daa5dd40', 'multiply', 'An act or instance of multiplying.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ba962a29-ea26-4dbf-b9dd-5d71500a23ce', 'mysterious', 'Of unknown origin.', 'He received a mysterious phone call this morning.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b7a06e90-716b-470e-ac1b-9706a503dc0c', 'myth', 'A traditional story which embodies a belief regarding some fact or phenomenon of experience, and in which often the forces of nature and of the soul are personified; a sacred narrative regarding a god, a hero, the origin of the world or of a people, etc.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d898c210-6143-41a1-ac12-c6c1c95b58c0', 'mythology', 'The collection of myths of a people, concerning the origin of the people, history, deities, ancestors and heroes.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9223efc2-e485-4581-ba5a-574bd5f62c23', 'naked', 'Bare, not covered by clothing.', 'She was as naked as the day she was born.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2e2be629-a9e9-48f6-950e-841c45a4f643', 'nanotechnology', 'The science and technology of creating nanoparticles and of manufacturing machines which have sizes within the range of nanometres.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a2f533d7-c3dd-4ead-98db-7512579152eb', 'nasty', 'Something nasty.', 'Processed foods are full of aspartame and other nasties.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('428ffaf7-3bbc-4f5d-9bdc-7b60d1b2a610', 'nationalism', 'Patriotism; the idea of supporting one''s country, people or culture.', '', 'Society', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('50912011-31be-4821-9536-c3166a1ebad4', 'navigation', 'The theory, practice and technology of charting a course for a ship, aircraft or spaceship or (colloquially) road vehicle.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2accc156-5541-402b-8ffc-069f68ad7759', 'nearby', 'Adjacent, near, close by', 'He stopped at a nearby store for some groceries.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('250950a1-2869-446a-b111-cc34d798af8d', 'neat', 'An artificial intelligence researcher who believes that solutions should be elegant, clear and provably correct. Compare scruffy.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b9060fdc-6585-4b28-8359-c59ddbf22383', 'necessity', 'The quality or state of being necessary, unavoidable, or absolutely requisite.', 'I bought a new table out of necessity. My old one was ruined.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2b2bbc34-e6e3-46bf-8417-ff4a65104c27', 'negotiate', 'To confer with others in order to come to terms or reach an agreement.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('014e8606-bd08-442d-b5cb-cbab427b3c01', 'negotiation', 'The process of achieving agreement through discussion.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8a761aa6-d9cc-4db2-a552-9e8faa46ea5a', 'nerve', 'A bundle of neurons with their connective tissue sheaths, blood vessels and lymphatics.', 'The nerves can be seen through the skin.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('71c1c95d-8256-4fc6-8580-97c63b3e0636', 'neurological', 'Dealing with neurology, the study of the brain', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('21fbc76e-a6f8-4792-a48f-c1970f1254a1', 'neutral', 'A nonaligned state, or a member of such a state.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f116b69b-8019-4fb6-a226-bd1342c35de2', 'nevertheless', 'In spite of what preceded; yet.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b155d17c-a2f8-4809-b36d-2ab78c54c81a', 'newly', 'Very recently; in the immediate past.', 'She smelled the newly budding flowers.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7f1e2056-92ae-4b0f-987c-ef31990b4946', 'nightmare', 'A demon or monster, thought to plague people while they slept and cause a feeling of suffocation and terror during sleep.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('991448cf-020c-442b-b3ac-18c510908aa8', 'nonetheless', 'Nevertheless.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('246bd110-ac61-4810-adee-3e75f9a71462', 'norm', 'That which is normal or typical.', 'Unemployment is the norm in this part of the country.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9f228343-253b-4829-a6a9-8fc3b7afaefe', 'nostalgia', 'A longing for home or familiar surroundings; homesickness.', '', 'Psychology', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f3cb9bca-0fb9-42a2-afdb-4177daf561a9', 'notebook', 'A book in which notes or memoranda are written.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('78469019-ae0e-49c2-82d4-ec9fe9ae2fd3', 'notion', 'Mental apprehension of whatever may be known, thought, or imagined; idea, concept.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('65042ef4-8f15-4495-bf50-bccf998faf82', 'novelist', 'An author of novels.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('18bcc59a-c308-4c3f-acb2-5e1650f1c1ab', 'nowadays', 'At the present time; in the current era.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3428e9bd-2153-4693-9585-12fbb0be8486', 'numerous', 'Indefinitely large numerically, many.', 'There are numerous definitions of the word ''man''.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ca8d6088-2ead-47e3-bc4e-29bbae376e9d', 'nursing', 'To breastfeed: to feed (a baby) at the breast; to suckle.', 'She believes that nursing her baby will make him strong and healthy.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('49f318d4-96d5-4119-99b3-caab36d3344b', 'obey', 'To do as ordered by (a person, institution etc), to act according to the bidding of.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3aed9d70-fb53-4325-8bb1-8564bb3cb5b9', 'objective', 'A material object that physically exists.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1c4edbc5-d2e2-4488-8603-d392ab3226f5', 'obligation', 'The act of binding oneself by a social, legal, or moral tie to someone.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1a19b693-9123-4acb-ab02-b53615c03e88', 'observation', 'The act of observing, and the fact of being observed (see observance)', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b258a125-3a92-4f6a-8284-423417961222', 'observe', 'To notice or view, especially carefully or with attention to detail.', 'From this vantage point we can observe the behavior of the animals in their natural habitat.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ef915ff1-f433-4550-8f9b-331c7b75e8d2', 'observer', 'One who makes observations, monitors or takes notice', 'Most impartial observers agreed that Sampras had not served well.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('36857914-2150-4ad4-bb4e-a685659a3378', 'obstacle', 'Something that impedes, stands in the way of, or holds up progress', 'A big obstacle to understanding the manual was that it had been poorly translated from the Japanese.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a5b96df8-af21-43fc-bf35-07fb7b434043', 'obtain', 'To get hold of; to gain possession of, to procure; to acquire, in any way.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b3ad2fc0-d90e-480f-a4da-6f089fc85f0f', 'occasionally', 'On the occasion of something else happening; incidentally, by the way.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9d33a4ae-2474-455b-8f36-c47095a1e0ff', 'occupation', 'An activity or task with which one occupies oneself; usually specifically the productive activity, service, trade, or craft for which one is regularly paid; a job.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ecca1783-366b-484a-9ee7-4944c7dbf87a', 'occupy', '(of time) To take or use.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a388a72b-83ee-4df3-88a5-847ae4d6ec19', 'offence', 'The act of offending:', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8075383d-298a-4a35-8d73-3f3483762317', 'offend', 'To hurt the feelings of; to displease; to make angry; to insult.', 'Your accusations offend me deeply.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8e242de8-f267-478f-b9b0-10817167ca83', 'offender', 'One who gives or causes offense, or does something wrong.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0f0d9bdf-91d7-40a8-8a67-2636c7b1570d', 'offensive', 'An attack.', 'The Marines today launched a major offensive.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('80fdc78b-8849-46df-bdff-04ea1ffa5feb', 'oncology', 'The branch of medicine concerned with tumors, including study of their development, diagnosis, treatment, and prevention.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('dcf81631-238c-47bf-bb90-c5eaf34f174b', 'ongoing', 'To be ongoing (occurring, happening); to last, proceed or continue.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('5bf586c3-a1e0-4438-a246-f79eaf04a202', 'opening', 'To make something accessible or allow for passage by moving from a shut position.', 'Turn the doorknob to open the door.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a77bab12-ba33-4f7b-b65b-eaf7eac0605f', 'openly', 'In an open manner, visibly, not covertly.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c59b67c0-9159-4a0f-88e1-ca60a8976cb3', 'opera', 'A theatrical work, combining drama, music, song and sometimes dance.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('dbedabe7-b50e-478a-abd7-f0919d86599f', 'operate', 'To perform a work or labour; to exert power or strength, physical or mechanical; to act.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('5ea5d893-226f-4a56-977f-7add37eb6e38', 'operator', 'One who operates.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d7d884e6-427f-45b9-b2e7-0c8ce6071275', 'opponent', 'One who opposes another; one who works or takes a position against someone or something; one who attempts to stop the progress of someone or something.', 'During the crackdown, many opponents of the regime were arrested.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('37ce6364-e8ab-40d7-80b7-569f3470f5bd', 'oppose', 'To attempt to stop the progression of; to resist or antagonize by physical means, or by arguments, etc.; to contend against.', 'There is still time to oppose this plan.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7e6af2a9-8bd2-44ab-b99e-e8b1367deb22', 'opposed', 'To attempt to stop the progression of; to resist or antagonize by physical means, or by arguments, etc.; to contend against.', 'There is still time to oppose this plan.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('829017e4-dbcc-4b62-99d4-fca9d4d1037a', 'opposition', 'The action of opposing or of being in conflict.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('88b95987-29e9-449f-9ed0-e3c628edaafc', 'optimistic', 'Expecting the best in all possible ways.', 'in an optimistic mood', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9b7b1a1a-c755-4e3e-9199-d255f7400e0d', 'orchestra', 'A large group of musicians who play together on various instruments, usually including some from strings, woodwind, brass and/or percussion; the instruments played by such a group.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3892d62f-d8e5-4cc5-802a-f72d64db375f', 'organ', 'A larger part of an organism, composed of tissues that perform similar functions.', 'bodily organs', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b60a7585-eaf0-4a5f-9687-cf2515dba4d2', 'organic', 'An organic compound.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2fba8147-0caa-4f5f-b063-9b619cbd8c36', 'organism', 'A discrete and complete living thing, such as animal, plant, fungus or microorganism.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0fcda1a4-e27e-4201-adbf-737d5bc45829', 'origin', 'The beginning of something.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('bba2e554-b13e-40a6-a448-c1ac834b59d2', 'otherwise', 'Other than supposed; different.', 'He said he didn’t do it, but the evidence was otherwise.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7abe7b92-1f77-4e2e-b589-4ad2f4676757', 'outcome', 'That which is produced or occurs as a result of an event or process.', 'A quality automobile is the outcome of the work of skilled engineers and thousands of workers.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('569508a6-f975-45bf-9ad6-ae10960432b2', 'outer', 'An outer part.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('365e8389-a830-4f2c-b2f2-9ff119f77515', 'outfit', 'A set of clothing (with accessories).', 'She wore a fashionable outfit with matching purse and shoes.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c6937981-d8fe-48ad-8a51-700964a1a85c', 'outline', 'A line marking the boundary of an object figure.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1c0e817d-af34-4b53-a99d-c663c2c6afb7', 'output', 'Production; quantity produced, created, or completed.', 'The factory increased its output this year.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('5406d3f5-821c-4a63-88c7-25461414f2c0', 'outstanding', 'To resist effectually; withstand; sustain without yielding.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6b291a19-ad3c-44ce-b699-223a6ca3e712', 'racial', 'A skill possessed by all characters of a certain race.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4121b5a5-11b1-4c39-b8bf-4f53c50044c8', 'overall', 'A garment worn over other clothing to protect it; a coverall or boiler suit. A garment, for manual labor or for casual wear, often made of a single piece of fabric, with long legs and a bib upper, supported from the shoulders with straps, and having several large pockets and loops for carrying tools.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b0847655-3df2-42d3-9b43-b1a15993f676', 'overcome', 'The burden or recurring theme in a song.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('02e27f30-cf3b-439d-9f66-4ddf0945e1c3', 'overnight', 'Items delivered or completed overnight.', 'Have you looked at the overnights yet?', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c6abd31a-6832-4045-9a3e-1ec78b9c1a43', 'overseas', 'Abroad.', 'Overseas branches of the company are doing well.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a23e93c0-3732-402b-8426-4177d7b1374c', 'owe', 'To be under an obligation to give something back to someone or to perform some action for someone.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f3fe7fe2-7c32-4121-ab41-72213e59faec', 'ownership', 'The state of having complete legal control of something; possession; proprietorship.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('581c4757-4f08-4f71-946d-7bae73d4d4a2', 'oxygen', 'The chemical element (symbol O) with an atomic number of 8 and relative atomic mass of 15.9994. It is a colorless and odorless gas.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('46a18a8a-6b08-4120-af30-b952147f74e4', 'pace', 'Step.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6d8c5891-5578-498a-bb6b-c2d8162c7ead', 'packet', 'A small pack or package; a little bundle or parcel', 'Don''t throw the crisp packet on the floor!', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('39ef3dd8-bfff-421a-b030-a55c9a4b2f8c', 'palm', 'Any of various evergreen trees from the family Palmae or Arecaceae, which are mainly found in the tropics.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4bb8b4f9-ae81-40d3-8c11-2cffb4222a7e', 'pandemic', 'A pandemic disease; a disease that affects a wide geographical area and a large proportion of the population.', '', 'Health', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a9d1165d-104c-4b9c-ad65-707918629b02', 'panel', 'A (usually) rectangular section of a surface, or of a covering or of a wall, fence etc.', 'Behind the picture was a panel on the wall.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('37f303ae-3687-42e9-b83d-3fc806ace81a', 'panic', 'Overpowering fright, often affecting groups of people or animals.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('470ac907-daef-4f40-a7e0-0994afb6601d', 'parade', 'An organized procession consisting of a series of consecutive displays, performances, exhibits, etc. displayed by moving down a street past a crowd of spectators.', 'The floats and horses in the parade were impressive, but the marching bands were really amazing.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('40b7769c-b5f7-43bf-aaab-2fe39234c0f5', 'paradigm', 'A pattern, a way of doing something, especially a pattern of thought, a system of beliefs, a conceptual framework.', 'Thomas Kuhn''s landmark “The Structure of Scientific Revolutions” got people talking about paradigm shifts, to the point the word itself now suggests an incomplete or biased perspective.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('15e4bac3-ef63-4cd0-8464-3d5e0ab2f7d3', 'parallel', 'One of a set of parallel lines.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f179565e-bc5e-4cde-a120-3f8a4f8ab1dd', 'parliament', 'A formal council summoned (especially by a monarch) to discuss important issues.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('bd151468-6bb1-47f5-a83d-1a5e9edae18e', 'part-time', 'For, during, or involving less than the normal time for some activity, especially the number of hours an employee works.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a9db3d61-d18f-4f1a-a000-759cd7a4f8dd', 'participant', 'One who participates.', 'All participants must adhere to the rules of the competition.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8b7f888d-dac7-4171-9355-746646a31d02', 'participation', 'The act of participating, of taking part in something.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d4929da9-b69c-4673-8577-e5189088f88b', 'partly', 'In part, or to some degree, but not completely.', 'they partly finished the house so they could move in before winter;  the car was partly visible in the garage', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('781d340c-e9b3-463d-aa4d-b6ac2c7725ec', 'partnership', 'The state of being associated with a partner.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c9916f9b-a325-4494-8bc8-5880aba69a00', 'passage', 'A paragraph or section of text or music with particular meaning.', 'She struggled to play the difficult passages.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('bfc808ae-694c-4e83-ace1-7ea4d94ada94', 'passionate', 'A passionate individual.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a1200a61-c9cb-4c1d-871c-41ce4938feed', 'password', 'A word used to gain admittance or to gain access to information; watchword.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e9dd2248-c061-47f8-8c46-05987bf81a92', 'patience', 'The quality of being patient.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('dd450158-f623-46f5-8dd7-bf44fad0b651', 'pause', 'A button whose functions are pausing and resuming something, such as a DVD player, a video game or a computer.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4f95ff90-4240-4a3e-9bdc-c1c81ca3d134', 'peer', 'A look; a glance.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('235cf0f0-6e3b-4dc1-8020-d95053a9c40a', 'penalty', 'A legal sentence.', 'The penalty for his crime was to do hard labor.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('80303063-30a5-409e-ac80-80dda48aa1e2', 'pension', 'An annuity paid regularly as benefit due to a retired employee, serviceman etc. in consideration of past services, originally and chiefly by a government but also by various private pension schemes.', 'Many old people depend on their pension to pay the bills.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('5596fc3d-fdc6-455f-a43a-416746ff3f96', 'perceive', 'To become aware of, through the physical senses or by thinking; to see; to understand.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('dd0d6ebb-9d8e-4467-ab42-512fdd2b3308', 'perception', 'The organisation, identification and interpretation of sensory information.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9b54bf8b-ddf6-4d25-a8f6-f1a387fecc6e', 'permanent', 'A chemical hair treatment imparting or removing curliness, whose effects typically last for a period of weeks; a perm.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a222c4e6-f196-4b5b-bd63-b62e5cee21ab', 'permanently', 'In a permanent manner; lastingly.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b8a0acf2-3b4e-4549-b055-e7bcb15de351', 'permit', 'An artifact or document rendering something allowed or legal.', 'A construction permit can be obtained from the town offices.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('860e4778-1290-4830-9588-d77f2d495dcc', 'perspective', 'A view, vista or outlook.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f0a420d5-fddd-40cc-be50-18097c1b128f', 'persuasion', 'The act of persuading, or trying to do so; the addressing of arguments to someone with the intention of changing their mind or convincing them of a certain point of view, course of action etc.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ec8f9448-285f-4461-9781-64437991968f', 'pharmaceutical', 'A pharmaceutical or pharmacological preparation or product; a drug.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d69ffa3e-a4c6-4ef5-b17f-bcef2dd3d7b9', 'tag', 'A small label.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('dec7def0-fe8e-4519-af21-b2be384063ab', 'phenomenon', 'A thing or being, event or process, perceptible through senses; or a fact or occurrence thereof.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d76be49e-22f0-485a-ace7-ff7b23a1ee53', 'philosophy', 'The love of wisdom.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8612ea0d-3455-4065-8e80-2ba429612470', 'pile', 'A mass of things heaped together; a heap.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0795fc71-9ff4-4100-ab2a-6b36a1f70d92', 'pill', 'A small, usually round or cylindrical object designed for easy swallowing, usually containing some sort of medication.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6e607c1e-bb92-47b7-b9c8-6aed263de245', 'pitch', 'A sticky, gummy substance secreted by trees; sap.', 'It is hard to get this pitch off my hand.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2d841055-867a-41b2-abc3-cf42576ec652', 'pity', 'A feeling of sympathy at the misfortune or suffering of someone or something.', 'I can''t feel any pity towards the gang, who got injured while attempting to break into a flat.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c7cac03d-36c6-444b-9dec-76bf7858a73c', 'placement', 'The act of placing or putting in place; the act of locating or positioning; the state of being placed.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4d7ef383-1b4e-474f-9c27-b2f523660e50', 'plain', 'Flat, level.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('aa2d03ba-a8e0-4b21-9c22-78ea4633501f', 'pointed', 'To extend the index finger in the direction of something in order to show where it is or to draw attention to it.', 'It''s rude to point at other people.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e077e843-7922-4c27-aa11-034499107b05', 'popularity', 'The quality or state of being popular; especially, the state of being esteemed by, or of being in favor with, the people at large', 'Politicians are rarely known for their popularity.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('177cf728-d80e-408c-9f05-05dff1da5541', 'portfolio', 'A case for carrying papers, drawings, photographs, maps and other flat documents.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c3c8e5cb-25fd-4ea1-8560-3dba9be9a160', 'portion', 'An allocated amount.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0eec2419-ceb2-415a-8f0a-657f851fdd84', 'portrayal', 'The act of portraying.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9beee4e0-7fbe-458b-bc11-293804820255', 'pose', 'Common cold, head cold; catarrh.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('5e1bcfa1-4833-4c35-b515-52c79abf59cb', 'possess', 'To have; to have ownership of.', 'He does not even possess a working telephone.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('28db1496-63dd-4931-8640-9dfe48d7893e', 'potential', 'Currently unrealized ability (with the most common adposition being to)', 'Even from a young age it was clear that she had the potential to become a great musician.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6be0a0c8-6ad5-41de-949e-a23c8a7406bc', 'potentially', 'In a manner showing much potential; with the possibility of happening in a given way.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a6aa2059-fb7e-4a4a-92e2-f2e137df4712', 'praise', 'Commendation; favourable representation in words', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9adfb4fa-1368-41eb-b769-7c98b3b8039f', 'precede', 'Brief editorial preface (usually to an article or essay)', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('56a0b951-b5c3-457c-af2f-4795ee395100', 'precious', 'Someone (or something) who is loved; a darling.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('82dd6cf1-0f07-49f9-aa3e-f77002c4c407', 'precipitation', 'Any or all of the forms of water particles, whether liquid or solid, that fall from the atmosphere (e.g., rain, hail, snow or sleet). It is a major class of hydrometeor, but it is distinguished from cloud, fog, dew, rime, frost, etc., in that it must fall. It is distinguished from cloud and virga in that it must reach the ground.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('bb66d84d-0d6c-4763-8511-74ae2f7f082e', 'precise', '(NNES or European Union documents) To make or render precise; to specify.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('927c4521-d205-4025-9ee6-e13953d1adfa', 'precisely', '(manner) In a precise manner; exactly.', 'I always try to express myself precisely.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ece3a257-ba9c-44f1-aa88-1b68d42c3e7e', 'predictable', 'Able to be predicted.', 'a boring film with a predictable ending', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('16a6ffd8-8b73-4ee3-b35d-1d87e8707d3e', 'preference', 'The selection of one thing or person over others (with the main adposition being "for" in relation to the thing or person, but possibly also "of")', 'He has a preference for crisp wines.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('89a20ad1-b326-40bf-99bf-7ee55d30d293', 'pregnant', 'A pregnant person.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('af7ef6a7-4c14-473b-8161-0868cd22446d', 'prejudice', 'An adverse judgment or opinion formed beforehand or without knowledge of the facts.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1a1a3bf3-e7aa-4c23-bf48-ef82299d1847', 'preparation', 'The act of preparing or getting ready.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c0a07abc-0e66-4d30-a6de-c3ae543ea39c', 'prescription', 'The act of prescribing a rule, law, etc..', '"Jurisdiction to prescribe" is a state''s authority to make its laws applicable to certain persons or activities. -- Richard G. Alexander, Iran and Libya Sanctions Act of 1996: Congress exceeds its jurisdiction to prescribe law. Washington and Lee Law Review, 1997.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6d4d277f-63fb-473c-99a6-35a2d7edd6d1', 'presence', 'The fact or condition of being present, or of being within sight or call, or at hand.', 'Any painter can benefit from the presence of a live model from which to draw.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ac3ca367-040a-42d4-a2f4-0ec4875e2fdc', 'preserve', 'A sweet spread made of any of a variety of fruits.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4f02b1ea-f925-465e-98ea-19a4d5102215', 'pride', 'The quality or state of being proud; an unreasonable overestimation of one''s own superiority in terms of talents, looks, wealth, importance etc., which manifests itself in lofty airs, distance, reserve and often contempt of others.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d1c5844b-5538-4121-ab01-ca38c952a52f', 'primarily', '(focus) Of a primary or central nature, first and foremost', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('00779745-08cc-4b56-afeb-55b13ee5b015', 'prime', 'The first hour of daylight; the first canonical hour.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('cbdc5d64-14d2-4bd0-950a-acb74b3eb42d', 'principal', 'The money originally invested or loaned, on which basis interest and returns are calculated.', 'A portion of your mortgage payment goes to reduce the principal, and the rest covers interest.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b9e02ebc-85ca-420d-8949-cf9b8d7b97b9', 'principle', 'A fundamental assumption or guiding belief.', 'We need some sort of principles to reason from.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('feefc7ee-f7a5-4c00-8d60-2c4017d8fdde', 'prior', 'A high-ranking member of a monastery, usually lower in rank than an abbot.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9f38974c-82d7-436c-98ef-82cd4bb72da9', 'priority', 'An item''s relative importance.', 'He set his e-mail message''s priority to high.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('18b0c874-a7c1-4008-a790-4910325b8b48', 'privacy', 'The state of being secluded from the presence, sight, or knowledge of others.', 'I need my privacy, so please stay out of my room.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1782c472-ee39-4adc-964c-e76a80f9b8f4', 'privatization', 'The transfer of a company or organization from government to private ownership and control.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f4ee091e-1c7a-4ad4-90ed-b4c0f61116e6', 'probability', 'The state of being probable; likelihood.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('022f2dc6-0b13-4394-ab0b-b393be4c35da', 'probable', 'Something that is likely.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f82c1d5f-5aef-4250-88ef-573e1702bdec', 'procedure', 'A particular method for performing a task.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('958a6972-eb08-486f-8c79-2e4eb629cb86', 'proceed', 'To move, pass, or go forward or onward; to advance; to carry on', 'To proceed on a journey.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2f397e07-80fc-4009-9c32-0e35092ca9f5', 'prognosis', 'A forecast of the future course of a disease or disorder, based on medical knowledge.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('626c1a03-10f4-4df8-8cd7-0f30108aaf99', 'programming', 'To enter a program or other instructions into (a computer or other electronic device) to instruct it to do a particular task.', 'He programmed the DVR to record his favorite show.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('da43f4e7-2cab-477a-8a1b-40b320b2777e', 'progressive', 'A person who actively favors or strives for progress towards improved conditions, as in society or government.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('dd1e4f76-d983-411d-9369-3478957361fa', 'prohibit', 'To forbid, disallow, or proscribe officially; to make illegal or illicit.', 'The restaurant prohibits smoking on the patio.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('782d4c99-d92f-4b75-9861-dd014cbe32b0', 'promising', 'To commit to (some action or outcome), or to assure (a person) of such commitment; to make an oath or vow.', 'He promised to never return to this town again.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3b9f0c41-d0c9-479b-8de7-efa3e9b47489', 'promotion', 'An advancement in rank or position.', 'I''ll have to give myself a promotion!', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3df40e6f-1a74-4d2b-a74d-97f562537750', 'prompt', 'A reminder or cue.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('832ef93e-f047-40cc-89ad-ddef1f060d1f', 'proof', 'An effort, process, or operation designed to establish or discover a fact or truth; an act of testing; a test; a trial.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b2d0c9bd-7586-473d-9a09-8c18bab4345d', 'propaganda', 'A concerted set of messages aimed at influencing the opinions or behavior of large numbers of people.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ff486e01-fb75-4b33-b8d3-fa6018c5f723', 'proportion', 'A quantity of something that is part of the whole amount or number.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c0154689-b003-4d45-84b7-573fa273ccd8', 'proposal', 'Something which is proposed, or offered for consideration or acceptance', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f0caef29-c053-43e6-a881-8e01e7df1b3f', 'propose', 'An objective or aim.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('eb527f16-20a7-49a7-8962-a2e910a46969', 'prosecution', 'The act of prosecuting a scheme or endeavor.', 'The prosecution of the war fell to Winston Churchill.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('38595dff-835f-4b64-a758-1ae9e59a921b', 'prospect', 'The region which the eye overlooks at one time; view; scene; outlook.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('20b1c197-2195-46d7-bf33-ab4b0f2a85d8', 'protection', 'The process of keeping (something or someone) safe.', 'Raincoats give protection from rain.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3c4891c0-3032-4e10-b670-bccf962bac84', 'protein', 'Any of numerous large, complex naturally-produced molecules composed of one or more long chains of amino acids, in which the amino acid groups are held together by peptide bonds.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8d6915cf-1ef8-42a1-9e9b-58e82ccced86', 'protester', 'One who protests, either singly or in a public display of group feeling.', 'The protesters thronged Trafalgar Square and sang anti-war songs.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('fba66af4-616b-438c-8ee5-143e96df3182', 'prototype', 'An original form or object which is a basis for other forms or objects (particularly manufactured items), or for its generalizations and models.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('19327b00-e8ba-4de5-a5ab-620106f19036', 'psychological', 'Of or pertaining to psychology.', 'I''m concerned about their psychological well-being.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7e9e2638-670e-4e5a-8fdd-e26212a3ce7c', 'psychologist', 'An expert in the field of psychology.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9869586f-3caa-4884-9488-99dd254ef87d', 'psychology', 'The study of the human mind.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('807ce772-3ec8-49d9-ab38-f87f3001e67c', 'publication', 'The act of publishing printed or other matter.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f8d42626-0ca5-4625-b3c1-d6b93b46fdb8', 'publicity', 'Advertising or other activity designed to rouse public interest in something.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f4bf4669-c31d-4cc5-a224-77b808adb3dc', 'publishing', 'To issue (something, such as printed work) for distribution and/or sale.', 'Most of the sketches Faulkner published in 1925 appeared in the Sunday magazine section of the New Orleans Times-Picayune.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0f412f47-3a20-4024-9944-0822520938b3', 'punk', 'A person used for sex, particularly:', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e622bcf9-43bf-4fc3-ab23-2b307b527682', 'pupil', 'A learner under the supervision of a teacher or professor.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ea160979-735d-484f-bbbb-636db7c5e7b6', 'purchase', 'The acquisition of title to, or property in, anything for a price; buying for money or its equivalent.', 'They offer a free hamburger with the purchase of a drink.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('eb1ef668-6dfe-4502-aab5-9946dc15ef67', 'pure', 'One who, or that which, is pure.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('de4c3717-5eac-45c4-ac68-b440e72006d4', 'purely', 'Wholly; really, completely.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1ad92f66-3dbd-4f69-9db4-ae325654184d', 'pursue', 'To follow urgently, originally with intent to capture or harm; to chase.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('335c0ba8-0ec9-4835-913e-059c6761bcaa', 'pursuit', 'The act of pursuing.', 'Unremitting pursuit of wealth doesn''t bring happiness, particularly if successful.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9ad23a9f-6b4a-481f-8236-cca88429118e', 'puzzle', 'Anything that is difficult to understand or make sense of.', 'Where he went after he left the house is a puzzle.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('edb25668-70d6-4a0b-be2a-0156781a73c0', 'questionnaire', 'A form containing a list of questions; a means of gathering information for a survey', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('85c8d06c-8618-42b7-b57b-cd089b94d2c0', 'racism', 'Belief that there are distinct human races with inherent differences which determine their abilities, and generally that some are superior and others inferior.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2e1d066a-df68-4b63-9af4-2b57f4d965ea', 'racist', 'A person who believes in or supports racism; a person who believes that a particular race is superior to others.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('56552897-b540-4809-9353-2a1764555f6f', 'radiation', 'The shooting forth of anything from a point or surface, like diverging rays of light.', 'heat radiation', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('851713b8-5174-46e0-aa46-f9e2acb45c60', 'rail', 'A horizontal bar extending between supports and used for support or as a barrier; a railing.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('30f794b8-368f-4bf2-9230-feaca90f8dff', 'random', 'A roving motion; course without definite direction; lack of rule or method; chance.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('81ccee55-576b-4efd-b168-45a2d7733467', 'rank', 'Strong of its kind or in character; unmitigated; virulent; thorough; utter (used of negative things).', 'rank nonsense', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8fc6f3b2-5443-4222-b6ac-0fa5541c0ce7', 'rapid', '(often in the plural) a rough section of a river or stream which is difficult to navigate due to the swift and turbulent motion of the water.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d4dd0131-66ad-4fe4-8c4b-80ac3585fd7d', 'rapidly', 'With speed; in a rapid manner.', 'She packed her case rapidly and hurried out.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9adc1862-8f9c-4513-8052-438ca68c8a4f', 'rat', 'A medium-sized rodent belonging to the genus Rattus.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('af51bc0f-5efd-4d06-9e35-8ae2ff347a46', 'rating', 'To assign or be assigned a particular rank or level.', 'She is rated fourth in the country.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f9f41b1b-3137-43dc-9509-1ed59d02dad7', 'raw', '(sugar refining, sugar trade) An unprocessed sugar; a batch of such.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2d7e6ad6-5a68-4e3e-9729-7af5e914b7b0', 'realistic', 'Expressed or represented as being accurate, practicable, or not idealistic.', 'A realistic appraisal of the situation.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9a10ffbe-8ec4-4919-83b4-0ce76ea1f0d6', 'reasonable', 'Having the faculty of reason; rational, reasoning.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b648041b-ac0b-4c83-9347-b6f5671b8dea', 'reasonably', 'In accordance with reason.', 'They were able handle their disagreements reasonably.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('5a003084-7da9-4d0b-b533-1de780c05b63', 'rebuild', 'A process or result of rebuilding.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e21f3a39-5c79-4af4-9a70-caff31527c86', 'recall', 'The action or fact of calling someone or something back.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('02ab746c-8937-440c-8163-0aa2900640e3', 'receiver', 'A person who or thing that receives or is intended to receive something. More formal, usually referring to one who receives such things as an award or medal.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ec900d51-0529-4b6d-807f-72d27e7e0ca4', 'recession', 'The act or an instance of receding or withdrawing.', '', 'Business', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b0cc2cb2-9b9c-403f-8f48-a44fd223fb06', 'reckon', 'To count; to enumerate; to number; also, to compute; to calculate.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('5fd1ee23-df2d-4aa4-bff1-8a7fca0bae47', 'recognition', 'The act of recognizing or the condition of being recognized (matching a current observation with a memory of a prior observation of the same entity)', 'He looked at her for ten full minutes before recognition dawned.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('fe7fa2d8-6238-4769-9fd1-6e7d8591d745', 'recovery', 'The act or process of regaining or repossession of something lost.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b36a6947-1793-4c13-b950-5cb177b417ec', 'recruit', 'A supply of anything wasted or exhausted; a reinforcement.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('dbac6da1-3f56-43b8-8c64-1f804db73f85', 'recruitment', 'The process or art of finding candidates for a post in an organization, or recruits for the armed forces.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b6dcddc1-6dcc-4d59-873b-be02b2b92174', 'reduction', 'The act, process, or result of reducing.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3e6aa102-2927-4986-a12d-74703586dac7', 'referee', 'An umpire or judge; an official who makes sure the rules are followed during a game.', 'The referee kicked Jim out of the game for fighting.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2f8d13c9-9d48-4526-b47d-07ff59df23e8', 'referendum', 'A direct popular vote on a proposed law or constitutional amendment. The adposition on is usually used before the related subject of the vote.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2dafacfe-36bf-4452-899f-3664823759ea', 'refugee', 'A person seeking refuge in a foreign country out of fear of political persecution or the prospect of such persecution in their home country, i.e., a person seeking political asylum.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d513a987-646c-420b-b06b-f4fe1ba68b30', 'regard', 'A steady look, a gaze.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6a7548d6-3224-4d8e-9b1e-0ae5203b8c23', 'regional', 'An entity or event with scope limited to a single region.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f916a076-844e-4034-9b41-2196c41d1bdf', 'register', 'A machine that tabulates the amount of sales transactions, makes a permanent and cumulative record of them, and has a drawer in which cash can be kept.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9d0c9dde-a207-4620-b3e0-7861b2c11bb2', 'registration', 'The act of signing up or registering for something.', 'Complete the registration process.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3a936517-c41a-4bf0-b819-54a5016f0089', 'regret', 'Emotional pain on account of something done or experienced in the past, with a wish that it had been different; a looking back with dissatisfaction or with longing.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2fb88522-7cd7-4c7a-8426-92ef89500390', 'regulate', 'To dictate policy.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a693c835-cac1-44cd-bd88-a9e26f0e67ca', 'regulation', 'The act of regulating or the condition of being regulated.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8e41cefe-e980-46ee-b830-4f7524a869ad', 'rehabilitation', 'The process of rehabilitating somebody or something.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('06ca7467-4f69-48f1-99d0-72e0303f712d', 'reinforce', 'To strengthen, especially by addition or augmentation.', 'He reinforced the handle with a metal rod and a bit of tape.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8cf76ed7-949d-4bc1-a618-9a5004fc72fc', 'relatively', 'Proportionally, in relation to some larger scale thing.', 'He measured his success relatively, that is, competitively.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('350e7c4f-6ebd-48d2-bcaa-45bdec087c25', 'relevant', 'Directly related, connected, or pertinent to a topic.', 'His mother provided some relevant background information concerning his medical condition.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('bd3617ba-b8d5-4b70-9e26-0cd83736f033', 'relief', 'The removal of stress or discomfort.', 'I sighed with relief when I found out that my daughter hadn''t got lost, but was waiting for me at home.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8d0d5ca3-2b1a-436b-9ee8-65dd9326699f', 'relieve', 'To ease (a person, person''s thoughts etc.) from mental distress; to stop (someone) feeling anxious or worried, to alleviate the distress of.', 'I was greatly relieved by the jury''s verdict.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('fdbe881a-4e44-47d6-8e30-eaa0d0c3f837', 'relieved', 'To ease (a person, person''s thoughts etc.) from mental distress; to stop (someone) feeling anxious or worried, to alleviate the distress of.', 'I was greatly relieved by the jury''s verdict.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('23164008-3067-4ae2-a402-df5502ea031a', 'rely', '(with on or upon, formerly also with in) to trust; to have confidence in; to depend.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('17724fe6-2d44-46fd-b893-5baad6d8f37d', 'remark', 'An act of pointing out or noticing; notice or observation.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f34b9efb-37cf-4a52-a8e0-537903dfd873', 'remarkable', 'Worthy of being remarked or noted; notable', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('919f2913-d5ff-4f28-a859-191ad89d23c2', 'remarkably', '(manner) In a remarkable manner.', 'He performed the piece remarkably, offering novel interpretations to its nearly cliched passages.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('28e0b8a1-dddb-4710-b163-362083437cca', 'renaissance', 'A rebirth or revival.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('28e84d81-70cd-4df3-8d32-def2cdc5bd80', 'renewable', 'A thing that is renewable; especially, a renewable source of energy.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('58fa45a4-9763-41e8-83a6-a1ae75cb7b23', 'reporting', 'To relate details of (an event or incident); to recount, describe (something).', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7c5df9c2-f0d0-4419-bd0a-59a316f2fa89', 'representative', 'A delegate.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8f35bf00-082b-4853-8a05-0e3dd014d683', 'reputation', 'What somebody is known for.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('814ab5b9-e736-4fc4-9fef-42a82588a4dd', 'requirement', 'A necessity or prerequisite; something required or obligatory. Its adpositions are generally of in relation to who or what has given it, on in relation to whom or what it is given to, and for in relation to what is required.', 'There was a requirement of the government on citizens for paying taxes.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2751bc17-a4cd-47ed-b94d-1ceaa36c302d', 'rescue', 'An act or episode of rescuing, saving.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7513ac88-ab3a-4cfb-96b3-828405fb9a9c', 'resentment', 'A feeling of anger or displeasure stemming from belief that one has been wronged by others or betrayed; indignation.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('bd768af7-8d18-4e12-b4fc-0bc086f277b4', 'reserve', '(behaviour) Restriction.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('363d1520-bd56-45ba-af34-0648f275711f', 'resident', 'A person, animal or plant living at a certain location or in a certain area.', 'The tiger lily is a resident of Asia.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('72a506dd-c1fb-4950-b9aa-9a926b4f37b0', 'resign', 'To give up; to relinquish ownership of.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('422b5120-d94c-4636-a26e-68983403ea4c', 'resilience', 'The mental ability to recover quickly from depression, illness or misfortune.', '', 'Psychology', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d2043da5-0eb0-417d-ab08-f8a545a1d9e8', 'resist', 'A protective coating or covering.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3ebfe8f1-6c77-49cd-a949-771b6ecbafde', 'resolution', 'A strong will, determination.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('dd31062b-13a1-4fd7-9bed-a149cf854f57', 'resolve', 'Determination; will power.', 'It took all my resolve to go through with the surgery.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('96d8838f-66b2-497a-a17c-cc745a953545', 'resort', 'A place where people go for recreation, especially one with facilities such as lodgings, entertainment, and a relaxing environment.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1434a8d0-c65a-4d13-8f6f-cc18d009fe65', 'restore', 'The act of recovering data or a system from a backup.', 'We backed up the data successfully, but the restore failed.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6d5026c5-37c9-4bfe-b8ad-5970cbffc2bb', 'restrict', 'To restrain within boundaries; to limit; to confine', 'After suffering diahrroea, the patient was restricted to a diet of rice, cold meat, and yoghurt.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4aa3bb74-386e-46c3-834f-555b4b5fc66c', 'restriction', 'The act of restricting, or the state of being restricted.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b9ee9b2f-99b6-41ee-91ed-dd5a6ad157e3', 'retail', 'The sale of goods directly to the consumer, encompassing the storefronts, mail-order, websites, etc., and the corporate mechanisms, branding, advertising, etc. that support them.', 'She works in retail.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('325d22e4-2249-42e9-93cc-879877e18b43', 'retain', 'To keep in possession or use.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3b35d907-1868-46ca-babd-cca302a8d622', 'retirement', 'An act of retiring; withdrawal.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b590586e-fbbd-45c1-b39c-34367b84d9b0', 'reveal', 'The outer side of a window or door frame; the jamb.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9469082b-e514-45aa-b338-a39fd5838d3f', 'revenue', 'The income returned by an investment.', '', 'Business', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('309133c4-dd8f-425e-8081-9f505e3c2f4a', 'revision', 'The process of revising:', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d6fdc288-7992-4806-a1b2-95919edb667e', 'revolution', 'A political upheaval in a government or nation state characterized by great change.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a8ef2adb-6458-4748-aa77-eb31d4570dd8', 'reward', 'Something of value given in return for an act.', 'For catching the thief, you''ll get a nice reward.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4db0ad96-38fa-4cbd-a9e0-d80bf69707a5', 'rhetoric', 'The art of using language, especially public speaking, as a means to persuade.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('866b6044-8e5c-4e0b-a16d-fedf86d7d146', 'rhythm', 'The variation of strong and weak elements (such as duration, accent) of sounds, notably in speech or music, over time; a beat or meter.', 'Dance to the rhythm of the music.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3db0e769-b99a-421e-9ffe-64d09dde1d75', 'rid', 'To free (something) from a hindrance or annoyance.', 'We''re trying to rid the world of poverty.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('180fcc6a-7b11-48b8-b77e-e71e385760ab', 'ridiculous', 'Deserving of ridicule; foolish; absurd.', 'It''s ridiculous to charge so much for a little souvenir.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d00f7d38-e647-45d9-8cc9-fa2cc601e6b3', 'risky', 'Dangerous, involving risks.', 'Investing in this start-up company could be risky.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('93afed65-419b-4670-baff-f90b14a7c22b', 'rival', 'A competitor (person, team, company, etc.) with the same goal as another, or striving to attain the same thing. Defeating a rival may be a primary or necessary goal of a competitor.', 'Chris is my biggest rival in the 400-metre race.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('70670f62-9f44-447b-b067-4cb0be8e319e', 'rob', 'To steal from, especially using force or violence.', 'He robbed three banks before he was caught.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ae4eefd6-c1b9-453f-9e87-76df08fd9dbc', 'robbery', 'The act or practice of robbing.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7feebfa3-cc81-4ee5-a831-96e0b62eaa3d', 'rocket', 'A rocket engine.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b6800bc6-c31e-42dd-89be-33fe2ce79737', 'romance', 'A story relating to chivalry; a story involving knights, heroes, adventures, quests, etc.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4bd303ef-aab5-4be0-ae89-78ccda228d9a', 'root', 'The part of a plant, generally underground, that anchors and supports the plant body, absorbs and stores water and nutrients, and in some plants is able to perform vegetative reproduction.', 'This tree''s roots can go as deep as twenty metres underground.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ba4cbee5-59eb-4641-aa03-e62ce9fd43b9', 'rose', 'A shrub of the genus Rosa, with red, pink, white or yellow flowers.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ac8997d4-3158-4cf3-9b68-4a99121ec2e1', 'roughly', 'In a rough manner; without kindness, softness, or gentleness.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c17cd269-d8a4-4e66-a64e-f16a345b1b6f', 'rub', 'An act of rubbing.', 'Give that lamp a good rub and see if any genies come out', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a0e99894-c22e-48fb-8847-5d96c46aaab4', 'rubber', 'Pliable material derived from the sap of the rubber tree; a hydrocarbon polymer of isoprene.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6a03d406-6987-44f9-a197-1467496056da', 'ruin', '(sometimes in the plural) The remains of a destroyed or dilapidated construction, such as a house or castle.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f4eb1c4f-0ca2-4854-9fd8-b5781e883c94', 'rural', 'A person from the countryside; a rustic.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4b1f2002-e6c3-4c83-bda1-d339cc967639', 'rush', 'Any of several stiff plants of the genus Juncus, or the family Juncaceae, having hollow or pithy stems and small flowers, and often growing in marshes or near water.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d874e623-721a-44dc-9619-444b063cbff6', 'satellite', 'A moon or other smaller body orbiting a larger one.', 'A spent upper stage is a derelict satellite.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('855bf64c-9a07-4d71-a6ef-5c7e561bf044', 'satirical', 'Of, pertaining to or connected with satire', 'Spitting Image was a famous satirical television program.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4faf2e20-f85e-4c19-81eb-74a97ed1d40e', 'satisfaction', 'A fulfilment of a need or desire.', 'He enjoyed the dish with great satisfaction. He''ll order it again the next time he arrives.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('de40cc41-2677-4ff3-85bc-231eb0724fb5', 'satisfied', 'To do enough for; to meet the needs of; to fulfill the wishes or requirements of.', 'I''m not satisfied with the quality of the food here.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('5589d818-b3a8-4e66-9ad6-ff065520bb15', 'satisfy', 'To do enough for; to meet the needs of; to fulfill the wishes or requirements of.', 'I''m not satisfied with the quality of the food here.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('5c3c7d03-db25-47e6-a271-407a1bdba9b8', 'saving', 'To prevent harm or difficulty.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a9f73979-f9b9-44a3-b9d3-4b812c933ce4', 'scale', 'A ladder; a series of steps; a means of ascending.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('887f4d4f-f5f8-43c6-b4c0-b8cddc06a490', 'scandal', 'An incident or event that disgraces or damages the reputation of the persons or organization involved.', 'Their affair was reported as a scandal by most tabloids.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8821c92d-4d98-4edb-9861-328039485c27', 'scare', 'A minor fright.', 'Johnny had a bad scare last night.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('114bd1a8-48c9-48b2-afa0-54cf4dbcf5a6', 'scenario', 'An outline of the plot of a dramatic or literary work.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4847b109-68a6-451b-bc7d-aa485c9c2131', 'scheme', 'A systematic plan of future action.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3aa9ba55-818d-4d71-9932-9b9e09be8f4b', 'scholar', 'A student; one who studies at school or college, typically having a scholarship.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('bdf4550f-40d8-4ecc-bd15-6a60a6493354', 'scholarship', 'A grant-in-aid to a student.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a6e1854c-99ec-46ac-b495-11eb014a2c1c', 'scratch', 'A disruption, mark or shallow cut on a surface made by scratching.', 'Her skin was covered with tiny scratches.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4dcfd21c-6c77-419f-8330-941b48094e44', 'scream', 'A loud, emphatic, exclamation of extreme emotion, especially horror, fear, excitement, or anger; it may comprise a word or a sustained, high-pitched vowel sound.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('215b7b4c-854e-42f6-af5d-f8b47b540f3c', 'screening', 'To filter by passing through a screen.', 'Mary screened the beans to remove the clumps of gravel.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d64bd31c-9c38-42b7-bcb5-d189fa871daf', 'sector', 'Section', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9ef0975c-be6c-4153-b557-82020b4d0606', 'secure', 'To make safe; to relieve from apprehensions of, or exposure to, danger; to guard; to protect.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a320ab4c-29c0-4cd4-8805-802952df51b1', 'seek', 'The operation of navigating through a stream.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('441cda3b-51ba-46ab-a5a2-8e7d8b7b619e', 'seeker', 'One who seeks.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('21a7560b-0eb6-48e3-a508-7aba51972b81', 'select', 'To choose one or more elements of a set, especially a set of options.', 'He looked over the menu, and selected the roast beef.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('77f0d8e8-8201-43da-82d4-64ae7ec332d8', 'selection', 'A process by which heritable traits conferring survival and reproductive advantage to individuals, or related individuals, tend to be passed on to succeeding generations and become more frequent in a population, whereas other less favourable traits tend to become eliminated; the differential survival and reproduction of phenotypes.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('cb3dde15-8599-4967-87f5-43895b25e5cf', 'self', 'One individual''s personality, character, demeanor, or disposition.', 'one''s true self; one''s better self; one''s former self', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d816e6b7-6036-4cdd-a718-08e55d5b9757', 'seminar', 'A class held for advanced studies in which students meet regularly to discuss original research, under the guidance of a professor.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4291fe01-b6bb-403b-8535-b506d429d01a', 'senior', 'An old person.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f5fb5e7f-8038-4ce7-a5a8-8ddb8ae7ae5f', 'sensitive', 'A person with a paranormal sensitivity to something that most cannot perceive.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8dc82922-074d-4dd5-a5a8-7633c4367e6b', 'sequence', 'A set of things next to each other in a set order; a series', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c926a9c5-2450-4012-9474-9b5943054f20', 'session', 'An informal gathering of musicians to play music, especially improvised jazz or a similar genre.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f04114f4-1e98-41f1-afb6-1cdf8e7af0db', 'settle', 'To conclude or resolve (something):', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e10c7955-f5bb-433a-a187-4308b4e87879', 'settler', 'Someone who settles in a new location, especially one who takes up residence in a previously uninhabited place; a colonist.', 'the first settlers of New England', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c9db9527-04db-402f-a292-1825794bccbd', 'severe', 'Very bad or intense.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ba1f69d1-743b-4a28-995a-b73625431b55', 'severely', 'In a severe manner.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7c830149-a226-47ca-b5f7-bd79e1151cd8', 'sexy', '(of a person) Having sex appeal; suggestive of sex.', 'The participants in the swimsuit competition are all very sexy.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7e605497-c04a-40b6-b180-a88af2e46558', 'shade', 'Darkness where light, particularly sunlight, is blocked.', 'The old oak tree gave shade in the heat of the day.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1eb70d0d-e484-47e4-aaf9-6c358c6e400f', 'shadow', 'A dark image projected onto a surface where light (or other radiation) is blocked by the shade of an object.', 'My shadow lengthened as the sun began to set.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a156145f-8592-48da-8197-8794a3256645', 'shallow', 'A shallow portion of an otherwise deep body of water.', 'The ship ran aground in an unexpected shallow.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f8736876-335b-4ce2-85a5-deba076d51ae', 'shame', 'Uncomfortable or painful feeling due to recognition or consciousness of one''s own impropriety or dishonor or something being exposed that should have been kept private.', 'The teenager couldn’t bear the shame of introducing his parents.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0f496e6f-eea7-4999-ac2e-9a152fc011b2', 'shaped', 'To create or make.', 'Earth was shapen by God for God''s folk.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('db1e2896-ea2a-4fbd-84fd-1eca36f57d16', 'shelter', 'A refuge, haven or other cover or protection from something.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('274c9ed4-d994-4e71-91a1-450ce9fcfd63', 'shock', 'A sudden, heavy impact.', 'The train hit the buffers with a great shock.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('06a3c151-737e-42a6-9437-789878af5323', 'shocked', 'To cause to be emotionally shocked, to cause (someone) to feel surprised and upset.', 'The disaster shocked the world.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1d3e3fee-4721-42ae-a878-c8cf88435521', 'shocking', 'To cause to be emotionally shocked, to cause (someone) to feel surprised and upset.', 'The disaster shocked the world.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6da63cbd-f1a9-4e3c-86b6-885067c6ddea', 'shooting', 'To launch a projectile.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('acdfd272-a1d9-42c8-bdb5-d807dbf09f9e', 'shore', 'Land adjoining a non-flowing body of water, such as an ocean, lake or pond.', 'lake shore;  bay shore;  gulf shore;  island shore;  mainland shore;  river shore;  estuary shore;  pond shore;  sandy shore;  rocky shore', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d9f9c475-836a-4c7a-b5a0-d05c3e67d006', 'short-term', 'Of or pertaining to the near or immediate future.', 'This short-term plan deals with the next few days.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4c1f5995-d8cf-4e4b-9732-3b61b99c25d1', 'shortage', 'A lack or deficiency; an insufficient amount.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('5bacf48f-ff17-4730-b01c-8b073b6314ee', 'shortly', 'In a short or brief time or manner; quickly.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d7716261-820c-4d73-b59c-bef302aa46d9', 'shot', 'To launch a projectile.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('45334a96-a72c-4ce0-8230-c5c8e93fc9f4', 'sibling', 'A person who shares a parent; one''s brother or sister who one shares a parent with.', 'None of my siblings are married yet.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a9427a10-09df-454a-8851-a977ba4ffc5c', 'signature', 'A person''s name, written by that person, used as identification or to signify approval of accompanying material, such as a legal contract.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c34493d9-d1de-4550-bfbe-0b3c471f5889', 'significance', 'The extent to which something matters; importance', 'As a juror your opinion is of great significance for the outcome of the trial.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9ddbf048-d67f-4fbd-9003-48ea40440114', 'significant', 'That which has significance; a sign; a token; a symbol.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9686a49e-b8d3-4822-bb21-c3275af947db', 'significantly', 'In a significant manner or to a significant extent.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('dd51745d-d3cf-4f38-937a-81d644eabeae', 'silence', 'The absence of any sound.', 'When the motor stopped, the silence was almost deafening.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('44f4d3da-2a8f-4b04-9724-ef95035cb0c3', 'silk', 'A fine fiber excreted by the silkworm or other arthropod (such as a spider).', 'The thread made of silk was barely visible.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('5e07e21a-4c01-446f-9644-7524b4268344', 'simulation', 'Something that simulates a system or environment in order to predict actual behaviour.', 'The most reliable simulation predicts that the hurricane will turn north.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('445f27a6-7a5c-4f75-a8bb-dbd57220c103', 'sincere', 'Genuine; meaning what one says or does; heartfelt.', 'I believe he is sincere in his offer to help.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('063b1e59-1302-41cf-8f3b-881696537059', 'skilled', 'Having or showing skill; skillful.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d4a73be4-45a9-489f-8a6a-9a29db25b69b', 'skull', 'The main bones of the head considered as a unit; including the cranium, facial bones, and mandible.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('bce9c510-027e-414d-91c9-966bf49a988c', 'slave', 'A person who is held in servitude as the property of another person, and whose labor (and often also whose body and life) is subject to the owner''s volition and control.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e298a0b6-24a9-4bad-b7a1-378de67b75c6', 'slide', 'An item of play equipment that children can climb up and then slide down again.', 'The long, red slide was great fun for the kids.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('80e5f363-3f66-4cca-81fd-455aaf64a25f', 'slight', 'The act of slighting; a deliberate act of neglect or discourtesy.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('abd3d38f-cc34-48df-9c9d-fd6b334386a6', 'slip', 'A thin, slippery mix of clay and water.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('17ac59fc-5a56-41cf-88ee-e9b61fef7732', 'slogan', 'A catch phrase associated with the product or service being advertised.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('336007f0-ed0a-4275-aaf3-4fe04e941b26', 'slope', 'An area of ground that tends evenly upward or downward.', 'I had to climb a small slope to get to the site.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8bf9e875-7b0f-4a10-aa22-8c4f3a531d84', 'so-called', 'So named; commonly called by such a name, often with a connotation that the item is not worthy of that name.', 'These so-called "assistants" are making our jobs harder, not easier!', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('700be510-5740-44c8-bc14-de4411868a38', 'solar', 'Of or pertaining to the sun; proceeding from the sun', 'solar influence', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d9dca4fb-334a-402a-9481-f678bb874f50', 'somehow', 'In one way or another; in a way not yet known or explained; by some means', 'This problem has to be tackled somehow.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b9f62d94-6c64-4a8a-b57b-0067c9044a67', 'sometime', 'Former, erstwhile; at some previous time.', 'my sometime friend and mentor', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('658b8b70-bc89-4fcb-b5e3-ffab7d4db220', 'somewhat', 'More or less; a certain quantity or degree; a part, more or less; something.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('224183ad-b403-426a-9cc2-21e707d02596', 'sophisticated', 'To make less natural or innocent.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d23350b0-9acb-4a8d-9cf9-0a23a9899674', 'soul', 'The spirit or essence of a person usually thought to consist of one''s thoughts and personality. Often believed to live on after the person''s death.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('98b377e8-ca8c-4846-a09d-512700289e5f', 'sovereignty', '(of a polity) The state of making laws and controlling resources without the coercion of other nations.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('19374d08-9637-4d1c-8535-6f75d68fc412', 'spare', 'The act of sparing; moderation; restraint.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('856990e2-d91d-4687-9549-afc8286ee638', 'specialist', 'Someone who is an expert in, or devoted to, some specific branch of study or research.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a21bc355-66d7-4482-bb70-936f16f7d387', 'specialize', 'To make distinct or separate, particularly:', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2d4bdd1d-4a3a-407a-ae9c-df8d6c0f2859', 'specify', 'To state explicitly, or in detail, or as a condition.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7a0731e9-cb35-44d4-97e1-74c3b0589d9c', 'spectacular', 'A spectacular display.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3709e8cc-7836-4cfa-bebf-1ee6d46e2f45', 'spectator', 'One who watches an event; especially, one held outdoors.', 'The cheering spectators watched the fireworks.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('58627fc2-88a1-4f06-80d7-5048ddbbbb05', 'speculate', 'To think, meditate or reflect on a subject; to consider, to deliberate or cogitate.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1104af7a-cb40-4af0-895a-7005006ab813', 'speculation', 'The process of thinking or meditating on a subject.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0955e1e4-719b-4b00-8366-3c08f61a3d62', 'spice', 'Aromatic or pungent plant matter (usually dried) used to season or flavour food.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9c30f1ae-4af2-4901-bfb8-e3125742b919', 'spill', 'A mess of something that has been dropped.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7b15f5fc-3e75-4a01-9cb7-3fa4ef87407d', 'spiritual', 'A Christian religious song, especially one in an African-American style, or a similar non-religious song.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8a0e7b66-44c4-4877-b56b-fd792a3eb9df', 'spite', 'Ill will or hatred toward another, accompanied with the desire to irritate, annoy, or thwart; a want to disturb or put out another; mild malice', 'He was so filled with spite for his ex-wife, he could not hold down a job.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d8ead477-b35f-440b-abae-c0e532854d05', 'split', 'A crack or longitudinal fissure.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1c2530d2-409e-4da0-8e70-137483213ce7', 'spoil', '(Also in plural: spoils) Plunder taken from an enemy or victim.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4f5bad37-74dd-4f55-9993-36dcc2ec2a6f', 'spokesman', 'One who speaks as the voice of a group of people.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c417be81-d2ad-476c-85f9-9d667b5db90a', 'spokesperson', 'A person who acts as the voice of a group of people.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f5290e34-e5b5-4147-a1b5-11d073359a96', 'spokeswoman', 'A woman who speaks as the voice of a group of people.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c41ed6bd-5ef5-4629-baac-445d438f86fc', 'sponsor', 'A person or organisation with some sort of responsibility for another person or organisation, especially where the responsibility has a religious, legal, or financial aspect.', 'He was my sponsor when I applied to join the club.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('30604010-0e09-438c-8d9b-522030100637', 'sponsorship', 'The state or practice of being a sponsor.', 'I find that for me, my sponsorship of a child via a charitable NGO provides a sense of great satisfaction.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1cb8368c-6446-461c-a446-a588e1b9bd66', 'sporting', 'To amuse oneself, to play.', 'children sporting on the green', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b96985fd-f83f-4ab3-a607-9dca7e91fa6a', 'stable', 'A building, wing or dependency set apart and adapted for lodging and feeding (and training) animals with hoofs, especially horses.', 'There were stalls for fourteen horses in the squire''s stables.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ea32ba77-de15-468f-9463-fdf283669469', 'stall', 'A compartment for a single animal in a stable or cattle shed.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3528afcd-7c7c-412d-84d3-d01c153862ba', 'stance', 'The manner, pose, or posture in which one stands.', 'The fencer’s stance showed he was ready to begin.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('526aeec3-2854-490f-9a0b-d2c4df27529b', 'stare', 'A persistent gaze.', 'the stares of astonished passers-by', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d48c01b4-0d80-4fd5-aae4-70806efbc158', 'starve', 'To die; in later use especially to die slowly, waste away.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('fddcf6c5-9972-4c78-9f34-e516c43f4d30', 'status', 'A person’s condition, position or standing relative to that of others.', 'Superstition is highly correlated with economic status.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('fd489f6c-be4d-4307-879b-7320d3e39707', 'steadily', 'In a steady manner.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1a1a0a4a-b88f-4890-b527-d7466fa2f38b', 'steady', 'A rest or support, as for the hand, a tool, or a piece of work.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f64fa8dd-54ce-4e4e-80b6-d4e24d8e6603', 'steam', 'The vapor formed when water changes from liquid phase to gas phase.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('72abb3c3-5742-4e04-86a3-55a2796770e7', 'steel', 'An artificial metal produced from iron, harder and more elastic than elemental iron; used figuratively as a symbol of hardness.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('34fe90c3-49b4-4ca6-a707-e29221d48920', 'steep', 'The steep side of a mountain etc.; a slope or acclivity.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('87351068-a555-4103-92fa-56a72315324d', 'stereotype', 'A conventional, formulaic, and often oversimplified or exaggerated conception, opinion, or image of (a person).', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1efdb749-9572-4e5b-b145-d22d4e6c0f87', 'sticky', 'A sticky note, such as a post-it note.', 'Her desk is covered with yellow stickies.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('14a001f6-b98b-4479-867b-083f0fcb08e7', 'stiff', 'An average person, usually male, of no particular distinction, skill, or education, often a working stiff or lucky stiff.', 'A Working Stiff''s Manifesto: A Memoir of Thirty Jobs I Quit, Nine That Fired Me, and Three I Can''t Remember was published in 2003.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ba05876e-e765-4c1b-9bc4-306358960038', 'stimulate', 'To encourage into action.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('27a56d62-7dc7-4d67-981d-c81f07f99e20', 'stock', 'A store or supply.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0701f4da-5e08-4c62-aad7-355e10e56007', 'stream', 'A small river; a large creek; a body of moving water confined by banks.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('869d8627-7394-4900-8967-d5ed01cdf4e3', 'strengthen', 'To make strong or stronger; to add strength to; to increase the strength of; to fortify.', 'strengthen a muscle', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('543ba441-08a3-4079-9546-c70bf8769aed', 'stretch', 'An act of stretching.', 'I was right in the middle of a stretch when the phone rang.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d9553bda-68f3-4324-9b84-12ab0edd4d15', 'strict', 'Strained; drawn close; tight.', 'strict embrace', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7bcbf3ff-6223-4a10-9f65-750b321b2d5e', 'strictly', 'In a strict manner.', 'He adhered strictly to the diet his doctor prescribed.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('27302fcf-3880-44b2-86af-9a68142944e8', 'strike', 'A status resulting from a batter swinging and missing a pitch, or not swinging at a pitch when the ball goes in the strike zone, or hitting a foul ball that is not caught.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3fdd157a-6c3d-4c9a-ae28-c6e98228fc02', 'stroke', 'An act of stroking (moving one''s hand over a surface).', 'She gave the cat a stroke.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('205e1019-4efd-4fd6-b425-dafe807181ab', 'struggle', 'A contortion of the body in an attempt to escape or to perform a difficult task.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('dc85b392-ff12-48ec-ae38-aa86797b59cb', 'stunning', 'To incapacitate; especially by inducing disorientation or unconsciousness.', 'Bill tried to stun the snake by striking it on the head.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1324ff82-6ff3-408a-97b1-7b3e54042d6c', 'subconscious', 'That part of the mind that is not consciously perceived; one''s innermost thoughts.', 'A person can sometimes wake up knowing the solution to a problem that their subconscious has been working on.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a7a52669-78c6-4f56-a74d-ebf4685ff185', 'submit', 'To yield or give way to another.', 'They will not submit to the destruction of their rights.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e26942dd-b64e-4de6-b17e-820fc430725d', 'subsequent', 'Following in time; coming or being after something else at any time, indefinitely.', 'Growth was dampened by a softening of the global economy in 2001, but picked up in the subsequent years due to strong growth in China.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0ca48b5f-491c-4f8a-977d-5ca68137445d', 'subsequently', 'Following, afterwards in either time or place.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e3cea78a-ef4a-441b-94e6-a5bc0934a399', 'subsidiary', 'A company owned by a parent company or a holding company, also called daughter company or sister company.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c0e01463-cd62-44f1-90bc-6104e14ed044', 'subsidy', 'Financial support or assistance, such as a grant.', 'Manufacturing firms are supported by government subsidies in some countries.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b2dcce17-bf45-4f93-bf10-4363169ec614', 'suburb', 'A residential area located on the outskirts of a city or large town that usually includes businesses that cater to its residents; such as schools, grocery stores, shopping centers, restaurants, convenience stores, etc.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('03c27dc3-514b-4cbf-b94e-5e1985a81e31', 'suffering', 'To undergo hardship.', 'Is anyone here afraid of suffering hardship?', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7d26ff9a-d3f1-44ed-8246-dae64876aecd', 'sufficient', 'Equal to the end proposed; adequate to what is needed; enough', 'There is not sufficient access to the internet in many small rural villages.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('491839e1-d014-479a-b176-55e446f17b92', 'sufficiently', '(manner) In a sufficient manner; enough.', 'Once we had eaten and drunk sufficiently, we padded off to sleep.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4c24f5d2-60f7-47ef-82c4-d272dca6ab29', 'sum', 'A quantity obtained by addition or aggregation.', 'The sum of 3 and 4 is 7.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('fe2ba4c9-f9ca-4515-b1b1-41ca24b27f40', 'super', 'Of excellent quality, superfine.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('152be62c-d0d7-47a2-9170-78d7608b7e39', 'surgeon', 'One who performs surgery; a doctor who performs operations on people or animals.', 'The surgeon refused to operate because the patient was her son.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('db6bf2e6-f7c9-46df-8071-abda1df78514', 'surround', 'Anything, such as a fence or border, that surrounds something.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9d83759d-2f8e-47de-aab0-419654d3030a', 'surrounding', 'To encircle something or simultaneously extend in all directions.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('af05b6da-f1d0-4582-826d-9cd02203da1a', 'surveillance', 'Close observation of an individual or group; person or persons under suspicion.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('46282fad-029b-4463-9456-98b6d3cd5bc5', 'survival', 'The fact or act of surviving; continued existence or life.', 'His survival in the open ocean was a miracle; he had fully expected to die.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('5584b21e-0fd0-49d0-b615-72a782b51567', 'survivor', 'One who survives, especially one who survives a traumatic experience.', 'From this moment on, I choose to live not as a victim, but as a survivor.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('90f1285b-dd46-40e3-8cf6-8e225e53df05', 'suspect', 'A person who is suspected of something, in particular of committing a crime.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c0bd1e48-e0c5-4d33-aced-2a9b6161563d', 'suspend', 'To halt something temporarily.', 'The meeting was suspended for lunch.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4b4fe212-514d-4dcc-b2d4-f4b402781c0a', 'sustainability', 'The ability to sustain something.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('65bfe2d6-2d3d-4321-8a78-e672caf992af', 'sustainable', 'Able to be sustained.', '', 'Environment', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('fa2a5fbd-695f-4308-8443-121e8e216c90', 'swallow', 'A deep chasm or abyss in the earth.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d8e7c6f4-26c9-4d86-b9d3-85324f455d39', 'swear', 'To take an oath, to promise.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3972205c-7fc3-4076-a1d3-1b044d5c2209', 'sweep', 'A single action of sweeping.', 'Give the front steps a quick sweep to get rid of those fallen leaves.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0cf621f1-219e-4869-9f01-d096ebcdbbae', 'symbolism', 'Representation of a concept through symbols or underlying meanings of objects or qualities.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('92ca6b28-f30c-4f70-a047-b87144f89905', 'sympathetic', 'Of, related to, showing, or characterized by sympathy', 'John looked very upset. I gave him a sympathetic look.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4666f574-e32b-429e-8020-9963481cc299', 'sympathy', 'A feeling of pity or sorrow for the suffering or distress of another; compassion.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c6d17760-9acc-4e14-ab8a-ecc016fd3bb7', 'systematic', 'Carried out using a planned, ordered procedure.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3c3ab90e-821d-4bc2-acbe-452384add015', 'tackle', 'A device for grasping an object and an attached means of moving it, as a rope and hook.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a72c0254-f2ab-4033-bc2b-ce8f9dabf07f', 'tale', 'An account of an asserted fact or circumstance; a rumour; a report, especially an idle or malicious story; a piece of gossip or slander; a lie.', 'Don''t tell tales!', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1bc8d0ad-7559-4631-8d40-738887497af5', 'tank', 'A closed container for liquids or gases.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f31936d5-b0b4-44c9-9044-8521062df3c5', 'tap', 'A tapering cylindrical pin or peg used to stop the vent in a cask.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('5be270db-ffa3-4142-81b6-c0f1a68eeab5', 'tariff', 'A system of government-imposed duties levied on imported or exported goods; a list of such duties, or the duties themselves.', '', 'Business', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6d587e85-59af-4047-9faf-4a136ad0516e', 'tear', 'A hole or break caused by tearing.', 'A small tear is easy to mend, if it is on the seam.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2dcbc3a1-f1a4-4cff-9ff7-4cc9d8881e2a', 'technological', 'Of, relating to, or involving technology, especially modern scientific technology.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('cccd1356-7fa7-43d0-a849-3e4073dc3264', 'teens', 'A teenager.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('58a8293c-1790-4a02-a534-0289e325a5c6', 'temple', 'A house of worship, especially:', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d86681fb-0549-4fae-a97b-b582a9475b4d', 'temporarily', 'For a limited period of time; not permanently.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('44e9be83-f700-482e-bb59-9e8b910c0194', 'temporary', 'One serving for a limited time; short-term employee.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('cbbc9c66-44ab-4818-bd7b-39deefecd0b9', 'tendency', 'A likelihood of behaving in a particular way or going in a particular direction; a tending toward.', 'Denim has a tendency to fade.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('02c5cbe6-99fd-4329-a2b7-d4883cf1373e', 'tension', 'The condition of being held in a state between two or more forces, which are acting in opposition to each other.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('5a0a1b21-222a-4672-a02c-48d963fe18a3', 'terminal', 'A building in an airport where passengers transfer from ground transportation to the facilities that allow them to board airplanes.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f561c184-657b-44f6-bc26-f8325a534597', 'terms', 'That which limits the extent of anything; limit, extremity, bound, boundary.', '"Alright, look...we can spend the holidays with your parents, but this time it will be on my terms."', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1000e2ba-6182-4da1-a3c2-3695feb6589d', 'terribly', 'So as to cause terror or awe.', 'The lion roared terribly.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('31a925ce-9dad-4140-b4af-2bbaca3230d7', 'terrify', 'To frighten greatly; to fill with terror.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('596b7c1a-3363-45e2-9864-9e6d176c5230', 'territory', 'A large extent or tract of land; for example a region, country or district.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9751222b-3b50-42cd-808b-592f280d4d62', 'terror', 'Intense dread, fright, or fear.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('fc43aa1e-a37e-4c46-80ec-8798a42604c5', 'terrorism', 'The deliberate commission of an act of violence to create public fear through the suffering of the victims in the furtherance of a political or social agenda.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('deb57d74-9231-47da-acaa-06ab3704bbda', 'terrorist', 'A person, group, or organization that uses violent action, or the threat of violent action, to further political goals.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d32c9038-99d3-424e-83da-7bf2236cc919', 'testimony', 'Statements made by a witness in court.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7b649c03-76ef-48f0-b974-957719891146', 'testing', 'To challenge.', 'Climbing the mountain tested our stamina.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c26a4ca0-4c5b-4faf-8bf7-15732b42e843', 'textbook', 'A coursebook, a formal manual of instruction in a specific subject, especially one for use in schools or colleges.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('fbdc218a-9608-447c-ad6e-fd07b5baabc8', 'theft', 'The act of stealing property.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('58934afa-4c93-4385-8862-28b1e3f50631', 'theoretical', 'Of or relating to theory; abstract; not empirical.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('45862095-ad20-4d87-8ef5-da03c815ea12', 'therapist', 'Someone who provides therapy, usually professionally.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0f64260d-e793-4891-bd3b-e937513cf5ae', 'therapy', 'Attempted remediation of a health problem following a diagnosis, usually synonymous with treatment.', '', 'Health', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('13f1a81c-9971-4e52-ba8c-cab444bbd664', 'thesis', 'Senses relating to logic, rhetoric, etc.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ba213172-1e65-490a-8d94-b5835607298b', 'thorough', 'A furrow between two ridges, to drain off the surface water.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('10da23fc-37f6-48e0-8430-6d743cad820a', 'thoroughly', 'In a thorough or complete manner.', 'He went out in the rain and came back thoroughly drenched.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f4398902-1d48-4370-ba7a-a80e0d561a7c', 'threat', 'An expression of intent to injure or punish another.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('fddf483d-eadd-4323-a368-d8469cc45d04', 'threaten', 'To make a threat against someone; to use threats.', 'He threatened me with a knife.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2e068aea-7447-4cac-98ee-279db4606d8c', 'thumb', 'The short thick digit of the hand that for humans has the most mobility and can be made to oppose (moved to touch) all of the other fingers.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a1c880dd-2e92-4c8a-a480-d3125954d8e8', 'thus', '(manner) In this way or manner.', 'If you throw the ball thus, as I’m showing you, you’ll have better luck hitting the target.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('aec8b9d5-0175-4c9e-b852-21a29997321e', 'timing', 'To measure or record the time, duration, or rate of.', 'I used a stopwatch to time myself running around the block.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('5029fbfa-1ad9-48f4-b373-b479e8df91ce', 'tissue', 'Thin, woven, gauze-like fabric.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e3daed81-cc68-4aa4-bea6-797969d28fe6', 'tolerance', 'The ability to endure pain or hardship; endurance.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('cffc12e3-d846-4961-841e-66ddd2f3eda6', 'ton', 'A unit of weight (mass) equal to 2240 pounds (a long ton) or 2000 pounds (a short ton) or 1000 kilograms (a metric ton).', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('113a1cf2-2ab5-4e82-a0fd-131400e3a704', 'tone', 'A specific pitch.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('5677fa00-3ff5-46e7-928c-1af3980d11b6', 'tonne', 'A metric unit of mass equal to 1000 kilograms. Symbol: t', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8f4f1a64-e055-45e7-85dd-fa3f75197d91', 'tough', 'A person who obtains things by force; a thug or bully.', 'They were doing fine until they encountered a bunch of toughs from the opposition.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e8d030e6-d477-486b-a235-bda326241ee4', 'tournament', 'During the Middle Ages, a series of battles and other contests designed to prepare knights for war.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('cfd97547-d77b-48c8-87f0-188fd6f33110', 'trace', 'An act of tracing.', 'Your cell phone company can put a trace on your line.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('be440fd9-e6e6-4695-9977-c7138b10506f', 'trading', 'To engage in trade.', 'This company trades (in) precious metal.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ca0ef2e2-ade0-4ad4-8f92-9a033afc9b2f', 'tragedy', 'A drama or similar work, in which the main character is brought to ruin or otherwise suffers the extreme consequences of some tragic flaw or weakness of character.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('cad12e55-6e1f-404d-9114-7edf3b67ef0a', 'tragic', 'An obsessive fan, a superfan', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6a7709cf-26c6-4423-bd88-1d30eee981e1', 'trait', 'An identifying characteristic, habit or trend.', 'The number one personality trait I hate is hypocrisy. Why can''t you be consistent!?', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('70ecb1d6-9d1b-4315-87f4-505f99831e63', 'transfer', 'The act of conveying or removing something from one place, person or thing to another.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('81d8ec44-aac2-4011-a8f3-aeae96306aac', 'transform', 'An operation (often an integration) that converts one function into another.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('376afefa-c943-4e80-a264-922964351493', 'transition', 'The process of change from one form, state, style or place to another.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4b0f2d53-09b4-46bb-a79f-339bcb9cb27c', 'transmit', 'To send or convey something from one person, place or thing to another.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('eb4c01a5-c96b-4275-aa37-c1893629a9c2', 'transparency', 'The quality of being transparent; transparence.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('86fa7be8-99b0-489b-8395-5042ba339f30', 'transportation', 'The act of transporting, or the state of being transported; conveyance, often of people, goods etc.', 'We have to get people out of their cars and encourage them to use alternative forms of transportation.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8338d0a3-a6a9-4720-8f62-28dbfa4aafea', 'trap', 'A machine or other device designed to catch (and sometimes kill) animals, either by holding them in a container, or by catching hold of part of the body.', 'I put down some traps in my apartment to try and deal with the mouse problem.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('542e9d83-9498-4bfc-81a0-ba45dae74570', 'treasure', 'A collection of valuable things; accumulated wealth; a stock of money, jewels, etc.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4d5c2c2c-d60f-4ed8-8d4c-df051f6b3bce', 'treaty', 'A binding agreement concluded by subjects of international law, namely states and international organizations.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('723d20db-006a-4151-8c40-7e0d803e08a4', 'trial', 'An opportunity to test something out; a test.', 'They will perform the trials for the new equipment next week.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ab413bdf-8664-4cf3-b34f-108d20483a07', 'tribe', 'A socially, ethnically, or politically cohesive group of people.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('22954535-5e55-42d3-befa-b1e199a8ba4e', 'trigger', 'A finger-operated lever used to fire a gun.', 'Just pull the trigger.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('77492878-bc2b-41d9-9150-c542d68a6985', 'trillion', '(short scale) A million million: 1 followed by twelve zeros, 1012.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4956d21f-c66e-401b-adc5-d744ebf32ad1', 'troop', '(collective) A collection of people; a number; a multitude (in general).', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('31cd365a-ac6a-4c1e-8687-9e7866edc6e1', 'tropical', 'A tropical plant.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('cf8d2e97-e3a4-4029-b25e-11dd298b1161', 'truly', '(manner) In accordance with the facts; truthfully, accurately.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0fd5e9c9-cf5a-4391-86b9-81ea7884ab3c', 'trust', 'Confidence in or reliance on some person or quality.', 'He needs to regain her trust if he is ever going to win her back.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('bf16ebbe-7839-4e6a-8735-b1fca2484756', 'tsunami', 'A very large and destructive wave, generally caused by a tremendous disturbance in the ocean, such as an undersea earthquake or volcanic eruption. Tsunami are usually a series of waves, or wave train.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e409fa62-1258-4203-9b4d-6ccb04cb742e', 'tune', 'A melody.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('69f6751f-797b-4d8c-8c11-339cd0bc4c87', 'tunnel', 'An underground or underwater passage.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('fa72cecc-03b6-4b61-98ee-8aa56a15ea5b', 'ultimate', 'The most basic or fundamental of a set of things', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('47a789b5-011f-476c-92ce-bd28fe2e2a24', 'ultimately', 'Indicating the last item.', 'Firstly,… Secondly,… Ultimately,…', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('50d16cb5-4d46-4944-a889-fac2434fb2d2', 'unacceptable', 'Something that is not acceptable.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('60dfe082-8cc8-486d-8c2b-ba60fedc1c9e', 'uncertainty', 'Doubt; the condition of being uncertain or without conviction.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d4e968c9-ba57-41a8-9c98-4a9a7aacd7d5', 'unconscious', 'Unconscious mind', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('72a57d4b-3224-4439-beb3-c5d3d2bbffc8', 'undergo', 'To go or move under or beneath.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('487202e0-6d49-408b-95b3-84219d2bc841', 'undertake', 'To take upon oneself; to start, to embark on (a specific task etc.).', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('79540ada-8d01-47d2-beb7-4a24247b3a3d', 'unexpected', 'Not expected, anticipated or foreseen.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f52b699c-82cd-4917-9d82-35702d507a1c', 'unfold', 'In functional programming, a kind of higher-order function that is the opposite of a fold.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('195c8124-4599-4572-be98-ed7d1054d323', 'unfortunate', 'An unlucky person; one who has fallen into bad circumstances.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ea41946c-5d67-48b1-a41d-466c2fc6b4f9', 'unique', 'A thing without a like; something unequalled or unparallelled.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4b416a80-cbf0-4971-b4fb-f5a26be53059', 'unite', 'A British gold coin worth 20 shillings, first produced during the reign of King James I, and bearing a legend indicating the king''s intention of uniting the kingdoms of England and Scotland.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e715c128-9db8-4599-b6ed-ff2dae5d2a72', 'unity', 'Oneness; the state or fact of being one undivided entity.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1f8ba295-6beb-4eb5-b765-0560682602a4', 'universal', 'A characteristic or property that particular things have in common.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b9fe8ac9-44ba-48f6-9cd8-b3cf03af60b4', 'universe', 'Our universe, the sum of everything that exists in the cosmos, including time and space itself.', 'Powerful telescopes look far back into the distant reaches of the Universe.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8222eaa1-53f9-401d-98f7-8bff9a334785', 'unknown', 'To undo the process of knowing, to lose knowledge of something.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1e44778b-ad6d-4b0e-a87e-105a85abc8cd', 'upper', 'A stimulant, such as amphetamine, that increases energy and decreases appetite.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f1583165-4cb0-48ad-ab99-f7b7a4aa5b9d', 'upwards', 'Towards a higher place; towards what is above.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('802d668c-5043-4f73-8660-4d5288e6a7ef', 'urban', 'Related to the (or any) city.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('031835d2-ab44-4aa3-8bf9-da4e811fe051', 'urge', 'A strong desire; an itch to do something.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('287b5ff4-11da-4c0f-9b2e-d58e75e4df95', 'urgent', 'Requiring immediate attention.', 'An urgent appeal was sent out for assistance.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3b3a00dd-defc-4c7b-bc54-a84466d76517', 'usage', 'The manner or the amount of using; use.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3a60bb87-cff4-4483-a5d6-03e72ba3bc03', 'useless', 'Without use or possibility to be used.', 'This fork has prongs that are bent. It''s useless now.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8fbe20c4-6f6b-4c23-920a-ef22cc1472b7', 'vaccination', 'Inoculation with a vaccine, in order to protect from a particular disease or strain of disease.', '', 'Health', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('16d42b8f-3d21-432d-a099-683bf27db72c', 'valid', 'Well grounded or justifiable, pertinent.', 'I will believe him as soon as he offers a valid answer.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2c8e3e08-9f1c-42b4-8485-7bf50c76fb5e', 'variation', 'The act of varying; a partial change in the form, position, state, or qualities of a thing.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('06eee79b-feb2-4542-ab77-799eabe0e41c', 'vary', 'Alteration; change.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('06c92543-829c-48bd-ba2e-ea07bc13ea25', 'vast', 'A vast space.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ef7d3768-a164-4684-8b34-5c027c041391', 'vegetation', 'Plants, taken collectively.', 'There were large amounts of vegetation in the forest.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('074a9c4b-bc3b-4e1f-ae58-ad84608b2467', 'venture', 'A risky or daring undertaking or journey.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9c39accb-b7fe-4c31-9a42-19c613049242', 'venue', 'A theater, auditorium, arena, or other area designated for sporting or entertainment events.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('620a785e-5a73-408a-83a2-312f3158d94c', 'verdict', 'A decision on an issue of fact in a civil or criminal case or an inquest.', 'The jury returned a “not guilty” verdict.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('702b29dd-9d1e-4d34-b0ea-877ba9ee0f8d', 'verification', 'The act of verifying.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('07734ff0-dec3-41d5-91aa-325e628e7641', 'vertical', 'A vertex or zenith.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('000e6a36-ede8-4c41-b1eb-43274fc62ec0', 'via', 'A main road or highway, especially in ancient Rome. (Mainly used in set phrases, below.)', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('bce39c64-443c-469d-87d4-5fb1979b17c1', 'victory', 'An instance of having won a competition or battle or succeeded in an effort.', 'It was a great victory on the battlefield.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('53802893-1932-4fb8-9cae-e2cb50bf0df6', 'viewpoint', 'The position from which something is observed or considered; an angle, outlook or point of view.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b0f577a5-806f-44a0-8211-f9b2dcb6ea89', 'violation', 'The act or an instance of violating or the condition of being violated.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('89e38eea-6ca7-4ff2-b0c0-c2cc46aadb3f', 'violence', 'Extreme force.', 'The violence of the storm, fortunately, was more awesome than destructive.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('eff009c8-9e90-4ef1-936e-62a89a419d60', 'virtual', 'A virtual member function of a class.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('fe4042af-c9c4-4dab-96e9-aa77b701296b', 'visible', 'Able to be seen.', 'When the sun rises, the world becomes visible.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('701ba3b9-783f-44fc-b90f-e8d5b71a5801', 'vision', 'The sense or ability of sight.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('82e276ab-2a71-43c9-81f4-12e9638b7ac1', 'visual', 'Any element of something that depends on sight.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('85598ca4-1ead-4606-9092-9dd9fd72432e', 'vital', 'Relating to, or characteristic of life.', 'vital energies; vital functions; vital actions', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('28ab5eb8-e4d3-4474-935c-5d9316a56324', 'vitamin', 'Any of a specific group of organic compounds essential in small quantities for healthy human growth, metabolism, development, and body function; found in minute amounts in plant and animal foods or sometimes produced synthetically; deficiencies of specific vitamins produce specific disorders.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8698b361-c662-4e3d-abc7-c7dee133b3d3', 'volume', 'A three-dimensional measure of space that comprises a length, a width and a height. It is measured in units of cubic centimeters in metric, cubic inches or cubic feet in English measurement.', 'The room is 9x12x8, so its volume is 864 cubic feet.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('59cffe94-4d4a-40f2-a58c-4a5fa73d9d9a', 'voluntary', 'A short piece of music, often having improvisation, played on a solo instrument.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('56b90c33-0ea0-4c80-b9a3-3f913e45f48d', 'voting', 'To cast a vote; to assert a formalized choice in an election', 'Did you vote last month?', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('07106b62-df7b-4f62-a8c7-ce0695000ae2', 'wage', '(often in plural) An amount of money paid to a worker for a specified quantity of work, usually calculated on an hourly basis and expressed in an amount of money per hour.', 'Before her promotion, her wages were 20% less.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('82b8e03e-b184-45b3-99be-825447858410', 'wander', 'The act or instance of wandering.', 'to go for a wander in the park', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0bf3641e-d0dc-4ffe-8a84-7843e6ed26dd', 'warming', 'To make or keep warm.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6a23ef46-dd20-43d7-a2d6-55d54afbd845', 'weakness', 'The condition of being weak.', 'In a small number of horses, muscle weakness may progress to paralysis.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('645bd652-a877-4488-a223-1ed6815fd40a', 'wealth', 'Riches; valuable material possessions.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('79ee8801-9449-434c-adda-151316eabb28', 'wealthy', 'A rich person.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1e70868a-d11d-4e22-85ef-4ec631921117', 'weekly', 'A publication that is published once a week.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('96bffe9a-78e7-41ab-a2ac-d4cd4c47d331', 'weird', 'Fate; destiny; luck.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('406240de-7f85-4f2b-adf7-03b77f5bc286', 'welfare', 'Health, safety, happiness and prosperity; well-being in any respect.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ee999d29-592e-424e-bcb2-c4d185a5a308', 'wheat', 'Any of several cereal grains, of the genus Triticum, that yields flour as used in bakery.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9589dd7a-ce4b-4f88-bf3f-71654b709dbf', 'whereas', 'A clause, as in legal documents, stating whereas.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c97c76fe-481e-4c79-b5bd-3b7ba71b2b43', 'wherever', 'An emphatic form of where.', 'Wherever have you been all my life?', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ed8d8c74-883b-4755-bcbe-83a46870f29b', 'whisper', 'The act of speaking in a quiet voice, especially, without vibration of the vocal cords.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('89074d02-2e45-4e22-a151-38d80f61263c', 'whoever', '(interrogative) Who ever: an emphatic form of who.', 'Whoever thought up that stupid idea?', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6556f208-dacd-4439-8123-915bc55ca0b9', 'whom', '(interrogative) What person or people; which person or people.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('bab035a5-75fb-415b-a556-44f0995f4104', 'widely', 'In a wide manner; across a wide area.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('52bcd7de-249e-4ebe-bb52-b37eabf9d429', 'widespread', 'Affecting a large area (e.g. the entire land or body); broad in extent; widely diffused.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('97f31f94-da01-4e5f-bf9b-e8fe8445370d', 'wilderness', 'An unsettled and uncultivated tract of land in its natural state; a barren land; a wild or waste.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c08787d7-c6de-4f71-a5e6-53b1d62722a3', 'wildlife', 'Animals, plants, and fungi, not normally domesticated, often to the exclusion of plants, fungi, fish, insects and other invertebrates, and microscopic plants and animals; hence:', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('569416e0-ecb7-4e26-be34-752a2545d77c', 'willing', 'To wish, desire.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e43047d6-3afb-4c3e-b4d3-0ab5bddc6261', 'wire', 'Metal formed into a thin, even thread, now usually by being drawn through a hole in a steel die.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9dea4d57-c67b-4b5b-9fa7-8ecd71bde9c7', 'wisdom', 'An element of personal character that enables one to distinguish the wise from the unwise.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d2ef3597-bdd7-4e98-86da-96a833efe4ca', 'wise', 'To become wise.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b029b2b3-6557-4f01-b2ff-798ab49c152b', 'withdraw', 'To pull (something) back, aside, or away.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('27374740-86b7-48af-989d-8dadd6cf8052', 'witness', 'Attestation of a fact or event; testimony.', 'She can bear witness, since she was there at the time.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2b5ee783-bbe3-4dc0-bfe3-37de4e4ad8fb', 'workforce', 'All the workers employed by a specific organization or state, or on a specific project', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8ff9b267-9463-4a5e-8167-b1bcdc1db728', 'workplace', 'The place where someone works.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e58a9133-a367-4f4c-808d-963968cd4c59', 'workshop', 'A room, especially one which is not particularly large, used for manufacturing or other light industrial work.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1a002009-b3a7-47cf-a3d8-e6877bb5d9c1', 'worm', 'A generally tubular invertebrate of the annelid phylum; an earthworm.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('16f650f7-7d4e-4d7d-b74c-2bec9e6d8ec0', 'wound', 'An injury, such as a cut, stab, or tear, to a (usually external) part of the body.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e6dde1ed-b388-4255-b14a-b262f11004f2', 'wrap', 'To enclose (an object) completely in any flexible, thin material such as fabric or paper.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b1ddae53-5295-456a-ab65-bdbb4f659196', 'wrist', 'The complex joint between forearm bones, carpus, and metacarpals where the hand is attached to the arm; the carpus in a narrow sense.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d69f737d-f092-44b9-bb1c-2b4eb65b7394', 'zone', 'Each of the five regions of the earth''s surface into which it was divided by climatic differences, namely the torrid zone (between the tropics), two temperate zones (between the tropics and the polar circles), and two frigid zones (within the polar circles).', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('01db2fa1-d368-4b9e-bc1b-f4ebb49657f5', 'clew', 'A roughly spherical mass or body.', '', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('cdd64a41-b30b-4fb4-a3d5-43260294a42e', 'netherworld', 'The place to which one''s spirit descends upon death, conceived as below the surface of the earth.', 'In some religions, one''s soul departs to a netherworld, hell, instead of the heavens.', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('66ec38c5-5de4-436c-81ce-8b2d59089e6e', 'segment', 'A length of some object.', 'a segment of rope', 'General', 'B2');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('532e6a29-3214-441f-984a-4c944dc5374b', 'abolish', 'To end a law, system, institution, custom or practice.', 'Slavery was abolished in the nineteenth century.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b0abea75-c8e3-4414-b749-30ebc0557d05', 'abortion', 'The expulsion from the womb of a foetus or embryo before it is fully developed, with loss of the foetus; either naturally as a spontaneous abortion (now usually called a miscarriage), or deliberately as an induced abortion.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e9c06cd5-1de9-4dbe-8950-f88d5769558e', 'absence', 'A state of being away or withdrawn from a place or from companionship; the period of being away.', 'Absence makes the heart grow fonder.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('18ff95a8-1eb1-4cf3-b2f0-3d29770cc977', 'absent', '(with definite article) Something absent, especially absent people collectively; those who were or are not there.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('cbe4d0d8-1ef0-496e-9f8d-7d34f5a9df4a', 'absurd', 'An absurdity.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('11bba814-0fcb-4670-9b7f-a456dc564394', 'abundance', 'A large quantity; many.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('deaea64e-ea88-4456-861f-c10f15ce89a8', 'abuse', 'Improper treatment or usage; application to a wrong or bad purpose; an unjust, corrupt or wrongful practice or custom.', 'All abuse, whether physical, verbal, psychological or sexual, is bad.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d47ece02-2ddb-4571-af97-53794920eb8e', 'academy', '(usually capitalized) The garden where Plato taught.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a0e0f6f0-8592-4bbd-9e2c-510be988dbfb', 'accelerate', 'To cause to move faster; to quicken the motion of; to add to the speed of.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1031bf00-5c3a-44c9-b96b-6b6f59d422ba', 'acceptance', 'The act of accepting; a receiving of something offered, with acquiescence, approbation, or satisfaction; especially, favourable reception; approval.', 'the acceptance of a gift, office, doctrine, etc.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('317d1847-97ad-42df-9929-9496312fb804', 'accessible', 'Easy of access or approach.', 'an accessible town or mountain', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('499c251e-6ece-4869-b575-3d8ed69a60da', 'accomplishment', 'The act of accomplishing; completion; fulfilment.', 'the accomplishment of an enterprise, of a prophecy, etc', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4adbccb8-7b8c-46f6-af85-89c074bc74eb', 'accordance', 'Agreement; harmony; conformity; compliance.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2c21cd9c-4b34-4871-b37e-82c5b26656f7', 'humanity', 'Mankind; human beings as a group.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('27af32ad-1984-462c-a9a1-0d2af56d4884', 'accordingly', '(manner) Agreeably; correspondingly; suitably', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('98305ceb-66fc-4b23-8991-f668693cf750', 'accountable', 'Obliged, when called upon, to answer (for one’s deeds); answerable.', 'Every man is accountable to God for his conduct.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('fb4d9f91-9f16-45bb-9a37-3a281015daf9', 'accumulate', 'To heap up in a mass; to pile up; to collect or bring together (either literally or figuratively)', 'He wishes to accumulate a sum of money.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a0201d96-dc5e-43c2-9fef-996859eb727d', 'accumulation', 'The act of amassing or gathering, as into a pile.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a54cbd85-378e-4d07-b989-d1463470a683', 'accused', 'To find fault with, blame, censure', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a899863f-96aa-4e57-9808-d9e9027161a5', 'acre', 'An English unit of land area (symbol: a. or ac.) originally denoting a day''s plowing for a yoke of oxen, now standardized as 4,840 square yards or 4,046.86 square meters.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8b5a5d76-5de3-48a8-a8b5-b7bdd5501eda', 'activation', 'Making active and effective; bringing into a state of activity.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('437d6470-c2e4-492f-9528-efbb88a9e1c8', 'activist', 'One who is politically active in the role of a citizen; especially, one who campaigns for change.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e5d96687-f1d5-41ee-ade7-0cb40c756dc3', 'adaptation', 'The process of adapting something or becoming adapted to a situation; adjustment, modification.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8caf2896-4adb-4115-9438-d7776168f46d', 'adhere', 'To stick fast or cleave, as a glutinous substance does; to become joined or united.', 'wax adhered to his finger', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('621e88e5-06ca-4c92-8cfa-655cf290ea22', 'adjacent', 'Something that lies next to something else, especially the side of a right triangle that is neither the hypotenuse nor the opposite.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('77b55f49-c9e7-47d9-800e-95dc02b4b110', 'adjustment', 'The action of adjusting something', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0f97a157-06ca-4eab-9a94-8e94e2d7a629', 'administer', 'To cause to ingest (a drug), either by openly offering or through deceit.', 'We administered the medicine to our dog by mixing it in his food.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2900e814-0590-47fe-9145-7623541dcb2b', 'administrative', 'Of or relating to administering or administration.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2577c65c-cd31-4ab3-99de-cbec5f75611b', 'administrator', 'One who administers affairs; one who directs, manages, executes, or dispenses, whether in civil, judicial, political, or ecclesiastical affairs; a manager', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9a5650bf-d42e-49e7-91db-de24ba46ec20', 'admission', 'The act or practice of admitting.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('730bcfa4-8ac2-4b22-9668-0b849e4de474', 'adolescent', 'A person who is in adolescence; someone who has reached puberty but is not yet an adult.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('eb210b4d-4d06-4979-af9a-5dd81cd83502', 'adoption', 'The act of adopting.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4dfd04db-97d3-417e-8044-4e0eebd2d56d', 'adverse', 'Unfavorable; antagonistic in purpose or effect; hostile; actively opposing one''s interests or wishes; contrary to one''s welfare; acting against; working in an opposing direction.', 'adverse criticism', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('35ac75d9-954a-4a39-94fd-283fa1d37324', 'advocate', 'Someone whose job is to speak for someone''s case in a court of law; a counsel.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4df7e6f3-679d-4bc6-aa45-9b2d0ab7ad51', 'affection', 'The act of affecting or acting upon.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1224d1b7-fef2-4787-b765-e7dd3c5100fb', 'aftermath', 'A second mowing; the grass which grows after the first crop of hay in the same season.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('df0e863e-6e11-47c2-b9f0-e497f909f1a3', 'aggression', 'The act of initiating hostilities or invasion.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('076d8aea-5042-48f6-a5ce-1aab6ef7f343', 'agricultural', 'A product or commodity from agriculture.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3d109ed1-c9e7-4dde-b419-86061062a232', 'aide', 'An assistant.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0b39e28e-2870-49d9-bfca-d8ee1dd3e610', 'albeit', 'Although, despite (it) being.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c5ee0fc7-e522-4391-b983-4e3d4721a5a2', 'alert', 'An alarm.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3867caf5-f0ad-4974-97c0-312ebf2c2fc9', 'align', 'To form a line; to fall into line.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4df7cc43-ba4f-4bde-aee3-0c958769aaab', 'alignment', 'An arrangement of items in a line.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('cae9e05b-2a9d-4b44-aa3b-ee6a0c602d13', 'alike', 'Having resemblance or similitude; similar; without difference.', 'The twins were alike.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ef64a2ba-851c-4176-8939-cb3e4d4fe115', 'allege', 'To state under oath, to plead.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f32f72c3-4c8f-4aea-ac82-4031a272608c', 'allegedly', 'According to someone''s allegation.', 'The suspect was allegedly involved in the robbery, but his alibi placed him in another state at the time.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9b83b609-8593-425d-88d6-835e3dd354d2', 'alliance', 'The state of being allied.', 'matrimonial alliances; an alliance between church and state, or between two countries', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8a75815f-436c-479e-a284-9cc7f369de68', 'allocate', 'To set aside for a purpose.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('81d47ca0-e981-4eab-b8e2-4394150110aa', 'allocation', 'The process or procedure for allocating things, especially money or other resources.', 'The allocation of new permits is on a first-come, first-served basis.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1eeb02ad-402f-420b-ba02-d6514fd821bc', 'allowance', 'Permission; granting, conceding, or admitting', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('71b96275-10d7-4b51-a5c8-8476f709af31', 'ally', 'A person, group, or state (etc) which is associated with another for a common cause; one united to another by treaty or common purpose; a confederate.', 'the two countries were allies in WWI', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e91586f2-aca9-42e6-a9c3-172e9f5f1599', 'aluminium', 'A light, silvery metal extracted from bauxite, and a chemical element (symbol Al) with an atomic number of 13.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('14c5e18f-d6ce-48d3-8d94-376baf92bed8', 'amateur', 'A lover of something.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6b61eee7-709d-4c5d-8fba-49cd5b777f23', 'incidence', 'The act of something happening; occurrence.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c2a5de4e-2434-40b3-97c8-4236bfb5a00f', 'ambassador', 'A minister of the highest rank sent to a foreign court to represent there his sovereign or country. (Sometimes called ambassador-in-residence)', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8c0ae2e8-85ec-4d1a-9d23-f35f1833bcb5', 'amend', '(usually in the plural) An act of righting a wrong; compensation.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6464c925-08c1-4653-9c50-ee507a011f90', 'amendment', 'An alteration or change for the better; correction of a fault or of faults; reformation of life by quitting vices.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('33d7d6b5-bc9e-44fd-b861-77efb57c050a', 'amid', 'In the middle of; in the center of; surrounded by.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ab8a02a9-1dc3-4e55-b07a-dff64d1ba7cb', 'analogy', 'A relationship of resemblance or equivalence between two situations, people, or objects, especially when used as a basis for explanation or extrapolation.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ae87d7fd-6dc6-4330-a2a1-e0044ec98870', 'anchor', 'A tool used to moor a vessel to the bottom of a sea or river to resist movement.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d2dc01fd-1fca-4d74-a90d-afe1d963f02c', 'angel', 'An incorporeal and sometimes divine messenger from a deity, or other divine entity, often depicted in art as a youthful winged figure in flowing robes.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('bd8056fd-7e2f-40bb-a1e2-ff7b5655ad88', 'apparatus', 'The entirety of means whereby a specific production is made existent or task accomplished.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('298d7172-acd5-4806-a37b-10a63bdbc4e4', 'appealing', 'To call upon another to decide a question controverted, to corroborate a statement, to vindicate one''s rights, etc.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a7bdbe47-3e00-49e8-aef4-09a343166776', 'appetite', 'Desire to eat food or consume drink.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('574ed044-dbb8-42fd-9b64-3fd12f442255', 'applaud', 'Applause; applauding.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('105b6091-5b74-493c-b0dd-b9e77839d0c5', 'applicable', 'Suitable for application, relevant', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('90401989-cca9-4032-8a46-e7d85ec25189', 'appoint', 'To set, fix or determine (a time or place for something such as a meeting, or the meeting itself) by authority or agreement.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('558603ac-d26a-4c4d-b3d4-3cdca1e2405d', 'appreciation', 'A fair valuation or estimate of merit, worth, weight, etc.; recognition of excellence.', 'We give to you this trophy as a token of our appreciation of all your years of service.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ec9227d1-6320-4036-b4ff-7e9e3f57bb2c', 'arbitrary', 'Anything arbitrary, such as an arithmetical value or a fee.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a101865a-e52b-4c44-b29a-79a7dabd671c', 'architectural', 'Pertaining to architecture.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b831e766-02e5-4b6d-9259-d0f67ec012a9', 'archive', 'A place for storing earlier, and often historical, material. An archive usually contains documents (letters, records, newspapers, etc.) or other types of media kept for historical interest.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('432bec66-be4d-4575-8ff5-d71587d5e52e', 'arena', 'An enclosed area, often outdoor, for the presentation of sporting events (sports arena) or other spectacular events; earthen area, often oval, specifically for rodeos (North America) or circular area for bullfights (especially Hispanic America).', 'A large crowd filled the seats of the arena.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('18be57f7-9d65-4d6f-b3ec-7599470153ad', 'arguably', 'As can be supported or proven by sound logical deduction, evidence, and precedent.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d703025f-b7b7-4baf-a4f8-22bc8571513d', 'array', 'Clothing and ornamentation.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('798b2bf1-c362-4d10-9c0d-4ff8ac201f39', 'articulate', 'An animal of the subkingdom Articulata.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ceb3eece-a148-46d9-9068-6ec92e62f2b2', 'ash', 'The solid remains of a fire.', 'Ash from a fireplace can restore minerals to your garden''s soil.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('93ad0a85-0dd6-4bbf-a0d0-adb201743bcb', 'aspiration', 'The act of aspiring or ardently desiring; an ardent wish or desire, chiefly after what is elevated or spiritual (with common adjunct adpositions being to and of).', 'Morgan has an aspiration of winning the game.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('504281d6-7f46-4997-98e2-356912f7354d', 'aspire', 'To have a strong desire or ambition to achieve something.', 'He aspires to become a successful doctor.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('98e18313-fe8a-4f7b-9819-61a181521d10', 'assassination', 'The murder of a person, especially for political reasons or for personal gain.', 'The assassination of the king occurred at night.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b802cfb5-e05d-4ac3-a92c-01fe26a01be5', 'assault', 'A violent onset or attack with physical means, for example blows, weapons, etc.', 'to make assault upon a man, a house, or a town', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('80d90b19-bc82-490d-a01a-084023c9dbb9', 'assemble', 'To put together.', 'He assembled the model ship.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a8a8ed11-b81d-41fa-a2db-26e7dff92007', 'assembly', 'A set of pieces that work together in unison as a mechanism or device.', 'In order to change the bearing, you must first remove the gearbox assembly.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('983f1365-9eef-4cd5-9c4c-f2021449bcc9', 'assert', 'An assertion; a section of source code which tests whether an expected condition is true.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('58178ba2-fefa-40df-9c5c-c10896a3c53b', 'assertion', 'The act of asserting; positive declaration or averment.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f5dc7166-4134-4722-82ac-b468d08c5898', 'assurance', 'The act of assuring; a declaration tending to inspire full confidence; that which is designed to give confidence.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d527845f-1510-4aba-aa4b-eee7e98fe124', 'asylum', 'A place of safety.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3fd72d30-963d-4b37-a5b6-a74ac0de706d', 'atrocity', 'An extremely cruel act; a horrid act of injustice.', 'The regime is guilty of mass atrocities including forced displacement and the use of chemical weapons.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ccca8eb1-e05a-4931-bcb7-c186007c1ba0', 'attain', 'To gain (an object or desired result).', 'To attain such a high level of proficiency requires hours of practice each day.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2cea6101-8c2f-4b38-b460-7ccbccc48161', 'attendance', 'The state of attending; presence or waiting upon.', 'Attendance at the meeting is required.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9e5bc7a1-8e74-4052-adb6-7bae6397dc44', 'attorney', 'A lawyer; one who advises or represents others in legal matters as a profession.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e25cf2fb-876b-4da4-9d1c-24524f3e2768', 'attribute', 'A characteristic or quality of a thing.', 'His finest attribute is his kindness.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c00ef10c-548d-4e20-a9b3-128f371ea56d', 'audit', 'A judicial examination.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0dfd9023-1834-4245-9a02-d7c2d56bbdcd', 'authentic', 'Of the same origin as claimed; genuine.', 'The experts confirmed it was an authentic signature.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9f376fa2-ada0-45b5-8481-67bd4c1f9cde', 'authorize', 'To grant (someone) the permission or power necessary to do (something).', 'The General Assembly authorized the Council to take up the matter.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8d081664-e39d-46dd-8a40-95da53c66ed4', 'auto', 'An automobile.', 'My brother is an auto mechanic.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b832cf33-8c38-4f3e-81e8-3fddd0eeb4ae', 'autonomy', 'Self-government; freedom to act or function independently.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b357f766-9e5b-4eb2-a986-acd7086c6c4c', 'availability', 'The quality of being available.', 'What is your availability this week?', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('601dd9e9-d164-4831-b7d6-1a99ee1e15f9', 'await', 'A waiting for; ambush.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3a36539c-a754-48d7-91d0-c94666fe25d3', 'backdrop', 'A decorated cloth hung at the back of a stage.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('afa90b0d-0133-414c-bd4a-cbc22e9ac8ba', 'backing', 'To go in the reverse direction.', 'the train backed into the station;  the horse refuses to back', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f3affb96-e6e1-43c8-8d6d-ae92a54dee7e', 'backup', 'A reserve or substitute.', 'If the goalkeeper is injured, we have a backup.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8612fd58-db05-42de-b459-8a8e22f3ede1', 'bail', 'Security, usually a sum of money, exchanged for the release of an arrested person as a guarantee of that person''s appearance for trial.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b7fe7ea0-fcd5-4272-90e9-f466cd487130', 'ballot', 'Originally, a small ball placed in a container to cast a vote; now, by extension, a piece of paper or card used for this purpose, or some other means used to signify a vote.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('14246fd9-cc0b-4018-932b-26d287b3b036', 'banner', 'A flag or standard used by a military commander, monarch or nation.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('5cc65ffe-69ce-49cd-b14a-8092b481062c', 'bare', '(‘the bare’) The surface, the (bare) skin.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6f7e76b0-cb9d-433b-a72a-4a61f350d63b', 'barrel', 'A round vessel or cask, of greater length than breadth, and bulging in the middle, made of staves bound with hoops, and having flat ends or heads. Sometimes applied to a similar cylindrical container made of metal, usually called a drum.', 'a cracker barrel', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a4f12fe4-7e71-455a-bdef-c4679d24ec8c', 'bass', 'A low spectrum of sound tones.', 'Peter adjusted the equalizer on his audio equipment to emphasize the bass.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a9118b49-09da-4941-8bfb-990ef245a5c3', 'battlefield', 'The area where a land battle is or was fought, which is not necessarily a field.', '1886 The night of the 16th of May found McPherson''s command bivouacked from two to six miles west of the battlefield, along the line of the road to Vicksburg — Ulysses S. Grant, Personal memoirs of U.S. Grant, Chapter 35.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b897ef68-af84-4999-8ce8-844c398beb3e', 'bay', 'A berry.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('061dc60d-498c-4e12-83ef-c46e271667e3', 'beam', 'Any large piece of timber or iron long in proportion to its thickness, and prepared for use.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1908889e-832d-4201-9f3a-831cddb0d968', 'beast', 'Any animal other than a human; usually only applied to land vertebrates, especially large or dangerous four-footed ones.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c34efcdd-7b10-485f-9bbe-375786d5759a', 'beloved', 'To please.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('67b6e2b8-1f80-4150-9855-e3c712d382fe', 'bench', 'A long seat with or without a back, found for example in parks and schools.', 'They sat on a park bench and tossed bread crumbs to the ducks and pigeons.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ae1a5078-8e07-4af2-ab38-de88c3b1b47e', 'benchmark', 'A standard by which something is evaluated or measured.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('34bf3881-5a2e-4492-b393-ef8b3a68555d', 'beneath', 'Below or underneath.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f54a56a3-9f31-431e-a536-da4ea6c32072', 'beneficiary', 'One who benefits or receives an advantage.', 'You are the lucky beneficiary of this special offer.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1164f657-428b-4f72-93f1-e6a9c55535da', 'betray', 'To deliver into the hands of an enemy by treachery or fraud, in violation of trust; to give up treacherously or faithlessly.', 'an officer betrayed the city', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ddc8d3ec-2955-4a20-b4af-19f74b944339', 'bind', 'That which binds or ties.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('619677ad-b740-474a-be0b-ff0a2c721550', 'biography', 'A person''s life story, especially one published.', 'There are many biographies of Benjamin Franklin.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b10bf0b5-075e-4b5e-adf5-22ba019f21ae', 'bishop', 'An overseer of congregations: either any such overseer, generally speaking, or (in Eastern Orthodoxy, Catholicism, Anglicanism, etc.) an official in the church hierarchy (actively or nominally) governing a diocese, supervising the church''s priests, deacons, and property in its territory.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8b60e1a0-9129-448b-9b1d-f5701f688f60', 'bizarre', 'Strangely unconventional in style or appearance.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1fe3594a-70a6-4d76-b51e-27005a9eb366', 'blade', 'The sharp cutting edge of a knife, chisel, or other tool, a razor blade/sword.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c1bc2d7a-0ddc-4099-8011-da28bf0318b6', 'blast', 'A violent gust of wind.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0c82ed20-c04e-4e53-8a80-6251d78589b4', 'bleed', 'An incident of bleeding, as in haemophilia.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('cb76f18b-50e9-4efb-aaec-82d4f6d13f13', 'blend', 'A mixture of two or more things.', 'Our department has a good blend of experienced workers and young promise.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a70bdbdd-88d7-445d-89f5-de220fafa4e9', 'bless', 'To make something holy by religious rite, sanctify.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('52e0225f-1cab-469c-9376-89d67ca8e388', 'blessing', 'To make something holy by religious rite, sanctify.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('63f2468c-785f-4c42-8d83-56bbc63f6673', 'boast', 'A brag; ostentatious positive appraisal of oneself.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7473d8a9-8f5c-4780-843d-3bdd9bc11d77', 'bonus', 'Something extra that is good; an added benefit.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f613b8b4-69b4-4e41-b2e2-d8fd5547f1b0', 'boom', 'A low-pitched, resonant sound, such as of an explosion.', 'The boom of the surf.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f6e633af-f387-4d71-93aa-6cda97ef433e', 'bounce', 'A change of direction of motion after hitting the ground or an obstacle.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('70a159fe-291b-449c-ac97-1ba64ac15c2d', 'boundary', 'The dividing line or location between two areas.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('64a340df-88d5-4301-afa8-1fbe7c95243d', 'bow', 'A weapon made of a curved piece of wood or other flexible material whose ends are connected by a string, used for shooting arrows.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b036b95a-8a2c-48f2-ac05-7be0c4333337', 'breach', 'A gap or opening made by breaking or battering, as in a wall, fortification or levee / embankment; the space between the parts of a solid body rent by violence', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8017ead5-3dd6-41c1-964a-21a5bb6899a1', 'breakdown', 'A failure, particularly mechanical; something that has failed', 'We saw a breakdown by the side of the road.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6510cb69-f28b-47d4-9796-796eb5d34e35', 'breakthrough', 'An advance through and past enemy lines.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('87118e25-9b6d-44d1-800d-a203b6684e72', 'breed', 'All animals or plants of the same species or subspecies.', 'a breed of animal', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('66837c26-bf88-4d4c-a342-60a1b71d75db', 'broadband', 'A wide band of electromagnetic frequencies', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7b9305c4-aae4-46a0-841f-a77b7628c1d4', 'browser', 'A person or animal who browses.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('79f5c577-7172-4ae5-8c11-0c2e9ad1e1c2', 'brutal', 'Savagely violent, vicious, ruthless, or cruel', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2c8693ec-e4f0-47b3-a7b6-705abb88ddff', 'buck', 'A male deer, antelope, sheep, goat, rabbit, hare, and sometimes the male of other animals such as the hamster, ferret and shad.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f6fcace8-6422-4f37-8f3b-1cd7c45b912a', 'buddy', 'A friend or casual acquaintance.', 'They have been buddies since they were in school.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b150356f-b7eb-45d7-a8bb-26623e6854e9', 'buffer', 'Of the color of buff leather, a brownish yellow.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('94e63fbf-ff43-4e15-be3a-8fbb5c307798', 'bulk', 'Size, specifically, volume.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6087495d-445c-4205-8863-9ab611d6c79c', 'burden', 'A heavy load.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2a4269ab-a885-4ed6-a7e6-c6e3e7248343', 'burial', 'The act of burying; interment', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e4316fbf-1eb2-4d12-809f-7b04c09852b5', 'burst', 'An act or instance of bursting.', 'The bursts of the bombs could be heard miles away.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c259c11b-c47e-4191-886f-bab0d16d3e65', 'cabinet', 'A storage closet either separate from, or built into, a wall.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('5de8da1e-1a0a-4aba-a224-7aa058d9b391', 'calculation', 'The act or process of calculating.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b3972883-74f3-495a-95cb-2ba611dce904', 'canvas', 'A type of coarse cloth, woven from hemp, useful for making sails and tents or as a surface for paintings.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a30ff7d7-613f-4c91-a064-287569ec1fd4', 'capability', 'The power or ability to generate an outcome', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2896fa2e-af05-49b6-8364-72dac9e16ca0', 'capitalism', 'A socio-economic system based on private ownership of resources or capital.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('38ad2d5a-b09e-4745-a549-306315f61202', 'capitalist', 'A person who is a supporter of capitalism.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3d2c5e4a-2b12-49d8-bab8-07a294452a72', 'cargo', 'Freight carried by a ship, aircraft, or motor vehicle.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ee3d821b-5c0e-4914-b2d8-95e43c1f6085', 'carriage', 'The act of conveying; carrying.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a45eb02e-d82f-4fbd-b9b4-0dfbad255f5a', 'carve', 'A carucate.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('5eb95b7b-680d-45e4-9480-bf83942a2f5f', 'casino', 'A public building or room for entertainment, especially gambling.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('adc3d285-7ab1-411d-a147-fcb22918df4d', 'casualty', 'Something that happens by chance, especially an unfortunate event; an accident, a disaster.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a20965c0-8991-4925-ac81-c37b3c418740', 'catalogue', 'A systematic list of names, books, pictures etc.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('adb423ab-07cf-4103-9da8-bf8d99a8b7a7', 'cater', 'Caterer', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d818e0bf-ce8b-4b3c-a7d2-8ed6b2572081', 'cattle', 'Domesticated bovine animals (cows, bulls, steers etc).', 'Do you want to raise cattle?', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('cd4d8670-eeab-4fb4-a736-862f0d38eccb', 'caution', 'Precept or warning against evil or danger of any kind; exhortation to wariness; advice; injunction; prudence in regard to danger; provident care', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('35f915ea-7dc2-4e4e-903c-6ce7e8ed32c5', 'cautious', 'Careful; using or exercising caution; tentative', 'He took a few cautious steps toward the cave.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1472833d-c76e-4922-a1bf-5e652ad3bd5d', 'cease', 'Cessation; extinction (see without cease).', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('42819a4c-de1c-4b8b-9e91-93885866ee39', 'cemetery', 'A place where the dead are buried; a graveyard or memorial park.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ddad5281-1d93-499b-bbfd-cdae32ca0027', 'chamber', 'A room or set of rooms, particularly:', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('dba23701-0aec-4a84-830b-07dd13dd3ea1', 'chaos', 'The unordered state of matter in classical accounts of cosmogony.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('549fe01e-54b2-4994-8753-a6541b0eee24', 'characterize', 'To depict someone or something a particular way (often negative).', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4cce9290-f307-4314-9346-bfe96f4ba43b', 'charm', 'An object, act or words believed to have magic power (usually carries a positive connotation).', 'It works like a charm.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('fc33fb31-94d0-46ce-a3d3-68442e62a7fa', 'charter', 'A document issued by some authority, creating a public or private institution, and defining its purposes and privileges.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('80f44bf1-8d2a-4fc4-93b5-29d0a0edeaec', 'chunk', 'A part of something that has been separated.', 'The statue broke into chunks.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b935403d-f231-44ae-bc94-9e9a33b350f3', 'circulate', 'To move in circles or through a circuit', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('5e09c413-1fd7-41eb-b78f-dae04b7f9e57', 'circulation', 'The act of moving in a circle, or in a course which brings the moving body to the place where its motion began.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('99485dab-2210-4525-a596-af1d97c5d79e', 'citizenship', 'The status of being a citizen, in its various senses.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('91f26885-1217-4e7b-9bfb-a328769b4ae0', 'civic', 'Of, relating to, or belonging to a city, a citizen, or citizenship; municipal or civil.', 'Thousands of people came to the Civic Center to show off their civic pride.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('16c7c29e-fbb8-4cdd-aae9-21f7781bcc3d', 'civilian', 'A person following the pursuits of civil life, especially one who is not an active member of the armed forces.', 'Three civilians were apprehended by the soldiers and taken away in a military vehicle.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e6ddbc00-14d6-44fb-a7c3-d08f3178be39', 'clarity', 'The state or measure of being clear, either in appearance, thought or style; lucidity.', 'Lack of clarity on the part of the teacher will cause confusion among the students.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('010e8d14-c848-4ddb-a74c-c576b230a40a', 'clash', 'A loud sound, like the crashing together of metal objects.', 'I heard a clash from the kitchen, and rushed in to find the cat had knocked over some pots and pans.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2c4a75a0-fcd2-4ea4-802f-88b938790bb0', 'classification', 'The act of forming into a class or classes; a distribution into groups, as classes, orders, families, etc., according to some common relations or attributes.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('be81dbb0-1e68-4321-84d8-e63e7bfaa924', 'cling', 'Fruit (especially peach) whose flesh adheres strongly to the pit.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('941c1101-11d2-42f8-ad2d-476a2049d987', 'closure', 'An event or occurrence that signifies an ending.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('98e984af-7b3e-4c2b-8cda-90c25a7a5cad', 'cluster', 'A group or bunch of several discrete items that are close to each other.', 'A cluster of flowers grew in the pot.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('678dd1c0-977c-4a09-bc39-e2f618a5a7b2', 'coalition', 'A temporary group or union of organizations, usually formed for a particular advantage.', 'The Liberal Democrats and Conservative parties formed a coalition government in 2010.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('26e1d83e-3d68-45f5-8528-30a1477d5a46', 'coastal', 'Relating to the coast; on or near the coast, as a coastal town, a coastal breeze', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('5696626e-5761-4128-852a-7cd3879e4e62', 'cocktail', 'A mixed alcoholic beverage.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9b42797f-3cba-4cce-ac74-4c2bc5a5d384', 'cognitive', 'Cognate.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('263b85c1-e244-46f2-930a-d3ea8cc38a87', 'coincide', 'To occupy exactly the same space.', 'The two squares coincide nicely.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('452c17e3-d3d5-488c-ad38-4e23aceb6f43', 'collaborate', 'To work together with others to achieve a common goal.', 'Let''s collaborate on this project, and get it finished faster.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('20ac1b1c-cd74-4e13-acc5-6ef94b2d935f', 'collaboration', 'The act of collaborating.', 'Collaboration can be a useful part of the creative process.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0da0a9fb-ad0e-444f-8049-e5d0ea6a0f9a', 'collective', 'A farm owned by a collection of people', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('be6267c8-70a6-4e8d-a226-c72894b62869', 'collision', 'An instance of colliding.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('921d1f19-7a6b-43d9-885b-b18b93b4c5fe', 'colonial', 'A person from a country that is or was controlled by another.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('af6093bf-b9cc-420c-b734-4521d933bf00', 'columnist', 'A regular writer of a column, such as in a magazine or newspaper', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c2bd764e-c93f-48b1-bdae-f19c274d2530', 'combat', 'A battle, a fight (often one in which weapons are used).', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('04374af5-7d9e-4b24-b9c2-7181a78da646', 'commence', 'To begin, start.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('00607206-ccad-4e0f-b94d-c257d96f8456', 'commentary', 'A series of comments or annotations; especially, a book of explanations or expositions on the whole or a part of some other work', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2e55b980-e4f2-46fd-ba77-2aadd9404c86', 'commentator', 'A person who comments; especially someone who is paid to give his/her opinions in the media about current affairs, sports, etc.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('cf3dd01f-1226-4b0c-b295-aa72bb1b1fb5', 'commerce', 'The exchange or buying and selling of commodities; especially the exchange of merchandise, on a large scale, between different places or communities; extended trade or traffic.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('279cdc9e-ceb9-4ae9-95d4-6c131646c8c6', 'commissioner', 'A member of a commission.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0d7b8d22-e765-49cb-96c5-22f1c2e5ef1e', 'communist', 'An advocate of a society based on the common ownership of property; a proponent of communism.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('da2c749c-55ff-4b80-a920-fd986acaed71', 'companion', 'A friend, acquaintance, or partner; someone with whom one spends time or keeps company', 'His dog has been his trusted companion for the last five years.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('71018edf-5cc2-457f-a15e-72e43e7a2a50', 'comparable', 'Something suitable for comparison.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a31106e6-ef87-404d-a9b8-3b4693bcddd8', 'compel', 'To drive together, round up', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c5052ce8-ea36-49f9-a933-12d8c914ea6c', 'compelling', 'To drive together, round up', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b86c3135-21cd-4d4b-ad84-622aaf24e7cf', 'compensate', 'To do (something good) after (something bad) happens', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('929a2518-c57f-4ce6-82bb-bcb15404aa76', 'compensation', 'The act or principle of compensating.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8f25bbd0-f895-412c-8d26-dd7f0db3095a', 'competence', 'The quality or state of being competent, i.e. able or suitable for a general role.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('abbf94e1-696e-4e00-9474-02eefad638d7', 'competent', 'Having sufficient skill, knowledge, ability, or qualifications.', 'He is a competent skier and an expert snowboarder.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('34ad108f-d76d-4ff4-83ef-efda9c0b8efc', 'compile', 'An act of compiling code.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('807d3d4f-175a-4a21-aa43-aef37dfd4389', 'complement', 'A protective substance that exists in the serum or other bodily fluid and is capable of killing microorganisms; complement.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b95cc15a-dbbc-4d6a-9961-e675ac23e689', 'complexity', 'The state of being complex; intricacy; entanglement.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('5494d52f-8020-435a-86f0-eef070e694cf', 'compliance', 'An act of complying.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f5b00a35-b226-46a4-97d4-0d3856741870', 'complication', 'The act or process of complicating.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8faac6a9-5bcf-4221-94ac-600029a9ea24', 'comply', 'To yield assent; to accord; to acquiesce, agree, consent; to adapt oneself, to conform.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2d433f96-3d57-4ed6-b07c-242fdac04320', 'composition', 'The act of putting together; assembly.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f89f129a-d85b-48ef-b3ed-49305a8f87f9', 'compromise', 'The settlement of differences by arbitration or by consent reached by mutual concessions.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6b02bd9c-6532-40de-bd4d-19f5934bdb00', 'compute', 'Computational power', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('20783e60-f4ef-452a-ba4a-e49948451132', 'conceal', 'To hide something from view or from public knowledge, to try to keep something secret.', 'He tried to conceal the truth about his health.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7f08c59d-aa49-48d4-a066-25338848f776', 'concede', 'To yield or suffer; to surrender; to grant', 'He conceded the race once it was clear he could not win.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f6d90721-5f96-4e16-8ce9-5a614457c84a', 'conceive', 'To develop an idea; to form in the mind; to plan; to devise; to originate.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0dca1e1f-7e13-48a2-8692-f3437f123ded', 'conception', 'The act of conceiving.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c28c6cc5-7072-496b-8a61-b10cd8ec3ef6', 'concession', 'The act of conceding.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ba4e11f0-5bdb-4114-84cc-558c446b0fe4', 'condemn', 'To strongly criticise or denounce; to excoriate the perpetrators of.', 'The president condemned the terrorists.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ce0ec173-4081-434c-8482-670640c7a963', 'confer', 'To grant as a possession; to bestow.', 'The college has conferred an honorary degree upon the visiting Prime Minister.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e6e3e014-8647-42c3-89cd-477ae16e67e3', 'confession', 'The open admittance of having done something (especially something bad).', 'Without the real murderer''s confession, an innocent person will go to jail.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2f8bf2fb-9a78-4d9b-9071-09d3c7379bf3', 'configuration', 'Form, as depending on the relative disposition of the parts of a thing''s shape; figure; form factor.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c7a5ecd1-965c-4119-8667-0fb3ecd52151', 'confine', '(chiefly in the plural) A boundary or limit.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('92988ed2-a2c2-4505-8304-1717adcf7788', 'confirmation', 'An official indicator that things will happen as planned.', 'We will send you a written confirmation of your hotel booking.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('bbbee637-dd32-4942-b0ca-02bf11b17547', 'confront', 'To stand or meet facing, especially in competition, hostility or defiance; to come face to face with', 'We should confront him about the missing money.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2a9f8ac2-f468-4a82-b35b-4a8e2c8ca44b', 'confrontation', 'The act of confronting or challenging another, especially face to face.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b6da44dc-fa54-4664-98ec-17dfe2d280c9', 'congratulate', 'To express one’s sympathetic pleasure or joy to the person(s) it is felt for.', 'Remind me to congratulate Dave and Lisa on their wedding.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ec81cc74-a305-40b7-bf63-0b4150bd0d2f', 'congregation', 'The act of congregating or collecting together.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1e71586b-ef4e-4f63-b9dc-cecf0da30839', 'congressional', 'Of or pertaining to a congress.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('97f0e362-476d-4f3d-a2dc-8ffe088ffa1c', 'conquer', 'To defeat in combat; to subjugate.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d63b2801-c461-4d95-b786-cc8d6e34c681', 'conscience', 'The moral sense of right and wrong, chiefly as it affects one''s own behaviour.', 'Your conscience is your highest authority.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f1b896c5-4704-450c-b1cd-3244072d422b', 'consecutive', 'A sequence of notes or chords that results from repeated shifts in pitch of the same interval.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('5e1e3f7b-5942-442c-afb4-ac1c3b08f9cb', 'consensus', 'A process of decision-making that seeks widespread agreement among group members.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4365d993-c2e3-4d53-9ab4-0a37625f6cd4', 'conserve', 'Wilderness where human development is prohibited.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f86319fb-3884-479e-a620-3d2d31815796', 'consistency', 'Local coherence.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8a9514f4-7cca-4fee-a4a7-a353ca90b283', 'consolidate', 'To combine into a single unit; to group together or join.', 'He consolidated his luggage into a single large bag.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ef324f1c-c55d-411c-b0d1-a04c79e9a392', 'constituency', 'A district represented by one or more elected officials.', 'John was elected to parliament from the Bedford constituency.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('bc05e00d-823f-472f-ae17-c9d9641d45d2', 'constitute', 'An established law.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ccba6508-2a7d-4188-b3fd-b3e0152df2ac', 'constitutional', 'A walk that is taken regularly for good health and wellbeing.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('fa065471-c7b7-4c8b-935b-0fb4c2ef1b71', 'constraint', 'Something that constrains; a restriction.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6be5e21b-9037-4f86-b85e-32e9eb8685e7', 'consultation', 'The act of consulting.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('92c09efd-0295-42ba-bbfa-9085b36ca1fa', 'contemplate', 'To look at on all sides or in all its aspects; to view or consider with continued attention; to regard with deliberate care; to meditate on; to study, ponder, or consider.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6f08e543-a5fc-48ac-a440-61633bb26f9a', 'contempt', 'The state or act of contemning; the feeling or attitude of regarding someone or something as inferior, base, or worthless; scorn, disdain.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('bf8d9f11-3d8c-493a-a58d-aefc862eb103', 'contend', 'To strive in opposition; to contest; to dispute; to vie; to quarrel; to fight.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('157979a1-1416-44b1-a7c6-1d99f137f1ea', 'contender', 'Someone who competes with one or more other people.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('75bcabba-9769-434b-8ac5-ba4d33b54435', 'contention', 'Argument, contest, debate, strife, struggle.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('eb4e589b-1e48-40a1-919b-7239133fcf39', 'continually', 'In a continual manner; non-stop.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('49f4aefa-fb0b-4a9f-9ab9-e0868f211b11', 'contractor', 'A person or company that builds or improves buildings.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('90dc9d3a-a05f-4f9b-a2d7-ef62728932bb', 'contradiction', 'The act of contradicting.', 'His contradiction of the proposal was very interesting.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('afa7ba60-1f47-42c1-9260-b58bf28d2d19', 'contrary', 'The opposite.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d355173f-efd7-45e9-85f6-6630790d1d3d', 'contributor', 'A benefactor; someone who donates to charity or some cause.', 'I am a longstanding financial contributor to Amnesty International.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1201e094-6422-4536-b623-28cc1740c900', 'conversion', 'The act of converting something or someone.', 'His conversion to Christianity', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6a71fb13-9ce6-4829-9c9f-56314b635ad3', 'convict', 'A person convicted of a crime by a judicial body.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8806ec6c-1ddb-49b1-a663-406e6f2d45c0', 'conviction', 'A firmly held belief.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7d54d9af-899d-4276-a0c8-3c614a8745be', 'cooperate', 'To work or act together, especially for a common purpose or benefit.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d83add36-918a-4293-b1de-aa7887fda8ab', 'cooperative', 'A type of company that is owned partially or wholly by its employees, customers or tenants.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e59fd1d0-a27e-4c1c-ad2d-779e42405239', 'intent', 'A purpose; something that is intended.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('638080f4-b674-45f5-ba13-cdf5754b1ddd', 'coordinate', 'A number representing the position of a point along a line, arc, or similar one-dimensional figure.', 'Give me your coordinates and we''ll come and rescue you.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4612cfea-03c7-4cb5-bcbf-8e526deaf747', 'coordination', 'The act of coordinating, making different people or things work together for a goal or effect.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('983ab197-a7dc-4df4-902c-52834620079c', 'coordinator', 'One who coordinates.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('926dfdeb-2b9b-4f70-82df-54ae96d99940', 'cop', 'A spider.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d1dba6c4-e8a9-4838-9c02-141901b61117', 'copper', 'A reddish-brown, malleable, ductile metallic element with high electrical and thermal conductivity, symbol Cu, and atomic number 29.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d5677598-e07e-45c2-8ab5-39bb1c2fe0c8', 'copyright', 'The right by law to be the entity which determines who may publish, copy and distribute a piece of writing, music, picture or other work of authorship.', 'Copyright is a separate legal area from trademarks.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('243ee924-251a-4c2c-9ce5-fbe4e590085a', 'correction', 'The act of correcting.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4cc86fe1-d83e-4ffd-b174-cc1f6de3df7f', 'correlate', 'Either of a pair of things related by a correlation; a correlative.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('96f1dd56-ac5e-4c67-8be8-e317e502e7ce', 'correlation', 'A reciprocal, parallel or complementary relationship between two or more comparable objects.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d4788875-17e0-43bd-90e6-d789f112a728', 'correspond', '(constructed with to) To be equivalent or similar in character, quantity, quality, origin, structure, function etc.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b9c0eb27-80a2-4573-a3a6-a413c249450b', 'correspondence', 'Friendly discussion.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7d46a478-b0bb-43af-8668-7b47e1b93540', 'correspondent', 'Someone who or something which corresponds.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('766c535d-0c35-4f7c-9f2b-d62c1a9341ec', 'corresponding', '(constructed with to) To be equivalent or similar in character, quantity, quality, origin, structure, function etc.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c5625aa0-6ff9-4fcc-aa6c-6ed51de3cf6d', 'corrupt', 'To make corrupt; to change from good to bad; to draw away from the right path; to deprave; to pervert.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2883fa40-3e86-48ed-914a-c071e6b5fbd1', 'costly', 'Of high cost; expensive.', 'a costly activity', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('5f31216d-b384-4a6c-a0ed-c69ee86f48bf', 'councillor', 'A member of a council.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('85dfe6e8-7878-4900-b106-a27c04668d3b', 'counselling', 'To give advice, especially professional advice, to (somebody).', 'Psychiatrists, psychologists, social workers and other mental health professionals counsel clients.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d0eacce2-2ef1-40b8-af47-3075f6d5d627', 'counsellor', 'A professional who counsels people, especially on personal problems.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c9c21420-814c-4513-9e13-8a4a9ea16195', 'counterpart', 'Either of two parts that fit together, or complement one another.', 'Those brass knobs and their hollow counterparts interlock perfectly', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('fbdb7d30-039a-4211-af57-91c3ba02decf', 'countless', 'Too many to count; innumerable or incalculable', 'There is a countless number of stars.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e6daab33-fd56-4752-ab97-e2a966e5873d', 'coup', 'A quick, brilliant, and highly successful act.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ef33253e-c153-4617-8fbc-614fa5fe3012', 'courtesy', 'Polite behavior.', 'He was always known for his grace, kindness, and courtesy to people of every rank.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6436ca99-8eb2-422f-9653-d640bb3d9f9d', 'crawl', 'The act of moving slowly on hands and knees etc, or with frequent stops.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8d0e5c60-282f-40e8-919a-dd9b9a33ddc6', 'creator', 'Something or someone which creates or makes something.', 'Kenneth E. Iverson was the creator of APL.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('fb19ae9b-f081-457f-867b-a72186158cb9', 'credible', 'Believable or plausible.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e8f60c1f-7aef-4e20-a990-184edc06677c', 'creep', 'To move slowly with the abdomen close to the ground.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('44c71d48-8dbd-4f6b-8574-279ece7d947e', 'critique', 'The art of criticism.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b3fd0438-2a66-4fa2-adad-28520cfd906b', 'crown', 'A royal, imperial or princely headdress; a diadem.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('457b400c-fb1b-4de8-a76e-4bb8aa1f91b6', 'crude', 'Any substance in its natural state.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4b9ea646-2544-4303-9bae-0b468fe0fbfc', 'crush', 'A violent collision or compression; a crash; destruction; ruin.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0c110498-a49c-4269-af11-421f506c3d3a', 'crystal', 'A solid composed of an array of atoms or molecules possessing long-range order and arranged in a pattern which is periodic in three dimensions.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0a430916-c0b9-477d-bf67-5799155a3f15', 'cult', 'A group or sect of people with a deviant religious, philosophical or cultural identity, often existing on the margins of society or exploitative towards its members.', 'Oh my gosh, I''m in a repressive cult! How can I leave it?', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0ca9850d-3823-4425-8439-5fc58694d089', 'cultivate', 'To grow plants, notably crops', 'Most farmers in this region cultivate maize.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('823d1c0c-7e3a-4815-a307-e3384785681c', 'curiosity', '(uncountable) Inquisitiveness; the tendency to ask and learn about things by asking questions, investigating, or exploring.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('31115dfb-63df-439b-963e-95a352da29d6', 'custody', 'The legal right to take care of something or somebody, especially children.', 'The court awarded custody to the child''s father.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f65a1aa7-330d-4b94-aa73-9b1ddb061ce0', 'cutting', '(heading) To incise, to cut into the surface of something.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('5a022b00-8ec9-490d-9aee-d7268e293e0b', 'cynical', 'Of or relating to the belief that human actions are motivated only or primarily by base desires or selfishness.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('203dce77-8f46-4da5-9d2f-f78ea12f2a77', 'dam', 'A structure placed across a flowing body of water to stop the flow or part of the flow, generally for purposes such as retaining or diverting some of the water or retarding the release of accumulated water to avoid abrupt flooding.', 'A dam is often an essential source of water to farmers of hilly country.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('330e1427-8d97-44bf-a4cf-f0c0ce0340d5', 'damaging', 'To impair the soundness, goodness, or value of; to harm or cause destruction.', 'Be careful not to damage any of the fragile items while unpacking them.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('bf1b47a5-86ad-4dc0-94c6-a8b626bc7621', 'dawn', 'The morning twilight period immediately before sunrise.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f7af09fd-0610-44d6-89d7-5850dc748531', 'debris', 'Rubble, wreckage, scattered remains of something destroyed.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ce8d733d-79f4-4cba-a691-30d3fa588119', 'debut', 'A performer''s first performance to the public, in sport, the arts or some other area.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('95ab1e53-2188-4e3e-8667-292df57ae8a6', 'decision-making', 'The process of reaching a decision.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e9dc2657-7134-407e-bf21-3a4c10cccb06', 'decisive', 'Having the power or quality of deciding a question or controversy; putting an end to contest or controversy; final; conclusive.', 'A decisive battle is fatal for one side''s war chances', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7620a32f-572e-4634-9405-81a6ea907e9d', 'declaration', 'A written or oral indication of a fact, opinion, or belief.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f6a2bc66-0e30-4675-a1c2-204bf346db46', 'dedicated', 'To set apart for a deity or for religious purposes; consecrate.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('69d87c4e-fe02-49af-acf4-95e56cf94b8d', 'dedication', 'The act of dedicating or the state of being dedicated.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('bffc6ec8-e0c5-4c8b-bd25-aee0e7a3be19', 'deed', 'An action or act; something that is done.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('020d9faa-940d-4abc-8589-5b4168a2389a', 'deem', 'An opinion, a judgment, a surmise.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('76b41b8c-a749-48d0-ad16-ff60b995763f', 'default', 'The condition of failing to meet an obligation.', 'He failed to make payments on time and is now in default.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d68404c0-facc-46fb-9713-007d0022535d', 'defect', 'A fault or malfunction.', 'a defect in the ear or eye; a defect in timber or iron; a defect of memory or judgment', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c8ebf6b8-f727-402c-99e0-307cd2882727', 'defensive', 'A means, attitude or position of defense.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('42f7f036-63f3-4c70-9399-7794b0385063', 'deficiency', 'Inadequacy or incompleteness.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b1b78dfe-91d0-4445-aa25-2e0b5c5fe28e', 'deficit', 'Deficiency in amount or quality; a falling short; lack.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('90a9c761-4b96-4cb6-beff-5bb1f67105de', 'defy', 'A challenge.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1b1fb1a5-193c-41c2-96d7-2a9ebea0ca42', 'delegate', 'A person authorized to act as representative for another; a deputy', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('5fa4b5e4-c0b0-4527-bdb8-a9bc80c300d1', 'delegation', 'An act of delegating.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e8187b2d-c3a1-4b85-8cd7-4e8e476bec33', 'delicate', 'A delicate item of clothing, especially underwear or lingerie.', 'Don''t put that in with your jeans: it''s a delicate!', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('86c2400c-ab92-45ef-ab35-0f77c3177b70', 'demon', 'An evil supernatural spirit.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2755c79d-955c-48dd-9dd9-81c0881662fd', 'denial', 'The negation in logic.', 'The denial of "There might be X" is the null, "False, there is no X."', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4935cab7-18f9-4562-a338-29d31decc99c', 'denounce', 'To make known in a formal manner; to proclaim; to announce; to declare.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4eac2fba-1337-4c5b-ad3e-255dbc7200ae', 'dense', 'A thicket.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d658e166-f731-4a86-b858-5d3c52cbd975', 'density', 'A measure of the mass of matter contained by a unit volume.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('894033cb-dafe-45a3-964b-0c6de37afa6e', 'dependence', 'The state of being dependent, of relying upon another.', 'He had a deep dependence on her for guidance.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('634d4084-a5c5-4174-ba1c-e92972125b99', 'depict', 'To render a representation of something, using words, sounds, images, or other means.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('506fbaaf-e324-4402-b9bc-e5e7cb8a3427', 'deploy', 'Deployment', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3978699f-9fc1-47a8-943d-7723297c829a', 'deployment', 'An arrangement or classification of things.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a986d441-90ce-4abb-84fd-53dcc3daf4e5', 'deprive', 'To take something away from (someone) and keep it away; to deny someone something.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('39cab311-e6ea-4205-b5f9-602cebc5d4fb', 'deputy', 'One appointed as the substitute of another, and empowered to act for them, in their name or their behalf; a substitute in office', 'As the deputy store manager, he is able to fire staff.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('34e9e241-12d7-42a6-baea-6cb7a6830d6b', 'descend', 'To pass from a higher to a lower place; to move downwards; to come or go down in any way, for example by falling, flowing, walking, climbing etc.', 'The rain descended, and the floods came.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2df69ca3-e234-4bf0-a4e7-c942290da0cc', 'descent', 'An instance of descending; act of coming down.', 'We climbed the mountain with difficulty, but the descent was easier.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d7d55358-e8ba-481c-b83c-73aa8fdd2e58', 'designate', 'To mark out and make known; to point out; to indicate; to show; to distinguish by marks or description', 'to designate the boundaries of a country', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('60864128-b5ca-416a-9616-28c7282ddaf8', 'desirable', 'A thing that people want; something that is desirable.', 'There are plenty of desirables on display in the window.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4cc42d3f-75c2-45e7-8cf2-559eac845316', 'desktop', 'The top surface of a desk.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('bbcc4839-5fc6-42f5-ac17-85602ceaec82', 'destructive', 'Causing destruction; damaging.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1038cc4b-1b25-4c36-b5f8-8a26acb4c97a', 'detain', 'To keep someone from proceeding by holding them back or making claims on their attention.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('449c6243-c8d1-4e56-9f74-1db7cca2066a', 'detection', 'The act of detecting or sensing something; discovering something that was hidden or disguised.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('00b4e247-0a71-4693-8257-6fea21a4facc', 'detention', 'The act of detaining or the state of being detained.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('cd92b258-a455-42fc-ae84-b034ff6951d1', 'deteriorate', 'To make worse; to make inferior in quality or value; to impair.', 'to deteriorate the mind', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('97a02be1-96c2-4c39-afa9-26335eca9916', 'devastate', 'To ruin many or all things over a large area, such as most or all buildings of a city, or cities of a region, or trees of a forest.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d51d77f4-cee7-4c17-aead-e4b4e5896d97', 'devil', 'An evil creature.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('de873aff-cfad-479c-ac2d-d564f6780a67', 'devise', 'The act of leaving real property in a will.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('49b360d1-0587-4bfa-81fb-98eeb1c8e959', 'diagnose', 'To determine which disease is causing a sick person''s signs and symptoms; to find the diagnosis.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b58c6ce9-5302-433c-957f-2e029e75b3f4', 'dictate', 'An order or command.', 'I must obey the dictates of my conscience.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e14ea8e8-1fe0-4b39-afba-33b89343248e', 'dictator', 'A totalitarian leader of a country, nation, or government.', 'Dictators are always punished eventually.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('cffeeaaa-3e1d-4a02-bdb8-5e52940c504a', 'differentiate', 'Something that has been differentiated or stratified.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('21176314-e737-4ba2-ab9f-ade42bc771f5', 'dignity', 'The state of being dignified or worthy of esteem: elevation of mind or character.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0affbbda-1274-4824-b5b3-5bc8399ebd6c', 'dimension', 'A single aspect of a given thing.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('573817ac-1d7c-49b6-ac78-faea4a3b7021', 'diminish', 'To make smaller.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ae8819bd-7976-40e3-b660-0d80697f0d1c', 'dip', 'A lower section of a road or geological feature.', 'There is a dip in the road ahead.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('139d6bdc-77dc-4121-ac06-399495ea1ef4', 'diplomat', 'A person, such as an ambassador, who is accredited to represent a government officially in its relations with other governments or international organisations', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('08a50291-8fcf-45ce-b607-67f7dad75b5d', 'diplomatic', 'The science of diplomas, or the art of deciphering ancient writings and determining their age, authenticity, etc.; paleography.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d90cec2f-039f-4026-a6df-c7f771cf1a44', 'directory', 'A list of names, addresses etc, of specific classes of people or organizations, often in alphabetical order or in some classification.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('31f7969f-78af-4de8-ac06-a0280ebc2f21', 'disastrous', 'Of the nature of a disaster; calamitous.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a8310a0a-be28-433a-bb55-ebfaff03813c', 'discard', 'Anything discarded.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c5e3da94-e0ab-4b7b-9223-48f88f442215', 'discharge', 'Pus or exudate (other than blood) from a wound or orifice, usually due to infection or pathology.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('bfb48f70-853d-44c5-a962-fd652f27123b', 'disclose', 'A disclosure.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('30ae6aef-7a72-414f-bf19-78228cc77a7f', 'disclosure', 'The act of revealing something.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b9c229fd-9913-4e01-8c9c-1a9c049319ad', 'discourse', 'Verbal exchange, conversation.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('41301859-c995-4a2d-b69e-37f37f848abc', 'discretion', 'The quality of being discreet or circumspect.', 'Bob showed great discretion despite his knowledge of the affair.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('723cfc75-38f7-453a-a196-5c7205cf6f64', 'dismissal', 'The act of sending someone away.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2082e828-c3f1-4a6d-8218-578eca4b6181', 'displace', 'To put out of place; to disarrange.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('86725734-24e0-4efc-93ca-e62aa8feb0d7', 'disposal', 'An arrangement, categorization or classification of things.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4975346b-4f28-4da6-85c5-938c95f7ea72', 'dispose', 'The disposal or management of something.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('daf2e863-25d2-4e84-a9e4-5c0e90f3d5ce', 'dispute', 'An argument or disagreement, a failure to agree.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6c126397-499a-4e3e-aa67-570ce3af9264', 'disrupt', 'To throw into confusion or disorder.', 'Hecklers disrupted the man''s speech.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('bd2a41d4-1426-450a-85de-06b3d9e6394c', 'disruption', 'An interruption to the regular flow or sequence of something.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b1384195-1540-470b-bad3-40470fb2a311', 'dissolve', 'A form of film punctuation in which there is a gradual transition from one scene to the next', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c26e5952-0f96-4262-b7f8-4c01d3b60d56', 'distinction', 'That which distinguishes; a single occurrence of a determining factor or feature, the fact of being divided; separation, discrimination.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1e4d381c-824d-4cd8-be4a-cb2e74457be7', 'distinctive', 'A distinctive thing: a quality or property permitting distinguishing; a characteristic.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9cacaa22-bd86-47f1-89c1-ed06f3976ca8', 'distort', 'To bring something out of shape, to misshape.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('832185fb-5847-4e25-ba4c-9dfddb33919e', 'distress', '(Cause of) discomfort.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3aa2400f-3d87-4e45-ba6e-05549785579a', 'disturbing', 'To confuse a quiet, constant state or a calm, continuous flow, in particular: thoughts, actions or liquids.', 'A school of fish disturbed the water.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a64cdfe1-e988-4db4-94b6-c0a304193926', 'divert', 'To turn aside from a course.', 'The workers diverted the stream away from the road.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7046cd1b-010c-483b-8f92-d47c1249c317', 'divine', 'One skilled in divinity; a theologian.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('bff560b4-a1e4-4aeb-87a6-aa91e5dbeb67', 'doctrine', 'A belief or tenet, especially about philosophical or theological matters.', 'The four noble truths summarise the main doctrines of Buddhism.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d4faf2e6-44bf-407e-8e72-87b05c6d344e', 'documentation', 'Something transposed from a thought to a document; the written account of an idea.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('939f8c29-50cd-47db-9a96-83a6cc4ddb7a', 'domain', 'A geographic area owned or controlled by a single person or organization.', 'The king ruled his domain harshly.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('940ddab8-d083-4438-9c9c-58809be33e75', 'dominance', 'The state of being dominant; of prime importance; supremacy.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6b3f8bfd-49c7-4b30-b40d-1451e6a7b1e7', 'donor', 'One who makes a donation.', 'The charity raised $2,000 from various donors.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e016f28e-590e-49c8-9e8b-7193c39e5d89', 'drain', 'A conduit allowing liquid to flow out of an otherwise contained volume; a plughole (UK)', 'The drain in the kitchen sink is clogged.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3e68a67b-e636-4e70-8d0a-6c6e207e3e8e', 'drift', '(physical) Movement; that which moves or is moved.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('aec4f886-6f9e-435c-bf19-5f8e046e903e', 'drown', 'To die from suffocation while immersed in water or other fluid.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('5300cea0-6207-4902-ac26-5f39937de8fb', 'dual', 'Of an item that is one of a pair, the other item in the pair.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2063854d-36e0-4de0-aa5d-cb4941de2d37', 'dub', 'To confer knighthood; the conclusion of the ceremony was marked by a tap on the shoulder with a sword.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('237dab23-3905-4ffa-8cb7-4b96e8b71265', 'interactive', 'A feature (as in a museum) that can be interacted with.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d767d6e4-5461-4f2c-b5c4-a23881e3803c', 'dumb', 'Unable to speak; lacking power of speech (kept in "deaf, dumb, and blind").', 'His younger brother was born dumb, and communicated with sign language.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3434190c-c5e5-410b-a423-30fb89980e06', 'duo', 'Two people who work or collaborate together as partners; especially, those who perform music together.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ffb1527b-0b81-4da9-9954-854ebf20af7c', 'eager', 'Sharp; sour; acid.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ba788bdd-bdde-4e0b-bb8b-b1783ed82719', 'earnings', 'Wages, money earned, income.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('bca8e99f-44d0-467b-82b6-1e43fc9ce1d3', 'ease', 'Ability, the means to do something, particularly:', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('35f086e1-3694-45f2-b753-f58956f4bd51', 'echo', 'A reflected sound that is heard again by its initial observer.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7554137a-1c91-4599-b35d-a255f3a4ee19', 'ecological', 'Relating to ecology, the interrelationships of organisms and their environment.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e3caabb4-ff38-487e-ac0e-6656f8edb9c9', 'educator', 'A person distinguished for his/her educational work, a teacher.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e917f5d9-5dec-4302-b5cd-cdc511101bbc', 'effectiveness', 'The property of being effective, of achieving results.', 'The effectiveness of the drug was well established.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('eb229c38-8aaa-4d25-ad2f-606ac0ec9281', 'efficiency', 'The extent to which time is well used for the intended task.', 'The efficiency of the planning department is deplorable.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6b26538b-24b7-4175-8b68-b570aa71afb2', 'ego', 'The self, especially with a sense of self-importance.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ac4fb6c8-ad87-479b-bfdf-7b35e08fe99a', 'elaborate', 'To develop in detail or complexity', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('cd952a05-b72b-4135-9a50-daefa1a135bb', 'electoral', 'Relating to or composed of electors.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6a035d85-da3e-4390-99be-e40f064e9c5b', 'elevate', 'To raise (something) to a higher position.', 'The doctor told me elevating my legs would help reduce the swelling.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ebd21810-3416-460a-b515-bb1036c39ddf', 'eligible', 'One who is eligible.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('82ff6704-88e2-46a4-9d7c-c7a865096946', 'elite', 'A special group or social class of people which have a superior intellectual, social or economic status as, the elite of society.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d16daee0-877b-4a31-afbb-411c7ba73e65', 'embark', 'To get on a boat or ship or (outside the USA) an aeroplane.', 'All passengers please embark now.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8ce321f6-11d7-4fd0-b6a9-ceed6c19ebc1', 'embarrassment', 'A state of discomfort arising from bashfulness or consciousness of having violated a social rule; humiliation.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2f069a7f-d85b-4f63-b962-8a44a14ad3db', 'embassy', 'The function or duty of an ambassador.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d8dc5a9d-6b3a-40f1-9862-1b31ee0fcdd9', 'embed', 'An embedded reporter or journalist, such as a war reporter assigned to and travelling with a military unit, or a political reporter assigned to follow and report on the campaign of a candidate.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d893cbdb-ecef-4ab9-81bf-d7562742f5e3', 'embody', 'To represent in a physical or concrete form; to incarnate or personify.', 'As the car salesman approached, wearing a plaid suit and slicked-back hair, he seemed to embody sleaze.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9fac381f-30b8-4440-b546-fa3f7c64de8b', 'emergence', 'The act of rising out of a fluid, or coming forth from envelopment or concealment, or of rising into view; sudden uprising or appearance.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7cca374b-6003-4730-932d-ae9de4e78d31', 'empower', 'To give permission, power, or the legal right to do something.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2b720623-4e36-4173-84c6-509944e83a41', 'enact', 'Purpose; determination', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('747a4b73-7402-49ad-b43c-a494785858ea', 'encompass', 'To form a circle around; to encircle.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f315b947-b0ce-4d84-9c97-02e4180fea43', 'encouragement', 'The act of encouraging', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2e85cccc-70d0-4145-aafd-45dc50f11d1c', 'encouraging', 'To mentally support; to motivate, give courage, hope or spirit.', 'I encouraged him during his race.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d6e53b87-f8dd-4521-a8e0-c5244949d0ae', 'endeavour', 'A sincere attempt; a determined or assiduous effort towards a specific goal; assiduous or persistent activity.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('91d5e561-9346-467d-b8f7-eb5589f9cd7a', 'endless', 'Having no end.', 'endless time; endless praise', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a5303b0e-61d9-4560-a7b0-fffddaacb5eb', 'endorse', 'A diminutive of the pale, usually appearing in pairs on either side of a pale.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('de372fef-871b-4dca-8872-6c4d9e6481f3', 'endorsement', 'The act or quality of endorsing', 'Companies sometimes pay millions for product endorsement by celebrities.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('21f99e5a-4293-4216-97a5-b15baadf0992', 'endure', 'To continue or carry on, despite obstacles or hardships; to persist.', 'The singer''s popularity endured for decades.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7ad646f6-950c-410d-9597-c551272ad169', 'enforce', 'To keep up, impose or bring into effect something, not necessarily by force.', 'The police are there to enforce the law.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('96847a1b-0754-44a2-abe6-bb5d0b892d77', 'enforcement', 'The act of enforcing; compulsion.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('cd4cbd3f-aca9-4219-b4e7-94d7670fd779', 'engagement', 'An appointment, especially to speak or perform.', 'The lecturer has three speaking engagements this week.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('030dbbf6-f85e-45fc-845a-5e8f7f732368', 'engaging', '(heading) To interact socially.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d023d328-2589-468f-8af1-b3562dc47065', 'enquire', 'To make an enquiry.', 'He enquired about the availability of rental bicycles in the town.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('5d045f8d-4283-4e4c-a5ad-1e281d5559f2', 'enrich', 'To enhance.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('24e8ff8f-46ba-419d-aac6-cf7ae4ed16a9', 'enrol', 'To enter (a name, etc.) in a register, roll or list', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('22747406-af1b-4002-953c-c0cec810f8b8', 'ensue', 'To follow (a leader, inclination etc.).', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d59ef832-055f-4e92-98ed-f5af5f181520', 'enterprise', 'A company, business, organization, or other purposeful endeavor.', 'A micro-enterprise is defined as a business having 5 or fewer employees and a low seed capital.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c9b204c2-fd30-4d6c-9e0e-7699d62960b3', 'enthusiast', 'A person filled with or guided by enthusiasm.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ad6f6ad4-546e-4ba5-b9d3-e38f951fb368', 'entitle', 'To give a title to.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('46cba187-0ed1-48fb-865f-4165f832faec', 'entity', 'That which has a distinct existence as an individual unit. Often used for organisations which have no physical form.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('da0c46b2-4cee-4b56-808c-76de2a5a452d', 'equation', 'The act or process of equating two or more things, or the state of those things being equal (that is, identical).', 'We need to bring the balance of power into equation', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a88fa80d-e956-456b-b062-0df67e55466a', 'erect', 'Upright; vertical or reaching broadly upwards.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('26c67cab-2117-44d6-b650-e752e83c5eaf', 'escalate', 'To increase (something) in extent or intensity; to intensify or step up.', 'The shooting escalated the existing hostility.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3d7b6718-5812-468b-99f2-b78b197672d5', 'essence', 'The inherent nature of a thing or idea.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('72b4b1f1-1f9a-402c-aa20-60bca0fa9ed5', 'establishment', 'The act of establishing; a ratifying or ordaining; settlement; confirmation.', 'Since their establishment of the company in 1984, they have grown into a global business.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e266d40c-fa72-4492-8912-fbd6fd39df1f', 'eternal', 'One who lives forever; an immortal.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('736ade67-d179-432e-8294-ed45f1ac31ca', 'evacuate', 'To leave or withdraw from; to quit; to retire from', 'The firefighters told us to evacuate the area as the flames approached.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('5a5b4261-1fe0-46de-ba33-050ffe7e89e5', 'evoke', 'To call out; to draw out or bring forth.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e0c74d3d-cc75-4699-a36a-9ec407b79a3a', 'evolutionary', 'Of or relating to the biological theory of evolution.', 'The evolutionary history of marine mammals includes land-dwelling ancestors.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e5176e2c-2504-49fd-bc71-6e3c11e0e7d9', 'exaggerate', 'To overstate, to describe more than is fact.', 'He said he''d slept with hundreds of girls, but I know he''s exaggerating. The real number is about ten.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6b605b07-d423-47f6-a0cf-697b03f2cab2', 'excellence', 'The quality of being excellent; brilliance', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('828599d1-4d0e-4442-9ce2-b5946d47a2da', 'exceptional', 'An exception, or something having an exceptional value', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e57511ee-2083-42a8-adf7-f5782f2756d5', 'excess', 'The state of surpassing or going beyond limits; the being of a measure beyond sufficiency, necessity, or duty; that which exceeds what is usual or proper', 'The excess of heavy water was given away to the neighbouring country.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('df633f4f-c2df-408b-a2be-474384b9ae67', 'exclusion', 'The act of excluding or shutting out; removal from consideration or taking part.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6f1fa8d9-9337-47f6-bdb5-1f3d3f2d5d30', 'exclusive', 'Information (or an artefact) that is granted or obtained exclusively.', 'The editor agreed to keep a lid on a potentially disastrous political scoop in exchange for an exclusive of a happier nature.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('475397de-884f-443c-8c5e-8822ba3a3e87', 'exclusively', '(focus) to the exclusion of anything or anyone else; solely or entirely', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('be904682-8753-4761-a946-b874f99f83d1', 'execute', 'To kill as punishment for capital crimes.', 'There are certain states where it is lawful to execute prisoners convicted of certain crimes.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('004541fa-51eb-4d36-80c9-834ca3a05a7e', 'execution', 'The act, manner or style of executing (actions, maneuvers, performances).', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e0fe80d3-7b02-4740-a7c6-1def41fd6b3f', 'exert', 'To put in vigorous action.', 'I exerted myself in today''s training.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('fadf79aa-b80f-4f7e-960b-88a94a13a812', 'exile', 'The state of being banished from one''s home or country.', 'He lived in exile.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('535ee1dd-9e53-415d-a6ee-9bbbef7c92f3', 'experimental', 'The subject of an experiment.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('58471669-9a38-49ac-8223-762a548ef0ec', 'expire', 'To die.', 'The patient expired in hospital.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7e8709f8-cb54-4775-b1aa-08d1bbf055b8', 'explicit', 'Very specific, clear, or detailed.', 'I gave explicit instructions for him to stay here, but he followed me, anyway.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6f170540-be77-41b1-a0f7-859c37f60a4a', 'explicitly', 'In an explicit manner.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('83edfa48-2365-490a-b436-159a6c9625e7', 'exploitation', 'The act of utilizing something; industry.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f42b0abd-f918-4a90-9433-b0467c3254ab', 'explosive', 'Any explosive substance.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6294e69f-2ff6-4dd6-b8b4-2adb1d522083', 'extremist', 'A person who holds extreme views, especially one who advocates such views; a radical or fanatic.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('81017e4e-f16c-49ba-8595-b7412cebac73', 'facilitate', 'To make easy or easier.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('194ad85e-cfe9-49ea-a88e-e8a240236386', 'faction', 'A group of people, especially within a political organization, which expresses a shared belief or opinion different from people who are not part of the group.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2dcb8f59-e209-4e2c-9cbd-72f8e5556763', 'faculty', 'The academic staff at schools, colleges, universities or not-for-profit research institutes, as opposed to the students or support staff.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9228ce5c-049d-4ec1-a08c-581ed39a7316', 'fade', 'A golf shot that (for the right-handed player) curves intentionally to the right. See slice, hook, draw.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('14cd6e69-6310-4be4-a43a-43124a36d55e', 'fairness', 'The property of being fair or equitable.', 'Some questioned the fairness of the new laws.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('5aa6a042-bb79-4c3f-9465-54e48df97a09', 'fatal', 'A fatality; an event that leads to death.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a2f0600b-be7b-48c7-94df-5ca50d8b665a', 'fate', 'The presumed cause, force, principle, or divine will that predetermines events.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2f4a29ee-9a96-4d91-af3f-08a840f65210', 'favourable', 'Pleasing, encouraging or approving.', 'The candidate wearing the business suite made a favourable impression.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('60d3037f-5785-4b70-a9ed-6a47d6d15b84', 'feat', 'A relatively rare or difficult accomplishment.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e30c1606-6d71-43eb-848c-1eee68b0be5b', 'feminist', 'An advocate of feminism; a person who believes in bringing about the equality of the sexes (of women and men) in all aspects of public and private life', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('80fda5f9-d6bf-45aa-8bf8-b90ac42cb4e5', 'fibre', 'A single piece of a given material, elongated and roughly round in cross-section, often twisted with other fibres to form thread.', 'The microscope showed several different fibres stuck to the sole of the shoe.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1c39f145-f095-45ad-ba20-e04dd9d2d6ae', 'fierce', 'Exceedingly violent, severe, ferocious, cruel or savage.', 'A fierce storm battered the coast.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c9a48538-7f81-4e87-b4bd-4ea52b479b23', 'film-maker', 'A producer or director of films/movies.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('55a186af-be30-4bd4-bc2d-517ed7c4d47c', 'filter', 'A device which separates a suspended, dissolved, or particulate matter from a fluid, solution, or other substance; any device that separates one substance from another.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('652299c2-705e-463e-b66b-493d6fd7cec2', 'firearm', 'A personal weapon that uses explosive powder to propel a projectile often made of lead.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('10dd8d6c-ca29-4353-9935-2c24b13aa23f', 'fixture', 'Something that is fixed in place, especially a permanent appliance or other item of personal property that is considered part of a house and is sold with it; compare fitting, furnishing.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e1b3e707-f4d5-4644-bf93-6dd115ef9905', 'flaw', 'A flake, fragment, or shiver.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('301de67f-ab25-46c7-836d-d908dd38e85c', 'flawed', 'Having a flaw or imperfection.', 'Flawed diamonds are generally not used in jewellery.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d0ffb191-1c82-4abd-af89-d99bbfb00563', 'flee', 'To run away; to escape.', 'The prisoner tried to flee, but was caught by the guards.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b37b70c9-8f5c-4288-9259-ad19f95e8248', 'fleet', 'A group of vessels or vehicles.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2a426a3c-6a89-4eec-9d56-089a720b0118', 'flesh', 'The soft tissue of the body, especially muscle and fat.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2a20110d-2751-4826-a052-ee2e054fe522', 'flexibility', 'The quality of being flexible; suppleness; pliability.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('efeb378d-785d-451e-a387-c1c363541462', 'flourish', 'A dramatic gesture such as the waving of a flag.', 'With many flourishes of the captured banner, they marched down the avenue.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7f148578-7d44-4a70-94c2-c3e1ff9553a8', 'fluid', 'Any substance which can flow with relative ease, tends to assume the shape of its container, and obeys Bernoulli''s principle; a liquid, gas or plasma.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b49093b7-357a-4584-a5eb-21d6e03f9ea9', 'footage', 'An amount of film or tape that has been used to record something.', 'The footage we shot at the riot yesterday got ruined.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('38f4d8a4-da0a-49bd-92dc-8f2419fc85c8', 'foreigner', 'A person from a foreign country.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f3f897e4-cd76-4940-847a-8e8334469bea', 'forge', 'Furnace or hearth where metals are heated prior to hammering them into shape.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('708369b0-7174-49b2-ba5e-4d7306e1185d', 'formula', 'Any mathematical rule expressed symbolically.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c28ca312-e074-41f0-9b4e-b503a8983709', 'formulate', 'To reduce to, or express in, a formula; to put in a clear and definite form of statement or expression.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6c74f065-5d8f-4ae3-b927-b8ed74e9ec09', 'forth', 'Forward in time, place or degree.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f65f27cf-2d0b-411e-a854-46b778945365', 'forthcoming', 'An act of coming forth.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4b69eeda-9135-4ada-9e7d-b5bafcac2b67', 'foster', 'A foster parent.', 'Some fosters end up adopting.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4a72b54e-649a-4e5f-b584-8936a3484971', 'fragile', 'Easily broken or destroyed, and thus often of subtle or intricate structure.', 'He is a very fragile person and gets easily depressed.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('487a4844-29ae-4b88-83f2-a6eadb34a0c3', 'franchise', 'The right to vote at a public election or referendum; see: suffrage, suffragette.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('cc44b4b8-8ad0-459a-b3e9-802fbf322fa9', 'frankly', '(manner) In a frank, open or (too) honest manner.', 'He spoke frankly about the economy.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('cb591677-f58d-4caa-a875-281519646dae', 'frustrated', 'To disappoint or defeat; to vex by depriving of something expected or desired.', 'It frustrates me to do all this work and then lose it all.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('cce385e7-fbd3-488a-b0b0-97bdf951a944', 'frustrating', 'To disappoint or defeat; to vex by depriving of something expected or desired.', 'It frustrates me to do all this work and then lose it all.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('75f5edaf-8012-4809-afe3-a4c107b56802', 'functional', 'A function that takes a function as its argument; More precisely: A function y=f(x) whose argument x varies in a space of (real valued, complex valued) functions and whose value belongs to a monodimensional space. An example: the definite integration of integrable real functions in a real interval.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9149850e-badb-4646-a5a6-057fc2f50e42', 'fundraising', 'The process of collecting money by requesting donations from individuals and businesses.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('987a7b15-7aa1-4fd8-b9a5-ecf825f8f5f8', 'funeral', 'A ceremony to honour and remember a deceased person. Often distinguished from a memorial service by the presence of the body of the deceased.', 'Many mourners turned up at the local artist''s funeral to pay homage.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9fcfc890-f946-46dc-8ab7-cd7c437f8ddc', 'gallon', 'A unit of volume, equivalent to eight pints', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('99e0531d-a344-48c7-aea5-f6d5edf212bd', 'gambling', 'To take a risk, with the potential of a positive outcome.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('853ae929-9802-4112-9ee5-eca674628aa1', 'gathering', 'A meeting or get-together; a party or social function.', 'I met her at a gathering of engineers and scientists.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8e259677-30d3-4951-b9aa-7f2ea72d9905', 'gaze', 'A fixed look; a look of eagerness, wonder, or admiration; a continued look of attention.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ad134508-340f-4291-87d9-084218005439', 'gear', 'Equipment or paraphernalia, especially that used for an athletic endeavor.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8d74587f-d99f-4689-9abf-36d8e915d65e', 'generic', 'A product sold under a generic name.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('322431a8-6d5f-45cd-8496-6f70eeff18a8', 'genocide', 'The systematic killing of substantial numbers of people on the basis of their ethnicity, religion, political beliefs, social status, or other particularities.', 'A genocide will always be followed by the denial that it ever happened.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('08356ffc-ea82-412a-92cf-236a41b9f403', 'glance', 'A brief or cursory look.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('fa4de9bf-1f47-442f-9857-8d7bda3092e9', 'glimpse', 'A brief look, glance, or peek.', 'I only got a glimpse of the car, so I can tell you the colour but not the registration number.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e722d3e2-a719-4157-a08f-d02911fd539d', 'glorious', 'Exhibiting attributes, qualities, or acts that are worthy of or receive glory.', 'glorious deeds', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('02274a21-a3d8-4f88-8a67-205aceed165d', 'glory', 'Great or overwhelming beauty or splendour.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('234b1502-fa08-40eb-b60b-1e9405680795', 'governance', 'The process, or the power, of governing; government or administration.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('dc30d1f7-d733-4c21-acf0-aeb65ecd2848', 'grace', 'Charming, pleasing qualities.', 'The Princess brought grace to an otherwise dull and boring party.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0d3c0194-b81e-4613-a63f-f0a8995e9ddf', 'grasp', '(sometimes figurative) Grip.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('591283d5-51e4-44fc-82f3-e30ee820596a', 'grave', 'An excavation in the earth as a place of burial', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('faec23f9-d9bd-4b9c-80e1-008f7a09f73b', 'gravity', 'The state or condition of having weight; weight; heaviness.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3fbf00d8-c873-4e28-bafd-47feb3407416', 'grid', 'A rectangular array of squares or rectangles of equal size, such as in a crossword puzzle.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1f84c33d-cc25-438b-801a-60676edc8907', 'grief', 'Suffering, hardship.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d9d4d96a-cbdd-43b2-b3b9-68db217613c5', 'grin', 'A smile in which the lips are parted to reveal the teeth.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('16beaa1c-2219-4f87-bada-760b864a0fb5', 'grind', 'The act of reducing to powder, or of sharpening, by friction.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d03bb979-9fcd-46e1-a913-0c502c8af044', 'grip', 'To take hold of, particularly with the hand.', 'After a few slips, the tires gripped the pavement.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('5148ed1b-0d86-4abe-acf4-1b019539e864', 'gross', 'Twelve dozen = 144.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('cbba3b39-799d-4a09-bf42-0c44e4520121', 'guerrilla', 'A soldier in a small independent group, fighting against the government or regular forces by surprise raids.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('555fcee6-ba6f-40a9-8cec-b8f24dd019c6', 'guidance', 'The act or process of guiding.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('bd68443c-67fc-4937-9611-7c0767635f9a', 'guilt', 'Responsibility for wrongdoing.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3117c476-1c00-46cd-86a0-a3b90171ae3b', 'gut', 'The alimentary canal, especially the intestine.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('59ef1a97-af60-484a-bb42-87a50aa41251', 'hail', 'Balls or pieces of ice falling as precipitation, often in connection with a thunderstorm.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('42399392-b5bd-4778-ad1b-1704a1c4187a', 'halfway', 'Half of the way between two points; midway.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7e032db1-b88a-49de-bbb3-8ccc83466fa9', 'halt', 'To limp; move with a limping gait.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7c30f1d6-7536-468a-8818-04b6c7f912ef', 'handful', 'The amount that a hand will grasp or contain.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('29755b24-988c-44a8-ab24-3bd4e89ee42a', 'handling', 'A touching, controlling, managing, using, take care of, etc., with the hand or hands, or as with the hands.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0fb30bd3-0443-44e6-a0cf-1d4b99a906dd', 'handy', 'Easy to use, useful.', 'Some people regard duct tape as a handy fix-all.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2e72d8ee-2817-4c99-ab5f-876b16585005', 'harassment', 'Persistent attacks and criticism causing worry and distress.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8fb80418-7e7a-41df-a664-210ec6075f9b', 'hardware', 'Fixtures, equipment, tools and devices used for general-purpose construction and repair of a structure or object. Also such equipment as sold as stock by a store of the same name, e.g. hardware store.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b4222dd8-3f08-4b22-a75d-68cdee45bd3c', 'harmony', 'Agreement or accord.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('25fcec02-1d94-45b9-8245-5da1c2f3b1a5', 'harsh', 'To negatively criticize.', 'Quit harshing me already, I said that I was sorry!', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('5b69a4ae-d4a4-4ca5-a51d-2be97e236d8f', 'harvest', 'The third season of the year; autumn; fall.', 'Harvest is usually very damp and rainy.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3b4194f1-9d8c-426a-99fa-3d9cd83c1efb', 'hatred', 'Strong aversion; intense dislike', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('52b7791a-8827-4547-9120-46f7dbabda2a', 'haunt', 'A place at which one is regularly found; a habitation or hangout.', 'I went back the town I used to live and visited all my old haunts.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('56268dcd-2958-45cd-888e-75411bff9b8e', 'hazard', 'The chance of suffering harm; danger, peril, risk of loss.', 'He encountered the enemy at the hazard of his reputation and life.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8827ceb8-0dd4-4519-b588-71b20b1daabc', 'heighten', 'To make high; to raise higher; to elevate.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6b015f21-f10a-49ef-916a-c47ba9a75aa2', 'hierarchy', 'A body of authoritative officials organized in nested ranks.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('34bbef0d-54aa-477d-82e7-6d2d0299f870', 'high-profile', 'Important or well publicized.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('233e028a-84c2-42f6-8966-a8103f16746b', 'hint', 'A clue.', 'I needed a hint to complete the crossword.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a600fc5e-e42e-485c-8b88-d18c0f89b00e', 'homeland', 'The country that one regards as home.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('537da9a1-6907-4577-8542-4f6dd8152b15', 'hopeful', 'Someone who is hoping for success or victory, especially as a candidate in a political election.', 'Several presidential hopefuls are campaigning in New Hampshire this week.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('5f8f05e9-4b7d-46a2-b595-13a30f23f53f', 'horizon', 'The visible horizontal line or point (in all directions) that appears to connect the Earth to the sky.', 'A tall building was visible on the horizon.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c61bda83-6383-495d-8fc9-34612e748d03', 'horn', 'A hard growth of keratin that protrudes from the top of the head of certain animals, usually paired.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f4b54fc8-2a72-46a2-a604-aa74ff528249', 'hostage', 'A person given as a pledge or security for the performance of the conditions of a treaty or similar agreement, such as to ensure the status of a vassal.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b70bfddf-d92d-42a0-b77c-025049b96c13', 'hostile', '(chiefly in the plural) An enemy.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('337b75c1-c7cb-456d-a7b0-d87c26ab46ed', 'hostility', 'The state of being hostile.', 'My resentment and anger towards you caused hostility and a division between us.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3fc71a75-6c47-4f9d-8558-786398a6494c', 'humanitarian', 'A scholar of one of the subjects in the humanities.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('5ecadba4-146f-465b-8910-c5a6658a0fb3', 'humble', '(Baltimore) An arrest based on weak evidence intended to demean or punish the subject.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2a16d7a9-3c54-4344-b694-cd661bca5021', 'hydrogen', 'The lightest chemical element (symbol H), with an atomic number of 1 and atomic weight of 1.00794.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6f225c15-8163-4097-a1d4-43af0342a103', 'identification', 'The act of identifying, or proving to be the same.', 'Much education and experience is required for proper identification of bird species', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b1b2b38b-33d1-456b-9b40-250c059c1c92', 'ideological', 'Of or pertaining to an ideology.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9dab5ee4-d260-46ab-b426-f509b0936e12', 'idiot', 'A person of low general intelligence.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a59a824c-8736-4a95-bee2-fccbac1f0a63', 'ignorance', 'The condition of being uninformed or uneducated. Lack of knowledge or information.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d9ba8679-b958-443e-85fb-5cf09a9d7d1e', 'imagery', 'The work of one who makes images or visible representation of objects.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('75b7aa91-ea88-425e-968a-a18b2476286f', 'immense', 'Immense extent or expanse; immensity', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8329f4d9-aa8d-4598-b548-a6b1aaf841ae', 'imminent', 'About to happen, occur, or take place very soon, especially of something which won''t last long.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('34afe4ca-cd69-4461-8de2-91aa7f3c9ac3', 'imprison', 'To put in or as if in prison; confine.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a6b4cf31-7ba8-449c-a13b-cdb76ca04482', 'imprisonment', 'A confinement in a place, especially a prison or a jail, as punishment for a crime.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('896acb9a-e248-4518-9a09-0af9e976c307', 'inability', 'Lack of the ability to do something; incapability.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6a1c236a-d675-4fa9-97a8-89c6e87327e8', 'inadequate', 'An individual who is inadequate.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c5ee9051-eb1f-465f-b046-74b24b822751', 'inappropriate', 'Not appropriate; not suitable for the situation, time, or place.', 'It is inappropriate to burp at a formal dinner.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('30d39a59-651a-433c-bcab-c8094246cc2e', 'inclined', 'To bend or move (something) out of a given plane or direction, often the horizontal or vertical.', 'He had to incline his body against the gusts to avoid being blown down in the storm.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e410171d-8b77-4eb2-83d8-59f0b5a31db0', 'inclusion', 'An addition or annex to a group, set, or total.', 'The poem was a new inclusion in the textbook.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3f00e7d1-6afe-4e9c-914c-39db2c512273', 'incur', 'To bring upon oneself or expose oneself to, especially something inconvenient, harmful, or onerous; to become liable or subject to', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('37ac35ee-3aed-4b2a-bf32-80571ad72c93', 'indicator', 'A pointer or index that indicates something.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('20a841e9-fcfd-4d2a-811c-39b7c5956eaf', 'indictment', 'An official formal accusation for a criminal offence, or the process by which it is brought to a jury.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e6a0deb2-b54d-4c92-8c02-0e4782a09f46', 'indigenous', 'Born or originating in, native to a land or region, especially before an intrusion.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8478d2a6-397a-41de-a500-267591649d3a', 'induce', 'To lead by persuasion or influence; incite or prevail upon.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('5a37318e-f859-438b-8def-6491aa9192df', 'indulge', '(often followed by "in"): To yield to a temptation or desire.', 'He looked at the chocolate but didn''t indulge.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3d2ec5e3-1da1-4c15-ae50-064bbb52ea6e', 'infamous', 'Having a bad reputation, disreputable; notoriously bad, unpleasant or evil; widely known, especially for something bad.', 'He was an infamous perjurer.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b7686cea-03c0-4438-ab32-2de41e84cb37', 'infant', 'A very young human being, from birth to somewhere between six months and two years of age, needing almost constant care and/or attention.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('84f2e2bb-cd99-4282-8619-ff46222d40a1', 'infect', 'To bring into contact with a substance that causes illness (a pathogen).', 'Not everyone will be infected when an epidemic strikes.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('43ba8bb3-6284-4675-9328-a7fc9b1a6d06', 'inflict', 'To thrust upon; to impose.', 'They inflicted terrible pains on her to obtain a confession.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4f815632-aa71-4739-a85b-eccacedb510e', 'influential', 'A person who has influence', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9b86f7d0-3b3b-43f1-b3ac-681e2ce036cc', 'inhibit', 'To hold in or hold back; to keep in check; restrain.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2e3a2f3a-6e4d-4b19-b2ae-feef6d9d0da9', 'initiate', 'A new member of an organization.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9657f9ab-291d-4dd1-8cda-09fe34162732', 'inject', 'To push or pump (something, especially fluids) into a cavity or passage.', 'The nurse injected a painkilling drug into the veins of my forearm.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('36fe6d58-d966-4ec7-8c65-0298899e994e', 'injection', 'The act of injecting, or something that is injected.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('581e4e2f-4ec0-4dab-9443-9afbbb654ed3', 'injustice', 'Absence of justice; unjustice.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('651dd838-6a50-4c88-b06c-35fed3509906', 'inmate', 'A person confined to an institution such as a prison (as a convict) or hospital (as a patient).', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6aed7e63-f356-4c08-9ff9-eab9e678130c', 'insertion', 'The act of inserting, or something inserted.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b0b6b07c-ca7d-42cc-a4d6-154b01d60191', 'insider', 'A person who has special knowledge about the inner workings of a group, organization, or institution.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('af6cc514-39c7-410e-8e8a-144b714f62e4', 'inspect', 'To examine critically or carefully; especially, to search out problems or determine condition; to scrutinize.', 'Inspect the system for leaks.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('46d1794a-4356-44d5-ac88-d14f60b4f7a9', 'inspection', 'The act of examining something, often closely.', 'Upon closer inspection, the animal turned out to be a dolphin, not a shark!', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ed8f2653-e406-489a-963c-893282f5df08', 'inspiration', 'The drawing of air into the lungs, accomplished in mammals by elevation of the chest walls and flattening of the diaphragm, as part of the act of respiration.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c538dcbe-1d3f-4510-8316-c0612208bf9e', 'instinct', 'A natural or inherent impulse or behaviour.', 'Many animals fear fire by instinct.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2c3e15be-d2b2-478e-a943-5ec6e38d4b40', 'institutional', 'Of, pertaining to, characteristic of, or organized along the lines of an institution.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9db36bc2-1a9a-4e4b-abc4-2280ac50af7a', 'instruct', 'Instruction.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('09b75e7d-d680-4bcc-b55b-f2a27c284dfe', 'instrumental', '(grammar) The instrumental case.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('067d6c0a-ff67-4786-9b51-2518b2b3bd43', 'insufficient', 'Not sufficient.', 'Insufficient time is available to reflect on the problem', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('05f11f10-1250-4015-8494-03160ec56427', 'insult', 'Action or form of speech deliberately intended to be rude; a particular act or statement having this effect.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8f18ef0a-17d8-414d-a0a5-a1daf516eac4', 'intact', 'Left complete or whole; not touched, defiled, sullied or otherwise damaged', 'I packed my belongings carefully so that they would survive the move intact.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e1aa861e-9895-48f2-bb8a-b84381d65279', 'intake', 'The place where water, air or other fluid is taken into a pipe or conduit; opposed to outlet.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f93dc5e6-150a-4aa9-ad06-2a579878019d', 'integral', 'A number, the limit of the sums computed in a process in which the domain of a function is divided into small subsets and a possibly nominal value of the function on each subset is multiplied by the measure of that subset, all these products then being summed.', 'The integral of x\mapsto x^2 on [0,1] is \frac{1}{3}.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9cd0cbd6-637e-4285-ac43-61a381fcf347', 'integrated', 'To form into one whole; to make entire; to complete; to renew; to restore; to perfect.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('847b853b-872d-4fa3-ae35-c15decbc8e8d', 'integrity', 'Steadfast adherence to a strict moral or ethical code.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('aeb67783-576b-4ff4-a49b-03aadc221104', 'intensify', 'To render more intense', 'to intensify a photographic negative', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9d0f2171-311f-4fae-bf0f-b8cfb79d64bc', 'intensity', 'The quality of being intense.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('08f8a061-c087-4cb5-bf63-99208499820a', 'intensive', 'Form of a word with a stronger or more forceful sense than the root on which the intensive is built.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('cc1deac0-edcc-4ae3-a2d7-87cd7891a5ab', 'interface', 'The point of interconnection or contact between entities.', 'Public relations firms often serve as the interface between a company and the press.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1c1bee3a-5a13-403d-ad02-7ddede11e33e', 'interfere', 'To get involved or involve oneself, causing disturbance.', 'I always try not to interfere with other people’s personal affairs.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('32a615f0-e4e3-4ee1-baa0-1d695f66c3d6', 'interference', 'The act of interfering with something, or something that interferes.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d232cbb1-49e7-4261-9a33-4db4f1fa475e', 'interim', 'A transitional or temporary period between other events.', 'His car is in the shop, but they gave him a rental to drive in the interim.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9e467111-8480-4885-832b-fb18d9cde7f0', 'interior', 'The inside of a building, container, cavern, or other enclosed structure.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('575ee239-e81e-4afe-ac5d-72866c9b04c2', 'intermediate', 'Anything in an intermediate position.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('be0904c5-f333-4b53-a021-9e519100cf49', 'intervene', 'To become involved in a situation, so as to alter or prevent an action.', 'The police had to be called to intervene in the fight.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6b51f632-f06d-40ae-bff9-f4723d9694ff', 'intervention', 'The action of intervening; interfering in some course of events.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c40ca6d9-e9a3-479b-8bca-47b3b7333188', 'intimate', 'A very close friend.', 'Only a couple of intimates had ever read his writing.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7583e7d2-c53e-4a71-8fe4-818e6c36a5c4', 'intriguing', 'To conceive or carry out a secret plan intended to harm; to form a plot or scheme.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('58e0908f-6ec3-44a5-abad-bd751e1f4ec8', 'investigator', 'One who investigates.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7a817ea3-e330-4f43-8215-e8d732ee1bf1', 'invisible', 'An invisible person or thing; specifically, God, the Supreme Being.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0f0c20ba-258d-4188-818d-5524707e1417', 'invoke', 'To call upon (a person, a god) for help, assistance or guidance.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('278133ea-8833-445d-8aa9-656f6c4dd40c', 'involvement', 'The act of involving, or the state of being involved.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4f2cab4c-41c6-4678-bc47-ee84e5f781ca', 'ironic', 'Characterized by or constituting (any kind of) irony.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d44dc701-686a-4263-a179-35295a28d395', 'ironically', '(manner) In an ironic manner; in a way displaying irony.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('de8c20be-8b23-462a-bbd7-a7467e28ea23', 'irony', 'A statement that, when taken in context, may actually mean something different from, or the opposite of, what is written literally; the use of words expressing something other than their literal intention, often in a humorous context.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0cbe032b-1a89-4993-8d72-b93874831184', 'irrelevant', 'Not related, not applicable, unimportant, not connected.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('87d2ef91-6848-4a8b-915f-6d3b711158de', 'isolation', 'The state of being isolated, detached, or separated.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('dd5d8bff-5d85-4799-90e4-f59d32e95152', 'judicial', 'That branch of government which is responsible for maintaining the courts of law and for the administration of justice.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6b349342-7ec5-4f87-90fa-b513e3958326', 'junction', 'The act of joining, or the state of being joined.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('fee6a530-b4e7-42b2-a8de-568aac936264', 'justification', 'A reason, explanation, or excuse which provides convincing, morally acceptable support for behavior or for a belief or occurrence.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('971d8b80-ba6f-4084-8e2a-661a2389757d', 'kidnap', 'The crime, or an instance, of kidnapping.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('62065388-fa0a-483d-8ec8-acda0608ea1f', 'kidney', 'An organ in the body that filters the blood, producing urine.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d323d6f7-06d6-47da-81f6-447a3ee09e30', 'kingdom', 'A realm having a king and/or queen as its actual or nominal sovereign.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('523b0c76-171c-4570-81b2-bdde8c899aee', 'lad', 'A boy or young man.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('94edc6ab-bfc1-42f8-b64a-01bf12f2da43', 'landlord', 'A person who owns and rents land such as a house, apartment, or condo.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('415863ba-df68-4a52-b995-1555e1f90d36', 'landmark', 'An object that marks the boundary of a piece of land (usually a stone, or a tree).', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c6a231c6-e533-44c9-b70c-785b65dc0266', 'lap', 'The loose part of a coat; the lower part of a garment that plays loosely; a skirt; an apron.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('77f7d2f1-0e1d-4972-9a61-def976209ca6', 'large-scale', 'Large in amount, scope or extent.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('62aff52a-f64b-4962-be55-738273aaea59', 'laser', 'A device that produces a monochromatic, coherent beam of light.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('91eb0a5f-10e2-4c19-82d0-eb61e387a3c7', 'latter', 'Relating to or being the second of two items.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('96ae9d92-bfdb-441a-95df-8c9c88779465', 'lawn', 'An open space between woods.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('90a24fd4-8f4b-4055-9f51-edf2aef4a4f5', 'lawsuit', 'In civil law, a case where two or more people disagree and one or more of the parties take the case to a court for resolution.', 'The lawyer advised his client against filing a lawsuit as it would take a lot of time and money to resolve.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3a3c7f72-879a-40c0-ae68-832cb1e809de', 'layout', 'A structured arrangement of items within certain limits.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('228c9758-8e0b-4d6e-a550-23318f003c76', 'leak', 'A crack, crevice, fissure, or hole which admits water or other fluid, or lets it escape.', 'a leak in a boat', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('dc93482f-6036-4dab-8820-b43a95ff3b88', 'leap', 'The act of leaping or jumping.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('962f850f-18b3-4f60-beeb-a45d6843e797', 'legacy', 'Money or property bequeathed to someone in a will.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('514e40dd-c236-4042-b315-85ec8848a8a1', 'legendary', 'A collection of legends, in particular of lives of saints.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4e52ff19-2efe-4a33-a7c5-03aee81464c1', 'legislative', 'That branch of government which is responsible for making, or having the power to make, a law or laws.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4a1a55b2-60a4-4705-938f-847aa38b5de1', 'legislature', 'A governmental body with the power to make, amend and repeal laws.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0a9a047e-7164-48d8-ba6d-e79543821df9', 'legitimate', 'A person born to a legally married couple.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('82e67fd5-8c8c-4c3c-a7bd-c7031690717f', 'lengthy', 'Having length; long and overextended, especially in time rather than dimension.', 'She died last night after a lengthy illness.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('30c271b1-0372-4206-9935-5feebfc38826', 'ranking', 'To place abreast, or in a line.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('23b31ec8-18c2-43f8-8d04-e8a96b76f9e3', 'lesbian', 'A homosexual woman, one who is mostly or exclusively sexually or romantically attracted to other women.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d214e6e6-9ec2-458f-b75f-866e85ecbe9b', 'lesser', 'A thing that is of smaller size, value, importance etc.', 'The greater sand hills increasingly do not migrate, but almost all lessers do.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('33097207-0b59-46ef-9c3d-6e897c5a2bdd', 'lethal', 'Any weapon that causes death.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4aa31cff-06a1-4a9c-9602-1b53d80cb417', 'liable', 'Bound or obliged in law or equity; responsible; answerable.', '1748. David Hume. Enquiries concerning the human understanding and concerning the principles of moral. London: Oxford University Press, 1973. § 34.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('74075021-e8f9-4700-8b76-ffa6e3466cc3', 'liberal', 'One with liberal views, supporting individual liberty (see Wikipedia''s article on Liberalism).', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('93b3c239-1f07-4f74-b552-4b3594175284', 'liberation', 'The act of liberating or the state of being liberated.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8c05df25-a041-4ce9-ac62-607c2725b266', 'liberty', 'The condition of being free from control or restrictions.', 'The army is here, your liberty is assured.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c2524098-9edf-4049-b729-1036fd95dc88', 'license', 'A legal document giving official permission to do something; a permit.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ad9e2153-dd0c-42bf-9b5d-e75e00137a08', 'lifelong', 'Extending for the entire duration of life.', 'They were lifelong friends; they met in elementary school and ended their lives in the same rest home.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2b84d06e-ae9b-4fbb-8a12-0e1defb15335', 'likelihood', 'The probability of a specified outcome; the chance of something happening; probability; the state or degree of being probable.', 'In all likelihood the meeting will be cancelled.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('bbdce04d-1cc7-4bf5-ab0d-1ebf358a62e8', 'limb', 'A major appendage of human or animal, used for locomotion (such as an arm, leg or wing).', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d607697d-4dc5-4d60-83dc-0276f50a4c31', 'line-up', 'A physical or photographic queue of people allegedly involved in a crime, allowing a witness to identify them', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('48afb136-31c6-4f66-b33a-049eeacf27fa', 'linear', 'Having the form of a line; straight or roughly straight; following a direct course.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('afa0ffd0-3dab-4b6e-ae98-a665f415276d', 'linger', 'To stay or remain in a place or situation, especially as if unwilling to depart or not easily able to do so; to loiter.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ce8a255c-2544-47be-a774-58a21d9b417d', 'listing', 'To create or recite a list.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9115738c-127d-4221-8400-0cfba58c9cb5', 'literacy', 'The ability to read and write.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0ed60711-63c1-4a1e-a037-e750021b8d6f', 'liver', 'A large organ in the body that stores and metabolizes nutrients, destroys toxins and produces bile. It is responsible for thousands of biochemical reactions.', 'Steve Jobs is a famous liver transplant recipient.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ee799132-8017-46b6-a730-6521caa34091', 'lobby', 'An entryway or reception area; vestibule; passageway; corridor.', 'I had to wait in the lobby for hours before seeing the doctor.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('34afeb6a-a13d-4376-944b-a4a36f2c4ce6', 'log', 'The trunk of a dead tree, cleared of branches.', 'They walked across the stream on a fallen log.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('004ff321-ea87-40ff-bdd0-3f9ee3e5f706', 'logic', 'A method of human thought that involves thinking in a linear, step-by-step manner about how a problem can be solved. Logic is the basis of many principles including the scientific method.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ee303a98-2b7f-479c-94d9-a0c93ca74cae', 'long-standing', 'Having existed for a long time.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e22edbb4-8cc8-4777-87a2-b68a1abc8ec5', 'long-time', 'Having endured for a long period of time.', 'My longtime friend, since birth actually, called and gently broke the bad news to me.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('343fb563-10c6-45f9-af7b-f5602ce846bc', 'loom', 'A utensil; tool; a weapon; (usually in compound) an article in general.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8372869e-ca9c-46ab-8d58-e1bfc5175e48', 'loop', 'A length of thread, line or rope that is doubled over to make an opening.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('aa03f949-0dd9-4f39-b768-f1464ea7fcc9', 'loyalty', 'The state of being loyal; fidelity.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('232af193-5d46-42e8-9f2e-120dcfb7c312', 'machinery', 'The machines constituting a production apparatus, in a plant etc., collectively.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('350806ef-240c-4c03-ba19-c60a4a0824c9', 'magical', 'Of or relating to magic.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('bd20986e-ddd6-407a-82e3-10001b0569c4', 'magistrate', 'A judicial officer with limited authority to administer and enforce the law. A magistrate''s court may have jurisdiction in civil or criminal cases, or both.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c437a6fe-87a8-41ea-9f0d-3bae84e8ddc3', 'magnetic', 'Of, relating to, operating by, or caused by magnetism.', 'a magnetic recorder', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3a25a4ab-df84-4dac-954c-368a75986c37', 'magnitude', 'The absolute or relative size, extent or importance of something.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1a0c1fb5-84fe-404c-8031-b1551770c088', 'mainland', 'The continent; the principal land, as distinguished from islands or a peninsula.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('dd24af47-7746-4d79-8950-aa443650b943', 'mainstream', 'The principal current in a flow, such as a river or flow of air', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('505719c5-92eb-4fcf-893f-6cf2e684dd76', 'maintenance', 'Actions performed to keep some machine or system functioning or in service.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7cf5963d-b64a-43cc-be7f-9ed33ed2b247', 'mandate', 'An official or authoritative command; an order or injunction; a commission; a judicial precept.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8de06359-2c21-447b-8621-bfd43a6c1561', 'mandatory', 'A sign or line that require the path of the disc to be above, below or to one side of it.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('257eff0a-b991-4531-b157-a4c680f8ab44', 'manifest', 'A list or invoice of the passengers or goods being carried by a commercial vehicle or ship.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f12e99b4-4de5-4890-bcb3-fb7c10567bf7', 'manipulate', 'To move, arrange or operate something using the hands', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c767373b-869e-4c3e-88d9-00510b3a7d31', 'marginal', 'Something that is marginal.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('978648a8-80b1-488b-96af-c5f989c3d86a', 'marine', 'A soldier, normally a member of a marine corps, trained to serve on board or from a ship', 'He was a marine in World War II.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('216d210e-ee66-41cc-a0de-2d7cd4aed630', 'marketplace', 'An open area in a town housing a public market.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a86bc0da-8f56-47fc-b6e8-6736e246bdaf', 'mask', 'A cover, or partial cover, for the face, used for disguise or protection.', 'a dancer''s mask; a fencer''s mask; a ball player''s mask', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c6aa3cf9-f78f-4f14-b7bc-451edece966e', 'massacre', 'The killing of a considerable number (usually limited to people) where little or no resistance can be made, with indiscriminate violence, without necessity, and contrary to civilized norms.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8b0d6d71-26cb-41fc-9895-bc2d58cb480f', 'mathematical', 'Of, or relating to mathematics', 'a mathematical problem', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('780ef423-c66d-4d46-a2bd-f7845293b3d3', 'mature', 'Fully developed; grown up in terms of physical appearance, behaviour or thinking; ripe.', 'She is quite mature for her age.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('5e46b9aa-4575-413a-a76c-dc23c57a0608', 'maximize', 'To make as large as possible', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f43f0b58-206b-41b2-8534-bb7428866ef7', 'meaningful', 'Having meaning, significant.', 'I think we made a meaningful contribution to this project today.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('04c2cd80-4ede-45e5-a84d-ac214a67cadb', 'meantime', 'The time spent waiting for another event; time in between.', 'I''ll get started tomorrow but, in the meantime, let''s see if we can get a few more opinions.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1583925d-01ab-44e4-9ca2-907181704103', 'medieval', 'Someone living in the Middle Ages.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c134982c-c8cb-4608-9684-d56820d96644', 'meditation', 'A devotional exercise of, or leading to contemplation.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('fc1e7ee0-583c-4ddb-bab2-fb3f74495228', 'melody', 'Tune; sequence of notes that makes up a musical phrase', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('14f7b9b4-3db7-42fb-813c-823adf293303', 'memo', 'A short note; a memorandum.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('48cb32af-b8b1-4a3d-8513-c57a23ccc757', 'memoir', 'An autobiography; a book describing the personal experiences of an author.', 'When I retire, I''m going to write my memoirs.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('075d2f22-2557-40ed-b77a-5048d8906fe7', 'memorial', 'Memory; recollection.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1d472690-4525-4feb-a555-6c86743fd9f8', 'mentor', 'A wise and trusted counselor or teacher', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c9bf81f1-49ca-445f-b20f-005a4da0b017', 'merchant', 'A person who traffics in commodities for profit.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('25d8f3ab-4d96-477b-896c-0aaf61123231', 'mercy', 'Relenting; forbearance to cause or allow harm to another.', 'She took mercy on him and quit embarrassing him.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('167a98c5-fd27-4544-afd0-f6036f16e954', 'mere', 'A body of standing water, such as a lake or a pond. More specifically, it can refer to a lake that is broad in relation to its depth. Also included in place names such as Windermere.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c5d45c08-fc5f-4c04-bfbd-813b68deb101', 'merely', 'Wholly, entirely.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('950911f6-4437-49d1-864d-720c8da89608', 'merge', 'The joining together of multiple sources.', 'The merge of the two documents failed.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e4c0689f-78bd-4077-888c-4701f34b5703', 'merit', 'A claim to commendation or a reward.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('14165e89-973a-41e6-a9a2-4db8081dafb4', 'midst', 'A place in the middle of something; may be used of a literal or metaphorical location.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ff04f0e6-4644-4296-8cca-cb13b4c6d8e3', 'migration', 'An instance of moving to live in another place for a while.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0221651f-3b38-49ae-89ff-dac723b0c0db', 'militant', 'A soldier, a combatant.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('883a9053-a6cf-4d21-9270-b35bc3de1c26', 'militia', 'An army of trained civilians, which may be an official reserve army, called upon in time of need, the entire able-bodied population of a state which may also be called upon, or a private force not under government control.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('41348ecd-66a0-4589-84d1-0b3baf4bd9a0', 'mill', 'A grinding apparatus for substances such as grains, seeds, etc.', 'Pepper has a stronger flavor when it is ground straight from a mill.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b166d1ec-631c-4ffa-99d3-a5c736eed9fa', 'minimal', 'The smallest possible amount, quantity, or degree.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b816301d-1d12-416b-a6e0-47aec3d4c090', 'minimize', 'To make (something) as small or as insignificant as possible.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3ecce3c5-4d7f-44e5-92e0-96ce3b134fb4', 'mining', 'To remove (ore) from the ground.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('669a28a5-9796-4528-bbd1-8eb28b10d977', 'ministry', 'Government department, at the administrative level normally headed by a minister (or equivalent rank, e.g. secretary of state), who holds it as portfolio, especially in a constitutional monarchy, but also as a polity', 'She works for the ministry of finance.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2abae82b-e81d-436b-b504-a308d09a53d4', 'miracle', 'An event that appears inexplicable by the laws of nature and so is held to be supernatural in origin.', 'An example of a miracle associated with Muhammad is the splitting of the moon.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b07765d2-6233-43a6-9af0-8ca5207be5ab', 'misery', 'Great unhappiness; extreme pain of body or mind; wretchedness; distress; woe.', 'Ever since his wife left him you can see the misery on his face.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9dcaa533-c96b-4c2b-8756-7ef60cadb2de', 'misleading', 'To lead astray, in a false direction.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('02baf058-aef7-44d9-a04e-ad83ed090bda', 'missile', 'Any object used as a weapon by being thrown or fired through the air, such as stone, arrow or bullet.', 'The Rhodians, who used leaden bullets, were able to project their missiles twice as far as the Persian slingers, who used large stones.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('94d401c1-abfa-4762-9a68-4ffea9aa4ba8', 'mob', 'A large or disorderly group of people; especially one bent on riotous or destructive action.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('5be64313-1902-43f1-84ff-517f4b4b20dc', 'mobility', 'The ability to move; capacity for movement.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f528f405-0ee2-4d9f-8d50-481df4b3efb2', 'mobilize', 'To make something mobile.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('fc123741-97e2-43cb-a857-007c0263f62e', 'moderate', 'One who holds an intermediate position between extremes, as in politics.', 'The moderates are the natural advocates of ecumenism against the fanatics of their churches.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e718c619-71b2-42a3-a2be-245f7a1ef5ce', 'modification', 'The form of existence belonging to a particular object, entity etc.; a mode of being.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('fc8cf209-189c-43a4-a98a-07c3b09b4464', 'momentum', 'Of a body in motion: the tendency of a body to maintain its inertial motion; the product of its mass and velocity.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a48dedb1-43fb-41ef-b48d-7c54e7a7c915', 'monk', 'A male member of a monastic order who has devoted his life for religious service.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('60868e45-3385-487c-8a1a-1434d023f926', 'monopoly', 'A situation, by legal privilege or other agreement, in which solely one party (company, cartel etc.) exclusively provides a particular product or service, dominating that market and generally exerting powerful control over it.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8911b5b0-5f84-49f2-8a4e-8dd0516369c9', 'morality', 'Recognition of the distinction between good and evil or between right and wrong; respect for and obedience to the rules of right conduct; the mental disposition or characteristic of behaving in a manner intended to produce morally good results.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d822e6e6-f7ba-4f9c-b6a7-a74eb15e4176', 'motive', 'An idea or communication that makes one want to act, especially from spiritual sources; a divine prompting.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7f6e6540-fa9f-4d2e-9350-7fb761000c06', 'motorist', 'One who drives a motor vehicle.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9ae39820-bd5d-409b-ae21-dec1a6055f79', 'municipal', 'A financial instrument issued by a municipality.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f129c4dc-67ba-4f40-9808-5ae07560af19', 'mutual', 'A mutual fund.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e17669ac-adf7-4945-a289-f773cd3cf4c8', 'namely', 'Specifically; that is to say.', 'Some of the students — namely Paul, Alice and Jake — seem to have trouble with geometry.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e916561f-be1f-4b00-9046-03cb3bb139b9', 'nationwide', 'Extending throughout an entire nation.', 'There was a nationwide search on for the bankrobbers.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('784942c7-8311-4837-ace9-1c6d635c172d', 'naval', 'Of or relating to a navy.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a6f357bf-a718-4447-a42a-5c6ae4e55ab7', 'neglect', 'The act of neglecting.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7a58a442-e47b-485b-a61e-174fafc5a974', 'neighbouring', 'Situated or living nearby or adjacent to.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('85ea30da-7b61-455e-b781-444e0b840d21', 'nest', 'A structure built by a bird as a place to incubate eggs and rear young.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8f6b8059-8781-47e3-9148-b8409316f203', 'newsletter', 'A periodically sent publication containing current events or the like, generally on a particular topic or geared toward a limited audience.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ce142843-6e4c-4960-bcf9-ffa94f525674', 'niche', 'A cavity, hollow, or recess, generally within the thickness of a wall, for a statue, bust, or other erect ornament. Hence, any similar position, literal or figurative.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('afbdc38a-73ab-4969-bb90-da73f32ba88f', 'noble', 'An aristocrat; one of aristocratic blood.', 'This country house was occupied by nobles in the 16th century.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a425ed5b-af1c-499f-a17a-480c56e8799a', 'nod', 'An instance of inclining the head up and down, as to indicate agreement, or as a cursory greeting.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b319404e-9bc8-4270-ae78-73b19c173b5e', 'nominate', 'To name someone as a candidate for a particular role or position, including that of an office.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6904a39a-5c3e-4ff0-832d-7f5ea62731d2', 'nomination', 'An act or instance of nominating.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c032b95c-9a97-4166-96f1-ac1f897ca153', 'nominee', 'A person named, or designated, by another, to any office, duty, or position; one nominated, or proposed, by others for office or for election to office.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('565bed93-68bd-46f2-87c3-e7c4cd0c7a97', 'non-profit', 'An organization that exists for reasons other than to make a profit, such as a charitable, educational or service organization.', 'Employees of a nonprofit rarely make as much as greedy counterparts in the commercial world.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('adfb0a71-2ce0-4f8a-bbab-d39e440a73c4', 'nonsense', 'Letters or words, in writing or speech, that have no meaning or pattern or seem to have no meaning.', 'After my father had a stroke, every time he tried to talk, it sounded like nonsense.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e67ae50b-cf1b-4bc4-b432-ff4e132a5894', 'noon', 'The ninth hour of the day counted from sunrise; around three o''clock in the afternoon.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c42cc9ea-0de3-4c32-833c-e05e7ebf3f45', 'notable', 'A person or thing of distinction.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('bc2f3f9b-4398-4f45-a007-322deea432ac', 'notably', '(focus) As a pointed example; in a notable manner.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e66936fb-f72e-4a3b-b570-cf04909f29c5', 'notify', 'To give (someone) notice (of some event).', 'Once a decision has been reached and notified to the parties it becomes binding.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('bba0a641-13b0-46fa-8821-c04a7c1c0563', 'notorious', 'Widely known, especially for something negative; infamous.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0669a8cf-cf72-4fe9-9263-2b01e44defda', 'nursery', 'A place where nursing or the raising of children is carried on.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('facadda6-e965-4fa7-8470-1a4c862fc5f8', 'objection', 'The act of objecting.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('db5ead15-6a8f-42ca-9360-bbaef05bc0af', 'oblige', 'To constrain someone by force or by social, moral or legal means.', 'I am obliged to report to the police station every week.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ba532a43-82ae-4c45-8afa-d395aae7c8e9', 'obsess', '(passive, constructed with "with") To be preoccupied with a single topic or emotion.', 'Some people are obsessed with sports.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2c1ce493-2708-43fb-8561-ad45155ccaf1', 'obsession', 'A compulsive or irrational preoccupation.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a6bf7c8c-d150-4309-bf55-9dde7515bc3a', 'occasional', 'A person who does something only occasionally.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2101556d-4aee-42af-a68a-537c894525a8', 'occurrence', 'An actual instance when a situation occurs; an event or happening.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('fbfd7591-15d0-4bb4-a1d5-816acd3e1731', 'odds', '(diminutive) An odd number.', 'So let''s see. There are two evens here and three odds.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0798f190-9389-4e30-a37f-92206a6ef5fb', 'offering', 'To propose or express one''s willingness (to do something).', 'She offered to help with her homework.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('750217a6-57bb-4d6f-860e-abe7f81bdad4', 'offspring', 'A person''s daughter(s) and/or son(s); a person''s children.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ccd21cd9-ee38-4fec-87ae-dbd615c92e55', 'operational', 'Of or relating to operations, especially military operations.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4898aa3c-c623-4be8-9619-e5d8b48290cc', 'opt', 'To choose; select.', 'He opted not to go.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e7f82ac3-8f31-4a63-9a95-63da9fab3dd0', 'optical', 'Of, or relating to sight; visual.', 'Strabismus is an optical defect.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9b4b3adf-8771-46cc-92ba-b3d16c9be5ec', 'ratio', 'A number representing a comparison between two named things.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('744b74d5-17da-49ae-82c2-d2ba31900403', 'optimism', 'A tendency to expect the best, or at least, a favourable outcome', 'I love her youth, her beauty and above all her optimism that everything will turn out fine.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('18959748-6fba-45d7-b259-ebe1c18685f8', 'oral', 'A spoken test or examination, particularly in a language class.', 'We''ve got our Spanish oral tomorrow.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('307b163f-e6ad-4877-b914-f0d1cdbc5bc6', 'organizational', 'Of, relating to, or produced by an organization.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('880959c3-1211-459a-ab39-a9c4855846b4', 'orientation', 'The determination of the relative position of something or someone.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4f28d93a-16d0-40e8-a93b-01f4b82ff08d', 'originate', 'To cause to be, to bring into existence; to produce, initiate.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('82652114-f9db-4fe3-8e52-596985edd89b', 'outbreak', 'An eruption; the sudden appearance of a rash, disease, etc.', 'Any epidemic outbreak causes understandable panic.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6c8959c4-68bd-4d21-a562-3573b1189f31', 'outing', 'To eject; to expel.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('565eed17-37b1-426a-8df2-5eebb6c35b78', 'outlet', 'A vent or similar passage to allow the escape of something.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('68a66620-d632-46fb-a616-ea0026c6206a', 'outlook', 'A place from which something can be viewed.', 'Perched on the edge of the cliff was a hidden outlook.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('727702fd-2e7f-4b31-ba03-774621b81193', 'outrage', 'An excessively violent or vicious attack; an atrocity.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4fee8000-8c12-4748-846a-53a4f2a91efd', 'outsider', 'One who is not part of a community or organization.', 'While the initiated easily understand the symbols, they are wholly inaccessible to outsiders.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('107b39e5-a750-400e-8982-ca8fb94e5dd3', 'overlook', 'A vista or point that gives a beautiful view.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a4857a1d-8b5f-459a-88b3-e6d5b58581a7', 'overly', 'Superficial; not thorough; careless, negligent, inattentive.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c472788e-deb1-49da-9488-fa960fee88d2', 'oversee', 'To survey, look at something in a wide angle.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('847ed776-8c60-44cc-abd9-475c53d0acd1', 'overturn', 'A turning over or upside-down; inversion.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7c8425aa-0ee1-4336-94a2-1b2621c5906c', 'overwhelm', 'The state or condition of being overwhelmed.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('54e0e811-d15d-431c-84ba-41a3c68aff3c', 'overwhelming', 'To engulf, surge over and submerge.', 'The dinghy was overwhelmed by the great wave.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('afee1f74-df96-462f-9153-27264e13135d', 'pad', 'A flattened mass of anything soft, to sit or lie on.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0cf02cb7-c14f-404d-a108-9ab9e3d5b9dc', 'parameter', 'A value kept constant during an experiment, equation, calculation or similar, but varied over other versions of the experiment, equation, calculation, etc.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6991f70f-3d5e-4d43-80cf-bb251b9116ad', 'parental', 'A person fulfilling a parental role.', 'Nowadays there are all kinds of potential parentals besides parents, grandparents, aunts and uncles, step-parents, in-laws, older siblings and cousins, and those in civil unions.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3eb54084-f67b-46b1-945b-f6af08c51e36', 'parish', 'In the Anglican, Eastern Orthodox, Lutheran and Roman Catholic Church, an administrative part of a diocese that has its own church.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f58281a4-4922-4ef6-9a4c-f1eb199f356f', 'parliamentary', 'A parliamentary train.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('06dc2e1d-9f3c-4564-8d88-6d2b1a8cc9e2', 'partial', 'A partial derivative: a derivative with respect to one independent variable of a function in multiple variables while holding the other variables constant.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('98dc030e-f487-449a-a6bf-9854a62ab0c0', 'partially', 'To a partial degree or extent, incompletely.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e5780f4f-8479-4aa3-a29a-43cbf41f7216', 'passing', 'To change place.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7e45b647-d27b-47fd-be48-7fe99ac4025a', 'passive', '(grammar) The passive voice of verbs.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('67e475ed-26f0-4d61-9af6-96e5130da4d7', 'pastor', 'A shepherd; someone who tends to a flock of animals.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ac1212b5-0e2a-42f9-a8ae-983f486d0546', 'patch', 'A piece of cloth, or other suitable material, sewed or otherwise fixed upon a garment to repair or strengthen it, especially upon an old garment to cover a hole.', 'His sleeves had patches on the elbows where different fabric had been sewn on to replace material that had worn away.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('13136230-956f-4f0e-93cb-266945fbfd05', 'patent', 'A declaration issued by a government agency declaring someone the inventor of a new invention and having the privilege of stopping others from making, using or selling the claimed invention; a letter patent.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a30f47ca-ecf5-42e2-99e3-8b95df7d57fe', 'pathway', 'A footpath or other path or track.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9061d922-32a0-4007-894f-0618a319ad04', 'patrol', 'A going of the rounds along the chain of sentinels and between the posts, by a guard, usually consisting of three or four men, to insure greater security from attacks on the outposts.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('715b2f33-a5f3-4012-aea8-c80869f0cfcb', 'patron', 'One who protects or supports; a defender or advocate.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1418a2fb-3139-4821-8dad-bc34d58577bc', 'peak', 'A point; the sharp end or top of anything that terminates in a point; as, the peak, or front, of a cap.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3b274fdf-365a-430b-ae97-de022812be97', 'peasant', 'A member of the lowly social class that toils on the land, constituted by small farmers and tenants, sharecroppers, farmhands and other laborers on the land where they form the main labor force in agriculture and horticulture.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b3a9b5d4-40da-4a5f-ab2b-feafc2091fd2', 'peculiar', 'That which is peculiar; a sole or exclusive property; a prerogative; a characteristic.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7f2e48b7-3d22-445d-b322-9f08582115fc', 'persist', 'To go on stubbornly or resolutely.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9555bae9-7e7c-48b0-b907-aafa9210536b', 'persistent', 'Obstinately refusing to give up or let go.', 'She has had a persistent cough for weeks.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d696b494-2459-412b-9e5b-420515e7cce5', 'personnel', 'Employees; office staff.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f1ae437a-c7ca-4847-92b3-fee8c71835a8', 'petition', 'A formal, written request made to an official person or organized body, often containing many signatures.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c55ce836-9d18-4914-bf41-df34a9c3de63', 'philosopher', 'A lover of wisdom.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3ca33532-90c3-42c6-b3e8-5f29452cbd2e', 'philosophical', 'Of, or pertaining to, philosophy.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c1c7339d-ffb2-4004-aafd-41af4345afb2', 'physician', 'A practitioner of physic, i.e. a specialist in internal medicine, especially as opposed to a surgeon; a practitioner who treats with medication rather than with surgery.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6cc8ea93-c98a-4b57-8a36-0bb30e8dd127', 'pioneer', 'One who goes before, as into the wilderness, preparing the way for others to follow.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('bac5b2ae-3cc9-49fc-8a36-f7bbd77512f6', 'pipeline', 'A conduit made of pipes used to convey water, gas or petroleum etc.', 'An oil pipeline has been opened from the Caspian Sea.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e0d8047c-6aa9-470c-9102-5b2692fa57e9', 'pirate', 'A criminal who plunders at sea; commonly attacking merchant vessels, though often pillaging port towns.', 'You should be cautious due to the Somali pirates.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6bdf7ecd-d190-4e20-a5f8-63276fbcbd22', 'pit', 'A hole in the ground.', 'The meadow around the town is full of old pits.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1e168f7a-c0ae-43f6-954c-050a7d04aa5e', 'plea', 'An appeal, petition, urgent prayer or entreaty.', 'a plea for mercy', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6ea0589d-7e5c-4938-bede-f58e3be3763f', 'plead', 'To present (an argument or a plea), especially in a legal case.', 'The defendant has decided to plead not guilty.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3cc93fe3-51a5-47b2-ba7f-8c1296ee3a0b', 'pledge', 'A solemn promise to do something.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1852fd78-b730-4df5-8cc0-b8fbd199b369', 'plug', 'A pronged connecting device which fits into a mating socket, especially an electrical one.', 'I pushed the plug back into the electrical socket and the lamp began to glow again.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7e87619f-5c80-4042-b799-73dff20aca71', 'plunge', 'The act of plunging or submerging', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c5418de8-fad1-41db-8f7d-3612c4d3f210', 'pole', 'Originally, a stick; now specifically, a long and slender piece of metal or (especially) wood, used for various construction or support purposes.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8bb1ff52-d9b9-4868-8c29-8fc0e0ebab16', 'poll', 'A survey of people, usually statistically analyzed to gauge wider public opinion.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d2ff9e07-74a8-441d-94c9-d4eb7a2b3ecc', 'pond', 'An inland body of standing water, either natural or man-made, that is smaller than a lake.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f83d4105-eabd-4266-9e7a-c5aa364a2832', 'portray', 'To paint or draw the likeness of.', 'I will portray a king on horseback.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f1da85a2-c423-4794-af41-3c7d3dc9524e', 'post-war', 'Pertaining to a period of time immediately following the end of a war; where there is a cessation of conflict.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('86c5aeff-374d-48c5-97d3-5ff6d36584a9', 'postpone', 'To delay or put off an event, appointment etc.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d541101c-e34c-43a3-a129-85c2a33d6442', 'practitioner', 'A person who practices a profession or art, especially law or medicine.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('19a52ee8-d419-4c8f-9f89-f402840332b9', 'preach', 'A religious discourse.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0442f5a7-6449-42f4-ae30-e01664c649f8', 'precedent', 'An act in the past which may be used as an example to help decide the outcome of similar instances in the future.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f86187fa-39b9-4ca9-b54f-0cf578a3efbb', 'precision', 'The state of being precise or exact; exactness.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('bd2d1054-1767-4e04-83e0-762dd6940b58', 'predator', 'Any animal or other organism that hunts and kills other organisms (their prey), primarily for food.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0e69a95d-4aba-4af6-88a2-56c055306516', 'predecessor', 'One who precedes; one who has preceded another in any state, position, office, etc.; one whom another follows or comes after, in any office or position.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9038d215-f51b-4fdb-8ca2-2e0858ef2620', 'predominantly', 'In a predominant manner. Most commonly or frequently by a large margin.', 'The membership is predominantly elderly, 90% are over age 60.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('bdef1b97-a069-4fa5-b541-cebc3df96ddf', 'pregnancy', 'The condition of being pregnant.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e526aae5-7c31-4c1a-8052-7617158aeb8c', 'preliminary', 'A preparation for a main matter; an introduction.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b6b3af7f-90b2-4e7e-b776-05f7f74176c7', 'premier', '(Westminster system) The head of government in parliament and leader of the cabinet.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('034cdc81-a661-4d43-bbe1-8d4817e97632', 'premise', 'A proposition antecedently supposed or proved; something previously stated or assumed as the basis of further argument; a condition; a supposition.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0517189e-6a33-4d12-88a8-299fa79099aa', 'premium', 'A prize or award.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('5f319ec0-4c5f-449a-abbf-0321927fff7a', 'prescribe', 'To order (a drug or medical device) for use by a particular patient (under licensed authority).', 'The doctor prescribed aspirin.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e3a53643-61e4-4f44-b7bb-668509aff3ea', 'presently', 'Immediately, at once; quickly.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b6129372-f854-4417-b4a2-19f9ca9ad460', 'preservation', 'The act of preserving; care to preserve; act of keeping from destruction, decay or any ill.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('227e9029-ed9b-4673-8d9d-36d71e1ded9b', 'preside', 'To act as president or chairperson.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('38db69e1-e0e6-478d-9612-3bc18f566bce', 'presidency', 'The office or role of president.', 'After many years as a party leader, she finally ascended to the presidency.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('364dafba-d975-4bba-bab0-c61ebb3ce5fa', 'presidential', 'Pertaining to a president or presidency.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('86d9237d-ea5a-45a5-aca4-e8b92187f3cf', 'prestigious', 'Of high prestige.', 'She has a prestigious job with an international organization.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('26a89a84-bcb1-4b9c-a8e5-90ae619c0511', 'presumably', 'Able to be sensibly presumed', 'Presumably, he will attend the opening.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('73722bfb-3df2-477c-8fbd-51224e739a4e', 'presume', 'With infinitive object: to be so presumptuous as (to do something) without proper authority or permission.', 'I wouldn''t presume to tell him how to do his job.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c47bfcf1-4019-4d8a-9b5b-2069f80320af', 'prevail', 'To be superior in strength, dominance, influence or frequency; to have or gain the advantage over others; to have the upper hand; to outnumber others.', 'Red colour prevails in the Canadian flag.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e00a0f27-9803-4142-8bc3-5d7075238b23', 'prevalence', 'The quality or condition of being prevalent; wide extension or spread.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4f284364-e2ca-49a9-98f8-68362fca335d', 'residence', 'The place where one lives; one''s home.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('bbbf7b63-a5b8-44c8-98b5-b805a2caff53', 'prevention', 'The act of preventing or hindering; obstruction of action, access, or approach; thwarting.', 'a fire prevention campaign', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('649b93dc-e7d8-4953-b6ff-20fe6750b977', 'prey', 'Anything, as goods, etc., taken or got by violence; anything taken by force from an enemy in war', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('411eeebb-3af9-426c-a351-f75777e0c50a', 'privilege', '(ecclesiastical law) An exemption from certain laws granted by the Pope.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('5e24d26a-2db5-42c4-9ce6-b1f2711db24e', 'probe', 'Any of various medical instruments used to explore wounds, organs, etc.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('54f898b7-991d-4a57-9388-2c80642e8c66', 'problematic', '(chiefly in the plural) A problem or difficulty in a particular field of study.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2998ced1-e2c7-439e-8544-d2c5942e6ed7', 'proceeding', 'To move, pass, or go forward or onward; to advance; to carry on', 'To proceed on a journey.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('5b56eb2d-75a9-4efe-8c00-93b3c09c23ec', 'proceeds', 'To move, pass, or go forward or onward; to advance; to carry on', 'To proceed on a journey.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('53807d7b-5238-47ea-8ed1-e61b6f9838bf', 'processing', 'To perform a particular process on a thing.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('87c8bd68-df04-46eb-be43-b0be98687986', 'processor', 'A person or institution who processes things (foods, photos, applications, etc.).', 'He is a loan processor with a bank.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4b1387d7-beee-4557-8a3d-40f6c7b2bf7c', 'proclaim', 'To announce or declare.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9e742ac9-ee37-4a55-9800-b9aa2886758b', 'productive', 'Capable of producing something, especially in abundance; fertile.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('81746b78-1c62-41ea-b1d4-f72c83b30d7a', 'productivity', 'The state of being productive, fertile or efficient', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8dacf057-4517-4ff1-ada9-4135f1197065', 'profitable', 'Producing a profit.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('deac5b80-7be6-4a6e-8ede-d126ad3ce772', 'profound', 'The deep; the sea; the ocean.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('fe5438c6-885e-489e-a5eb-6106880cdd33', 'projection', 'Something which projects, protrudes, juts out, sticks out, or stands out.', 'The face of the cliff had many projections that were big enough for birds to nest on.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3cee04ee-ad8e-4924-a928-55857c83c76e', 'prominent', 'Standing out, or projecting; jutting; protuberant', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('dfbbf226-7b0c-4f1e-9a34-f4e567b28674', 'pronounced', 'To declare formally, officially or ceremoniously.', 'I hereby pronounce you man and wife.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ab3e3970-d234-480a-b9be-f5fa5e080c78', 'proposition', 'The act of offering (an idea) for consideration.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0f2cea1a-2c57-4cff-a588-9a5757e7d425', 'prosecute', 'To start criminal proceedings against.', 'to prosecute a man for trespass, or for a riot', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c4fe706a-10fc-44a6-bed1-540ef7679ba5', 'prosecutor', 'A prosecuting attorney.', 'Annie Jay was the Wisconsin government prosecutor in the trial of a man for forging his client''s signature.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('331fc4bb-585b-4121-8b24-2c7bcbf68a42', 'prospective', 'The scene before or around, in time or in space; view; prospect.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ff8e09cd-8089-41fc-a5ca-ec1b19a7a3d0', 'prosperity', 'The condition of being prosperous, of having good fortune', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('744e70a0-05e0-4219-bb8d-253a439d94d3', 'protective', 'Something that protects.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b87473f8-42a9-4d53-ae2a-874ee3d556d2', 'protocol', 'The minutes, or official record, of a negotiation or transaction; especially a document drawn up officially which forms the legal basis for subsequent agreements based on it.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f8c8f6a6-8b01-45f2-9bab-1810e93f17d1', 'province', 'A region of the earth or of a continent; a district or country.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('354bee36-0896-4159-9787-8df07322213f', 'provincial', 'A person belonging to a province; one who is provincial.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('361e932c-209c-4bb0-a447-359ffa609930', 'provision', 'An item of goods or supplies, especially food, obtained for future use.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('5f886a8c-c087-4c99-9719-6d4338d32c64', 'provoke', 'To cause someone to become annoyed or angry.', 'Don''t provoke the dog; it may try to bite you.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8851c2f6-09a0-4d30-adef-6472d57a882b', 'psychiatric', 'Of, or relating to, psychiatry.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b85e407e-5222-4b62-a676-b480f4c5f432', 'pulse', 'A normally regular beat felt when arteries are depressed, caused by the pumping action of the heart.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('746a751d-a519-47f0-8c51-496549aa1716', 'pump', 'A device for moving or compressing a liquid or gas.', 'This pump can deliver 100 gallons of water per minute.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('424e5bb4-7ab8-4929-b30c-fcb7bb2d2218', 'punch', 'A hit or strike with one''s fist.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ec59d588-cc40-43b4-ae23-053e9509950a', 'query', 'A question, an inquiry (US), an enquiry (UK).', 'The teacher answered the student’s query concerning biosynthesis.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3e5ca792-ac6e-4787-ab1a-c1257f2387fb', 'quest', 'A journey or effort in pursuit of a goal (often lengthy, ambitious, or fervent); a mission.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('39cf2c54-4e8b-439d-9e37-65b9d5b5e499', 'quota', 'A proportional part or share; the share or proportion assigned to each in a division.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('da911d7b-cb5c-43aa-8b5f-f1aa442bd9f9', 'radar', 'A method of detecting distant objects and determining their position, velocity, or other characteristics by analysis of sent radio waves (usually microwaves) reflected from their surfaces', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a97e41d2-0a86-4caa-a2a0-962493fd3c01', 'radical', '(historical: 19th-century Britain) A member of the most progressive wing of the Liberal Party; someone favouring social reform (but generally stopping short of socialism).', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('75f9fe43-f615-4fbd-9ef9-99d99a2f236f', 'rage', 'Violent uncontrolled anger.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f38b8db4-925d-4231-bafe-902a8fa385d7', 'raid', 'A quick hostile or predatory incursion or invasion in a battle.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('072406a3-9eb9-4bbe-a4f9-4cd2fdb08e4b', 'rally', 'A public gathering or mass meeting that is not mainly a protest and is organized to inspire enthusiasm for a cause.', 'a campaign rally', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4e6f7a8f-018a-432e-a0cc-4b43c2632d0f', 'rational', 'A rational number: a number that can be expressed as the quotient of two integers.', 'The quotient of two rationals is again a rational.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1116951b-b837-46ca-b52b-67cb34207c60', 'ray', 'A beam of light or radiation.', 'I saw a ray of light through the clouds.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('38cfd228-7d77-484b-9831-5a18d9fc7cde', 'readily', 'Without unwillingness or hesitation; showing readiness.', 'The suspect readily answered all questions the police officers asked him.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2b811607-3ae4-4fc2-b806-2607ab7d8329', 'realization', 'The act of realizing.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('bfb882c0-ca4e-4bbc-9c76-ea31540564c1', 'realm', 'An abstract sphere of influence, real or imagined.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f54aacf8-7369-46f5-b757-d264c3c3b984', 'rear', 'To bring up to maturity, as offspring; to educate; to instruct; to foster.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8e8f2340-8179-49e3-b8f4-c1237fdfa584', 'reasoning', 'To deduce or come to a conclusion by being rational', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0cd407ad-7142-46ec-a986-c9b835c620a6', 'reassure', 'To assure anew; to restore confidence to; to free from fear or self-doubt.', 'The boy''s mother reassured him that there was no monster hiding under the bed.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('56bb8e5d-34c1-43d5-ac7b-94c50380b0e7', 'rebel', 'A person who resists an established authority, often violently', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6a33d99c-9b64-46b8-8ca6-39b60aa81ecf', 'rebellion', 'Armed resistance to an established government or ruler.', 'The government is doing its best to stop rebellion in the country.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0fc3cf01-5c9c-4131-b4c9-f020610e9add', 'recipient', 'One who receives.', 'My e-mail never reached the intended recipient.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('38d2726a-88e5-4380-aa91-cce5dccce805', 'reconstruction', 'A thing that has been reconstructed or restored to an earlier state.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ce90442d-df44-4c6b-83c3-a829e4899a8e', 'recount', 'Narration, account, description, rendering', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ca03e7c1-fbf4-4d50-9348-7f57cdf56ba5', 'reflection', 'The act of reflecting or the state of being reflected.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4790d01d-610c-40b0-88eb-69c147c8701e', 'reform', 'The change of something that is defective, broken, inefficient or otherwise negative, in order to correct or improve it', 'A major reform is needed to improve the efficiency in the factory.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3ad7c764-f992-4fab-ab73-1cbbabbc0687', 'refuge', 'A state of safety, protection or shelter.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3fc28494-452d-46a8-b41d-8d493198183a', 'refusal', 'The act of refusing.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('42ab2d35-b614-468c-ab06-04d4fc5479b0', 'regain', 'To get back; to recover possession of.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0433525c-b049-422f-88d7-10b1479d620b', 'regardless', 'Having no regard; heedless; careless.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('13e2d716-e694-438d-b697-82bf018300a1', 'regime', 'Mode of rule or management.', 'a prison regime', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('60dfcbe1-ba1f-4026-bbf3-d8a7ea1c4ede', 'regulator', 'A device that controls or limits something.', 'The voltage regulator stopped working and the resulting overload destroyed the device.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('93894342-dbd6-4ebc-99cf-984c0a4bd256', 'regulatory', 'Of or pertaining to regulation.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8771a665-c184-4d55-bca9-3e1a29a7da4e', 'reign', 'The exercise of sovereign power.', 'England prospered under Elizabeth I''s reign.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f1282d00-5648-4f84-a9cc-f2a52f6c9ede', 'rejection', 'The act of rejecting.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4a0c1223-d801-45e7-b302-5ea0f2484ae0', 'relevance', 'The property or state of being relevant or pertinent.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b311d792-5624-4753-9f32-198066147f01', 'reliability', 'The quality of being reliable, dependable or trustworthy.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('27183115-600b-4588-9773-536017f37156', 'reluctant', 'Opposing; offering resistance (to).', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f83548f8-67f0-4fe4-b6e5-6c4e3417bc2e', 'remainder', 'A part or parts remaining after some has/have been removed.', 'My son ate part of his cake and I ate the remainder.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('fe7814e6-0646-402b-9018-b265c9f7a0d8', 'remains', '(chiefly in the plural) That which is left; relic; remainder.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('66cf7baf-0718-4660-8aca-9928e9b25e25', 'remedy', 'Something that corrects or counteracts.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d0008771-6be7-4ef8-9ee9-11d929446334', 'reminder', 'Someone or something that reminds.', 'He left a note as a reminder to get groceries.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c2b38ff1-7ee3-4068-ada8-5e6bf3c35a03', 'removal', 'The process of moving, or the fact of being removed.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a28ba16b-2b44-452d-8a11-dd7b8e6835c5', 'render', 'Stucco or plaster applied to walls (mostly to outside masonry walls).', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ba61db40-2864-4e5b-b8a3-b2cdedd24e7f', 'renew', 'To make (something) new again; to restore to freshness or original condition.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('96f5a963-27f1-4767-b90b-3c3a7da08c0f', 'renowned', 'Famous, celebrated, or well-known.', 'The movie “Three Stars” is about world-renowned chefs.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('5dbe3905-af30-429e-a87f-6885672d8cda', 'rental', 'Something that is rented.', 'It''s just a rental, so I don''t need to take very good care of it.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('fbf2442d-a2d5-4a20-881d-31beda026ac2', 'replacement', 'A person or thing that takes the place of another; a substitute.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('5dbdab5f-2b2c-442d-b00f-1acb10aac709', 'reportedly', 'According to reports or rumors; supposedly.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('35ad4b51-28a0-4825-9109-091a9373c310', 'representation', 'That which represents something else.', 'The Venus of Willendorf was an early representation of the female body.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('faa0f129-14a9-44b1-9ce4-6a872f39360f', 'reproduce', 'To produce an image or copy of.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a897c77e-eb6c-481d-9301-677057d5276b', 'reproduction', 'The act of reproducing new individuals biologically.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f78ce9dd-f720-42b7-a256-dc8dab9720fd', 'republic', 'A state where sovereignty rests with the people or their representatives, rather than with a monarch or emperor; a country with no monarchy.', 'The United States is a republic; the United Kingdom of Great Britain and Northern Ireland is a constitutional monarchy.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f1852e41-8144-48a1-9080-85262618c60d', 'resemble', 'To be like or similar to (something); to represent as similar.', 'The twins resemble each other.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f55f5c99-0ec2-43ba-bbfb-93c4877748d6', 'reside', 'To dwell permanently or for a considerable time; to have a settled abode for a time; to remain for a long time.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('aea82cc1-4e4b-4348-ac8a-7454575d5892', 'residential', 'A trip during which people temporarily live together.', 'The youth group organises annual residentials.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d7e2a1d9-7655-4500-ab2d-2f003e6e9522', 'residue', 'Whatever remains after something else has been removed.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7c360c05-bad5-4e74-820a-1db7710a9cc6', 'resignation', 'The act of resigning.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0ac72558-4f79-45bb-968e-ffe13fdea330', 'resistance', 'The act of resisting, or the capacity to resist.', 'the resistance of bacteria to certain antibiotics', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e4e6df9f-5808-40e3-b2d9-df7d8a5c414e', 'respective', 'Relating to particular persons or things, each to each; particular; own.', 'They returned to their respective places of abode.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('825617fd-7c37-4f28-aabb-6a169cc5971b', 'respectively', 'In a relative manner; often used when comparing lists, where the term denotes that the items in the lists correspond to each other in the order they are given.', 'Serena Williams and Roger Federer won the women''s and men''s singles titles, respectively, at the 2010 Australian Open.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('cfcff4b3-92c7-4233-bb17-ebf7fb82d932', 'restoration', 'The process of bringing an object back to its original state; the process of restoring something.', 'The restoration of this medieval church involved undoing all the Victorian modifications.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a98abd3c-2ca6-493e-b37c-517356f9f1ce', 'restraint', 'Something that restrains, ties, fastens or secures', 'Make sure all the restraints are tight.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('41fe0056-38dd-492b-b32a-b4cb6b14d09d', 'resume', 'To take back possession of (something).', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7cdb29db-f914-4b85-b0d8-6e7a773c80ca', 'retreat', 'The act of pulling back or withdrawing, as from something dangerous, or unpleasant.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f25874b8-b732-48e9-b281-28c9bb15346a', 'retrieve', 'A retrieval', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c0e650f1-39ce-4ed5-8076-856b0ddf23b0', 'revelation', 'The act of revealing or disclosing.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ecfdc02c-5d88-4b24-8dd6-1f54aa46f9ea', 'revenge', 'Any form of personal retaliatory action against an individual, institution, or group for some alleged or perceived harm or injustice.', 'Indifference is the sweetest revenge.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('afadee4e-424e-405d-9a60-e7c712745dd3', 'reverse', 'The opposite of something.', 'We believed the Chinese weren''t ready for us. In fact, the reverse was true.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ec2f97ef-358e-4619-9a45-e7f04f5549e1', 'revival', 'The act of reviving, or the state of being revived', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e2291a4c-21ae-4644-9d7f-79e850868d3b', 'revive', 'To return to life; to become reanimated or reinvigorated.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('60be080a-1be4-41fd-976d-055e8d9ebcbe', 'revolutionary', 'A revolutionist; a person who revolts.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7ae078fd-3d76-456d-ae02-763951b172fe', 'rifle', 'A shouldered firearm with a long, rifled barrel to improve range and accuracy.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('28279a88-38da-426d-b586-de63b05e70df', 'riot', 'Wanton or unrestrained behavior; uproar; tumult.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ed08665e-5e22-4be9-9c57-a8b7f40c625d', 'rip', 'A tear (in paper, etc.).', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7e544273-ae47-43b3-9f4b-2a411a4a929b', 'ritual', 'Rite; a repeated set of actions', 'They carried out the ritual carefully.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('889417ba-02b2-46fc-bf3b-25b0a42672af', 'robust', 'Evincing strength and health; strong.', 'A robust wall was put up.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('19885685-4c84-4e2e-ae4f-b0d5dce0c4da', 'rod', 'A straight, round stick, shaft, bar, cane, or staff.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('fdd05884-0a49-4588-abf4-1957b2dbc049', 'rotate', 'To spin, turn, or revolve.', 'He rotated in his chair to face me.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('40cfe76e-a014-43d4-a817-bc36445bcdf8', 'rotation', 'The act of turning around a centre or an axis.', 'The earth''s rotation about its axis is responsible for its being slightly oblate rather than a sphere.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f5f011a5-9f27-4a9c-a7f5-a137fd285c98', 'ruling', 'To regulate, be in charge of, make decisions for, reign over.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d71c0ae7-f21f-457e-94cc-cd3760a50cb3', 'rumour', 'A statement or claim of questionable accuracy, from no known reliable source, usually spread by word of mouth.', 'There''s a rumor going round that he''s going to get married.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('75fb595b-5db7-47c0-add8-84cd400c60b7', 'sack', 'A bag; especially a large bag of strong, coarse material for storage and handling of various commodities, such as potatoes, coal, coffee; or, a bag with handles used at a supermarket, a grocery sack; or, a small bag for small items, a satchel.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1ce577c0-bb08-4c8b-81c6-f684455725ce', 'sacred', 'Characterized by solemn religious ceremony or religious use, especially, in a positive sense; consecrated, made holy.', 'a sacred day', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d880a42f-e0b1-4ac3-8eb7-cfbc8f8257ef', 'sacrifice', 'The offering of anything to a god; a consecratory rite.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8e4713f7-cd4e-4226-8cc8-bfad98354965', 'saint', 'A person whom a church or another religious group has officially recognised as especially holy or godly; one eminent for piety and virtue.', 'Kateri Tekakwitha was proclaimed a saint.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('bdff8a7e-c17c-4ec6-b277-cab0f325b515', 'sake', 'Cause, interest or account', 'For the sake of argument', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c89f6823-8bdb-4f1b-8459-aac8be540fa4', 'sanction', 'An approval, by an authority, generally one that makes something valid.', 'The whalers had been operating in the contested waters off the island with sanction from the Japanese government.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('12ae326e-1666-4066-9280-ec8b93c28499', 'scattered', 'To (cause to) separate and go in different directions; to disperse.', 'The crowd scattered in terror.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9932456f-1d08-4b35-bc92-89d936626492', 'sceptical', 'Having, or expressing doubt; questioning.', 'I can see why people are so skeptical [sic] about him, but I think he''s on to something here. (regarded by organizations such as the BBC as an error)', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('5293bbdf-a34f-4adb-9170-4af567497ae9', 'scope', 'The breadth, depth or reach of a subject; a domain.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6247977c-d6a1-4720-9a15-0f3590c793fc', 'screw', 'A device that has a helical function.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f7605696-2563-47f4-93d3-ead52e868469', 'scrutiny', 'Intense study of someone or something.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('563a730b-6a71-4c51-86d3-9b6c567fadde', 'seal', 'A pinniped (Pinnipedia), particularly an earless seal (true seal) or eared seal.', 'The seals in the harbor looked better than they smelled.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('80a9b589-ebd8-42af-99b7-ac2aafd472cc', 'secular', 'A secular ecclesiastic, or one not bound by monastic rules.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f1aaf2f6-351b-4ca2-9455-1503977b11aa', 'seemingly', 'As it appears; apparently.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('bfef172c-c670-4183-9a78-93780f683ab5', 'seize', 'To deliberately take hold of; to grab or capture.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('fe72e8d6-11bd-4db4-9a03-f1e746d4b52d', 'seldom', 'Rare; infrequent.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8d9a8eed-1556-4c6a-be1b-6dcaf273d754', 'selective', 'Of or relating to the process of selection.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('57b97c76-7ef0-4533-b9da-2693d2e4c862', 'senator', 'A member, normally elected, in the house or chamber of a legislature called a senate. The legislatures of the United States and Canada have senators.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ba8e76e3-be2a-49b5-beb5-3dabf260947e', 'sensation', 'A physical feeling or perception from something that comes into contact with the body; something sensed.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('29fe628d-e14e-4109-bb17-80bea9bf0d8d', 'sensitivity', 'The quality or state of being sensitive; sensitiveness.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b552193e-a1fe-4f97-89ce-5b347dd28554', 'sentiment', 'A general thought, feeling, or sense.', 'The sentiment emerged that we were acting too soon.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9c8b97ed-b676-41d5-b5e3-9a34f8231ab5', 'separation', 'The act of disuniting two or more things, or the condition of being separated.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('bd9ae3b7-88de-4a1e-9169-d663a484f9eb', 'serial', 'A work, such as a work of fiction, published in installments, often numbered and without a specified end.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2d751591-e999-40b9-8364-e758d17505c3', 'set-up', 'Equipment designed for a particular purpose; an apparatus.', 'The laboratory included an elaborate setup for measuring the energy.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6f7f5793-cde6-4afa-a4ad-4e4859dccb89', 'settlement', 'The act of settling.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('cea53d65-7f25-4ba2-bf92-639fb02b9950', 'sexuality', 'The quality of being sexual; that which is characterized or distinguished by sex.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d15eb0dd-2729-45be-817f-263061f34dda', 'shareholder', 'One who owns shares of stock in a corporation.', 'Shareholders are the real owners of a publicly traded business, but management runs it.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('dd15c0e8-02b6-46e1-86e2-93ebf2a1f5a6', 'shatter', 'A fragment of anything shattered.', 'to break a glass into shatters', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2e21b35c-b558-4429-97b6-c34fc3923542', 'shed', 'To part, separate or divide.', 'A metal comb shed her golden hair.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f3ea41f4-910d-44e6-be8a-e0cd9f97301e', 'sheer', 'A sheer curtain or fabric.', 'Use sheers to maximize natural light.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f03eba26-abe5-49bc-b792-e20a76194340', 'shipping', 'The transportation of goods.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('820f9d10-ccd2-4eaa-a4ad-0cf7bb5c5a22', 'shrink', 'Shrinkage; contraction; recoil.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('bf06a4d1-7519-4309-9f1b-d157af558f73', 'shrug', 'A lifting of the shoulders to signal indifference or a casual lack of knowledge.', 'He dismissed my comment with a shrug.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b4274626-cc31-40e3-9053-b0aa63bc7688', 'sigh', 'A deep, prolonged audible inhale and exhale of breath; as when fatigued, frustrated, grieved, or relieved; the act of sighing.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('56d9d87e-9ca8-496f-a1eb-1e239f648b0a', 'simulate', 'To model, replicate, duplicate the behavior, appearance or properties of.', 'We will use a smoke machine to simulate the fog you will actually encounter.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('36963d7d-ecca-4a19-bb4f-c182e17b2855', 'simultaneously', 'Occurring at the same time.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('79bdb0fe-d081-432b-a824-c20a7f1c355b', 'sin', 'A violation of God''s will or religious law.', 'As a Christian, I think this is a sin against God.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8daa7e22-652f-4d6d-8c8f-7f62d3e32296', 'situated', 'To place on or into a physical location.', 'The statue is situated in a corner hardly visible to the public, except through a window from an outside maintenance area situated behind the building.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ef920b21-ff3e-40db-9fd7-185bf88a52a0', 'sketch', 'A rapidly executed freehand drawing that is not intended as a finished work, often consisting of a multitude of overlapping lines.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0605e7b4-572c-42ef-8475-43edb742c18d', 'skip', 'A leaping, jumping or skipping movement.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('23be6ad9-d5dd-459b-a4c6-1db112e11c13', 'slam', 'A sudden impact or blow.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('74985517-6da1-437c-a6f4-e18cc2bbb06e', 'slap', 'A blow, especially one given with the open hand, or with something broad and flat.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('51255fb4-5dae-4746-9187-718b59142b06', 'slash', 'A slashing action or motion, particularly:', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f78a722f-2da5-4c3c-ad6d-a1abd1d50c1b', 'slavery', 'An institution or social practice of owning human beings as property, especially for use as forced laborers.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a64a46dd-5ba2-42d8-8802-91cb2f540135', 'slot', 'A broad, flat, wooden bar, a slat, especially as used to secure a door, window, etc.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('10b6a9b7-c7c9-4344-99a7-67111dbe53fd', 'smash', 'The sound of a violent impact; a violent striking together.', 'I could hear the screech of the brakes, then the horrible smash of cars colliding.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ae637e48-9b70-4e1e-be28-4b93fa9999a8', 'snap', 'A quick breaking or cracking sound or the action of producing such a sound.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4a6e74bc-c794-479a-81f9-1249edb23fe0', 'soak', 'An immersion in water etc.', 'After the strenuous climb, I had a nice long soak in a bath.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('24363583-e890-49e8-afde-12d7fb057565', 'soar', 'The act of soaring.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3d9beb45-86c2-439a-b842-6bd5307dfe65', 'socialist', 'One who practices or advocates socialism.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b766e1cb-db3f-418c-878e-cd12f833abb8', 'sole', 'A wooden band or yoke put around the neck of an ox or cow in the stall.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f767c45a-fa9e-4ecb-bc9b-07e9fb0bc5bd', 'solely', 'Alone; exclusively.', 'The new chef was solely responsible for attending the grill.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('12e2691f-7206-41b8-a045-4e3ee6546a2e', 'solicitor', 'One who solicits.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('95e4e441-1446-47b5-9c75-2f10908d09a8', 'solidarity', 'A bond of unity or agreement between individuals, united around a common goal or against a common enemy, such as the unifying principle that defines the labor movement; mutual support within a group.', 'A long time union member himself, Phil showed solidarity with the picketing grocery store workers by shopping at a competing, unionized store.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('35b1c870-5dd0-4f55-aab5-c18adc443754', 'solo', 'A piece of music for one performer.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9453f104-9acd-4487-9df1-889116ab9129', 'spam', '(rarely countable) Unsolicited bulk electronic messages.', 'I get far too much spam.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('230ff055-da5c-4e78-b1a2-985fa2301f61', 'span', 'The space from the thumb to the end of the little finger when extended; nine inches; an eighth of a fathom.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6ddec4fb-d6c3-41f3-b259-cbffe2e7844c', 'spark', 'A small particle of glowing matter, either molten or on fire.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b601f973-333d-4d14-87b5-f99ccdb6d43f', 'specialized', 'To make distinct or separate, particularly:', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4380b39d-218c-4382-9c2f-dae4fef42069', 'specification', 'An explicit set of requirements to be satisfied by a material, product, or service.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9e52e2af-6322-4657-8673-42dba284ef72', 'specimen', 'An individual instance that represents a class; an example.', 'early specimens of the art of Picasso', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('229ff3c5-6036-4479-ae07-b38e40733c46', 'spectacle', 'An exciting or extraordinary scene, exhibition, performance etc.', 'The horse race was a thrilling spectacle.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8778c57f-c6f3-459a-b7fb-7b6c9e974eff', 'spectrum', 'A range; a continuous, infinite, one-dimensional set, possibly bounded by extremes.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c9e16260-8e82-49f3-8530-2412b34c7c64', 'sphere', 'A regular three-dimensional object in which every cross-section is a circle; the figure described by the revolution of a circle about its diameter .', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a1b1dba2-e098-449d-ae15-c6bef5a31b47', 'spin', 'Rapid circular motion.', 'He put some spin on the cue ball.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f881780f-d2e7-47dd-abe8-4a2077f43185', 'spine', 'The series of bones situated at the back from the head to the pelvis of a person, or from the head to the tail of an animal; backbone, vertebral column.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f1476ea0-4af8-4f25-926f-4807148a9cd9', 'spotlight', 'A bright, directional light or lamp, especially one used to illuminate the focus or center of attention on a stage.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ec7f1f61-db48-47ca-b0f1-95f0f818b19f', 'spouse', 'A person in a marriage or marital relationship.', 'People should treat their spouses with respect.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('10ada66d-8d67-48bd-b904-a7c131b4de2b', 'spy', 'A person who secretly watches and examines the actions of other individuals or organizations and gathers information on them (usually to gain an advantage).', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('433cadb9-252b-4af1-86c5-83ef4733d308', 'squad', 'A group of people organized for some common purpose, usually of about ten members.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e73acc5d-3493-435b-8e33-9cd91823fb94', 'squeeze', 'A close or tight fit.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('20ff6189-3933-4ec3-aec7-85e89c7744a0', 'stab', 'An act of stabbing or thrusting with an object.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('23c36938-66c0-4bb5-a8a5-d416c4d5c0e6', 'stability', 'The condition of being stable or in equilibrium, and thus resistant to change.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('400aa18b-6a0b-4f0a-afd2-992027f871aa', 'stabilize', 'To make stable.', 'Jody stabilized the table by putting a book under the short leg.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b984f391-6385-41ba-a5bc-f4ffedc8ceed', 'stake', 'A piece of wood or other material, usually long and slender, pointed at one end so as to be easily driven into the ground as a marker or a support or stay.', 'We have surveyor''s stakes at all four corners of this field, to mark exactly its borders.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0b3f913b-26b5-4f41-85df-ff925f4b8050', 'standing', '(heading) To position or be positioned physically.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e0aa616c-c186-4d94-be6f-9d85fa5e5faa', 'stark', 'Hard, firm; obdurate.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('855b398b-b62c-47d9-a13d-d514c8da5b4e', 'statistical', 'Of or pertaining to statistics.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0ef795ca-ed87-433a-a54f-cf37cd297c2a', 'steer', 'A suggestion about a course of action.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b420f79b-d978-4919-bf6d-e0679fb01a94', 'stem', 'The stock of a family; a race or generation of progenitors.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('487f92ea-6b27-4a85-8f3d-98707903fb03', 'stimulus', 'Any external phenomenon that has an influence on a system, by triggering or modifying an internal phenomenon.', 'an economic stimulus', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('119e96fb-6ee4-44ed-b38e-a7181175aeba', 'storage', 'The act of storing goods; the state of being stored.', 'There''s a lot of storage space in the loft.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('32b8b6e1-4ae8-4d4f-b22a-b3e6bae4ad06', 'straightforward', 'Proceeding in a straight course or manner; not deviating.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3545aa69-aeff-48f0-91fa-71a0c9b00d71', 'strain', 'Treasure.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('142c2c83-6db3-4e08-9b57-2a2dbf60f0e7', 'strand', 'The shore or beach of the sea or ocean; shore; beach.', 'Grand Strand', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('135636ab-9385-44f2-a337-8d26830ba505', 'strategic', 'Of or pertaining to strategy', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0fbeb05f-60fb-4c52-9ebf-8c6b8b8a3b58', 'striking', '(sometimes with out or through) To delete or cross out; to scratch or eliminate.', 'Please strike the last sentence.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('cfbb637b-b4cd-426f-a290-3bca45e1d5ba', 'strip', 'A long, thin piece of land; any long, thin area.', 'The countries were in dispute over the ownership of a strip of desert about 100 metres wide.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('21cb2291-a501-4309-810a-e36dbc66f9d2', 'strive', 'Striving; earnest endeavor; hard work.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ecc57976-781e-4170-9bea-e216404d3c19', 'structural', 'Structural steel, used in construction.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('93690737-ddff-441c-b34e-0d4a17e61d97', 'stumble', 'A fall, trip or substantial misstep.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('59f07766-0dc4-4d39-8b5f-78331de22139', 'stun', 'The condition of being stunned.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f145af1b-b65c-49e2-a4a3-156ec91dddd3', 'submission', 'The act of submitting or yielding; surrender.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7a80af11-5b04-4a80-8067-7ff6faef8c74', 'subscriber', 'A person who subscribes to a publication or a service', 'Our magazine has over ten thousand subscribers.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f8c9a7cd-17a4-45a0-bef4-fdd55a60388f', 'subscription', 'Access to a resource for a period of time, generally for payment.', 'I have a monthly subscription to the Daily Telegraph newspaper.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0d2d428b-48e0-4250-8028-f2ab90075169', 'substantial', 'Anything having substance; an essential part.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8249ce3d-69ea-479f-8f19-e88124f69ea8', 'substantially', 'In a strong substantial manner; considerably.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('72a7b9ff-584c-44c9-a502-bf7e8fe3545f', 'substitute', 'A replacement or stand-in for something that achieves a similar result or purpose.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ec634c9d-3f30-4724-b809-012868829229', 'substitution', 'The act of substituting or the state of being substituted.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('75b5b13a-c2cc-436e-8eb0-5f154271fbc3', 'subtle', 'Hard to grasp; not obvious or easily understood; barely noticeable.', 'The difference is subtle, but you can hear it if you listen carefully.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a5a78c29-b809-481c-b076-fd81ca194a8a', 'suburban', 'A person who lives in a suburb.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('54756164-bebb-4643-aa7a-811f525e3482', 'succession', 'An act of following in sequence.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6f5051f1-9482-4504-a860-6562365bf1bc', 'successive', 'Coming one after the other in a series.', 'They had won the title for five successive years.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('91ecbd3f-4b45-4706-b912-9771e34f45f6', 'successor', 'A person or thing that immediately follows another in holding an office or title.', 'George W. Bush was successor to Bill Clinton as President of the US.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('915f7fe8-7fc8-44e9-b60b-4ab8d91106fd', 'suck', 'An instance of drawing something into one''s mouth by inhaling.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('aecc2a5d-f7e4-4d6c-a6c0-f771a7c85e11', 'sue', 'To file a legal action against someone, generally a non-criminal action.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('30915b77-9da4-4dce-90c6-a4bcfae418e4', 'suite', 'A retinue or company of attendants, as of a distinguished personage', 'the ambassador''s suite', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('26c02116-d9af-4ffb-80e2-afdbce35f646', 'summit', 'A peak; the topmost point or surface, as of a mountain.', 'In summer, it is possible to hike to the summit of Mount Shasta.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0878ac13-0135-4ffc-807b-8d75211c9a98', 'superb', 'First-rate; of the highest quality; exceptionally good.', 'This champagne is superb.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a3d6124b-463a-4381-b3d4-b596b341328b', 'superior', 'A person of higher rank or quality.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('54fe944a-13f6-48aa-ba41-cc0add6154fb', 'supervise', 'To oversee or direct a task or organization.', 'Without someone to supervise them, the group will lack direction.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('56d5644b-1271-4b57-ac3b-d330342b94d8', 'supervision', 'The act or instance of supervising.', 'Under his parents'' supervision he drilled the holes in the wood.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b716b55e-f1f3-4ed3-a67c-d951068357bd', 'supervisor', 'A person with the official task of overseeing the work of a person or group, or of other operations and activities.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('43547cbd-2683-4cdd-8ba0-fdda0dbdb8c6', 'supplement', 'Something added, especially to make up for a deficiency.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('29d09c54-ec2c-4c1c-835d-238b05d2d196', 'supportive', 'Providing support.', 'I had a very supportive coach who helped me.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('00c700b7-97eb-4ba5-8f97-e7d769fa1527', 'supposedly', 'As a matter of supposition; in the beliefs or according to the claims of some people.', 'According to your testimony, you were supposedly at home watching TV when the murder occurred.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('76fd3297-9ca6-4a1a-8ba1-a198ac0564b9', 'suppress', 'To put an end to, especially with force, to crush, do away with; to prohibit, subdue.', 'Political dissent was brutally suppressed.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('42d46270-23c3-4216-b817-d7eeb17fd080', 'supreme', 'The highest point.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8a5827f6-2c69-4d4c-a39d-76da158a135f', 'surge', 'A sudden transient rush, flood or increase.', 'He felt a surge of excitement.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('29fd16b3-3928-4ef3-926c-568d7da34dcd', 'surgical', 'Of, relating to, used in, or resulting from surgery.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7b1f35a7-258c-448f-bdab-5be3959883b9', 'surplus', 'That which remains when use or need is satisfied, or when a limit is reached; excess; overplus.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a7e1309c-6209-405f-9c40-1b4917270e3a', 'surrender', 'An act of surrendering, submission into the possession of another; abandonment, resignation.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6f414c59-fe28-4379-b7c7-7b1bf76a6a6b', 'suspension', 'The act of suspending, or the state of being suspended.', 'suspension from a hook', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9a44b830-4bb8-47c2-93b2-7be8928eaf41', 'suspicion', 'The act of suspecting something or someone, especially of something wrong.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0d4dc83c-f9db-4778-8501-f014c52e1e86', 'suspicious', 'Arousing suspicion.', 'His suspicious behaviour brought him to the attention of the police.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d2516b39-f64e-41de-a0bb-5789a8f2efcf', 'sustain', 'A mechanism which can be used to hold a note, as the right pedal on a piano.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('53af7aa7-9a87-4a04-8eb7-7c88b496f0b2', 'swing', 'The manner in which something is swung.', 'Door swing indicates direction the door opens.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e3775d78-278d-4dc7-93ba-b1c718b5cebf', 'sword', 'A long-bladed weapon with a hilt, and usually a pommel and cross-guard, which is designed to stab, slash, and/or hack.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('971c90f0-677f-40e7-baed-51d7da8dd61e', 'symbolic', 'Pertaining to a symbol.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('66193a72-ee9f-415f-af70-867d4ad4c38d', 'syndrome', 'A recognizable pattern of signs, symptoms and/or behaviours, especially of a disease or medical or psychological condition.', 'Down syndrome; acquired immune deficiency syndrome; restless-leg syndrome; battered-wife syndrome', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('17cee70d-270c-4c93-b92d-935c3ba2bbae', 'synthesis', 'The formation of something complex or coherent by combining simpler things.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f7e7a66f-ffc9-4e8b-8554-971eb71b990a', 'tactic', 'A maneuver, or action calculated to achieve some end.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('43b4864a-8857-41d5-8c65-f3addf89ac5b', 'tactical', 'A combinator of proof tactics.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e1ebf60a-94a7-47a5-bb43-e7d7076272bf', 'taxpayer', 'A person who is subject to, liable for, or pays tax as opposed to a nontaxpayer who is neither the subject nor the object of revenue laws.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1719addc-73bc-45b9-946e-80775ec50ce4', 'tempt', 'To provoke someone to do wrong, especially by promising a reward; to entice.', 'She tempted me to eat the apple.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f4d74ade-50e9-4b21-a46d-6d19b4a590c1', 'tenant', 'One who pays a fee (rent) in return for the use of land, buildings, or other property owned by others.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('159175f1-0424-49e7-9ca5-818959db6af5', 'tender', 'Care, kind concern, regard.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('913996d6-425b-4c71-8567-95dea0b8cf4a', 'tenure', 'A status of possessing a thing or an office; an incumbency.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a0ee0100-42c6-4a90-a2d5-c02fa13d55f6', 'terminate', 'To end, especially in an incomplete state.', 'to terminate a surface by a line', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8e6797dc-0663-4a0f-9d9f-68975bbaf543', 'terrain', 'A single, distinctive rock formation; an area having a preponderance of a particular rock or group of rocks.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('5d648466-6b50-42f3-8199-825b6077b95a', 'terrific', 'Terrifying, causing terror; terrible; sublime, awe-inspiring.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('40881cb1-4e40-4849-aea6-e445643ef5d0', 'testify', 'To make a declaration, or give evidence, under oath.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('66567f6b-57c7-4a24-98d8-19d69a879bc0', 'texture', 'The feel or shape of a surface or substance; the smoothness, roughness, softness, etc. of something.', 'The beans had a grainy, gritty texture in her mouth.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('12de6efa-7d4d-4028-b867-318ce5c5bbfa', 'thankfully', 'In a thankful manner; giving thanks.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('702037c3-1c37-42b5-965a-eca73aa53682', 'theatrical', 'A stage performance, especially one by amateurs.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d94b6f66-ed18-4164-ac13-973930b085f5', 'theology', 'The study of God, a god, or gods; and of the truthfulness of religion in general.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d734acd0-2beb-471e-8bf0-3abee4d6fc96', 'thereafter', 'After that, from then on; thenceforth.', 'He left; thereafter we never met again.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4e4f47c1-1302-4859-8c72-442cbfbed7aa', 'thereby', 'By it; by that; by that means, or as a consequence of that.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9a5b56ce-4b39-4239-b6a8-ffb2112aa848', 'thought-provoking', 'Interesting in a way that challenges one''s beliefs, attitudes, or perspective.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('26e29a36-6b2b-4b24-9f28-5ca1ec656c14', 'thoughtful', 'Demonstrating thought or careful consideration.', 'Most thoughtful people eventually solve the puzzle.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('815c4b41-c9d4-4859-8c21-6811ad651ffe', 'thread', 'A long, thin and flexible form of material, generally with a round cross-section, used in sewing, weaving or in the construction of string.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('49332b47-4fbf-467f-b185-be1c03dd1b5c', 'threshold', 'The bottom-most part of a doorway that one crosses to enter; a sill.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f2ab0b4a-5a69-4f52-9d35-17f846ef336c', 'thrilled', 'To suddenly excite someone, or to give someone great pleasure; to (figuratively) electrify; to experience such a sensation.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7e895648-10a9-4417-8f3c-11e50ad97169', 'thrive', 'To grow or increase stature; to grow vigorously or luxuriantly, to flourish.', 'Not all animals thrive well in captivity.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1ac42744-4f28-483b-bfc1-031189074f0d', 'tide', 'The periodic change of the sea level, particularly when caused by the gravitational influence of the sun and the moon.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2a4d56a4-1293-4f49-91fa-93a3d1e21a94', 'tighten', 'To make tighter.', 'Please tighten that screw a quarter-turn.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4fd7024f-2125-4de0-a3a3-c2de181cf284', 'timber', 'Trees in a forest regarded as a source of wood.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c84559c1-9ffd-4206-95e5-8002ad62c475', 'timely', 'Done at the proper time or within the proper time limits; prompt.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b0bd4604-2ea9-42b9-8c1f-097044c9eb3d', 'tobacco', 'Any plant of the genus Nicotiana.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('93f9bf06-8d7f-4ecb-a4a5-da387df9c50c', 'tolerate', 'To accept hardship without objection.', 'I can tolerate working on Saturdays, but not on Sundays.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('13cb4778-e4a4-43a8-9cc4-260dffc33508', 'toll', 'Loss or damage incurred through a disaster.', 'The war has taken its toll on the people.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ce634297-418a-498b-a165-0fae45926838', 'torture', 'Intentional causing of somebody''s experiencing agony', 'In every war there are acts of torture that cause the world to shudder.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('39abec9d-6a01-422b-abfa-36ced3862c4a', 'toss', 'A throw, a lob, of a ball etc., with an initial upward direction, particularly with a lack of care.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('599eee0f-7924-43b4-9f6a-9559c182d99c', 'toxic', 'Having a chemical nature that is harmful to health or lethal if consumed or otherwise entering into the body in sufficient quantities.', 'Tobacco smoke contains many toxic substances.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d10c191d-00ef-4f71-a0b1-fbb6de9d012e', 'trademark', 'A word, symbol, or phrase used to identify a particular company''s product and differentiate it from other companies'' products.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2eae24aa-29c5-4bb9-9a8e-6ac4016824d9', 'trail', 'The track or indication marking the route followed by something that has passed, such as the footprints of animal on land or the contrail of an airplane in the sky.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d507fcde-3188-4e55-aceb-d8848ef38bb6', 'trailer', 'Someone who or something that trails.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c5e8b8a5-a19d-4c1b-bc7c-1b673a5003d7', 'transaction', 'The act of conducting or carrying out (business, negotiations, plans).', 'The transaction was made on Friday with the supplier.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('55d8786f-1ef6-4d79-90cb-f21387c16ab4', 'transcript', 'Something which has been transcribed; a writing or composition consisting of the same words as the original; a written copy.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b0f3ca13-2229-421d-8b47-b49577e42e42', 'transformation', 'The act of transforming or the state of being transformed.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('78238b09-b7cb-4925-8695-c08fbfdd139c', 'transit', 'The act of passing over, across, or through something.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c679405e-ca6b-4b4b-93d7-0b3fdd28d6e9', 'transmission', 'The act of transmitting, e.g. data or electric power.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8b06c485-0019-4794-a76c-d91294ebb2c7', 'transparent', '(of a material or object) See-through, clear; having the property that light passes through it almost undisturbed, such that one can see through it clearly.', 'The waters of the lake were transparent until the factory dumped waste there.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3df54008-5b68-4c33-905f-0540881586a0', 'trauma', 'Any serious injury to the body, often resulting from violence or an accident.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('5adedb93-60dd-4f70-80e5-fa2f928b00a0', 'tremendous', 'Awe-inspiring; terrific.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7935352d-696b-49e8-a014-5df88ae6cbad', 'tribal', 'A design or image that has been influenced by indigenous peoples; especially such a tattoo.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('11e12e73-f2bc-4203-b433-c42206c1edc2', 'tribunal', 'An assembly including one or more judges to conduct judicial business; a court of law.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9210330f-e460-4487-88e7-4584e79eb9e4', 'tribute', 'An acknowledgment of gratitude, respect or admiration; an accompanying gift.', 'Please accept this as a tribute of our thanks.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c73b5e4c-cce9-426c-99b4-5d5cc3f87eae', 'trio', 'A group of three people or things.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e947d409-8c3e-490a-958c-b02c8f7ebbdf', 'triumph', 'A conclusive success following an effort, conflict, or confrontation of obstacles; victory; conquest.', 'the triumph of knowledge', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c6381f70-1aed-4a47-bc4b-39a4adbcc716', 'trophy', 'Tropæum.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('48bfe81b-bcb9-464e-acf4-109730478b8a', 'troubled', 'To disturb, stir up, agitate (a medium, especially water).', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ddab0b9d-e2c5-43c2-9a4a-275cb256e042', 'trustee', 'A person to whom property is legally committed in trust, to be applied either for the benefit of specified individuals, or for public uses; one who is intrusted with property for the benefit of another.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('10896584-b25a-4729-a433-e6dfb130d795', 'tuition', 'A sum of money paid for instruction (such as in a high school, boarding school, university, or college).', 'These rosemaling workshops are no place for anyone who wants to pester me or the students with the "white privilege" card, inter alia. Therefore, I reserve the right to refund the tuition of such men and women, kick them out the door, and bar them from at least two of my future events.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a09dcaab-3996-4d3c-86fa-3a3dd211be02', 'turnout', 'The act of coming forth.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('2f1f7c5b-0027-4864-9a83-8b75c20ccafd', 'turnover', 'The amount of money taken as sales transacted in a given period.', 'The company had an annual turnover of $500,000.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('43bd0770-f17b-421b-a93d-fc28970f819d', 'twist', 'A twisting force.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e5fc1bbd-56e7-4bdf-9f10-f3ae68522ed3', 'undergraduate', 'A student at a university who has not yet received a degree.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f24048a9-19dc-4351-a461-23f26fa35e97', 'underlying', 'To lie in a position directly beneath.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('0d691b03-7f15-475b-888f-254154bb4dc9', 'undermine', 'To dig underneath (something), to make a passage for destructive or military purposes; to sap.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('5d14f25d-cab7-438b-b1db-94f864a150b4', 'undoubtedly', 'Without doubt; definitely.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f8b33f87-0bf9-4de2-8e16-bc4b7c6f3524', 'unify', 'Cause to become one; make into a unit; consolidate; merge; combine.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d1bf108f-c123-41ca-b768-c51cbfb0388e', 'unprecedented', 'Never before seen, done, or experienced; without precedent.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('504148ee-66b5-40ff-b935-03d1ac44e03e', 'unveil', 'To remove a veil from; to uncover; to reveal something hidden.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ef87afd2-8aef-43c1-8782-869158e2d501', 'upcoming', 'The act of coming up.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('78ebf332-2108-42d1-bf79-0007853da460', 'upgrade', 'An upward grade or slope.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b7e37b4f-6bc7-42e8-a8f3-a86cc5ae6a0c', 'uphold', 'To hold up; to lift on high; to elevate.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7fa5fb42-8df4-4044-bf31-fe9c26bba3ec', 'utility', 'The state or condition of being useful; usefulness.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ba2bc1dc-5724-4c67-9ba6-33005d517560', 'utilize', 'To make use of; to use.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ff9af842-9933-4b47-9bff-1c2d4019a2b9', 'utterly', 'Completely, entirely, to the fullest extent', 'I have failed you utterly.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c25d8a62-e52f-463b-a975-bd7ded9ea310', 'vacuum', 'A region of space that contains no matter.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7e7a2735-b8ae-45ef-b7f2-8951fbd17766', 'vague', 'A wandering; a vagary.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('369d5dd5-cd2e-4a0d-bb32-05fd9818f4fd', 'validity', 'The state of being valid, authentic or genuine.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ec33ec8a-2660-45ff-9426-44f2f11cb539', 'vanish', 'The brief terminal part of a vowel or vocal element, differing more or less in quality from the main part.', 'a as in ale ordinarily ends with a vanish of i as in ill.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b373c954-76d6-4fce-adc9-aee94e8f2cc2', 'variable', 'Something that is variable.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('aa184d29-3935-4446-bcd9-6b807ed3a48e', 'varied', 'Diverse or miscellaneous', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('41e2e871-58ca-4ddb-98fa-f7c5ae74a986', 'vein', 'A blood vessel that transports blood from the capillaries back to the heart.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7de7bef7-07c0-4060-a706-7e7d92304afa', 'verbal', '(grammar) A verb form which does not function as a predicate, or a word derived from a verb. In English, infinitives, participles and gerunds are verbals.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('6144dc0c-f643-4a7e-b8b5-0da6290f56b9', 'verify', 'To substantiate or prove the truth of something', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('9752e3c6-3c2f-4cac-ace8-ac7a18bedd3d', 'verse', 'A poetic form with regular meter and a fixed rhyme scheme.', 'Restoration literature is well known for its carefully constructed verse.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f70206d7-9068-4531-9b40-5a06bc0fcd1f', 'versus', 'Against; in opposition to.', 'It is the Packers versus the Steelers in the Super Bowl.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('adde2440-f89a-4852-8f0f-da1c91ee145d', 'vessel', 'Any craft designed for transportation on water, such as a ship or boat.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ee778209-1cc4-4092-a01a-8f2424ae3b3f', 'veteran', 'A person with long experience of a particular activity.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('da1b72eb-178d-4500-adba-31c92b0c54ea', 'viable', 'An organism that is able to live and develop.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('10606e6b-e080-4686-b98f-7a82a81447a3', 'vibrant', 'Pulsing with energy or activity.', 'He has a vibrant personality.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('a893cbda-8eb5-4acd-b508-2913c01c827c', 'vice', 'A bad habit.', 'Gluttony is a vice, not a virtue.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c0c38c6d-9227-42f2-af88-740a6e3cd6d4', 'vicious', 'Violent, destructive and cruel.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e0fc7220-fb40-4f37-921f-712b3f7ab87a', 'villager', 'A person who lives in, or comes from, a village.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1340b105-06de-4331-a80e-d8590d454d22', 'violate', 'To break or disregard (a rule or convention).', 'Accessing unauthorized files violates security protocol.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c2d943c6-5a67-4e95-9f45-787035182c7f', 'virtue', 'Accordance with moral principles; conformity of behaviour or thought with the strictures of morality; good moral conduct.', 'Without virtue, there is no freedom.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('66fee2d2-6ce5-4de5-a538-08852f6fc2c6', 'vocal', 'A vocal sound; specifically, a purely vocal element of speech, unmodified except by resonance; a vowel or a diphthong; a tonic element; a tonic; distinguished from a subvocal, and a nonvocal', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c86babe1-e5d4-4369-bb65-8f07320f053e', 'vow', 'A solemn promise to perform some act, or behave in a specified manner, especially a promise to live and act in accordance with the rules of a religious order.', 'The old hermit, up in the mountains, took a vow of silence.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1c2893fe-34ec-464d-8a10-e4522e2f7aae', 'vulnerability', 'Susceptibility to attack or injury; the state or condition of being weak or poorly defended.', 'The country recognized their defence vulnerability after an airplane landed in front of the central square without any consequences.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('78c13556-e354-4dcf-8b68-cc1e0576a6fe', 'vulnerable', 'More or most likely to be exposed to the chance of being attacked or harmed, either physically or emotionally.', 'It''s okay to get vulnerable every now and again.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('558d706f-efa2-499f-95cf-6e334efaf43f', 'ward', 'A warden; a guard; a guardian or watchman.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c3b5cc5a-9022-4d0e-9e8e-65e2d61da483', 'warehouse', 'A place for storing large amounts of products. In logistics, a place where products go to from the manufacturer before going to the retailer.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('8b54328d-60ec-4d96-b800-4638ef4094df', 'warfare', 'The waging of war or armed conflict against an enemy.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('7feb8ee9-8d98-40b3-b33f-48eb0670a59f', 'warrant', 'Authorization or certification; a sanction, as given by a superior.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('ec243826-0031-4fcd-a871-01252f58d962', 'warrior', 'A person who is actively engaged in battle, conflict or warfare; a soldier or combatant.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3f4357f5-c2e5-4e2b-8db2-05017985d251', 'weaken', 'To make weaker or less strong.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3835cae0-c851-47f8-9ee9-420217858bc0', 'weave', 'A type or way of weaving.', 'That rug has a very tight weave.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('42f2323c-b28a-4c96-954a-1530cc45c876', 'weed', 'Any plant regarded as unwanted at the place where, and at the time when it is growing.', 'If it isn''t in a straight line or marked with a label, it''s a weed.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1c4c0221-1de2-460e-bf01-0f11b5dd7cc7', 'well-being', 'A state of health, happiness and/or prosperity.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('598d48c4-b794-45fe-9b58-3f6ed3b8ca6c', 'whatsoever', 'Whatever.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d404ff06-68cf-44fb-a7b0-42cad4128f33', 'whereby', '(interrogative) By what, in which direction; how.', 'Whereby goest thou?', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('74841c06-bc0f-46b8-b76a-4f30a070d97c', 'whilst', '(rare or literary in North America) While, at the same time.', 'Drivers must switch off engines whilst on stand.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('c53277aa-78fe-413b-a34f-49c94e72703c', 'whip', 'A lash; a pliant, flexible instrument, such as a rod (commonly of cane or rattan) or a plaited or braided rope or thong (commonly of leather) used to create a sharp "crack" sound for directing or herding animals.', 'I had to use the whip to get the sheep''s attention.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('d102261f-baf0-46e6-92e2-59fa3479fbf1', 'wholly', 'Completely and entirely; to the fullest extent.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('fa03e185-c3b5-47c8-9ea1-cc52b35c6498', 'widen', 'To become wide or wider.', 'His eyes widened as her negligee fell to the floor.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('f58cf9e3-083f-46b2-ba75-2f7362a0a61d', 'widow', 'A woman whose spouse has died (and who has not remarried); feminine of widower.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('b8cf7f54-4161-4dc4-84f6-8a0175f18396', 'width', 'The state of being wide.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('4c5b6c86-489c-40c4-a387-f9971ec3a19c', 'willingness', 'The state of being willing', 'All it takes is a willingness to learn.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('887007d1-de41-4541-88cf-eda87bf6257d', 'wipe', 'The act of wiping something.', 'multiple wipes of a computer''s hard disk', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3d2b216b-3969-44be-bc8c-863c6cab665b', 'wit', '(now usually in the plural) Sanity.', 'He''s gone completely out of his wits.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('eab2add6-94fc-4b21-9f1a-a2dc4f9f6b30', 'withdrawal', 'Receiving from someone''s care what one has earlier entrusted to them. Usually refers to money.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('1947cfb3-a75c-4aac-9164-14e23d48e5e1', 'workout', 'An exercise session; a period of physical exercise.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('686c5af7-19db-4b11-a96d-509236ccd136', 'worship', 'The condition of being worthy; honour, distinction.', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('e126cc4a-6257-48bb-85b2-483b04b1c57f', 'worthwhile', 'Good and important enough to spend time, effort, or money on.', 'Doing volunteer work to help others is truly worthwhile.', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('3a001c2d-059e-462d-b99a-4298391ee59d', 'worthy', 'A distinguished or eminent person', '', 'General', 'C1');
INSERT INTO vocabulary (id, word, definition, example, topic, level) VALUES ('fb51da9d-f92f-4359-845d-b9233a41dbba', 'yell', 'A shout.', '', 'General', 'C1');
